package controle.api.back_end.service;

import controle.api.back_end.dto.dashboard.out.*;
import controle.api.back_end.dto.registros.mapper.RegistrosMapper;
import controle.api.back_end.dto.registros.out.RegistroResponseDto;
import controle.api.back_end.exception.EntidadeNaoEncontradaException;
import controle.api.back_end.model.categoria.CategoriaUsuario;
import controle.api.back_end.model.configuracoes.Configuracoes;
import controle.api.back_end.model.dashboard.TipoPeriodo;
import controle.api.back_end.model.eventoFinanceiro.*;
import controle.api.back_end.repository.configuracoes.ConfiguracoesRepository;
import controle.api.back_end.repository.eventoFinanceiro.EventoDetalheRepository;
import controle.api.back_end.repository.eventoFinanceiro.EventoFinanceiroRepository;
import controle.api.back_end.repository.eventoFinanceiro.EventoInstituicaoRepository;
import controle.api.back_end.repository.usuario.UsuarioRepository;
import controle.api.back_end.utils.PeriodoTemporalUtils;
import controle.api.back_end.utils.PeriodoTemporalUtils.Periodo;
import org.springframework.stereotype.Service;

import java.math.BigDecimal;
import java.math.RoundingMode;
import java.time.DayOfWeek;
import java.time.LocalDate;
import java.time.format.DateTimeFormatter;
import java.time.format.TextStyle;
import java.time.temporal.ChronoUnit;
import java.util.*;
import java.util.stream.Collectors;

@Service
public class DashboardService {

    private final UsuarioRepository usuarioRepository;
    private final EventoFinanceiroRepository eventoFinanceiroRepository;
    private final EventoInstituicaoRepository eventoInstituicaoRepository;
    private final EventoDetalheRepository eventoDetalheRepository;
    private final UsuarioService usuarioService;
    private final ConfiguracoesService configuracoesService;
    private final ConfiguracoesRepository configuracoesRepository;
    private final InstituicaoService instituicaoService;
    private final RegistroService registroService;

    public DashboardService(UsuarioRepository usuarioRepository,
                            RegistroService registroService,
                            EventoFinanceiroRepository eventoFinanceiroRepository,
                            EventoInstituicaoRepository eventoInstituicaoRepository,
                            EventoDetalheRepository eventoDetalheRepository,
                            InstituicaoService instituicaoService,
                            UsuarioService usuarioService,
                            ConfiguracoesService configuracoesService,
                            ConfiguracoesRepository configuracoesRepository) {
        this.usuarioRepository        = usuarioRepository;
        this.registroService          = registroService;
        this.eventoFinanceiroRepository = eventoFinanceiroRepository;
        this.eventoInstituicaoRepository = eventoInstituicaoRepository;
        this.eventoDetalheRepository  = eventoDetalheRepository;
        this.instituicaoService       = instituicaoService;
        this.usuarioService           = usuarioService;
        this.configuracoesService     = configuracoesService;
        this.configuracoesRepository  = configuracoesRepository;
    }

    // =========================================================================
    //  KPI 1 — SALDO TOTAL DO PERÍODO
    //  Saldo acumulado de TODA a história do usuário até o final do período
    //  (ou até hoje, se o período ainda está em aberto).
    // =========================================================================

    public SaldoTotalDto getSaldoTotal(TipoPeriodo tipo, int ano, Integer mes,
                                       Integer trimestre, Integer semestre, UUID userId) {
        validarUsuario(userId);
        PeriodoTemporalUtils.validar(tipo, ano, mes, trimestre, semestre);

        Periodo periodo = resolverPeriodo(userId, tipo, ano, mes, trimestre, semestre);
        LocalDate corte = dataCorte(periodo);

        List<EventoFinanceiro> todos = eventoFinanceiroRepository.findAllByUsuario_Id(userId);
        BigDecimal saldo = BigDecimal.ZERO;
        for (EventoFinanceiro e : todos) {
            if (!e.getDataEvento().isAfter(corte)) {
                saldo = saldoContribuicao(saldo, e);
            }
        }

        return new SaldoTotalDto(saldo, corte, periodo.label());
    }

    // =========================================================================
    //  KPI 2 — GASTO TOTAL DO PERÍODO + variação vs. período anterior
    // =========================================================================

    public GastoTotalDto getGastoTotal(TipoPeriodo tipo, int ano, Integer mes,
                                       Integer trimestre, Integer semestre, UUID userId) {
        validarUsuario(userId);
        PeriodoTemporalUtils.validar(tipo, ano, mes, trimestre, semestre);

        int diaFiscal    = getDiaFiscal(userId);
        Periodo atual    = PeriodoTemporalUtils.calcular(tipo, ano, mes, trimestre, semestre, diaFiscal);
        Periodo anterior = PeriodoTemporalUtils.calcularAnterior(tipo, ano, mes, trimestre, semestre, diaFiscal);

        List<EventoFinanceiro> eventos = eventoFinanceiroRepository.findAllByUsuario_Id(userId);

        BigDecimal gastosAtual    = somarGastos(eventos, atual.inicio(), atual.fim());
        BigDecimal gastosAnterior = somarGastos(eventos, anterior.inicio(), anterior.fim());

        int variacao = calcularVariacaoPercentual(gastosAtual, gastosAnterior);

        return new GastoTotalDto(gastosAtual, gastosAnterior, variacao, atual.label(), anterior.label());
    }

    // =========================================================================
    //  KPI 3 — MAIOR GASTO DO PERÍODO
    // =========================================================================

    public MaiorGastoDto getMaiorGasto(TipoPeriodo tipo, int ano, Integer mes,
                                       Integer trimestre, Integer semestre, UUID userId) {
        validarUsuario(userId);
        PeriodoTemporalUtils.validar(tipo, ano, mes, trimestre, semestre);

        Periodo periodo = resolverPeriodo(userId, tipo, ano, mes, trimestre, semestre);
        List<EventoFinanceiro> eventos = eventoFinanceiroRepository.findAllByUsuario_Id(userId);

        BigDecimal maiorValor  = BigDecimal.ZERO;
        BigDecimal totalGastos = BigDecimal.ZERO;
        EventoFinanceiro maiorEvento = null;

        for (EventoFinanceiro e : eventos) {
            if (!emPeriodo(e, periodo) || e.getTipo() != Tipo.Gasto) continue;

            BigDecimal v = BigDecimal.valueOf(e.getValor());
            totalGastos = totalGastos.add(v);
            if (v.compareTo(maiorValor) > 0) {
                maiorValor = v;
                maiorEvento = e;
            }
        }

        if (maiorEvento == null) {
            return new MaiorGastoDto("Sem gastos", "N/A", BigDecimal.ZERO, 0, null);
        }

        int pct = totalGastos.compareTo(BigDecimal.ZERO) > 0
                ? maiorValor.divide(totalGastos, 4, RoundingMode.HALF_UP)
                             .multiply(BigDecimal.valueOf(100)).intValue()
                : 0;

        return new MaiorGastoDto(
                tituloEvento(maiorEvento),
                categoriaEvento(maiorEvento),
                BigDecimal.valueOf(maiorEvento.getValor()),
                pct,
                maiorEvento.getDataEvento()
        );
    }

    // =========================================================================
    //  KPI 4 — CATEGORIA QUE MAIS IMPACTOU
    // =========================================================================

    public CategoriaImpactoDto getCategoriaImpacto(TipoPeriodo tipo, int ano, Integer mes,
                                                    Integer trimestre, Integer semestre, UUID userId) {
        validarUsuario(userId);
        PeriodoTemporalUtils.validar(tipo, ano, mes, trimestre, semestre);

        int diaFiscal    = getDiaFiscal(userId);
        Periodo atual    = PeriodoTemporalUtils.calcular(tipo, ano, mes, trimestre, semestre, diaFiscal);
        Periodo anterior = PeriodoTemporalUtils.calcularAnterior(tipo, ano, mes, trimestre, semestre, diaFiscal);

        List<EventoFinanceiro> eventos = eventoFinanceiroRepository.findAllByUsuario_Id(userId);

        Map<String, BigDecimal> atualPorCat    = somarGastosPorCategoria(eventos, atual.inicio(), atual.fim());
        Map<String, BigDecimal> anteriorPorCat = somarGastosPorCategoria(eventos, anterior.inicio(), anterior.fim());

        if (atualPorCat.isEmpty()) {
            return new CategoriaImpactoDto("Sem gastos", BigDecimal.ZERO, BigDecimal.ZERO, 0);
        }

        String categoriaTopo = atualPorCat.entrySet().stream()
                .max(Map.Entry.comparingByValue())
                .map(Map.Entry::getKey)
                .orElse("Sem categoria");

        BigDecimal valorAtual    = atualPorCat.getOrDefault(categoriaTopo, BigDecimal.ZERO);
        BigDecimal valorAnterior = anteriorPorCat.getOrDefault(categoriaTopo, BigDecimal.ZERO);
        int variacao = calcularVariacaoPercentual(valorAtual, valorAnterior);

        return new CategoriaImpactoDto(categoriaTopo, valorAtual, valorAnterior, variacao);
    }

    // =========================================================================
    //  GRÁFICO 1 — EVOLUÇÃO DOS GASTOS (line chart)
    //  MENSAL / TRIMESTRAL → granularidade diária
    //  SEMESTRAL           → granularidade semanal
    //  ANUAL               → granularidade mensal
    // =========================================================================

    public EvolucaoGastosDto getEvolucaoGastos(TipoPeriodo tipo, int ano, Integer mes,
                                                Integer trimestre, Integer semestre, UUID userId) {
        validarUsuario(userId);
        PeriodoTemporalUtils.validar(tipo, ano, mes, trimestre, semestre);

        Periodo periodo = resolverPeriodo(userId, tipo, ano, mes, trimestre, semestre);
        List<EventoFinanceiro> eventos = eventoFinanceiroRepository.findAllByUsuario_Id(userId);

        // daily map de gastos e de recebimentos
        Map<LocalDate, BigDecimal> porDia    = new TreeMap<>();
        Map<LocalDate, BigDecimal> porDiaRec = new TreeMap<>();
        for (EventoFinanceiro e : eventos) {
            if (!emPeriodo(e, periodo)) continue;
            if (e.getTipo() == Tipo.Gasto || e.getTipo() == Tipo.Transferencia) {
                porDia.merge(e.getDataEvento(), BigDecimal.valueOf(e.getValor()), BigDecimal::add);
            } else if (e.getTipo() == Tipo.Recebimento || e.getTipo() == Tipo.Emprestimo) {
                porDiaRec.merge(e.getDataEvento(), BigDecimal.valueOf(e.getValor()), BigDecimal::add);
            }
        }

        String granularidade;
        List<EvolucaoGastosDto.Ponto> dados;
        List<EvolucaoGastosDto.Ponto> dadosRec;

        switch (tipo) {
            case MENSAL, TRIMESTRAL -> {
                granularidade = "DIARIO";
                dados    = seriesDiaria(porDia,    periodo.inicio(), periodo.fim(), "dd/MM");
                dadosRec = seriesDiaria(porDiaRec, periodo.inicio(), periodo.fim(), "dd/MM");
            }
            case SEMESTRAL -> {
                granularidade = "SEMANAL";
                dados    = seriesSemanais(porDia,    periodo.inicio(), periodo.fim());
                dadosRec = seriesSemanais(porDiaRec, periodo.inicio(), periodo.fim());
            }
            default -> { // ANUAL
                granularidade = "MENSAL";
                dados    = seriesMensais(porDia,    periodo.inicio(), periodo.fim());
                dadosRec = seriesMensais(porDiaRec, periodo.inicio(), periodo.fim());
            }
        }

        return new EvolucaoGastosDto(periodo.label(), granularidade, dados, dadosRec);
    }

    // =========================================================================
    //  GRÁFICO 2 — CATEGORIAS (stacked bar chart)
    // =========================================================================

    public CategoriasGraficoDto getCategoriasGrafico(TipoPeriodo tipo, int ano, Integer mes,
                                                      Integer trimestre, Integer semestre, UUID userId) {
        validarUsuario(userId);
        PeriodoTemporalUtils.validar(tipo, ano, mes, trimestre, semestre);

        Periodo periodo = resolverPeriodo(userId, tipo, ano, mes, trimestre, semestre);
        List<EventoFinanceiro> eventos = eventoFinanceiroRepository.findAllByUsuario_Id(userId);

        Map<String, BigDecimal> totais     = new LinkedHashMap<>();
        Map<String, Integer>    ocorrencias = new LinkedHashMap<>();
        BigDecimal totalGeral = BigDecimal.ZERO;

        for (EventoFinanceiro e : eventos) {
            if (!emPeriodo(e, periodo)) continue;
            if (e.getTipo() != Tipo.Gasto && e.getTipo() != Tipo.Transferencia) continue;

            EventoDetalhe det = e.getGastoDetalhe();
            if (det == null || det.getCategoriaUsuario() == null) continue;

            for (CategoriaUsuario cu : det.getCategoriaUsuario()) {
                String nome = cu.getCategoria().getTitulo();
                totais.merge(nome, BigDecimal.valueOf(e.getValor()), BigDecimal::add);
                ocorrencias.merge(nome, 1, Integer::sum);
            }
            totalGeral = totalGeral.add(BigDecimal.valueOf(e.getValor()));
        }

        final BigDecimal tf = totalGeral;
        List<CategoriasGraficoDto.CategoriaData> lista = totais.entrySet().stream()
                .sorted(Map.Entry.<String, BigDecimal>comparingByValue().reversed())
                .map(entry -> {
                    int pct = tf.compareTo(BigDecimal.ZERO) > 0
                            ? entry.getValue().divide(tf, 4, RoundingMode.HALF_UP)
                                              .multiply(BigDecimal.valueOf(100)).intValue()
                            : 0;
                    return new CategoriasGraficoDto.CategoriaData(
                            entry.getKey(), entry.getValue(), pct,
                            ocorrencias.getOrDefault(entry.getKey(), 0));
                })
                .toList();

        return new CategoriasGraficoDto(periodo.label(), lista);
    }

    // =========================================================================
    //  GRÁFICO 3 — COMPARAÇÃO ENTRE PERÍODOS (multiple line chart)
    //  Ambas as séries são normalizadas por posição (Dia 1, Dia 2, … Dia N).
    // =========================================================================

    public ComparacaoPeriodoDto getComparacaoPeriodo(TipoPeriodo tipo, int ano, Integer mes,
                                                      Integer trimestre, Integer semestre, UUID userId) {
        validarUsuario(userId);
        PeriodoTemporalUtils.validar(tipo, ano, mes, trimestre, semestre);

        int diaFiscal    = getDiaFiscal(userId);
        Periodo atual    = PeriodoTemporalUtils.calcular(tipo, ano, mes, trimestre, semestre, diaFiscal);
        Periodo anterior = PeriodoTemporalUtils.calcularAnterior(tipo, ano, mes, trimestre, semestre, diaFiscal);

        List<EventoFinanceiro> eventos = eventoFinanceiroRepository.findAllByUsuario_Id(userId);

        Map<LocalDate, BigDecimal> porDiaAtual    = gastosPorDia(eventos, atual.inicio(), atual.fim());
        Map<LocalDate, BigDecimal> porDiaAnterior = gastosPorDia(eventos, anterior.inicio(), anterior.fim());

        // Para ANUAL: granularidade mensal (12 pontos com nome do mês)
        if (tipo == TipoPeriodo.ANUAL) {
            DateTimeFormatter fmtMes = DateTimeFormatter.ofPattern("MMM", new Locale("pt", "BR"));
            List<ComparacaoPeriodoDto.PontoComparacao> pontos = new ArrayList<>();
            for (int m = 0; m < 12; m++) {
                LocalDate inicioAtual    = atual.inicio().withDayOfMonth(1).plusMonths(m);
                LocalDate fimAtual       = inicioAtual.withDayOfMonth(inicioAtual.lengthOfMonth());
                LocalDate inicioAnterior = anterior.inicio().withDayOfMonth(1).plusMonths(m);
                LocalDate fimAnterior    = inicioAnterior.withDayOfMonth(inicioAnterior.lengthOfMonth());
                if (inicioAtual.isAfter(atual.fim())) break;
                String nomeMes = inicioAtual.format(fmtMes);
                nomeMes = Character.toUpperCase(nomeMes.charAt(0)) + nomeMes.substring(1);
                pontos.add(new ComparacaoPeriodoDto.PontoComparacao(
                        nomeMes,
                        somarRange(porDiaAtual,    inicioAtual,    fimAtual.isAfter(atual.fim())         ? atual.fim()     : fimAtual),
                        somarRange(porDiaAnterior, inicioAnterior, fimAnterior.isAfter(anterior.fim())   ? anterior.fim()  : fimAnterior)
                ));
            }
            return new ComparacaoPeriodoDto(atual.label(), anterior.label(), pontos);
        }

        long duracaoAtual    = ChronoUnit.DAYS.between(atual.inicio(), atual.fim()) + 1;
        long duracaoAnterior = ChronoUnit.DAYS.between(anterior.inicio(), anterior.fim()) + 1;
        long numPontos = Math.min(duracaoAtual, duracaoAnterior);

        List<ComparacaoPeriodoDto.PontoComparacao> pontos = new ArrayList<>();
        for (int i = 0; i < numPontos; i++) {
            LocalDate dAtual    = atual.inicio().plusDays(i);
            LocalDate dAnterior = anterior.inicio().plusDays(i);

            pontos.add(new ComparacaoPeriodoDto.PontoComparacao(
                    "Dia " + (i + 1),
                    porDiaAtual.getOrDefault(dAtual, BigDecimal.ZERO),
                    porDiaAnterior.getOrDefault(dAnterior, BigDecimal.ZERO)
            ));
        }

        return new ComparacaoPeriodoDto(atual.label(), anterior.label(), pontos);
    }

    // =========================================================================
    //  GRÁFICO 4 — GASTOS POR DIA DA SEMANA (heat map)
    // =========================================================================

    public HeatMapDiaSemanaDto getHeatMapDiaSemana(TipoPeriodo tipo, int ano, Integer mes,
                                                    Integer trimestre, Integer semestre, UUID userId) {
        validarUsuario(userId);
        PeriodoTemporalUtils.validar(tipo, ano, mes, trimestre, semestre);

        Periodo periodo = resolverPeriodo(userId, tipo, ano, mes, trimestre, semestre);
        List<EventoFinanceiro> eventos = eventoFinanceiroRepository.findAllByUsuario_Id(userId);

        Map<DayOfWeek, BigDecimal> porDia = new EnumMap<>(DayOfWeek.class);
        for (DayOfWeek d : DayOfWeek.values()) porDia.put(d, BigDecimal.ZERO);

        for (EventoFinanceiro e : eventos) {
            if (!emPeriodo(e, periodo)) continue;
            if (e.getTipo() != Tipo.Gasto && e.getTipo() != Tipo.Transferencia) continue;
            porDia.merge(e.getDataEvento().getDayOfWeek(), BigDecimal.valueOf(e.getValor()), BigDecimal::add);
        }

        BigDecimal max = porDia.values().stream().max(BigDecimal::compareTo).orElse(BigDecimal.ONE);
        Locale ptBr = new Locale("pt", "BR");

        DayOfWeek[] ordem = {
                DayOfWeek.MONDAY, DayOfWeek.TUESDAY, DayOfWeek.WEDNESDAY,
                DayOfWeek.THURSDAY, DayOfWeek.FRIDAY, DayOfWeek.SATURDAY, DayOfWeek.SUNDAY
        };

        List<HeatMapDiaSemanaDto.DiaDado> dias = Arrays.stream(ordem)
                .map(d -> {
                    BigDecimal v = porDia.get(d);
                    double norm = max.compareTo(BigDecimal.ZERO) > 0
                            ? v.divide(max, 4, RoundingMode.HALF_UP).doubleValue()
                            : 0.0;
                    String nome = d.getDisplayName(TextStyle.FULL, ptBr);
                    nome = Character.toUpperCase(nome.charAt(0)) + nome.substring(1);
                    return new HeatMapDiaSemanaDto.DiaDado(nome, v, norm);
                })
                .toList();

        return new HeatMapDiaSemanaDto(periodo.label(), dias);
    }

    // =========================================================================
    //  GRÁFICO 5 — FLUXO FINANCEIRO (Sankey)
    //  Fluxo: Entrada → Instituição → Categoria/Transferência/Poupança
    // =========================================================================

    public FluxoFinanceiroDto getFluxoFinanceiro(TipoPeriodo tipo, int ano, Integer mes,
                                                  Integer trimestre, Integer semestre, UUID userId) {
        validarUsuario(userId);
        PeriodoTemporalUtils.validar(tipo, ano, mes, trimestre, semestre);

        Periodo periodo = resolverPeriodo(userId, tipo, ano, mes, trimestre, semestre);
        List<EventoFinanceiro> eventos = eventoFinanceiroRepository.findAllByUsuario_Id(userId);

        // --- acumuladores ---
        Map<String, String>     instLabels    = new LinkedHashMap<>(); // id → label
        Map<String, BigDecimal> instEntrada   = new LinkedHashMap<>();
        Map<String, BigDecimal> instSaida     = new LinkedHashMap<>();
        Map<String, String>     catLabels     = new LinkedHashMap<>(); // id → label
        Map<String, BigDecimal> catTotal      = new LinkedHashMap<>();
        Map<String, BigDecimal> saidaSpecial  = new LinkedHashMap<>(); // "Transferência","Poupança"
        // links: source → target → valor
        Map<String, Map<String, BigDecimal>> flowMap = new LinkedHashMap<>();

        for (EventoFinanceiro e : eventos) {
            if (!emPeriodo(e, periodo)) continue;

            List<EventoInstituicao> insts = eventoInstituicaoRepository
                    .findEventoInstituicaoByEventoFinanceiro_Id(e.getId());
            String instNome = insts.isEmpty() ? "Sem Instituição"
                    : insts.get(0).getInstituicaoUsuario().getInstituicao().getNome();
            String instId = "inst_" + normalizeId(instNome);
            instLabels.put(instId, instNome);

            BigDecimal valor = BigDecimal.valueOf(e.getValor());

            switch (e.getTipo()) {
                case Recebimento, Emprestimo -> {
                    instEntrada.merge(instId, valor, BigDecimal::add);
                    // link: "entrada" → instituição
                    String entradaId = "entrada";
                    flowMap.computeIfAbsent(entradaId, k -> new LinkedHashMap<>())
                           .merge(instId, valor, BigDecimal::add);
                }
                case Gasto -> {
                    instSaida.merge(instId, valor, BigDecimal::add);
                    EventoDetalhe det = e.getGastoDetalhe();
                    if (det != null && det.getCategoriaUsuario() != null
                            && !det.getCategoriaUsuario().isEmpty()) {
                        int n = det.getCategoriaUsuario().size();
                        BigDecimal parcel = valor.divide(BigDecimal.valueOf(n), 2, RoundingMode.HALF_UP);
                        for (CategoriaUsuario cu : det.getCategoriaUsuario()) {
                            String catNome = cu.getCategoria().getTitulo();
                            String catId   = "cat_" + normalizeId(catNome);
                            catLabels.put(catId, catNome);
                            catTotal.merge(catId, parcel, BigDecimal::add);
                            // link: instituição → categoria
                            flowMap.computeIfAbsent(instId, k -> new LinkedHashMap<>())
                                   .merge(catId, parcel, BigDecimal::add);
                        }
                    } else {
                        // sem categoria → nó "Outros"
                        String catId = "cat_outros";
                        catLabels.put(catId, "Outros");
                        catTotal.merge(catId, valor, BigDecimal::add);
                        flowMap.computeIfAbsent(instId, k -> new LinkedHashMap<>())
                               .merge(catId, valor, BigDecimal::add);
                    }
                }
                case Transferencia -> {
                    instSaida.merge(instId, valor, BigDecimal::add);
                    saidaSpecial.merge("saida_transferencia", valor, BigDecimal::add);
                    flowMap.computeIfAbsent(instId, k -> new LinkedHashMap<>())
                           .merge("saida_transferencia", valor, BigDecimal::add);
                }
                case Poupanca -> {
                    instSaida.merge(instId, valor, BigDecimal::add);
                    saidaSpecial.merge("saida_poupanca", valor, BigDecimal::add);
                    flowMap.computeIfAbsent(instId, k -> new LinkedHashMap<>())
                           .merge("saida_poupanca", valor, BigDecimal::add);
                }
                default -> { /* Emprestimo já tratado acima */ }
            }
        }

        // --- montar lista de nós ---
        List<FluxoFinanceiroDto.No> nos = new ArrayList<>();

        // nó virtual "Entrada"
        BigDecimal totalEntrada = instEntrada.values().stream()
                .reduce(BigDecimal.ZERO, BigDecimal::add);
        if (totalEntrada.compareTo(BigDecimal.ZERO) > 0) {
            nos.add(new FluxoFinanceiroDto.No("entrada", "Entrada", "ENTRADA",
                    totalEntrada, BigDecimal.ZERO));
        }

        // nós de instituição
        Set<String> todasInst = new LinkedHashSet<>();
        todasInst.addAll(instEntrada.keySet());
        todasInst.addAll(instSaida.keySet());
        todasInst.forEach(id -> nos.add(new FluxoFinanceiroDto.No(
                id, instLabels.getOrDefault(id, id), "INSTITUICAO",
                instEntrada.getOrDefault(id, BigDecimal.ZERO),
                instSaida.getOrDefault(id, BigDecimal.ZERO))));

        // nós de categoria
        catLabels.forEach((id, label) -> nos.add(new FluxoFinanceiroDto.No(
                id, label, "CATEGORIA", BigDecimal.ZERO,
                catTotal.getOrDefault(id, BigDecimal.ZERO))));

        // nós especiais (Transferência / Poupança)
        if (saidaSpecial.containsKey("saida_transferencia")) {
            nos.add(new FluxoFinanceiroDto.No("saida_transferencia", "Transferência", "SAIDA",
                    BigDecimal.ZERO, saidaSpecial.get("saida_transferencia")));
        }
        if (saidaSpecial.containsKey("saida_poupanca")) {
            nos.add(new FluxoFinanceiroDto.No("saida_poupanca", "Poupança", "SAIDA",
                    BigDecimal.ZERO, saidaSpecial.get("saida_poupanca")));
        }

        // --- montar lista de links ---
        List<FluxoFinanceiroDto.Link> links = new ArrayList<>();
        flowMap.forEach((src, targets) ->
                targets.forEach((tgt, v) ->
                        links.add(new FluxoFinanceiroDto.Link(src, tgt, v))));

        return new FluxoFinanceiroDto(periodo.label(), nos, links);
    }

    // =========================================================================
    //  REGISTROS DO PERÍODO (lista completa — mantido)
    // =========================================================================

    public List<RegistroResponseDto> getRegistrosPorPeriodo(TipoPeriodo tipo, int ano, Integer mes,
                                                             Integer trimestre, Integer semestre, UUID userId) {
        usuarioService.getUsuario(userId);
        PeriodoTemporalUtils.validar(tipo, ano, mes, trimestre, semestre);

        Periodo periodo = resolverPeriodo(userId, tipo, ano, mes, trimestre, semestre);

        List<EventoFinanceiro> eventos = eventoFinanceiroRepository
                .findByUsuarioAndPeriodoFiscal(userId, periodo.inicio(), periodo.fim());

        List<List<EventoInstituicao>> institList = new ArrayList<>();
        List<EventoDetalhe>           detalheList = new ArrayList<>();

        for (EventoFinanceiro e : eventos) {
            institList.add(eventoInstituicaoRepository
                    .findEventoInstituicaoByEventoFinanceiro_Id(e.getId()));
            detalheList.add(eventoDetalheRepository.findGastoDetalheByEventoFinanceiro(e));
        }

        return RegistrosMapper.toResponse(eventos, institList, detalheList);
    }

    // =========================================================================
    //  HELPERS PRIVADOS
    // =========================================================================

    private Periodo resolverPeriodo(UUID userId, TipoPeriodo tipo, int ano,
                                    Integer mes, Integer trimestre, Integer semestre) {
        return PeriodoTemporalUtils.calcular(tipo, ano, mes, trimestre, semestre, getDiaFiscal(userId));
    }

    /** Para KPI 1: corta o cálculo em hoje se o período ainda não terminou. */
    private LocalDate dataCorte(Periodo p) {
        LocalDate hoje = LocalDate.now();
        return p.fim().isAfter(hoje) ? hoje : p.fim();
    }

    private int getDiaFiscal(UUID userId) {
        Configuracoes c = configuracoesService.getConfiguracaoByUserId(userId);
        return c.getInicioMesFiscal() != null ? c.getInicioMesFiscal() : 1;
    }

    private void validarUsuario(UUID userId) {
        if (!usuarioRepository.existsById(userId)) {
            throw new EntidadeNaoEncontradaException(
                    "Usuário de id: %s não encontrado".formatted(userId));
        }
    }

    private boolean emPeriodo(EventoFinanceiro e, Periodo p) {
        LocalDate d = e.getDataEvento();
        return !d.isBefore(p.inicio()) && !d.isAfter(p.fim());
    }

    /**
     * Calcula a contribuição ao saldo total de acordo com as regras de negócio:
     * <ul>
     *   <li>Recebimento / Empréstimo → +valor</li>
     *   <li>Gasto / Transferência / Poupança → -valor</li>
     * </ul>
     */
    private BigDecimal saldoContribuicao(BigDecimal acc, EventoFinanceiro e) {
        BigDecimal v = BigDecimal.valueOf(e.getValor());
        return switch (e.getTipo()) {
            case Recebimento, Emprestimo   -> acc.add(v);
            case Gasto, Transferencia, Poupanca -> acc.subtract(v);
        };
    }

    /** Soma apenas Gasto + Transferência dentro do intervalo. */
    private BigDecimal somarGastos(List<EventoFinanceiro> eventos,
                                   LocalDate inicio, LocalDate fim) {
        BigDecimal total = BigDecimal.ZERO;
        for (EventoFinanceiro e : eventos) {
            LocalDate d = e.getDataEvento();
            if (!d.isBefore(inicio) && !d.isAfter(fim)
                    && (e.getTipo() == Tipo.Gasto || e.getTipo() == Tipo.Transferencia)) {
                total = total.add(BigDecimal.valueOf(e.getValor()));
            }
        }
        return total;
    }

    /** Agrupa gastos por nome de categoria. */
    private Map<String, BigDecimal> somarGastosPorCategoria(List<EventoFinanceiro> eventos,
                                                             LocalDate inicio, LocalDate fim) {
        Map<String, BigDecimal> mapa = new LinkedHashMap<>();
        for (EventoFinanceiro e : eventos) {
            LocalDate d = e.getDataEvento();
            if (!d.isBefore(inicio) && !d.isAfter(fim)
                    && (e.getTipo() == Tipo.Gasto || e.getTipo() == Tipo.Transferencia)) {
                EventoDetalhe det = e.getGastoDetalhe();
                if (det == null || det.getCategoriaUsuario() == null) continue;
                for (CategoriaUsuario cu : det.getCategoriaUsuario()) {
                    mapa.merge(cu.getCategoria().getTitulo(),
                               BigDecimal.valueOf(e.getValor()), BigDecimal::add);
                }
            }
        }
        return mapa;
    }

    /** Variação percentual entre valor atual e anterior (+ = piorou / - = melhorou nos gastos). */
    private int calcularVariacaoPercentual(BigDecimal atual, BigDecimal anterior) {
        if (anterior.compareTo(BigDecimal.ZERO) == 0) {
            return atual.compareTo(BigDecimal.ZERO) > 0 ? 100 : 0;
        }
        return atual.subtract(anterior)
                .divide(anterior, 4, RoundingMode.HALF_UP)
                .multiply(BigDecimal.valueOf(100))
                .intValue();
    }

    // ── séries temporais para o gráfico de evolução ──────────────────────────

    /** Soma valores de um map Date→BigDecimal num intervalo fechado [inicio, fim]. */
    private BigDecimal somarRange(Map<LocalDate, BigDecimal> mapa, LocalDate inicio, LocalDate fim) {
        BigDecimal total = BigDecimal.ZERO;
        for (LocalDate d = inicio; !d.isAfter(fim); d = d.plusDays(1)) {
            total = total.add(mapa.getOrDefault(d, BigDecimal.ZERO));
        }
        return total;
    }

    private Map<LocalDate, BigDecimal> gastosPorDia(List<EventoFinanceiro> eventos,
                                                     LocalDate inicio, LocalDate fim) {
        Map<LocalDate, BigDecimal> mapa = new TreeMap<>();
        for (EventoFinanceiro e : eventos) {
            LocalDate d = e.getDataEvento();
            if (!d.isBefore(inicio) && !d.isAfter(fim)
                    && (e.getTipo() == Tipo.Gasto || e.getTipo() == Tipo.Transferencia)) {
                mapa.merge(d, BigDecimal.valueOf(e.getValor()), BigDecimal::add);
            }
        }
        return mapa;
    }

    private List<EvolucaoGastosDto.Ponto> seriesDiaria(Map<LocalDate, BigDecimal> por,
                                                         LocalDate inicio, LocalDate fim,
                                                         String pattern) {
        DateTimeFormatter fmt = DateTimeFormatter.ofPattern(pattern);
        List<EvolucaoGastosDto.Ponto> lista = new ArrayList<>();
        for (LocalDate d = inicio; !d.isAfter(fim); d = d.plusDays(1)) {
            lista.add(new EvolucaoGastosDto.Ponto(d.format(fmt),
                    por.getOrDefault(d, BigDecimal.ZERO)));
        }
        return lista;
    }

    private List<EvolucaoGastosDto.Ponto> seriesSemanais(Map<LocalDate, BigDecimal> por,
                                                          LocalDate inicio, LocalDate fim) {
        List<EvolucaoGastosDto.Ponto> lista = new ArrayList<>();
        int semana = 1;
        LocalDate semInicio = inicio;
        while (!semInicio.isAfter(fim)) {
            LocalDate semFim = semInicio.plusDays(6).isAfter(fim) ? fim : semInicio.plusDays(6);
            BigDecimal total = BigDecimal.ZERO;
            for (LocalDate d = semInicio; !d.isAfter(semFim); d = d.plusDays(1)) {
                total = total.add(por.getOrDefault(d, BigDecimal.ZERO));
            }
            lista.add(new EvolucaoGastosDto.Ponto("Sem " + semana, total));
            semana++;
            semInicio = semInicio.plusDays(7);
        }
        return lista;
    }

    private List<EvolucaoGastosDto.Ponto> seriesMensais(Map<LocalDate, BigDecimal> por,
                                                         LocalDate inicio, LocalDate fim) {
        DateTimeFormatter fmt = DateTimeFormatter.ofPattern("MMM/yy",
                new Locale("pt", "BR"));
        List<EvolucaoGastosDto.Ponto> lista = new ArrayList<>();
        LocalDate mesInicio = inicio.withDayOfMonth(1);
        while (!mesInicio.isAfter(fim)) {
            LocalDate mesFim = mesInicio.withDayOfMonth(mesInicio.lengthOfMonth());
            BigDecimal total = BigDecimal.ZERO;
            for (LocalDate d = mesInicio; !d.isAfter(mesFim) && !d.isAfter(fim); d = d.plusDays(1)) {
                total = total.add(por.getOrDefault(d, BigDecimal.ZERO));
            }
            lista.add(new EvolucaoGastosDto.Ponto(mesInicio.format(fmt), total));
            mesInicio = mesInicio.plusMonths(1);
        }
        return lista;
    }

    // ── helpers de string ────────────────────────────────────────────────────

    private String tituloEvento(EventoFinanceiro e) {
        try { return e.getGastoDetalhe().getTituloGasto(); }
        catch (Exception ex) { return "Sem título"; }
    }

    private String categoriaEvento(EventoFinanceiro e) {
        try {
            return e.getGastoDetalhe().getCategoriaUsuario().getFirst().getCategoria().getTitulo();
        } catch (Exception ex) { return "Sem categoria"; }
    }

    private String normalizeId(String s) {
        return s.toLowerCase(Locale.ROOT).replaceAll("[^a-z0-9]", "_");
    }
}

package controle.api.back_end.service;

import controle.api.back_end.dto.dashboard.out.*;
import controle.api.back_end.dto.registros.mapper.RegistrosMapper;
import controle.api.back_end.dto.registros.out.RegistroResponseDto;
import controle.api.back_end.exception.EntidadeNaoEncontradaException;
import controle.api.back_end.model.categoria.CategoriaUsuario;
import controle.api.back_end.model.configuracoes.Configuracoes;
import controle.api.back_end.model.dashboard.TipoPeriodo;
import controle.api.back_end.model.eventoFinanceiro.*;
import controle.api.back_end.repository.configuracoes.ConfiguracoesRepository;
import controle.api.back_end.repository.eventoFinanceiro.EventoDetalheRepository;
import controle.api.back_end.repository.eventoFinanceiro.EventoFinanceiroRepository;
import controle.api.back_end.repository.eventoFinanceiro.EventoInstituicaoRepository;
import controle.api.back_end.repository.usuario.UsuarioRepository;
import controle.api.back_end.utils.PeriodoTemporalUtils;
import controle.api.back_end.utils.PeriodoTemporalUtils.Periodo;
import org.springframework.stereotype.Service;

import java.math.BigDecimal;
import java.math.RoundingMode;
import java.time.DayOfWeek;
import java.time.LocalDate;
import java.time.format.DateTimeFormatter;
import java.time.format.TextStyle;
import java.time.temporal.ChronoUnit;
import java.util.*;
import java.util.stream.Collectors;

@Service
public class DashboardService {

    private final UsuarioRepository usuarioRepository;
    private final EventoFinanceiroRepository eventoFinanceiroRepository;
    private final EventoInstituicaoRepository eventoInstituicaoRepository;
    private final EventoDetalheRepository eventoDetalheRepository;
    private final UsuarioService usuarioService;
    private final ConfiguracoesService configuracoesService;
    private final ConfiguracoesRepository configuracoesRepository;
    private final InstituicaoService instituicaoService;
    private final RegistroService registroService;

    public DashboardService(UsuarioRepository usuarioRepository,
                            RegistroService registroService,
                            EventoFinanceiroRepository eventoFinanceiroRepository,
                            EventoInstituicaoRepository eventoInstituicaoRepository,
                            EventoDetalheRepository eventoDetalheRepository,
                            InstituicaoService instituicaoService,
                            UsuarioService usuarioService,
                            ConfiguracoesService configuracoesService,
                            ConfiguracoesRepository configuracoesRepository) {
        this.usuarioRepository        = usuarioRepository;
        this.registroService          = registroService;
        this.eventoFinanceiroRepository = eventoFinanceiroRepository;
        this.eventoInstituicaoRepository = eventoInstituicaoRepository;
        this.eventoDetalheRepository  = eventoDetalheRepository;
        this.instituicaoService       = instituicaoService;
        this.usuarioService           = usuarioService;
        this.configuracoesService     = configuracoesService;
        this.configuracoesRepository  = configuracoesRepository;
    }

    // =========================================================================
    //  KPI 1 — SALDO TOTAL DO PERÍODO
    //  Saldo acumulado de TODA a história do usuário até o final do período
    //  (ou até hoje, se o período ainda está em aberto).
    // =========================================================================

    public SaldoTotalDto getSaldoTotal(TipoPeriodo tipo, int ano, Integer mes,
                                       Integer trimestre, Integer semestre, UUID userId) {
        validarUsuario(userId);
        PeriodoTemporalUtils.validar(tipo, ano, mes, trimestre, semestre);

        Periodo periodo = resolverPeriodo(userId, tipo, ano, mes, trimestre, semestre);
        LocalDate corte = dataCorte(periodo);

        List<EventoFinanceiro> todos = eventoFinanceiroRepository.findAllByUsuario_Id(userId);
        BigDecimal saldo = BigDecimal.ZERO;
        for (EventoFinanceiro e : todos) {
            if (!e.getDataEvento().isAfter(corte)) {
                saldo = saldoContribuicao(saldo, e);
            }
        }

        return new SaldoTotalDto(saldo, corte, periodo.label());
    }

    // =========================================================================
    //  KPI 2 — GASTO TOTAL DO PERÍODO + variação vs. período anterior
    // =========================================================================

    public GastoTotalDto getGastoTotal(TipoPeriodo tipo, int ano, Integer mes,
                                       Integer trimestre, Integer semestre, UUID userId) {
        validarUsuario(userId);
        PeriodoTemporalUtils.validar(tipo, ano, mes, trimestre, semestre);

        int diaFiscal    = getDiaFiscal(userId);
        Periodo atual    = PeriodoTemporalUtils.calcular(tipo, ano, mes, trimestre, semestre, diaFiscal);
        Periodo anterior = PeriodoTemporalUtils.calcularAnterior(tipo, ano, mes, trimestre, semestre, diaFiscal);

        List<EventoFinanceiro> eventos = eventoFinanceiroRepository.findAllByUsuario_Id(userId);

        BigDecimal gastosAtual    = somarGastos(eventos, atual.inicio(), atual.fim());
        BigDecimal gastosAnterior = somarGastos(eventos, anterior.inicio(), anterior.fim());

        int variacao = calcularVariacaoPercentual(gastosAtual, gastosAnterior);

        return new GastoTotalDto(gastosAtual, gastosAnterior, variacao, atual.label(), anterior.label());
    }

    // =========================================================================
    //  KPI 3 — MAIOR GASTO DO PERÍODO
    // =========================================================================

    public MaiorGastoDto getMaiorGasto(TipoPeriodo tipo, int ano, Integer mes,
                                       Integer trimestre, Integer semestre, UUID userId) {
        validarUsuario(userId);
        PeriodoTemporalUtils.validar(tipo, ano, mes, trimestre, semestre);

        Periodo periodo = resolverPeriodo(userId, tipo, ano, mes, trimestre, semestre);
        List<EventoFinanceiro> eventos = eventoFinanceiroRepository.findAllByUsuario_Id(userId);

        BigDecimal maiorValor  = BigDecimal.ZERO;
        BigDecimal totalGastos = BigDecimal.ZERO;
        EventoFinanceiro maiorEvento = null;

        for (EventoFinanceiro e : eventos) {
            if (!emPeriodo(e, periodo) || e.getTipo() != Tipo.Gasto) continue;

            BigDecimal v = BigDecimal.valueOf(e.getValor());
            totalGastos = totalGastos.add(v);
            if (v.compareTo(maiorValor) > 0) {
                maiorValor = v;
                maiorEvento = e;
            }
        }

        if (maiorEvento == null) {
            return new MaiorGastoDto("Sem gastos", "N/A", BigDecimal.ZERO, 0, null);
        }

        int pct = totalGastos.compareTo(BigDecimal.ZERO) > 0
                ? maiorValor.divide(totalGastos, 4, RoundingMode.HALF_UP)
                             .multiply(BigDecimal.valueOf(100)).intValue()
                : 0;

        return new MaiorGastoDto(
                tituloEvento(maiorEvento),
                categoriaEvento(maiorEvento),
                BigDecimal.valueOf(maiorEvento.getValor()),
                pct,
                maiorEvento.getDataEvento()
        );
    }

    // =========================================================================
    //  KPI 4 — CATEGORIA QUE MAIS IMPACTOU
    // =========================================================================

    public CategoriaImpactoDto getCategoriaImpacto(TipoPeriodo tipo, int ano, Integer mes,
                                                    Integer trimestre, Integer semestre, UUID userId) {
        validarUsuario(userId);
        PeriodoTemporalUtils.validar(tipo, ano, mes, trimestre, semestre);

        int diaFiscal    = getDiaFiscal(userId);
        Periodo atual    = PeriodoTemporalUtils.calcular(tipo, ano, mes, trimestre, semestre, diaFiscal);
        Periodo anterior = PeriodoTemporalUtils.calcularAnterior(tipo, ano, mes, trimestre, semestre, diaFiscal);

        List<EventoFinanceiro> eventos = eventoFinanceiroRepository.findAllByUsuario_Id(userId);

        Map<String, BigDecimal> atualPorCat    = somarGastosPorCategoria(eventos, atual.inicio(), atual.fim());
        Map<String, BigDecimal> anteriorPorCat = somarGastosPorCategoria(eventos, anterior.inicio(), anterior.fim());

        if (atualPorCat.isEmpty()) {
            return new CategoriaImpactoDto("Sem gastos", BigDecimal.ZERO, BigDecimal.ZERO, 0);
        }

        String categoriaTopo = atualPorCat.entrySet().stream()
                .max(Map.Entry.comparingByValue())
                .map(Map.Entry::getKey)
                .orElse("Sem categoria");

        BigDecimal valorAtual    = atualPorCat.getOrDefault(categoriaTopo, BigDecimal.ZERO);
        BigDecimal valorAnterior = anteriorPorCat.getOrDefault(categoriaTopo, BigDecimal.ZERO);
        int variacao = calcularVariacaoPercentual(valorAtual, valorAnterior);

        return new CategoriaImpactoDto(categoriaTopo, valorAtual, valorAnterior, variacao);
    }

    // =========================================================================
    //  GRÁFICO 1 — EVOLUÇÃO DOS GASTOS (line chart)
    //  MENSAL / TRIMESTRAL → granularidade diária
    //  SEMESTRAL           → granularidade semanal
    //  ANUAL               → granularidade mensal
    // =========================================================================

    public EvolucaoGastosDto getEvolucaoGastos(TipoPeriodo tipo, int ano, Integer mes,
                                                Integer trimestre, Integer semestre, UUID userId) {
        validarUsuario(userId);
        PeriodoTemporalUtils.validar(tipo, ano, mes, trimestre, semestre);

        Periodo periodo = resolverPeriodo(userId, tipo, ano, mes, trimestre, semestre);
        List<EventoFinanceiro> eventos = eventoFinanceiroRepository.findAllByUsuario_Id(userId);

        // daily map de gastos e de recebimentos
        Map<LocalDate, BigDecimal> porDia    = new TreeMap<>();
        Map<LocalDate, BigDecimal> porDiaRec = new TreeMap<>();
        for (EventoFinanceiro e : eventos) {
            if (!emPeriodo(e, periodo)) continue;
            if (e.getTipo() == Tipo.Gasto || e.getTipo() == Tipo.Transferencia) {
                porDia.merge(e.getDataEvento(), BigDecimal.valueOf(e.getValor()), BigDecimal::add);
            } else if (e.getTipo() == Tipo.Recebimento || e.getTipo() == Tipo.Emprestimo) {
                porDiaRec.merge(e.getDataEvento(), BigDecimal.valueOf(e.getValor()), BigDecimal::add);
            }
        }

        String granularidade;
        List<EvolucaoGastosDto.Ponto> dados;
        List<EvolucaoGastosDto.Ponto> dadosRec;

        switch (tipo) {
            case MENSAL, TRIMESTRAL -> {
                granularidade = "DIARIO";
                dados    = seriesDiaria(porDia,    periodo.inicio(), periodo.fim(), "dd/MM");
                dadosRec = seriesDiaria(porDiaRec, periodo.inicio(), periodo.fim(), "dd/MM");
            }
            case SEMESTRAL -> {
                granularidade = "SEMANAL";
                dados    = seriesSemanais(porDia,    periodo.inicio(), periodo.fim());
                dadosRec = seriesSemanais(porDiaRec, periodo.inicio(), periodo.fim());
            }
            default -> { // ANUAL
                granularidade = "MENSAL";
                dados    = seriesMensais(porDia,    periodo.inicio(), periodo.fim());
                dadosRec = seriesMensais(porDiaRec, periodo.inicio(), periodo.fim());
            }
        }

        return new EvolucaoGastosDto(periodo.label(), granularidade, dados, dadosRec);
    }

    // =========================================================================
    //  GRÁFICO 2 — CATEGORIAS (stacked bar chart)
    // =========================================================================

    public CategoriasGraficoDto getCategoriasGrafico(TipoPeriodo tipo, int ano, Integer mes,
                                                      Integer trimestre, Integer semestre, UUID userId) {
        validarUsuario(userId);
        PeriodoTemporalUtils.validar(tipo, ano, mes, trimestre, semestre);

        Periodo periodo = resolverPeriodo(userId, tipo, ano, mes, trimestre, semestre);
        List<EventoFinanceiro> eventos = eventoFinanceiroRepository.findAllByUsuario_Id(userId);

        Map<String, BigDecimal> totais     = new LinkedHashMap<>();
        Map<String, Integer>    ocorrencias = new LinkedHashMap<>();
        BigDecimal totalGeral = BigDecimal.ZERO;

        for (EventoFinanceiro e : eventos) {
            if (!emPeriodo(e, periodo)) continue;
            if (e.getTipo() != Tipo.Gasto && e.getTipo() != Tipo.Transferencia) continue;

            EventoDetalhe det = e.getGastoDetalhe();
            if (det == null || det.getCategoriaUsuario() == null) continue;

            for (CategoriaUsuario cu : det.getCategoriaUsuario()) {
                String nome = cu.getCategoria().getTitulo();
                totais.merge(nome, BigDecimal.valueOf(e.getValor()), BigDecimal::add);
                ocorrencias.merge(nome, 1, Integer::sum);
            }
            totalGeral = totalGeral.add(BigDecimal.valueOf(e.getValor()));
        }

        final BigDecimal tf = totalGeral;
        List<CategoriasGraficoDto.CategoriaData> lista = totais.entrySet().stream()
                .sorted(Map.Entry.<String, BigDecimal>comparingByValue().reversed())
                .map(entry -> {
                    int pct = tf.compareTo(BigDecimal.ZERO) > 0
                            ? entry.getValue().divide(tf, 4, RoundingMode.HALF_UP)
                                              .multiply(BigDecimal.valueOf(100)).intValue()
                            : 0;
                    return new CategoriasGraficoDto.CategoriaData(
                            entry.getKey(), entry.getValue(), pct,
                            ocorrencias.getOrDefault(entry.getKey(), 0));
                })
                .toList();

        return new CategoriasGraficoDto(periodo.label(), lista);
    }

    // =========================================================================
    //  GRÁFICO 3 — COMPARAÇÃO ENTRE PERÍODOS (multiple line chart)
    //  Ambas as séries são normalizadas por posição (Dia 1, Dia 2, … Dia N).
    // =========================================================================

    public ComparacaoPeriodoDto getComparacaoPeriodo(TipoPeriodo tipo, int ano, Integer mes,
                                                      Integer trimestre, Integer semestre, UUID userId) {
        validarUsuario(userId);
        PeriodoTemporalUtils.validar(tipo, ano, mes, trimestre, semestre);

        int diaFiscal    = getDiaFiscal(userId);
        Periodo atual    = PeriodoTemporalUtils.calcular(tipo, ano, mes, trimestre, semestre, diaFiscal);
        Periodo anterior = PeriodoTemporalUtils.calcularAnterior(tipo, ano, mes, trimestre, semestre, diaFiscal);

        List<EventoFinanceiro> eventos = eventoFinanceiroRepository.findAllByUsuario_Id(userId);

        Map<LocalDate, BigDecimal> porDiaAtual    = gastosPorDia(eventos, atual.inicio(), atual.fim());
        Map<LocalDate, BigDecimal> porDiaAnterior = gastosPorDia(eventos, anterior.inicio(), anterior.fim());

        // Para ANUAL: granularidade mensal (12 pontos com nome do mês)
        if (tipo == TipoPeriodo.ANUAL) {
            DateTimeFormatter fmtMes = DateTimeFormatter.ofPattern("MMM", new Locale("pt", "BR"));
            List<ComparacaoPeriodoDto.PontoComparacao> pontos = new ArrayList<>();
            for (int m = 0; m < 12; m++) {
                LocalDate inicioAtual    = atual.inicio().withDayOfMonth(1).plusMonths(m);
                LocalDate fimAtual       = inicioAtual.withDayOfMonth(inicioAtual.lengthOfMonth());
                LocalDate inicioAnterior = anterior.inicio().withDayOfMonth(1).plusMonths(m);
                LocalDate fimAnterior    = inicioAnterior.withDayOfMonth(inicioAnterior.lengthOfMonth());
                if (inicioAtual.isAfter(atual.fim())) break;
                String nomeMes = inicioAtual.format(fmtMes);
                nomeMes = Character.toUpperCase(nomeMes.charAt(0)) + nomeMes.substring(1);
                pontos.add(new ComparacaoPeriodoDto.PontoComparacao(
                        nomeMes,
                        somarRange(porDiaAtual,    inicioAtual,    fimAtual.isAfter(atual.fim())         ? atual.fim()     : fimAtual),
                        somarRange(porDiaAnterior, inicioAnterior, fimAnterior.isAfter(anterior.fim())   ? anterior.fim()  : fimAnterior)
                ));
            }
            return new ComparacaoPeriodoDto(atual.label(), anterior.label(), pontos);
        }

        long duracaoAtual    = ChronoUnit.DAYS.between(atual.inicio(), atual.fim()) + 1;
        long duracaoAnterior = ChronoUnit.DAYS.between(anterior.inicio(), anterior.fim()) + 1;
        long numPontos = Math.min(duracaoAtual, duracaoAnterior);

        List<ComparacaoPeriodoDto.PontoComparacao> pontos = new ArrayList<>();
        for (int i = 0; i < numPontos; i++) {
            LocalDate dAtual    = atual.inicio().plusDays(i);
            LocalDate dAnterior = anterior.inicio().plusDays(i);

            pontos.add(new ComparacaoPeriodoDto.PontoComparacao(
                    "Dia " + (i + 1),
                    porDiaAtual.getOrDefault(dAtual, BigDecimal.ZERO),
                    porDiaAnterior.getOrDefault(dAnterior, BigDecimal.ZERO)
            ));
        }

        return new ComparacaoPeriodoDto(atual.label(), anterior.label(), pontos);
    }

    // =========================================================================
    //  GRÁFICO 4 — GASTOS POR DIA DA SEMANA (heat map)
    // =========================================================================

    public HeatMapDiaSemanaDto getHeatMapDiaSemana(TipoPeriodo tipo, int ano, Integer mes,
                                                    Integer trimestre, Integer semestre, UUID userId) {
        validarUsuario(userId);
        PeriodoTemporalUtils.validar(tipo, ano, mes, trimestre, semestre);

        Periodo periodo = resolverPeriodo(userId, tipo, ano, mes, trimestre, semestre);
        List<EventoFinanceiro> eventos = eventoFinanceiroRepository.findAllByUsuario_Id(userId);

        Map<DayOfWeek, BigDecimal> porDia = new EnumMap<>(DayOfWeek.class);
        for (DayOfWeek d : DayOfWeek.values()) porDia.put(d, BigDecimal.ZERO);

        for (EventoFinanceiro e : eventos) {
            if (!emPeriodo(e, periodo)) continue;
            if (e.getTipo() != Tipo.Gasto && e.getTipo() != Tipo.Transferencia) continue;
            porDia.merge(e.getDataEvento().getDayOfWeek(), BigDecimal.valueOf(e.getValor()), BigDecimal::add);
        }

        BigDecimal max = porDia.values().stream().max(BigDecimal::compareTo).orElse(BigDecimal.ONE);
        Locale ptBr = new Locale("pt", "BR");

        DayOfWeek[] ordem = {
                DayOfWeek.MONDAY, DayOfWeek.TUESDAY, DayOfWeek.WEDNESDAY,
                DayOfWeek.THURSDAY, DayOfWeek.FRIDAY, DayOfWeek.SATURDAY, DayOfWeek.SUNDAY
        };

        List<HeatMapDiaSemanaDto.DiaDado> dias = Arrays.stream(ordem)
                .map(d -> {
                    BigDecimal v = porDia.get(d);
                    double norm = max.compareTo(BigDecimal.ZERO) > 0
                            ? v.divide(max, 4, RoundingMode.HALF_UP).doubleValue()
                            : 0.0;
                    String nome = d.getDisplayName(TextStyle.FULL, ptBr);
                    nome = Character.toUpperCase(nome.charAt(0)) + nome.substring(1);
                    return new HeatMapDiaSemanaDto.DiaDado(nome, v, norm);
                })
                .toList();

        return new HeatMapDiaSemanaDto(periodo.label(), dias);
    }

    // =========================================================================
    //  GRÁFICO 5 — FLUXO FINANCEIRO (Sankey)
    //  Fluxo: Entrada → Instituição → Categoria/Transferência/Poupança
    // =========================================================================

    public FluxoFinanceiroDto getFluxoFinanceiro(TipoPeriodo tipo, int ano, Integer mes,
                                                  Integer trimestre, Integer semestre, UUID userId) {
        validarUsuario(userId);
        PeriodoTemporalUtils.validar(tipo, ano, mes, trimestre, semestre);

        Periodo periodo = resolverPeriodo(userId, tipo, ano, mes, trimestre, semestre);
        List<EventoFinanceiro> eventos = eventoFinanceiroRepository.findAllByUsuario_Id(userId);

        // --- acumuladores ---
        Map<String, String>     instLabels    = new LinkedHashMap<>(); // id → label
        Map<String, BigDecimal> instEntrada   = new LinkedHashMap<>();
        Map<String, BigDecimal> instSaida     = new LinkedHashMap<>();
        Map<String, String>     catLabels     = new LinkedHashMap<>(); // id → label
        Map<String, BigDecimal> catTotal      = new LinkedHashMap<>();
        Map<String, BigDecimal> saidaSpecial  = new LinkedHashMap<>(); // "Transferência","Poupança"
        // links: source → target → valor
        Map<String, Map<String, BigDecimal>> flowMap = new LinkedHashMap<>();

        for (EventoFinanceiro e : eventos) {
            if (!emPeriodo(e, periodo)) continue;

            List<EventoInstituicao> insts = eventoInstituicaoRepository
                    .findEventoInstituicaoByEventoFinanceiro_Id(e.getId());
            String instNome = insts.isEmpty() ? "Sem Instituição"
                    : insts.get(0).getInstituicaoUsuario().getInstituicao().getNome();
            String instId = "inst_" + normalizeId(instNome);
            instLabels.put(instId, instNome);

            BigDecimal valor = BigDecimal.valueOf(e.getValor());

            switch (e.getTipo()) {
                case Recebimento, Emprestimo -> {
                    instEntrada.merge(instId, valor, BigDecimal::add);
                    // link: "entrada" → instituição
                    String entradaId = "entrada";
                    flowMap.computeIfAbsent(entradaId, k -> new LinkedHashMap<>())
                           .merge(instId, valor, BigDecimal::add);
                }
                case Gasto -> {
                    instSaida.merge(instId, valor, BigDecimal::add);
                    EventoDetalhe det = e.getGastoDetalhe();
                    if (det != null && det.getCategoriaUsuario() != null
                            && !det.getCategoriaUsuario().isEmpty()) {
                        int n = det.getCategoriaUsuario().size();
                        BigDecimal parcel = valor.divide(BigDecimal.valueOf(n), 2, RoundingMode.HALF_UP);
                        for (CategoriaUsuario cu : det.getCategoriaUsuario()) {
                            String catNome = cu.getCategoria().getTitulo();
                            String catId   = "cat_" + normalizeId(catNome);
                            catLabels.put(catId, catNome);
                            catTotal.merge(catId, parcel, BigDecimal::add);
                            // link: instituição → categoria
                            flowMap.computeIfAbsent(instId, k -> new LinkedHashMap<>())
                                   .merge(catId, parcel, BigDecimal::add);
                        }
                    } else {
                        // sem categoria → nó "Outros"
                        String catId = "cat_outros";
                        catLabels.put(catId, "Outros");
                        catTotal.merge(catId, valor, BigDecimal::add);
                        flowMap.computeIfAbsent(instId, k -> new LinkedHashMap<>())
                               .merge(catId, valor, BigDecimal::add);
                    }
                }
                case Transferencia -> {
                    instSaida.merge(instId, valor, BigDecimal::add);
                    saidaSpecial.merge("saida_transferencia", valor, BigDecimal::add);
                    flowMap.computeIfAbsent(instId, k -> new LinkedHashMap<>())
                           .merge("saida_transferencia", valor, BigDecimal::add);
                }
                case Poupanca -> {
                    instSaida.merge(instId, valor, BigDecimal::add);
                    saidaSpecial.merge("saida_poupanca", valor, BigDecimal::add);
                    flowMap.computeIfAbsent(instId, k -> new LinkedHashMap<>())
                           .merge("saida_poupanca", valor, BigDecimal::add);
                }
                default -> { /* Emprestimo já tratado acima */ }
            }
        }

        // --- montar lista de nós ---
        List<FluxoFinanceiroDto.No> nos = new ArrayList<>();

        // nó virtual "Entrada"
        BigDecimal totalEntrada = instEntrada.values().stream()
                .reduce(BigDecimal.ZERO, BigDecimal::add);
        if (totalEntrada.compareTo(BigDecimal.ZERO) > 0) {
            nos.add(new FluxoFinanceiroDto.No("entrada", "Entrada", "ENTRADA",
                    totalEntrada, BigDecimal.ZERO));
        }

        // nós de instituição
        Set<String> todasInst = new LinkedHashSet<>();
        todasInst.addAll(instEntrada.keySet());
        todasInst.addAll(instSaida.keySet());
        todasInst.forEach(id -> nos.add(new FluxoFinanceiroDto.No(
                id, instLabels.getOrDefault(id, id), "INSTITUICAO",
                instEntrada.getOrDefault(id, BigDecimal.ZERO),
                instSaida.getOrDefault(id, BigDecimal.ZERO))));

        // nós de categoria
        catLabels.forEach((id, label) -> nos.add(new FluxoFinanceiroDto.No(
                id, label, "CATEGORIA", BigDecimal.ZERO,
                catTotal.getOrDefault(id, BigDecimal.ZERO))));

        // nós especiais (Transferência / Poupança)
        if (saidaSpecial.containsKey("saida_transferencia")) {
            nos.add(new FluxoFinanceiroDto.No("saida_transferencia", "Transferência", "SAIDA",
                    BigDecimal.ZERO, saidaSpecial.get("saida_transferencia")));
        }
        if (saidaSpecial.containsKey("saida_poupanca")) {
            nos.add(new FluxoFinanceiroDto.No("saida_poupanca", "Poupança", "SAIDA",
                    BigDecimal.ZERO, saidaSpecial.get("saida_poupanca")));
        }

        // --- montar lista de links ---
        List<FluxoFinanceiroDto.Link> links = new ArrayList<>();
        flowMap.forEach((src, targets) ->
                targets.forEach((tgt, v) ->
                        links.add(new FluxoFinanceiroDto.Link(src, tgt, v))));

        return new FluxoFinanceiroDto(periodo.label(), nos, links);
    }

    // =========================================================================
    //  REGISTROS DO PERÍODO (lista completa — mantido)
    // =========================================================================

    public List<RegistroResponseDto> getRegistrosPorPeriodo(TipoPeriodo tipo, int ano, Integer mes,
                                                             Integer trimestre, Integer semestre, UUID userId) {
        usuarioService.getUsuario(userId);
        PeriodoTemporalUtils.validar(tipo, ano, mes, trimestre, semestre);

        Periodo periodo = resolverPeriodo(userId, tipo, ano, mes, trimestre, semestre);

        List<EventoFinanceiro> eventos = eventoFinanceiroRepository
                .findByUsuarioAndPeriodoFiscal(userId, periodo.inicio(), periodo.fim());

        List<List<EventoInstituicao>> institList = new ArrayList<>();
        List<EventoDetalhe>           detalheList = new ArrayList<>();

        for (EventoFinanceiro e : eventos) {
            institList.add(eventoInstituicaoRepository
                    .findEventoInstituicaoByEventoFinanceiro_Id(e.getId()));
            detalheList.add(eventoDetalheRepository.findGastoDetalheByEventoFinanceiro(e));
        }

        return RegistrosMapper.toResponse(eventos, institList, detalheList);
    }

    // =========================================================================
    //  HELPERS PRIVADOS
    // =========================================================================

    private Periodo resolverPeriodo(UUID userId, TipoPeriodo tipo, int ano,
                                    Integer mes, Integer trimestre, Integer semestre) {
        return PeriodoTemporalUtils.calcular(tipo, ano, mes, trimestre, semestre, getDiaFiscal(userId));
    }

    /** Para KPI 1: corta o cálculo em hoje se o período ainda não terminou. */
    private LocalDate dataCorte(Periodo p) {
        LocalDate hoje = LocalDate.now();
        return p.fim().isAfter(hoje) ? hoje : p.fim();
    }

    private int getDiaFiscal(UUID userId) {
        try {
            Configuracoes c = configuracoesService.getConfiguracaoByUserId(userId);
            return c.getInicioMesFiscal() != null ? c.getInicioMesFiscal() : 1;
        } catch (Exception e) {
            // Usuário sem configuração → usa o dia 1 como padrão
            return 1;
        }
    }

    private void validarUsuario(UUID userId) {
        if (!usuarioRepository.existsById(userId)) {
            throw new EntidadeNaoEncontradaException(
                    "Usuário de id: %s não encontrado".formatted(userId));
        }
    }

    private boolean emPeriodo(EventoFinanceiro e, Periodo p) {
        LocalDate d = e.getDataEvento();
        return !d.isBefore(p.inicio()) && !d.isAfter(p.fim());
    }

    /**
     * Calcula a contribuição ao saldo total de acordo com as regras de negócio:
     * <ul>
     *   <li>Recebimento / Empréstimo → +valor</li>
     *   <li>Gasto / Transferência / Poupança → -valor</li>
     * </ul>
     */
    private BigDecimal saldoContribuicao(BigDecimal acc, EventoFinanceiro e) {
        BigDecimal v = BigDecimal.valueOf(e.getValor());
        return switch (e.getTipo()) {
            case Recebimento, Emprestimo   -> acc.add(v);
            case Gasto, Transferencia, Poupanca -> acc.subtract(v);
        };
    }

    /** Soma apenas Gasto + Transferência dentro do intervalo. */
    private BigDecimal somarGastos(List<EventoFinanceiro> eventos,
                                   LocalDate inicio, LocalDate fim) {
        BigDecimal total = BigDecimal.ZERO;
        for (EventoFinanceiro e : eventos) {
            LocalDate d = e.getDataEvento();
            if (!d.isBefore(inicio) && !d.isAfter(fim)
                    && (e.getTipo() == Tipo.Gasto || e.getTipo() == Tipo.Transferencia)) {
                total = total.add(BigDecimal.valueOf(e.getValor()));
            }
        }
        return total;
    }

    /** Agrupa gastos por nome de categoria. */
    private Map<String, BigDecimal> somarGastosPorCategoria(List<EventoFinanceiro> eventos,
                                                             LocalDate inicio, LocalDate fim) {
        Map<String, BigDecimal> mapa = new LinkedHashMap<>();
        for (EventoFinanceiro e : eventos) {
            LocalDate d = e.getDataEvento();
            if (!d.isBefore(inicio) && !d.isAfter(fim)
                    && (e.getTipo() == Tipo.Gasto || e.getTipo() == Tipo.Transferencia)) {
                EventoDetalhe det = e.getGastoDetalhe();
                if (det == null || det.getCategoriaUsuario() == null) continue;
                for (CategoriaUsuario cu : det.getCategoriaUsuario()) {
                    mapa.merge(cu.getCategoria().getTitulo(),
                               BigDecimal.valueOf(e.getValor()), BigDecimal::add);
                }
            }
        }
        return mapa;
    }

    /** Variação percentual entre valor atual e anterior (+ = piorou / - = melhorou nos gastos). */
    private int calcularVariacaoPercentual(BigDecimal atual, BigDecimal anterior) {
        if (anterior.compareTo(BigDecimal.ZERO) == 0) {
            return atual.compareTo(BigDecimal.ZERO) > 0 ? 100 : 0;
        }
        return atual.subtract(anterior)
                .divide(anterior, 4, RoundingMode.HALF_UP)
                .multiply(BigDecimal.valueOf(100))
                .intValue();
    }

    // ── séries temporais para o gráfico de evolução ──────────────────────────

    /** Soma valores de um map Date→BigDecimal num intervalo fechado [inicio, fim]. */
    private BigDecimal somarRange(Map<LocalDate, BigDecimal> mapa, LocalDate inicio, LocalDate fim) {
        BigDecimal total = BigDecimal.ZERO;
        for (LocalDate d = inicio; !d.isAfter(fim); d = d.plusDays(1)) {
            total = total.add(mapa.getOrDefault(d, BigDecimal.ZERO));
        }
        return total;
    }

    private Map<LocalDate, BigDecimal> gastosPorDia(List<EventoFinanceiro> eventos,
                                                     LocalDate inicio, LocalDate fim) {
        Map<LocalDate, BigDecimal> mapa = new TreeMap<>();
        for (EventoFinanceiro e : eventos) {
            LocalDate d = e.getDataEvento();
            if (!d.isBefore(inicio) && !d.isAfter(fim)
                    && (e.getTipo() == Tipo.Gasto || e.getTipo() == Tipo.Transferencia)) {
                mapa.merge(d, BigDecimal.valueOf(e.getValor()), BigDecimal::add);
            }
        }
        return mapa;
    }

    private List<EvolucaoGastosDto.Ponto> seriesDiaria(Map<LocalDate, BigDecimal> por,
                                                         LocalDate inicio, LocalDate fim,
                                                         String pattern) {
        DateTimeFormatter fmt = DateTimeFormatter.ofPattern(pattern);
        List<EvolucaoGastosDto.Ponto> lista = new ArrayList<>();
        for (LocalDate d = inicio; !d.isAfter(fim); d = d.plusDays(1)) {
            lista.add(new EvolucaoGastosDto.Ponto(d.format(fmt),
                    por.getOrDefault(d, BigDecimal.ZERO)));
        }
        return lista;
    }

    private List<EvolucaoGastosDto.Ponto> seriesSemanais(Map<LocalDate, BigDecimal> por,
                                                          LocalDate inicio, LocalDate fim) {
        List<EvolucaoGastosDto.Ponto> lista = new ArrayList<>();
        int semana = 1;
        LocalDate semInicio = inicio;
        while (!semInicio.isAfter(fim)) {
            LocalDate semFim = semInicio.plusDays(6).isAfter(fim) ? fim : semInicio.plusDays(6);
            BigDecimal total = BigDecimal.ZERO;
            for (LocalDate d = semInicio; !d.isAfter(semFim); d = d.plusDays(1)) {
                total = total.add(por.getOrDefault(d, BigDecimal.ZERO));
            }
            lista.add(new EvolucaoGastosDto.Ponto("Sem " + semana, total));
            semana++;
            semInicio = semInicio.plusDays(7);
        }
        return lista;
    }

    private List<EvolucaoGastosDto.Ponto> seriesMensais(Map<LocalDate, BigDecimal> por,
                                                         LocalDate inicio, LocalDate fim) {
        DateTimeFormatter fmt = DateTimeFormatter.ofPattern("MMM/yy",
                new Locale("pt", "BR"));
        List<EvolucaoGastosDto.Ponto> lista = new ArrayList<>();
        LocalDate mesInicio = inicio.withDayOfMonth(1);
        while (!mesInicio.isAfter(fim)) {
            LocalDate mesFim = mesInicio.withDayOfMonth(mesInicio.lengthOfMonth());
            BigDecimal total = BigDecimal.ZERO;
            for (LocalDate d = mesInicio; !d.isAfter(mesFim) && !d.isAfter(fim); d = d.plusDays(1)) {
                total = total.add(por.getOrDefault(d, BigDecimal.ZERO));
            }
            lista.add(new EvolucaoGastosDto.Ponto(mesInicio.format(fmt), total));
            mesInicio = mesInicio.plusMonths(1);
        }
        return lista;
    }

    // ── helpers de string ────────────────────────────────────────────────────

    private String tituloEvento(EventoFinanceiro e) {
        try { return e.getGastoDetalhe().getTituloGasto(); }
        catch (Exception ex) { return "Sem título"; }
    }

    private String categoriaEvento(EventoFinanceiro e) {
        try {
            return e.getGastoDetalhe().getCategoriaUsuario().getFirst().getCategoria().getTitulo();
        } catch (Exception ex) { return "Sem categoria"; }
    }

    private String normalizeId(String s) {
        return s.toLowerCase(Locale.ROOT).replaceAll("[^a-z0-9]", "_");
    }
}

(function () {
    const API = "http://localhost:8080";
    const usuarioLogado = JSON.parse(localStorage.getItem("usuarioLogado") || "null");
    const userId = usuarioLogado?.id;

    let cfgId = null;
    let cfgData = null;   // armazena config completa carregada do servidor
    let instituicoes = [];
    let categorias = [];
    let tipoPersonalizada = null; // 'instituicao' | 'categoria'
    let limiteModalTipo = null; // 'instituicao' | 'categoria'

    // ── helpers ──────────────────────────────────────────────────
    function habilitarFecharAlertaAoClicarFora() {
        const div = document.getElementById("div_alerta");
        const conteudo = document.getElementById("conteudoAlerta");
        if (!div || !conteudo || div.dataset.closeOutsideBound === "1") return;

        div.dataset.closeOutsideBound = "1";
        div.addEventListener("click", (event) => {
            if (event.target === div) {
                div.style.display = "none";
            }
        });
    }

    function mostrarAlerta(texto) {
        habilitarFecharAlertaAoClicarFora();
        const div = document.getElementById("div_alerta");
        const conteudo = document.getElementById("conteudoAlerta");
        if (!div || !conteudo) return;
        conteudo.innerHTML = texto;
        div.style.display = "flex";
        setTimeout(() => { div.style.display = "none"; }, 3000);
    }

    function mostrarConfirmacao(texto, onConfirm) {
        habilitarFecharAlertaAoClicarFora();
        const div = document.getElementById("div_alerta");
        const conteudo = document.getElementById("conteudoAlerta");
        if (!div || !conteudo) { onConfirm(); return; }
        conteudo.innerHTML = "";
        const msg = document.createElement("span");
        msg.textContent = texto;
        const divBtns = document.createElement("div");
        divBtns.style.cssText = "display:flex;gap:8px;margin-top:10px;";
        const btnNo = document.createElement("button");
        btnNo.textContent = "Cancelar";
        btnNo.style.background = "#888";
        const btnOk = document.createElement("button");
        btnOk.textContent = "Confirmar";
        btnOk.addEventListener("click", () => { div.style.display = "none"; onConfirm(); });
        btnNo.addEventListener("click", () => { div.style.display = "none"; });
        divBtns.appendChild(btnNo);
        divBtns.appendChild(btnOk);
        conteudo.appendChild(msg);
        conteudo.appendChild(divBtns);
        div.style.display = "flex";
    }

    function postJson(url, payload) {
        return fetch(url, {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify(payload)
        });
    }

    function putJson(url, payload) {
        return fetch(url, {
            method: "PUT",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify(payload)
        });
    }

    function formatarLocalDateTime(valor) {
        if (window.MainAPI?.formatarLocalDateTime) {
            return window.MainAPI.formatarLocalDateTime(valor, "-");
        }
        return "-";
    }

    function chaveAlertas() {
        return `cfg_alertas_${userId}`;
    }

    function salvarPreferenciasAlertas() {
        const swWhatsapp = document.getElementById("sw_alerta_whatsapp");
        const swEmail = document.getElementById("sw_alerta_email");
        if (!swWhatsapp || !swEmail) return;

        const preferencias = {
            whatsapp: !!swWhatsapp.checked,
            email: !!swEmail.checked
        };
        localStorage.setItem(chaveAlertas(), JSON.stringify(preferencias));
    }

    function inicializarSwitchesAlerta() {
        const swWhatsapp = document.getElementById("sw_alerta_whatsapp");
        const swEmail = document.getElementById("sw_alerta_email");
        if (!swWhatsapp || !swEmail) return;

        const salvas = JSON.parse(localStorage.getItem(chaveAlertas()) || "null");
        swWhatsapp.checked = !!salvas?.whatsapp;
        swEmail.checked = !!salvas?.email;

        swWhatsapp.addEventListener("change", salvarPreferenciasAlertas);
        swEmail.addEventListener("change", salvarPreferenciasAlertas);
    }

    // ── INIT ─────────────────────────────────────────────────────
    async function init() {
        if (!userId) {
            window.location.href = "login.html";
            return;
        }
        inicializarSwitchesAlerta();
        await Promise.all([
            carregarConfig(),
            carregarInstituicoes(),
            carregarCategorias()
        ]);
    }

    // ── Helper: busca todas as páginas de um endpoint paginado ──────
    async function fetchTodasPaginasCfg(url) {
        const allContent = [];
        let pagina = 0;
        let isLast = false;
        const LIMITE = 100;

        while (!isLast && pagina < LIMITE) {
            const sep = url.includes("?") ? "&" : "?";
            const res = await fetch(`${url}${sep}pagina=${pagina}`);
            if (res.status === 204) break;
            if (!res.ok) break;
            const data = await res.json();
            if (data && Array.isArray(data.content)) {
                allContent.push(...data.content);
                isLast = data.last === true;
            } else if (Array.isArray(data)) {
                allContent.push(...data);
                isLast = true;
            } else {
                break;
            }
            pagina++;
        }
        return allContent;
    }

    // ── CONFIGURAÇÕES ─────────────────────────────────────────────
    async function carregarConfig() {
        try {
            const res = await fetch(`${API}/configuracoes/usuarios/${userId}`);
            if (!res.ok) return;
            const cfg = await res.json();
            cfgId = cfg.id;
            cfgData = cfg;

            const sel = document.getElementById("mesFiscal");
            if (sel && cfg.inicioMesFiscal != null) {
                sel.value = String(cfg.inicioMesFiscal);
            }

            const limiteInput = document.getElementById("limiteMensal");
            if (limiteInput && cfg.limiteDesejadoMensal != null) {
                limiteInput.value = cfg.limiteDesejadoMensal;
            }

            renderLimites(cfg.limiteInstituicao || [], cfg.limitePorCategoria || []);
        } catch (e) {
            console.error("Erro ao carregar configurações:", e);
        }
    }

    function renderLimites(limitesInst, limitesCateg) {
        const tbody = document.getElementById("corpoLimites");
        if (!tbody) return;
        tbody.innerHTML = "";

        const linhas = [];
        limitesInst.forEach(l => {
            linhas.push({ tipo: "Instituição", item: l.instituicao?.nome || "-", limite: l.limiteDesejado });
        });
        limitesCateg.forEach(l => {
            linhas.push({ tipo: "Categoria", item: l.categoria?.titulo || "-", limite: l.limiteDesejado });
        });

        if (linhas.length === 0) {
            tbody.innerHTML = `<tr class="cfg-table-empty"><td colspan="4" style="padding:20px;">Nenhum limite configurado ainda.</td></tr>`;
            return;
        }
        linhas.forEach(l => {
            const tr = document.createElement("tr");
            tr.innerHTML = `<td>${l.tipo}</td><td>${l.item}</td><td>R$ ${Number(l.limite).toFixed(2)}</td><td>-</td>`;
            tbody.appendChild(tr);
        });
    }

    window.salvarMesFiscal = async function () {
        const sel = document.getElementById("mesFiscal");
        if (!sel?.value) {
            mostrarAlerta("Selecione o início do mês fiscal.");
            return;
        }
        const mes = parseInt(sel.value, 10);
        const limiteInput = document.getElementById("limiteMensal");
        const limiteMensal = limiteInput?.value ? parseFloat(limiteInput.value) : cfgData?.limiteDesejadoMensal;
        try {
            if (cfgId) {
                const payload = { inicioMesFiscal: mes };
                if (limiteMensal != null && !isNaN(limiteMensal)) payload.limiteDesejadoMensal = limiteMensal;
                const res = await putJson(`${API}/configuracoes/edit/${cfgId}`, payload);
                if (!res.ok) { mostrarAlerta(`Erro ao salvar (HTTP ${res.status}).`); return; }
            } else {
                const payload = { fkUsuario: userId, inicioMesFiscal: mes };
                if (limiteMensal != null && !isNaN(limiteMensal)) payload.limiteDesejadoMensal = limiteMensal;
                const res = await postJson(`${API}/configuracoes`, payload);
                if (res.ok) {
                    const cfg = await res.json();
                    cfgId = cfg.id;
                }
            }
            await carregarConfig();
            mostrarAlerta("Configurações salvas!");
        } catch (e) {
            mostrarAlerta("Erro ao salvar configurações.");
            console.error(e);
        }
    };

    window.salvarLimite = async function ({ instId = null, catId = null, valor = null } = {}) {
        if (!cfgId) {
            mostrarAlerta("Salve o mês fiscal primeiro para criar as configurações.");
            return false;
        }

        const idInst = instId || document.getElementById("selInstituicaoLimite")?.value;
        const idCat = catId || document.getElementById("selCategoriaLimite")?.value;
        const valorNum = valor != null
            ? parseFloat(valor)
            : parseFloat(document.getElementById("ipt_limite_valor")?.value);

        if (!idInst && !idCat) {
            mostrarAlerta("Selecione uma instituição ou categoria para definir o limite.");
            return false;
        }
        if (!valorNum || valorNum <= 0) {
            mostrarAlerta("Informe um valor de limite válido.");
            return false;
        }

        // Preserva valores atuais para evitar sobrescrita com null no backend
        const payload = {};
        if (cfgData?.inicioMesFiscal != null) payload.inicioMesFiscal = cfgData.inicioMesFiscal;
        if (cfgData?.limiteDesejadoMensal != null) payload.limiteDesejadoMensal = cfgData.limiteDesejadoMensal;
        if (idInst) payload.limitesInstituicao = [{ instituicaoId: parseInt(idInst), valor: valorNum }];
        if (idCat) payload.limitesCategoria = [{ categoriaId: parseInt(idCat), valor: valorNum }];

        try {
            const res = await putJson(`${API}/configuracoes/edit/${cfgId}`, payload);
            if (res.ok) {
                await carregarConfig();
                mostrarAlerta("Limite salvo!");
                return true;
            } else {
                const body = await res.json().catch(() => ({}));
                mostrarAlerta(`Erro ao salvar limite (HTTP ${res.status}): ${body.message || ""}`);
                return false;
            }
        } catch (e) {
            mostrarAlerta("Erro ao salvar limite.");
            console.error(e);
            return false;
        }
    };

    window.abrirModalLimite = function (tipo) {
        limiteModalTipo = tipo;
        const modal = document.getElementById("modalLimite");
        const titulo = document.getElementById("modalLimiteTitulo");
        const label = document.getElementById("lblLimiteItem");
        const sel = document.getElementById("selLimiteItem");
        const inputValor = document.getElementById("ipt_limite_modal_valor");
        if (!modal || !titulo || !label || !sel || !inputValor) return;

        sel.innerHTML = `<option value="" disabled selected></option>`;

        if (tipo === "instituicao") {
            titulo.textContent = "Definir limite por instituição";
            label.textContent = "Selecionar instituição";
            instituicoes.forEach(inst => {
                const opt = document.createElement("option");
                opt.value = inst.intituicao.id;
                opt.textContent = inst.intituicao.nome;
                sel.appendChild(opt);
            });
        } else {
            titulo.textContent = "Definir limite por categoria";
            label.textContent = "Selecionar categoria";
            categorias.forEach(cat => {
                const opt = document.createElement("option");
                opt.value = cat.categoria.id;
                opt.textContent = cat.categoria.titulo;
                sel.appendChild(opt);
            });
        }

        inputValor.value = "";
        modal.style.display = "flex";
    };

    window.fecharModalLimite = function () {
        const modal = document.getElementById("modalLimite");
        if (modal) modal.style.display = "none";
        limiteModalTipo = null;
    };

    window.salvarLimiteModal = async function () {
        const sel = document.getElementById("selLimiteItem");
        const valor = document.getElementById("ipt_limite_modal_valor");
        const idSelecionado = sel?.value;
        const valorSelecionado = valor?.value;

        if (!limiteModalTipo) {
            mostrarAlerta("Tipo de limite inválido.");
            return;
        }

        if (!idSelecionado) {
            mostrarAlerta("Selecione um item para limitar.");
            return;
        }

        const ok = await window.salvarLimite({
            instId: limiteModalTipo === "instituicao" ? idSelecionado : null,
            catId: limiteModalTipo === "categoria" ? idSelecionado : null,
            valor: valorSelecionado
        });

        if (ok) window.fecharModalLimite();
    };

    // ── INSTITUIÇÕES ──────────────────────────────────────────────
    async function carregarInstituicoes() {
        try {
            instituicoes = await fetchTodasPaginasCfg(`${API}/instituicoes/usuarios/${userId}`);
            renderInstituicoes();
            preencherSelectInstituicoes();
            await preencherSelectNovaInstituicao();
        } catch (e) {
            console.error("Erro ao carregar instituições:", e);
        }
    }

    function renderInstituicoes() {
        const tbody = document.getElementById("corpoInstituicoes");
        if (!tbody) return;
        tbody.innerHTML = "";
        if (instituicoes.length === 0) {
            const tr = document.createElement("tr");
            tr.className = "cfg-table-empty";
            const td = document.createElement("td");
            td.colSpan = 3;
            td.style.padding = "20px";
            td.textContent = "Nenhuma instituição cadastrada.";
            tr.appendChild(td);
            tbody.appendChild(tr);
            return;
        }
        instituicoes.forEach(inst => {
            const tr = document.createElement("tr");

            const tdNome = document.createElement("td");
            tdNome.textContent = inst.intituicao.nome;
            tr.appendChild(tdNome);

            const tdMod = document.createElement("td");
            tdMod.textContent = formatarLocalDateTime(inst.ultimaAtualizacao);
            tr.appendChild(tdMod);

            const tdAcoes = document.createElement("td");
            const btn = document.createElement("button");
            btn.className = "cfg-btn danger";
            btn.textContent = "Desvincular";
            btn.addEventListener("click", async () => 
                mostrarConfirmacao("Remover esta instituição do seu perfil?", async () => {
                try {
                    const res = await fetch(`${API}/instituicoes/${inst.intituicao.id}/usuarios/${userId}`, { method: "PATCH" });
                    if (!res.ok) { mostrarAlerta(`Erro ao desvincular (HTTP ${res.status}).`); return; }
                    await carregarInstituicoes();
                } catch (e) {
                    mostrarAlerta("Erro ao desvincular instituição.");
                    console.error(e);
                }
            }));
            tdAcoes.appendChild(btn);
            tr.appendChild(tdAcoes);

            tbody.appendChild(tr);
        });
    }

    function preencherSelectInstituicoes() {
        const sel = document.getElementById("selInstituicaoLimite");
        if (!sel) return;
        sel.innerHTML = `<option value="" disabled selected></option>`;
        instituicoes.forEach(inst => {
            const opt = document.createElement("option");
            opt.value = inst.intituicao.id;
            opt.textContent = inst.intituicao.nome;
            sel.appendChild(opt);
        });
    }

    window.adicionarInstituicao = async function () {
        const sel = document.getElementById("sel_nova_instituicao");
        const instId = sel?.value;
        if (!instId) { mostrarAlerta("Selecione uma instituição."); return; }
        try {
            const res = await fetch(`${API}/instituicoes/${instId}/usuarios/${userId}`, { method: "POST" });
            if (!res.ok) { mostrarAlerta(`Erro ao adicionar instituição (HTTP ${res.status}).`); return; }
            sel.value = "";
            await carregarInstituicoes();
        } catch (e) {
            mostrarAlerta("Erro ao adicionar instituição.");
            console.error(e);
        }
    };

    async function preencherSelectNovaInstituicao() {
        const sel = document.getElementById("sel_nova_instituicao");
        if (!sel) return;
        try {
            const todas = await fetchTodasPaginasCfg(`${API}/instituicoes`);
            const vinculadasIds = new Set(instituicoes.map(i => i.intituicao && i.intituicao.id));
            const disponiveis = todas.filter(i => !vinculadasIds.has(i.id));
            sel.innerHTML = `<option value="" disabled selected></option>`;
            disponiveis.forEach(inst => {
                const opt = document.createElement("option");
                opt.value = inst.id;
                opt.textContent = inst.nome;
                sel.appendChild(opt);
            });
        } catch (e) {
            console.error("Erro ao carregar instituições disponíveis:", e);
        }
    }



    // ── CATEGORIAS ────────────────────────────────────────────────
    async function carregarCategorias() {
        try {
            categorias = await fetchTodasPaginasCfg(`${API}/categorias/usuario/${userId}`);
            renderCategorias();
            preencherSelectCategorias();
            await preencherSelectNovaCategoria();
        } catch (e) {
            console.error("Erro ao carregar categorias:", e);
        }
    }

    async function preencherSelectNovaCategoria() {
        const sel = document.getElementById("sel_nova_categoria");
        if (!sel) return;
        try {
            const todas = await fetchTodasPaginasCfg(`${API}/categorias`);
            const vinculadasIds = new Set(categorias.map(c => c.categoria && c.categoria.id));
            const disponiveis = todas.filter(c => !vinculadasIds.has(c.id));
            sel.innerHTML = `<option value="" disabled selected></option>`;
            disponiveis.forEach(cat => {
                const opt = document.createElement("option");
                opt.value = cat.id;
                opt.textContent = cat.titulo;
                sel.appendChild(opt);
            });
        } catch (e) {
            console.error("Erro ao carregar categorias disponíveis:", e);
        }
    }

    function renderCategorias() {
        const tbody = document.getElementById("corpoCategorias");
        if (!tbody) return;
        tbody.innerHTML = "";
        if (categorias.length === 0) {
            const tr = document.createElement("tr");
            tr.className = "cfg-table-empty";
            const td = document.createElement("td");
            td.colSpan = 3;
            td.style.padding = "20px";
            td.textContent = "Nenhuma categoria cadastrada.";
            tr.appendChild(td);
            tbody.appendChild(tr);
            return;
        }
        categorias.forEach(cat => {
            const tr = document.createElement("tr");

            const tdNome = document.createElement("td");
            tdNome.textContent = cat.categoria.titulo;
            tr.appendChild(tdNome);

            const tdMod = document.createElement("td");
            tdMod.textContent = formatarLocalDateTime(cat.ultimaAtualizacao);
            tr.appendChild(tdMod);

            const tdAcoes = document.createElement("td");
            const btn = document.createElement("button");
            btn.className = "cfg-btn danger";
            btn.textContent = "Remover";
            btn.addEventListener("click", () => {
                mostrarConfirmacao("Remover esta categoria do seu perfil?", async () => {
                    try {
                        const res = await fetch(`${API}/categorias/${cat.categoria.id}/usuarios/${userId}`, { method: "PATCH" });
                        if (!res.ok) { mostrarAlerta(`Erro ao remover (HTTP ${res.status}).`); return; }
                        await carregarCategorias();
                    } catch (e) {
                        mostrarAlerta("Erro ao remover categoria.");
                        console.error(e);
                    }
                });
            });
            tdAcoes.appendChild(btn);
            tr.appendChild(tdAcoes);

            tbody.appendChild(tr);
        });
    }

    function preencherSelectCategorias() {
        const sel = document.getElementById("selCategoriaLimite");
        if (!sel) return;
        sel.innerHTML = `<option value="" disabled selected></option>`;
        categorias.forEach(cat => {
            const opt = document.createElement("option");
            opt.value = cat.categoria.id;
            opt.textContent = cat.categoria.titulo;
            sel.appendChild(opt);
        });
    }

    window.adicionarCategoria = async function () {
        const sel = document.getElementById("sel_nova_categoria");
        const catId = sel?.value;
        if (!catId) { mostrarAlerta("Selecione uma categoria."); return; }
        try {
            const res = await fetch(`${API}/categorias/${catId}/usuarios/${userId}`, { method: "POST" });
            if (!res.ok) { mostrarAlerta(`Erro ao adicionar categoria (HTTP ${res.status}).`); return; }
            sel.value = "";
            await carregarCategorias();
            window.dispatchEvent(new Event('xp:refresh'));
            mostrarAlerta("Categoria adicionada com sucesso!");
        } catch (e) {
            mostrarAlerta("Erro ao adicionar categoria.");
            console.error(e);
        }
    };

    window.abrirPersonalizada = function (tipo) {
        tipoPersonalizada = tipo;
        const modal  = document.getElementById("modalPersonalizada");
        const titulo = document.getElementById("modalPersonalizadaTitulo");
        const label  = document.getElementById("modalPersonalizadaLabel");
        const input  = document.getElementById("ipt_personalizada");
        if (tipo === "instituicao") {
            if (titulo) titulo.textContent = "Nova Instituição Personalizada";
            if (label)  label.textContent  = "Nome da instituição";
        } else {
            if (titulo) titulo.textContent = "Nova Categoria Personalizada";
            if (label)  label.textContent  = "Nome da categoria";
        }
        if (input) input.value = "";
        if (modal) modal.style.display = "flex";
    };

    window.fecharPersonalizada = function () {
        const modal = document.getElementById("modalPersonalizada");
        if (modal) modal.style.display = "none";
        tipoPersonalizada = null;
    };

    window.salvarPersonalizada = async function () {
        const input = document.getElementById("ipt_personalizada");
        const nome = input?.value?.trim();
        if (!nome) { mostrarAlerta("Informe o nome."); return; }
        try {
            if (tipoPersonalizada === "instituicao") {
                const resCreate = await postJson(`${API}/instituicoes`, { nome });
                if (!resCreate.ok) { mostrarAlerta("Erro ao criar instituição."); return; }
                const nova = await resCreate.json();
                const resLink = await fetch(`${API}/instituicoes/${nova.id}/usuarios/${userId}`, { method: "POST" });
                if (!resLink.ok) { mostrarAlerta("Erro ao vincular instituição."); return; }
                fecharPersonalizada();
                await carregarInstituicoes();
                window.dispatchEvent(new Event('xp:refresh'));
                mostrarAlerta("Instituição criada e vinculada com sucesso!");
            } else {
                const res = await postJson(`${API}/categorias/usuario/${userId}`, { titulo: nome });
                if (!res.ok) { mostrarAlerta("Erro ao criar categoria."); return; }
                fecharPersonalizada();
                await carregarCategorias();
                window.dispatchEvent(new Event('xp:refresh'));
                mostrarAlerta("Categoria personalizada criada com sucesso!");
            }
        } catch (e) {
            mostrarAlerta("Erro ao salvar.");
            console.error(e);
        }
    };

    window.removerCategoria = async function (catId) {
        try {
            await fetch(`${API}/categorias/${catId}/usuarios/${userId}`, { method: "PATCH" });
            await carregarCategorias();
        } catch (e) {
            mostrarAlerta("Erro ao remover categoria.");
            console.error(e);
        }
    };

    // ── IMPORTAR DADOS ────────────────────────────────────────────
    function garantirModalImportacao() {
        let modal = document.getElementById("cfgImportModal");
        if (modal) return modal;

        modal = document.createElement("div");
        modal.id = "cfgImportModal";
        // Estilo inline completo para garantir funcionamento em JavaFX WebView
        modal.style.cssText = [
            "display:none",
            "position:fixed",
            "inset:0",
            "background:rgba(0,0,0,0.55)",
            "z-index:9999",
            "align-items:center",
            "justify-content:center",
            "padding:16px"
        ].join(";");

        modal.innerHTML = `
            <div style="background:var(--cor-fundo-card,#FAFFFF);border-radius:20px;padding:28px 24px;
                        width:min(480px,94vw);display:flex;flex-direction:column;gap:16px;
                        box-shadow:0 8px 32px rgba(0,0,0,0.3);">
                <div style="display:flex;justify-content:space-between;align-items:center;">
                    <h2 style="margin:0;color:var(--cor-titulo,#004C58);font-size:1.4rem;">Importar dados</h2>
                    <button id="cfgImportFechar" style="background:none;border:1px solid #9cc9c9;border-radius:8px;
                            width:36px;height:36px;font-size:1.5rem;cursor:pointer;color:var(--cor-principal,#367373);
                            display:flex;align-items:center;justify-content:center;padding:0;margin:0;">&times;</button>
                </div>
                <p style="margin:0;color:var(--cor-texto-secundario,#4A4A4A);font-size:0.9rem;">
                    Selecione a instituição financeira e o arquivo exportado pelo banco.
                </p>

                <div style="position:relative;margin:4px 0;">
                    <select id="cfgImportBanco" style="height:52px;width:100%;border:2px solid var(--cor-principal,#367373);
                            border-radius:10px;padding:0 18px;font-size:1rem;font-weight:600;
                            color:var(--cor-principal,#367373);background:transparent;appearance:none;outline:none;">
                        <option value="" disabled selected>Selecione a instituição</option>
                    </select>
                    <span style="position:absolute;right:14px;top:50%;transform:translateY(-50%);
                                 color:var(--cor-principal,#367373);pointer-events:none;">▾</span>
                </div>

                <div style="border:2px dashed var(--cor-principal,#367373);border-radius:10px;
                            padding:16px;text-align:center;cursor:pointer;" id="cfgImportDropArea">
                    <p style="margin:0 0 8px;color:var(--cor-principal,#367373);font-weight:600;">
                        Clique para selecionar o arquivo
                    </p>
                    <p style="margin:0;font-size:0.8rem;color:var(--cor-texto-secundario,#4A4A4A);">
                        Formatos aceitos: .csv, .ofx, .xls, .xlsx, .json, .sql
                    </p>
                    <input type="file" id="cfgImportArquivo"
                           accept=".csv,.ofx,.qfx,.xls,.xlsx,.json,.sql,.pdf"
                           style="display:none;">
                    <p id="cfgImportNomeArquivo" style="margin:8px 0 0;font-size:0.85rem;
                       color:var(--cor-principal,#367373);font-weight:600;"></p>
                </div>

                <p id="cfgImportMsg" style="color:#e53e3e;font-size:0.85rem;display:none;margin:0;"></p>

                <div style="display:flex;gap:10px;justify-content:flex-end;flex-wrap:wrap;">
                    <button id="cfgImportCancelar"
                        style="height:44px;padding:0 20px;background:transparent;
                               border:2px solid var(--cor-principal,#367373);color:var(--cor-principal,#367373);
                               border-radius:10px;font-size:1rem;cursor:pointer;margin:0;">
                        Cancelar
                    </button>
                    <button id="cfgImportConfirmar"
                        style="height:44px;padding:0 20px;background:var(--cor-principal,#367373);
                               color:#fff;border:none;border-radius:10px;font-size:1rem;cursor:pointer;margin:0;">
                        Importar
                    </button>
                </div>
            </div>
        `;

        document.body.appendChild(modal);

        const fechar = () => { modal.style.display = "none"; };
        modal.querySelector("#cfgImportFechar").onclick = fechar;
        modal.querySelector("#cfgImportCancelar").onclick = fechar;
        modal.addEventListener("click", e => { if (e.target === modal) fechar(); });

        // Área de drop / clique para selecionar arquivo
        const dropArea = modal.querySelector("#cfgImportDropArea");
        const inputArq = modal.querySelector("#cfgImportArquivo");
        const nomeLabel = modal.querySelector("#cfgImportNomeArquivo");

        dropArea.addEventListener("click", () => inputArq.click());

        inputArq.addEventListener("change", () => {
            const f = inputArq.files && inputArq.files[0];
            nomeLabel.textContent = f ? `Arquivo selecionado: ${f.name}` : "";
        });

        modal.querySelector("#cfgImportConfirmar").onclick = async () => {
            const selBanco = modal.querySelector("#cfgImportBanco");
            const msg = modal.querySelector("#cfgImportMsg");
            const btn = modal.querySelector("#cfgImportConfirmar");

            const bancoId = selBanco ? selBanco.value : "";
            // O backend espera o NOME da instituição, não o ID
            const bancoNome = selBanco && selBanco.selectedIndex >= 0
                ? selBanco.options[selBanco.selectedIndex].textContent.trim()
                : "";
            const arquivo = inputArq && inputArq.files && inputArq.files[0];

            if (!bancoId) {
                msg.textContent = "Selecione uma instituição financeira.";
                msg.style.display = "";
                return;
            }
            if (!arquivo) {
                msg.textContent = "Selecione um arquivo para importar.";
                msg.style.display = "";
                return;
            }

            msg.style.display = "none";
            btn.disabled = true;
            btn.textContent = "Importando...";
            btn.style.opacity = "0.7";

            try {
                const formData = new FormData();
                // O backend espera: @RequestParam MultipartFile arquivo
                //                   @RequestParam(required = false) String bancoNome
                formData.append("arquivo", arquivo);
                if (bancoNome) formData.append("bancoNome", bancoNome);

                const res = await fetch(`${API}/configuracoes/upload-arquivo/usuarios/${userId}`, {
                    method: "POST",
                    body: formData
                });

                if (res.ok || res.status === 204) {
                    fechar();
                    mostrarAlerta("Dados importados com sucesso!");
                } else {
                    let detalhe = `HTTP ${res.status}`;
                    try { const corpo = await res.json(); detalhe = corpo.message || detalhe; } catch (_) {}
                    msg.textContent = `Erro ao importar: ${detalhe}`;
                    msg.style.display = "";
                }
            } catch (e) {
                console.error("Erro ao importar dados:", e);
                msg.textContent = "Erro de conexão ao importar. Verifique se o servidor está ativo.";
                msg.style.display = "";
            } finally {
                btn.disabled = false;
                btn.textContent = "Importar";
                btn.style.opacity = "1";
            }
        };

        return modal;
    }

    window.importarDados = function () {
        if (!userId) { mostrarAlerta("Usuário não identificado."); return; }

        const modal = garantirModalImportacao();
        const selBanco = modal.querySelector("#cfgImportBanco");
        const inputArq = modal.querySelector("#cfgImportArquivo");
        const nomeLabel = modal.querySelector("#cfgImportNomeArquivo");
        const msg = modal.querySelector("#cfgImportMsg");

        // Atualiza lista de instituições sempre que abrir
        if (selBanco) {
            selBanco.innerHTML = `<option value="" disabled selected>Selecione a instituição</option>`;
            (instituicoes || []).forEach(inst => {
                const opt = document.createElement("option");
                opt.value = inst.id;
                opt.textContent = (inst.intituicao && inst.intituicao.nome) ? inst.intituicao.nome : "Instituição";
                selBanco.appendChild(opt);
            });
        }
        if (inputArq) inputArq.value = "";
        if (nomeLabel) nomeLabel.textContent = "";
        if (msg) msg.style.display = "none";

        modal.style.display = "flex";
    };

    window.processarImportacao = function () {
        // Mantido por compatibilidade – fluxo agora via modal
    };

    function obterFormatosExportacaoDisponiveis() {
        return [
            { tipo: "pdf", label: "PDF (.pdf)" },
            { tipo: "excel", label: "Excel (.xlsx)" },
            { tipo: "json", label: "JSON (.json)" },
            { tipo: "sql", label: "SQL (.sql)" }
        ];
    }

    function garantirModalExportacao() {
        let modal = document.getElementById("cfgExportModal");
        if (modal) return modal;

        modal = document.createElement("div");
        modal.id = "cfgExportModal";
        modal.className = "modal";
        modal.style.display = "none";
        modal.innerHTML = `
            <div class="conteudoModal" style="max-width:460px;">
                <span id="cfgExportFechar" class="fechar" style="cursor:pointer;">&times;</span>
                <h2 style="margin-top:0; color:#0e5454;">Exportar dados</h2>
                <p style="margin:0 0 12px 0; color:#486468;">Selecione o formato do arquivo:</p>
                <div style="display:flex; flex-direction:column; gap:10px;">
                    <select id="cfgExportTipo" class="select_modal"></select>
                    <div style="display:flex; gap:10px; justify-content:flex-end;">
                        <button id="cfgExportCancelar" class="cfg-btn" style="background:transparent;border:2px solid var(--cor-principal);color:var(--cor-principal);">Cancelar</button>
                        <button id="cfgExportConfirmar" class="cfg-btn">Exportar</button>
                    </div>
                </div>
            </div>
        `;

        document.body.appendChild(modal);

        const fechar = () => { modal.style.display = "none"; };
        const btnFechar = document.getElementById("cfgExportFechar");
        const btnCancelar = document.getElementById("cfgExportCancelar");
        if (btnFechar) btnFechar.onclick = fechar;
        if (btnCancelar) btnCancelar.onclick = fechar;

        modal.addEventListener("click", (event) => {
            if (event.target === modal) {
                fechar();
            }
        });

        const btnConfirmar = document.getElementById("cfgExportConfirmar");
        if (btnConfirmar) {
            btnConfirmar.onclick = async () => {
                const select = document.getElementById("cfgExportTipo");
                const tipo = select?.value;
                if (!tipo) {
                    mostrarAlerta("Selecione um formato para exportação.");
                    return;
                }
                modal.style.display = "none";
                await exportarDadosPorTipo(tipo);
            };
        }

        return modal;
    }

    function abrirModalExportacao() {
        const modal = garantirModalExportacao();
        const select = document.getElementById("cfgExportTipo");
        if (!select) return;

        const formatos = obterFormatosExportacaoDisponiveis();
        select.innerHTML = formatos
            .map(f => `<option value="${f.tipo}">${f.label}</option>`)
            .join("");

        modal.style.display = "flex";
    }

    async function aguardarDesktopBridge(timeoutMs = 1800, intervaloMs = 120) {
        const inicio = Date.now();
        while (Date.now() - inicio < timeoutMs) {
            if (window.desktopBridge) {
                return window.desktopBridge;
            }
            await new Promise(resolve => setTimeout(resolve, intervaloMs));
        }
        return window.desktopBridge || null;
    }

    async function exportarDadosPorTipo(tipo) {
        if (!userId) {
            mostrarAlerta("Usuário não identificado para exportação.");
            return;
        }

        const ext = tipo === "excel" ? "xlsx" : tipo;
        let nomeArquivo = `registros.${ext}`;
        const downloadUrl = `${API}/registros/download/${userId}?tipo=${encodeURIComponent(tipo)}`;

        // 1. desktopBridge (JavaFX bridge nativo)
        const bridge = await aguardarDesktopBridge(3000);
        if (bridge) {
            try {
                const res = await fetch(downloadUrl);
                if (!res.ok) { mostrarAlerta(`Erro ao exportar (HTTP ${res.status}).`); return; }
                const blob = await res.blob();
                const cd = res.headers.get("content-disposition") || "";
                const m = cd.match(/filename=([^;]+)/i);
                if (m && m[1]) nomeArquivo = m[1].replace(/"/g, "").trim();

                const bytes = new Uint8Array(await blob.arrayBuffer());
                let binario = "";
                for (let i = 0; i < bytes.length; i += 0x8000) {
                    binario += String.fromCharCode(...bytes.subarray(i, i + 0x8000));
                }
                const salvo = bridge.saveBase64File(nomeArquivo, btoa(binario));
                if (salvo) { mostrarAlerta(`${tipo.toUpperCase()} exportado com sucesso!`); return; }
            } catch (bridgeErr) {
                console.warn("desktopBridge falhou:", bridgeErr);
            }
        }

        // 2. Verifica se o endpoint responde antes de tentar download
        try {
            const check = await fetch(downloadUrl, { method: "HEAD" });
            if (!check.ok) {
                mostrarAlerta(`Erro ao gerar arquivo no servidor (HTTP ${check.status}).`);
                return;
            }
        } catch (e) {
            console.warn("HEAD check falhou, tentando download direto:", e);
        }

        // 3a. Browser normal: blob URL + <a download>
        try {
            const res = await fetch(downloadUrl);
            if (res.ok) {
                const blob = await res.blob();
                const cd = res.headers.get("content-disposition") || "";
                const m = cd.match(/filename=([^;]+)/i);
                if (m && m[1]) nomeArquivo = m[1].replace(/"/g, "").trim();

                const blobUrl = URL.createObjectURL(blob);
                const a = document.createElement("a");
                a.href = blobUrl;
                a.download = nomeArquivo;
                a.style.display = "none";
                document.body.appendChild(a);
                a.click();
                a.remove();
                setTimeout(() => URL.revokeObjectURL(blobUrl), 60000);
            }
        } catch (e) {
            console.warn("Blob download falhou:", e);
        }

        // 3b. JavaFX fallback: <a href> direto (sem blob) — WebEngine pode interceptar
        setTimeout(function () {
            const a = document.createElement("a");
            a.href = downloadUrl;
            a.download = nomeArquivo;
            a.style.display = "none";
            document.body.appendChild(a);
            a.click();
            a.remove();
        }, 200);

        // 3c. JavaFX fallback: iframe oculto — WebEngine pode acionar download handler
        setTimeout(function () {
            const ifr = document.createElement("iframe");
            ifr.style.cssText = "position:fixed;top:-9999px;left:-9999px;width:1px;height:1px;border:0;opacity:0;";
            ifr.src = downloadUrl;
            document.body.appendChild(ifr);
            setTimeout(function () { try { document.body.removeChild(ifr); } catch (_) {} }, 120000);
        }, 400);

        // 3d. JavaFX fallback: window.open (createPopupHandler)
        setTimeout(function () {
            try { window.open(downloadUrl, "_blank"); } catch (_) {}
        }, 600);

        mostrarAlerta(`Download do ${tipo.toUpperCase()} iniciado. Verifique seu gerenciador de downloads ou a pasta de destino.`);
    }

    window.exportarDados = function () {
        abrirModalExportacao();
    };


    // ── CALENDÁRIO – SELEÇÃO DE PERÍODO PARA EXCLUSÃO ────────────
    let cfgCalCampo = null;        // 'inicio' | 'fim'
    let cfgCalDataSelecionada = null;
    let cfgDeleteInicio = null;    // YYYY-MM-DD
    let cfgDeleteFim    = null;    // YYYY-MM-DD

    let cfgCalMesAtual  = new Date().getMonth();
    let cfgCalAnoAtual  = new Date().getFullYear();

    function cfgCalFormatar(iso) {
        const [a, m, d] = iso.split("-");
        return `${d}/${m}/${a}`;
    }

    function cfgCalGerar() {
        const dias    = document.getElementById("cfgCalDias");
        const mesAno  = document.getElementById("cfgCalMesAno");
        const confirmar = document.getElementById("cfgCalConfirmar");
        if (!dias) return;

        dias.innerHTML = "";
        cfgCalDataSelecionada = null;
        if (confirmar) confirmar.disabled = true;

        mesAno.innerText = new Date(cfgCalAnoAtual, cfgCalMesAtual)
            .toLocaleString("pt-BR", { month: "long", year: "numeric" });

        const primeiroDia = new Date(cfgCalAnoAtual, cfgCalMesAtual, 1).getDay();
        const totalDias   = new Date(cfgCalAnoAtual, cfgCalMesAtual + 1, 0).getDate();

        for (let i = 0; i < primeiroDia; i++) dias.innerHTML += `<span></span>`;

        for (let dia = 1; dia <= totalDias; dia++) {
            const iso = `${cfgCalAnoAtual}-${String(cfgCalMesAtual + 1).padStart(2, "0")}-${String(dia).padStart(2, "0")}`;
            const span = document.createElement("span");
            span.innerText = dia;
            span.onclick = () => {
                dias.querySelectorAll(".diaSelecionado").forEach(e => e.classList.remove("diaSelecionado"));
                span.classList.add("diaSelecionado");
                cfgCalDataSelecionada = iso;
                if (confirmar) confirmar.disabled = false;
            };
            dias.appendChild(span);
        }
    }

    window.abrirCalendarioDelete = function (campo) {
        cfgCalCampo = campo;
        cfgCalMesAtual = new Date().getMonth();
        cfgCalAnoAtual = new Date().getFullYear();
        const modal = document.getElementById("cfgCalModal");
        if (modal) { modal.style.display = "flex"; cfgCalGerar(); }
    };

    document.addEventListener("DOMContentLoaded", () => {
        const fechar    = document.getElementById("cfgCalFechar");
        const anterior  = document.getElementById("cfgCalAnterior");
        const proximo   = document.getElementById("cfgCalProximo");
        const confirmar = document.getElementById("cfgCalConfirmar");
        const modal     = document.getElementById("cfgCalModal");

        if (fechar)    fechar.onclick   = () => { if (modal) modal.style.display = "none"; };
        if (anterior)  anterior.onclick = () => {
            cfgCalMesAtual--;
            if (cfgCalMesAtual < 0) { cfgCalMesAtual = 11; cfgCalAnoAtual--; }
            cfgCalGerar();
        };
        if (proximo)   proximo.onclick  = () => {
            cfgCalMesAtual++;
            if (cfgCalMesAtual > 11) { cfgCalMesAtual = 0; cfgCalAnoAtual++; }
            cfgCalGerar();
        };
        if (confirmar) confirmar.onclick = () => {
            if (!cfgCalDataSelecionada) return;
            if (cfgCalCampo === "inicio") {
                cfgDeleteInicio = cfgCalDataSelecionada;
                const lbl = document.getElementById("cfgDeleteInicioLabel");
                if (lbl) lbl.textContent = cfgCalFormatar(cfgDeleteInicio);
            } else {
                cfgDeleteFim = cfgCalDataSelecionada;
                const lbl = document.getElementById("cfgDeleteFimLabel");
                if (lbl) lbl.textContent = cfgCalFormatar(cfgDeleteFim);
            }
            if (modal) modal.style.display = "none";
        };
    });

    // ── APAGAR REGISTROS ─────────────────────────────────────────
    window.apagarRegistrosPeriodo = function () {
        if (!cfgDeleteInicio || !cfgDeleteFim) {
            mostrarAlerta("Escolha a data inicial e a data final do período.");
            return;
        }
        if (cfgDeleteInicio > cfgDeleteFim) {
            mostrarAlerta("A data inicial não pode ser maior que a data final.");
            return;
        }
        if (!cfgId) {
            mostrarAlerta("Configuração do usuário não carregada.");
            return;
        }

        mostrarConfirmacao(
            `Apagar todos os registros de ${cfgCalFormatar(cfgDeleteInicio)} até ${cfgCalFormatar(cfgDeleteFim)}? Esta ação é irreversível.`,
            async () => {
                try {
                    const res = await fetch(`${API}/configuracoes/${cfgId}/dados/periodo-tempo`, {
                        method: "DELETE",
                        headers: { "Content-Type": "application/json" },
                        body: JSON.stringify({ dataInical: cfgDeleteInicio, dataFinal: cfgDeleteFim })
                    });
                    if (res.status === 204) {
                        mostrarAlerta("Registros do período apagados com sucesso!");
                        cfgDeleteInicio = cfgDeleteFim = null;
                        const lI = document.getElementById("cfgDeleteInicioLabel");
                        const lF = document.getElementById("cfgDeleteFimLabel");
                        if (lI) lI.textContent = "";
                        if (lF) lF.textContent = "";
                    } else {
                        const txt = await res.text();
                        mostrarAlerta(`Erro ao apagar registros (HTTP ${res.status}): ${txt}`);
                    }
                } catch (e) {
                    console.error("Erro ao apagar registros por período:", e);
                    mostrarAlerta("Erro ao apagar registros do período.");
                }
            }
        );
    };

    window.apagarTodosRegistros = function () {
        if (!userId) {
            mostrarAlerta("Usuário não identificado.");
            return;
        }

        mostrarConfirmacao(
            "Apagar TODOS os registros do usuário? Esta ação é irreversível.",
            async () => {
                try {
                    const res = await fetch(`${API}/configuracoes/usuarios/${userId}/dados/deletar-tudo`, {
                        method: "DELETE"
                    });
                    if (res.status === 204) {
                        mostrarAlerta("Todos os registros foram apagados com sucesso!");
                    } else {
                        const txt = await res.text();
                        mostrarAlerta(`Erro ao apagar registros (HTTP ${res.status}): ${txt}`);
                    }
                } catch (e) {
                    console.error("Erro ao apagar todos os registros:", e);
                    mostrarAlerta("Erro ao apagar todos os registros.");
                }
            }
        );
    };

    if (document.readyState === "loading") {
        document.addEventListener("DOMContentLoaded", init);
    } else {
        init();
    }
})();

(function () {
    const API = "http://localhost:8080";
    const usuarioLogado = JSON.parse(localStorage.getItem("usuarioLogado") || "null");
    const userId = usuarioLogado?.id;

    let cfgId = null;
    let cfgData = null;   // armazena config completa carregada do servidor
    let instituicoes = [];
    let categorias = [];
    let tipoPersonalizada = null; // 'instituicao' | 'categoria'
    let limiteModalTipo = null; // 'instituicao' | 'categoria'

    // ── helpers ──────────────────────────────────────────────────
    function habilitarFecharAlertaAoClicarFora() {
        const div = document.getElementById("div_alerta");
        const conteudo = document.getElementById("conteudoAlerta");
        if (!div || !conteudo || div.dataset.closeOutsideBound === "1") return;

        div.dataset.closeOutsideBound = "1";
        div.addEventListener("click", (event) => {
            if (event.target === div) {
                div.style.display = "none";
            }
        });
    }

    function mostrarAlerta(texto) {
        habilitarFecharAlertaAoClicarFora();
        const div = document.getElementById("div_alerta");
        const conteudo = document.getElementById("conteudoAlerta");
        if (!div || !conteudo) return;
        conteudo.innerHTML = texto;
        div.style.display = "flex";
        setTimeout(() => { div.style.display = "none"; }, 3000);
    }

    function mostrarConfirmacao(texto, onConfirm) {
        habilitarFecharAlertaAoClicarFora();
        const div = document.getElementById("div_alerta");
        const conteudo = document.getElementById("conteudoAlerta");
        if (!div || !conteudo) { onConfirm(); return; }
        conteudo.innerHTML = "";
        const msg = document.createElement("span");
        msg.textContent = texto;
        const divBtns = document.createElement("div");
        divBtns.style.cssText = "display:flex;gap:8px;margin-top:10px;";
        const btnNo = document.createElement("button");
        btnNo.textContent = "Cancelar";
        btnNo.style.background = "#888";
        const btnOk = document.createElement("button");
        btnOk.textContent = "Confirmar";
        btnOk.addEventListener("click", () => { div.style.display = "none"; onConfirm(); });
        btnNo.addEventListener("click", () => { div.style.display = "none"; });
        divBtns.appendChild(btnNo);
        divBtns.appendChild(btnOk);
        conteudo.appendChild(msg);
        conteudo.appendChild(divBtns);
        div.style.display = "flex";
    }

    function postJson(url, payload) {
        return fetch(url, {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify(payload)
        });
    }

    function putJson(url, payload) {
        return fetch(url, {
            method: "PUT",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify(payload)
        });
    }

    function formatarLocalDateTime(valor) {
        if (window.MainAPI?.formatarLocalDateTime) {
            return window.MainAPI.formatarLocalDateTime(valor, "-");
        }
        return "-";
    }

    function chaveAlertas() {
        return `cfg_alertas_${userId}`;
    }

    function salvarPreferenciasAlertas() {
        const swWhatsapp = document.getElementById("sw_alerta_whatsapp");
        const swEmail = document.getElementById("sw_alerta_email");
        if (!swWhatsapp || !swEmail) return;

        const preferencias = {
            whatsapp: !!swWhatsapp.checked,
            email: !!swEmail.checked
        };
        localStorage.setItem(chaveAlertas(), JSON.stringify(preferencias));
    }

    function inicializarSwitchesAlerta() {
        const swWhatsapp = document.getElementById("sw_alerta_whatsapp");
        const swEmail = document.getElementById("sw_alerta_email");
        if (!swWhatsapp || !swEmail) return;

        const salvas = JSON.parse(localStorage.getItem(chaveAlertas()) || "null");
        swWhatsapp.checked = !!salvas?.whatsapp;
        swEmail.checked = !!salvas?.email;

        swWhatsapp.addEventListener("change", salvarPreferenciasAlertas);
        swEmail.addEventListener("change", salvarPreferenciasAlertas);
    }

    // ── INIT ─────────────────────────────────────────────────────
    async function init() {
        if (!userId) {
            window.location.href = "login.html";
            return;
        }
        inicializarSwitchesAlerta();
        await Promise.all([
            carregarConfig(),
            carregarInstituicoes(),
            carregarCategorias()
        ]);
    }

    // ── Helper: busca todas as páginas de um endpoint paginado ──────
    async function fetchTodasPaginasCfg(url) {
        const allContent = [];
        let pagina = 0;
        let isLast = false;
        const LIMITE = 100;

        while (!isLast && pagina < LIMITE) {
            const sep = url.includes("?") ? "&" : "?";
            const res = await fetch(`${url}${sep}pagina=${pagina}`);
            if (res.status === 204) break;
            if (!res.ok) break;
            const data = await res.json();
            if (data && Array.isArray(data.content)) {
                allContent.push(...data.content);
                isLast = data.last === true;
            } else if (Array.isArray(data)) {
                allContent.push(...data);
                isLast = true;
            } else {
                break;
            }
            pagina++;
        }
        return allContent;
    }

    // ── CONFIGURAÇÕES ─────────────────────────────────────────────
    async function carregarConfig() {
        try {
            const res = await fetch(`${API}/configuracoes/usuarios/${userId}`);
            if (!res.ok) return;
            const cfg = await res.json();
            cfgId = cfg.id;
            cfgData = cfg;

            const sel = document.getElementById("mesFiscal");
            if (sel && cfg.inicioMesFiscal != null) {
                sel.value = String(cfg.inicioMesFiscal);
            }

            const limiteInput = document.getElementById("limiteMensal");
            if (limiteInput && cfg.limiteDesejadoMensal != null) {
                limiteInput.value = cfg.limiteDesejadoMensal;
            }

            renderLimites(cfg.limiteInstituicao || [], cfg.limitePorCategoria || []);
        } catch (e) {
            console.error("Erro ao carregar configurações:", e);
        }
    }

    function renderLimites(limitesInst, limitesCateg) {
        const tbody = document.getElementById("corpoLimites");
        if (!tbody) return;
        tbody.innerHTML = "";

        const linhas = [];
        limitesInst.forEach(l => {
            linhas.push({ tipo: "Instituição", item: l.instituicao?.nome || "-", limite: l.limiteDesejado });
        });
        limitesCateg.forEach(l => {
            linhas.push({ tipo: "Categoria", item: l.categoria?.titulo || "-", limite: l.limiteDesejado });
        });

        if (linhas.length === 0) {
            tbody.innerHTML = `<tr class="cfg-table-empty"><td colspan="4" style="padding:20px;">Nenhum limite configurado ainda.</td></tr>`;
            return;
        }
        linhas.forEach(l => {
            const tr = document.createElement("tr");
            tr.innerHTML = `<td>${l.tipo}</td><td>${l.item}</td><td>R$ ${Number(l.limite).toFixed(2)}</td><td>-</td>`;
            tbody.appendChild(tr);
        });
    }

    window.salvarMesFiscal = async function () {
        const sel = document.getElementById("mesFiscal");
        if (!sel?.value) {
            mostrarAlerta("Selecione o início do mês fiscal.");
            return;
        }
        const mes = parseInt(sel.value, 10);
        const limiteInput = document.getElementById("limiteMensal");
        const limiteMensal = limiteInput?.value ? parseFloat(limiteInput.value) : cfgData?.limiteDesejadoMensal;
        try {
            if (cfgId) {
                const payload = { inicioMesFiscal: mes };
                if (limiteMensal != null && !isNaN(limiteMensal)) payload.limiteDesejadoMensal = limiteMensal;
                const res = await putJson(`${API}/configuracoes/edit/${cfgId}`, payload);
                if (!res.ok) { mostrarAlerta(`Erro ao salvar (HTTP ${res.status}).`); return; }
            } else {
                const payload = { fkUsuario: userId, inicioMesFiscal: mes };
                if (limiteMensal != null && !isNaN(limiteMensal)) payload.limiteDesejadoMensal = limiteMensal;
                const res = await postJson(`${API}/configuracoes`, payload);
                if (res.ok) {
                    const cfg = await res.json();
                    cfgId = cfg.id;
                }
            }
            await carregarConfig();
            mostrarAlerta("Configurações salvas!");
        } catch (e) {
            mostrarAlerta("Erro ao salvar configurações.");
            console.error(e);
        }
    };

    window.salvarLimite = async function ({ instId = null, catId = null, valor = null } = {}) {
        if (!cfgId) {
            mostrarAlerta("Salve o mês fiscal primeiro para criar as configurações.");
            return false;
        }

        const idInst = instId || document.getElementById("selInstituicaoLimite")?.value;
        const idCat = catId || document.getElementById("selCategoriaLimite")?.value;
        const valorNum = valor != null
            ? parseFloat(valor)
            : parseFloat(document.getElementById("ipt_limite_valor")?.value);

        if (!idInst && !idCat) {
            mostrarAlerta("Selecione uma instituição ou categoria para definir o limite.");
            return false;
        }
        if (!valorNum || valorNum <= 0) {
            mostrarAlerta("Informe um valor de limite válido.");
            return false;
        }

        // Preserva valores atuais para evitar sobrescrita com null no backend
        const payload = {};
        if (cfgData?.inicioMesFiscal != null) payload.inicioMesFiscal = cfgData.inicioMesFiscal;
        if (cfgData?.limiteDesejadoMensal != null) payload.limiteDesejadoMensal = cfgData.limiteDesejadoMensal;
        if (idInst) payload.limitesInstituicao = [{ instituicaoId: parseInt(idInst), valor: valorNum }];
        if (idCat) payload.limitesCategoria = [{ categoriaId: parseInt(idCat), valor: valorNum }];

        try {
            const res = await putJson(`${API}/configuracoes/edit/${cfgId}`, payload);
            if (res.ok) {
                await carregarConfig();
                mostrarAlerta("Limite salvo!");
                return true;
            } else {
                const body = await res.json().catch(() => ({}));
                mostrarAlerta(`Erro ao salvar limite (HTTP ${res.status}): ${body.message || ""}`);
                return false;
            }
        } catch (e) {
            mostrarAlerta("Erro ao salvar limite.");
            console.error(e);
            return false;
        }
    };

    window.abrirModalLimite = function (tipo) {
        limiteModalTipo = tipo;
        const modal = document.getElementById("modalLimite");
        const titulo = document.getElementById("modalLimiteTitulo");
        const label = document.getElementById("lblLimiteItem");
        const sel = document.getElementById("selLimiteItem");
        const inputValor = document.getElementById("ipt_limite_modal_valor");
        if (!modal || !titulo || !label || !sel || !inputValor) return;

        sel.innerHTML = `<option value="" disabled selected></option>`;

        if (tipo === "instituicao") {
            titulo.textContent = "Definir limite por instituição";
            label.textContent = "Selecionar instituição";
            instituicoes.forEach(inst => {
                const opt = document.createElement("option");
                opt.value = inst.intituicao.id;
                opt.textContent = inst.intituicao.nome;
                sel.appendChild(opt);
            });
        } else {
            titulo.textContent = "Definir limite por categoria";
            label.textContent = "Selecionar categoria";
            categorias.forEach(cat => {
                const opt = document.createElement("option");
                opt.value = cat.categoria.id;
                opt.textContent = cat.categoria.titulo;
                sel.appendChild(opt);
            });
        }

        inputValor.value = "";
        modal.style.display = "flex";
    };

    window.fecharModalLimite = function () {
        const modal = document.getElementById("modalLimite");
        if (modal) modal.style.display = "none";
        limiteModalTipo = null;
    };

    window.salvarLimiteModal = async function () {
        const sel = document.getElementById("selLimiteItem");
        const valor = document.getElementById("ipt_limite_modal_valor");
        const idSelecionado = sel?.value;
        const valorSelecionado = valor?.value;

        if (!limiteModalTipo) {
            mostrarAlerta("Tipo de limite inválido.");
            return;
        }

        if (!idSelecionado) {
            mostrarAlerta("Selecione um item para limitar.");
            return;
        }

        const ok = await window.salvarLimite({
            instId: limiteModalTipo === "instituicao" ? idSelecionado : null,
            catId: limiteModalTipo === "categoria" ? idSelecionado : null,
            valor: valorSelecionado
        });

        if (ok) window.fecharModalLimite();
    };

    // ── INSTITUIÇÕES ──────────────────────────────────────────────
    async function carregarInstituicoes() {
        try {
            instituicoes = await fetchTodasPaginasCfg(`${API}/instituicoes/usuarios/${userId}`);
            renderInstituicoes();
            preencherSelectInstituicoes();
            await preencherSelectNovaInstituicao();
        } catch (e) {
            console.error("Erro ao carregar instituições:", e);
        }
    }

    function renderInstituicoes() {
        const tbody = document.getElementById("corpoInstituicoes");
        if (!tbody) return;
        tbody.innerHTML = "";
        if (instituicoes.length === 0) {
            const tr = document.createElement("tr");
            tr.className = "cfg-table-empty";
            const td = document.createElement("td");
            td.colSpan = 3;
            td.style.padding = "20px";
            td.textContent = "Nenhuma instituição cadastrada.";
            tr.appendChild(td);
            tbody.appendChild(tr);
            return;
        }
        instituicoes.forEach(inst => {
            const tr = document.createElement("tr");

            const tdNome = document.createElement("td");
            tdNome.textContent = inst.intituicao.nome;
            tr.appendChild(tdNome);

            const tdMod = document.createElement("td");
            tdMod.textContent = formatarLocalDateTime(inst.ultimaAtualizacao);
            tr.appendChild(tdMod);

            const tdAcoes = document.createElement("td");
            const btn = document.createElement("button");
            btn.className = "cfg-btn danger";
            btn.textContent = "Desvincular";
            btn.addEventListener("click", async () => 
                mostrarConfirmacao("Remover esta instituição do seu perfil?", async () => {
                try {
                    const res = await fetch(`${API}/instituicoes/${inst.intituicao.id}/usuarios/${userId}`, { method: "PATCH" });
                    if (!res.ok) { mostrarAlerta(`Erro ao desvincular (HTTP ${res.status}).`); return; }
                    await carregarInstituicoes();
                } catch (e) {
                    mostrarAlerta("Erro ao desvincular instituição.");
                    console.error(e);
                }
            }));
            tdAcoes.appendChild(btn);
            tr.appendChild(tdAcoes);

            tbody.appendChild(tr);
        });
    }

    function preencherSelectInstituicoes() {
        const sel = document.getElementById("selInstituicaoLimite");
        if (!sel) return;
        sel.innerHTML = `<option value="" disabled selected></option>`;
        instituicoes.forEach(inst => {
            const opt = document.createElement("option");
            opt.value = inst.intituicao.id;
            opt.textContent = inst.intituicao.nome;
            sel.appendChild(opt);
        });
    }

    window.adicionarInstituicao = async function () {
        const sel = document.getElementById("sel_nova_instituicao");
        const instId = sel?.value;
        if (!instId) { mostrarAlerta("Selecione uma instituição."); return; }
        try {
            const res = await fetch(`${API}/instituicoes/${instId}/usuarios/${userId}`, { method: "POST" });
            if (!res.ok) { mostrarAlerta(`Erro ao adicionar instituição (HTTP ${res.status}).`); return; }
            sel.value = "";
            await carregarInstituicoes();
        } catch (e) {
            mostrarAlerta("Erro ao adicionar instituição.");
            console.error(e);
        }
    };

    async function preencherSelectNovaInstituicao() {
        const sel = document.getElementById("sel_nova_instituicao");
        if (!sel) return;
        try {
            const todas = await fetchTodasPaginasCfg(`${API}/instituicoes`);
            const vinculadasIds = new Set(instituicoes.map(i => i.intituicao && i.intituicao.id));
            const disponiveis = todas.filter(i => !vinculadasIds.has(i.id));
            sel.innerHTML = `<option value="" disabled selected></option>`;
            disponiveis.forEach(inst => {
                const opt = document.createElement("option");
                opt.value = inst.id;
                opt.textContent = inst.nome;
                sel.appendChild(opt);
            });
        } catch (e) {
            console.error("Erro ao carregar instituições disponíveis:", e);
        }
    }



