    window.adicionarCategoria = async function () {
        const sel = document.getElementById("sel_nova_categoria");
        const catId = sel?.value;
        if (!catId) { mostrarAlerta("Selecione uma categoria."); return; }
        try {
            const res = await fetch(`${API}/categorias/${catId}/usuarios/${userId}`, { method: "POST" });
            if (!res.ok) { mostrarAlerta(`Erro ao adicionar categoria (HTTP ${res.status}).`); return; }
            sel.value = "";
            await carregarCategorias();
            window.dispatchEvent(new Event('xp:refresh'));
            mostrarAlerta("Categoria adicionada com sucesso!");
        } catch (e) {
            mostrarAlerta("Erro ao adicionar categoria.");
            console.error(e);
        }
    };

    window.abrirPersonalizada = function (tipo) {
        tipoPersonalizada = tipo;
        const modal  = document.getElementById("modalPersonalizada");
        const titulo = document.getElementById("modalPersonalizadaTitulo");
        const label  = document.getElementById("modalPersonalizadaLabel");
        const input  = document.getElementById("ipt_personalizada");
        if (tipo === "instituicao") {
            if (titulo) titulo.textContent = "Nova Instituição Personalizada";
            if (label)  label.textContent  = "Nome da instituição";
        } else {
            if (titulo) titulo.textContent = "Nova Categoria Personalizada";
            if (label)  label.textContent  = "Nome da categoria";
        }
        if (input) input.value = "";
        if (modal) modal.style.display = "flex";
    };

    window.fecharPersonalizada = function () {
        const modal = document.getElementById("modalPersonalizada");
        if (modal) modal.style.display = "none";
        tipoPersonalizada = null;
    };

    window.salvarPersonalizada = async function () {
        const input = document.getElementById("ipt_personalizada");
        const nome = input?.value?.trim();
        if (!nome) { mostrarAlerta("Informe o nome."); return; }
        try {
            if (tipoPersonalizada === "instituicao") {
                const resCreate = await postJson(`${API}/instituicoes`, { nome });
                if (!resCreate.ok) { mostrarAlerta("Erro ao criar instituição."); return; }
                const nova = await resCreate.json();
                const resLink = await fetch(`${API}/instituicoes/${nova.id}/usuarios/${userId}`, { method: "POST" });
                if (!resLink.ok) { mostrarAlerta("Erro ao vincular instituição."); return; }
                fecharPersonalizada();
                await carregarInstituicoes();
                window.dispatchEvent(new Event('xp:refresh'));
                mostrarAlerta("Instituição criada e vinculada com sucesso!");
            } else {
                const res = await postJson(`${API}/categorias/usuario/${userId}`, { titulo: nome });
                if (!res.ok) { mostrarAlerta("Erro ao criar categoria."); return; }
                fecharPersonalizada();
                await carregarCategorias();
                window.dispatchEvent(new Event('xp:refresh'));
                mostrarAlerta("Categoria personalizada criada com sucesso!");
            }
        } catch (e) {
            mostrarAlerta("Erro ao salvar.");
            console.error(e);
        }
    };

    window.removerCategoria = async function (catId) {
        try {
            await fetch(`${API}/categorias/${catId}/usuarios/${userId}`, { method: "PATCH" });
            await carregarCategorias();
        } catch (e) {
            mostrarAlerta("Erro ao remover categoria.");
            console.error(e);
        }
    };

    // ── IMPORTAR DADOS ────────────────────────────────────────────
    function garantirModalImportacao() {
        let modal = document.getElementById("cfgImportModal");
        if (modal) return modal;

        modal = document.createElement("div");
        modal.id = "cfgImportModal";
        // Estilo inline completo para garantir funcionamento em JavaFX WebView
        modal.style.cssText = [
            "display:none",
            "position:fixed",
            "inset:0",
            "background:rgba(0,0,0,0.55)",
            "z-index:9999",
            "align-items:center",
            "justify-content:center",
            "padding:16px"
        ].join(";");

        modal.innerHTML = `
            <div style="background:var(--cor-fundo-card,#FAFFFF);border-radius:20px;padding:28px 24px;
                        width:min(480px,94vw);display:flex;flex-direction:column;gap:16px;
                        box-shadow:0 8px 32px rgba(0,0,0,0.3);">
                <div style="display:flex;justify-content:space-between;align-items:center;">
                    <h2 style="margin:0;color:var(--cor-titulo,#004C58);font-size:1.4rem;">Importar dados</h2>
                    <button id="cfgImportFechar" style="background:none;border:1px solid #9cc9c9;border-radius:8px;
                            width:36px;height:36px;font-size:1.5rem;cursor:pointer;color:var(--cor-principal,#367373);
                            display:flex;align-items:center;justify-content:center;padding:0;margin:0;">&times;</button>
                </div>
                <p style="margin:0;color:var(--cor-texto-secundario,#4A4A4A);font-size:0.9rem;">
                    Selecione a instituição financeira e o arquivo exportado pelo banco.
                </p>

                <div style="position:relative;margin:4px 0;">
                    <select id="cfgImportBanco" style="height:52px;width:100%;border:2px solid var(--cor-principal,#367373);
                            border-radius:10px;padding:0 18px;font-size:1rem;font-weight:600;
                            color:var(--cor-principal,#367373);background:transparent;appearance:none;outline:none;">
                        <option value="" disabled selected>Selecione a instituição</option>
                    </select>
                    <span style="position:absolute;right:14px;top:50%;transform:translateY(-50%);
                                 color:var(--cor-principal,#367373);pointer-events:none;">▾</span>
                </div>

                <div style="border:2px dashed var(--cor-principal,#367373);border-radius:10px;
                            padding:16px;text-align:center;cursor:pointer;" id="cfgImportDropArea">
                    <p style="margin:0 0 8px;color:var(--cor-principal,#367373);font-weight:600;">
                        Clique para selecionar o arquivo
                    </p>
                    <p style="margin:0;font-size:0.8rem;color:var(--cor-texto-secundario,#4A4A4A);">
                        Formatos aceitos: .csv, .ofx, .xls, .xlsx, .json, .sql
                    </p>
                    <input type="file" id="cfgImportArquivo"
                           accept=".csv,.ofx,.qfx,.xls,.xlsx,.json,.sql,.pdf"
                           style="display:none;">
                    <p id="cfgImportNomeArquivo" style="margin:8px 0 0;font-size:0.85rem;
                       color:var(--cor-principal,#367373);font-weight:600;"></p>
                </div>

                <p id="cfgImportMsg" style="color:#e53e3e;font-size:0.85rem;display:none;margin:0;"></p>

                <div style="display:flex;gap:10px;justify-content:flex-end;flex-wrap:wrap;">
                    <button id="cfgImportCancelar"
                        style="height:44px;padding:0 20px;background:transparent;
                               border:2px solid var(--cor-principal,#367373);color:var(--cor-principal,#367373);
                               border-radius:10px;font-size:1rem;cursor:pointer;margin:0;">
                        Cancelar
                    </button>
                    <button id="cfgImportConfirmar"
                        style="height:44px;padding:0 20px;background:var(--cor-principal,#367373);
                               color:#fff;border:none;border-radius:10px;font-size:1rem;cursor:pointer;margin:0;">
                        Importar
                    </button>
                </div>
            </div>
        `;

        document.body.appendChild(modal);

        const fechar = () => { modal.style.display = "none"; };
        modal.querySelector("#cfgImportFechar").onclick = fechar;
        modal.querySelector("#cfgImportCancelar").onclick = fechar;
        modal.addEventListener("click", e => { if (e.target === modal) fechar(); });

        // Área de drop / clique para selecionar arquivo
        const dropArea = modal.querySelector("#cfgImportDropArea");
        const inputArq = modal.querySelector("#cfgImportArquivo");
        const nomeLabel = modal.querySelector("#cfgImportNomeArquivo");

        dropArea.addEventListener("click", () => inputArq.click());

        inputArq.addEventListener("change", () => {
            const f = inputArq.files && inputArq.files[0];
            nomeLabel.textContent = f ? `Arquivo selecionado: ${f.name}` : "";
        });

        modal.querySelector("#cfgImportConfirmar").onclick = async () => {
            const selBanco = modal.querySelector("#cfgImportBanco");
            const msg = modal.querySelector("#cfgImportMsg");
            const btn = modal.querySelector("#cfgImportConfirmar");

            const bancoId = selBanco ? selBanco.value : "";
            // O backend espera o NOME da instituição, não o ID
            const bancoNome = selBanco && selBanco.selectedIndex >= 0
                ? selBanco.options[selBanco.selectedIndex].textContent.trim()
                : "";
            const arquivo = inputArq && inputArq.files && inputArq.files[0];

            if (!bancoId) {
                msg.textContent = "Selecione uma instituição financeira.";
                msg.style.display = "";
                return;
            }
            if (!arquivo) {
                msg.textContent = "Selecione um arquivo para importar.";
                msg.style.display = "";
                return;
            }

            msg.style.display = "none";
            btn.disabled = true;
            btn.textContent = "Importando...";
            btn.style.opacity = "0.7";

            try {
                const formData = new FormData();
                // O backend espera: @RequestParam MultipartFile arquivo
                //                   @RequestParam(required = false) String bancoNome
                formData.append("arquivo", arquivo);
                if (bancoNome) formData.append("bancoNome", bancoNome);

                const res = await fetch(`${API}/configuracoes/upload-arquivo/usuarios/${userId}`, {
                    method: "POST",
                    body: formData
                });

                if (res.ok || res.status === 204) {
                    fechar();
                    mostrarAlerta("Dados importados com sucesso!");
                } else {
                    let detalhe = `HTTP ${res.status}`;
                    try { const corpo = await res.json(); detalhe = corpo.message || detalhe; } catch (_) {}
                    msg.textContent = `Erro ao importar: ${detalhe}`;
                    msg.style.display = "";
                }
            } catch (e) {
                console.error("Erro ao importar dados:", e);
                msg.textContent = "Erro de conexão ao importar. Verifique se o servidor está ativo.";
                msg.style.display = "";
            } finally {
                btn.disabled = false;
                btn.textContent = "Importar";
                btn.style.opacity = "1";
            }
        };

        return modal;
    }

    window.importarDados = function () {
        if (!userId) { mostrarAlerta("Usuário não identificado."); return; }

        const modal = garantirModalImportacao();
        const selBanco = modal.querySelector("#cfgImportBanco");
        const inputArq = modal.querySelector("#cfgImportArquivo");
        const nomeLabel = modal.querySelector("#cfgImportNomeArquivo");
        const msg = modal.querySelector("#cfgImportMsg");

        // Atualiza lista de instituições sempre que abrir
        if (selBanco) {
            selBanco.innerHTML = `<option value="" disabled selected>Selecione a instituição</option>`;
            (instituicoes || []).forEach(inst => {
                const opt = document.createElement("option");
                opt.value = inst.id;
                opt.textContent = (inst.intituicao && inst.intituicao.nome) ? inst.intituicao.nome : "Instituição";
                selBanco.appendChild(opt);
            });
        }
        if (inputArq) inputArq.value = "";
        if (nomeLabel) nomeLabel.textContent = "";
        if (msg) msg.style.display = "none";

        modal.style.display = "flex";
    };

    window.processarImportacao = function () {
        // Mantido por compatibilidade – fluxo agora via modal
    };

    function obterFormatosExportacaoDisponiveis() {
        return [
            { tipo: "pdf", label: "PDF (.pdf)" },
            { tipo: "excel", label: "Excel (.xlsx)" },
            { tipo: "json", label: "JSON (.json)" },
            { tipo: "sql", label: "SQL (.sql)" }
        ];
    }

    function garantirModalExportacao() {
        let modal = document.getElementById("cfgExportModal");
        if (modal) return modal;

        modal = document.createElement("div");
        modal.id = "cfgExportModal";
        modal.className = "modal";
        modal.style.display = "none";
        modal.innerHTML = `
            <div class="conteudoModal" style="max-width:460px;">
                <span id="cfgExportFechar" class="fechar" style="cursor:pointer;">&times;</span>
                <h2 style="margin-top:0; color:#0e5454;">Exportar dados</h2>
                <p style="margin:0 0 12px 0; color:#486468;">Selecione o formato do arquivo:</p>
                <div style="display:flex; flex-direction:column; gap:10px;">
                    <select id="cfgExportTipo" class="select_modal"></select>
                    <div style="display:flex; gap:10px; justify-content:flex-end;">
                        <button id="cfgExportCancelar" class="cfg-btn" style="background:transparent;border:2px solid var(--cor-principal);color:var(--cor-principal);">Cancelar</button>
                        <button id="cfgExportConfirmar" class="cfg-btn">Exportar</button>
                    </div>
                </div>
            </div>
        `;

        document.body.appendChild(modal);

        const fechar = () => { modal.style.display = "none"; };
        const btnFechar = document.getElementById("cfgExportFechar");
        const btnCancelar = document.getElementById("cfgExportCancelar");
        if (btnFechar) btnFechar.onclick = fechar;
        if (btnCancelar) btnCancelar.onclick = fechar;

        modal.addEventListener("click", (event) => {
            if (event.target === modal) {
                fechar();
            }
        });

        const btnConfirmar = document.getElementById("cfgExportConfirmar");
        if (btnConfirmar) {
            btnConfirmar.onclick = async () => {
                const select = document.getElementById("cfgExportTipo");
                const tipo = select?.value;
                if (!tipo) {
                    mostrarAlerta("Selecione um formato para exportação.");
                    return;
                }
                modal.style.display = "none";
                await exportarDadosPorTipo(tipo);
            };
        }

        return modal;
    }

    function abrirModalExportacao() {
        const modal = garantirModalExportacao();
        const select = document.getElementById("cfgExportTipo");
        if (!select) return;

        const formatos = obterFormatosExportacaoDisponiveis();
        select.innerHTML = formatos
            .map(f => `<option value="${f.tipo}">${f.label}</option>`)
            .join("");

        modal.style.display = "flex";
    }

    async function aguardarDesktopBridge(timeoutMs = 1800, intervaloMs = 120) {
        const inicio = Date.now();
        while (Date.now() - inicio < timeoutMs) {
            if (window.desktopBridge) {
                return window.desktopBridge;
            }
            await new Promise(resolve => setTimeout(resolve, intervaloMs));
        }
        return window.desktopBridge || null;
    }

    // ── MODAL DE DOWNLOAD MANUAL (fallback para JavaFX) ──────────
    function mostrarModalDownload(url, nome, tipo) {
        const anterior = document.getElementById("cfgModalDownload");
        if (anterior) anterior.remove();

        const modal = document.createElement("div");
        modal.id = "cfgModalDownload";
        modal.style.cssText = [
            "position:fixed", "inset:0", "background:rgba(0,0,0,0.55)",
            "z-index:9999", "display:flex", "align-items:center",
            "justify-content:center", "padding:16px"
        ].join(";");

        modal.innerHTML = `
            <div style="background:var(--cor-fundo-card,#FAFFFF);border-radius:20px;padding:28px 24px;
                        width:min(520px,96vw);display:flex;flex-direction:column;gap:16px;
                        box-shadow:0 8px 32px rgba(0,0,0,0.3);">
                <div style="display:flex;align-items:center;gap:10px;">
                    <i class='bx bx-download' style="font-size:1.8rem;color:var(--cor-principal,#367373);"></i>
                    <h3 style="margin:0;color:var(--cor-titulo,#004C58);font-size:1.3rem;">
                        Exportar ${tipo.toUpperCase()}
                    </h3>
                </div>

                <p style="margin:0;font-size:0.9rem;color:var(--cor-texto-secundario,#4A4A4A);line-height:1.5;">
                    Clique em <strong>"Baixar arquivo"</strong> para iniciar o download.
                    Se não funcionar automaticamente, copie o link e abra no navegador do sistema.
                </p>

                <div style="background:var(--cor-fundo-pagina,#EBF4F4);border-radius:10px;padding:10px 14px;
                            word-break:break-all;font-size:0.78rem;font-family:monospace;
                            color:var(--cor-texto-principal,#1A1A1A);border:1px solid var(--cor-hover,#B4D9D5);">
                    ${url}
                </div>

                <div style="display:flex;gap:10px;flex-wrap:wrap;">
                    <button id="cfgDlBaixar"
                        style="flex:2;min-width:140px;height:46px;background:var(--cor-principal,#367373);
                               color:#fff;border:none;border-radius:10px;font-size:0.95rem;
                               cursor:pointer;font-weight:600;margin:0;display:flex;
                               align-items:center;justify-content:center;gap:6px;">
                        <i class='bx bx-download'></i> Baixar arquivo
                    </button>
                    <button id="cfgDlCopiar"
                        style="flex:1;min-width:110px;height:46px;background:transparent;
                               color:var(--cor-principal,#367373);border:2px solid var(--cor-principal,#367373);
                               border-radius:10px;font-size:0.95rem;cursor:pointer;margin:0;">
                        Copiar link
                    </button>
                    <button id="cfgDlFechar"
                        style="height:46px;padding:0 14px;background:transparent;color:#888;
                               border:1px solid #ccc;border-radius:10px;font-size:0.9rem;
                               cursor:pointer;margin:0;">
                        Fechar
                    </button>
                </div>

                <p style="margin:0;font-size:0.78rem;color:#888;line-height:1.4;">
                     <em>Dica IntelliJ/JavaFX:</em> se o download não abrir automaticamente,
                    copie o link acima e cole em um navegador (Chrome, Firefox etc.).
                </p>
            </div>
        `;

        document.body.appendChild(modal);

        const fechar = () => modal.remove();
        modal.querySelector("#cfgDlFechar").onclick = fechar;
        modal.addEventListener("click", e => { if (e.target === modal) fechar(); });

        // Botão COPIAR
        modal.querySelector("#cfgDlCopiar").onclick = function () {
            const btn = this;
            const copiar = () => {
                const ta = document.createElement("textarea");
                ta.value = url;
                ta.style.cssText = "position:fixed;top:-9999px;left:-9999px;";
                document.body.appendChild(ta);
                ta.focus();
                ta.select();
                try { document.execCommand("copy"); } catch (_) {}
                ta.remove();
            };
            if (navigator.clipboard && navigator.clipboard.writeText) {
                navigator.clipboard.writeText(url).catch(copiar);
            } else {
                copiar();
            }
            btn.textContent = "✓ Copiado!";
            setTimeout(() => { btn.textContent = "Copiar link"; }, 2000);
        };

        // Botão BAIXAR — tenta todos os métodos disponíveis
        modal.querySelector("#cfgDlBaixar").onclick = function () {
            const btn = this;
            btn.textContent = "Iniciando...";
            btn.disabled = true;

            // Método 1: window.location.href (JavaFX WebEngine: pode disparar download handler)
            // Usamos um timeout para não travar a UI
            setTimeout(() => {
                try { window.open(url, "_blank"); } catch (_) {}
            }, 0);

            setTimeout(() => {
                // Método 2: a.click() direto na URL (sem blob)
                const a = document.createElement("a");
                a.href = url;
                a.download = nome;
                a.style.display = "none";
                document.body.appendChild(a);
                a.click();
                a.remove();
            }, 150);

            setTimeout(() => {
                // Método 3: navigate (pode ser interceptado pelo loadWorker do JavaFX)
                window.location.href = url;
            }, 500);

            setTimeout(() => {
                btn.disabled = false;
                btn.innerHTML = "<i class='bx bx-download'></i> Baixar arquivo";
            }, 3000);
        };
    }

    async function exportarDadosPorTipo(tipo) {
        if (!userId) {
            mostrarAlerta("Usuário não identificado para exportação.");
            return;
        }

        const ext = tipo === "excel" ? "xlsx" : tipo;
        let nomeArquivo = `registros.${ext}`;
        const downloadUrl = `${API}/registros/download/${userId}?tipo=${encodeURIComponent(tipo)}`;

        // 1. desktopBridge (JavaFX bridge nativo — se disponível)
        const bridge = await aguardarDesktopBridge(2000);
        if (bridge) {
            try {
                const res = await fetch(downloadUrl);
                if (!res.ok) { mostrarAlerta(`Erro ao exportar (HTTP ${res.status}).`); return; }
                const blob = await res.blob();
                const cd = res.headers.get("content-disposition") || "";
                const m = cd.match(/filename=([^;]+)/i);
                if (m && m[1]) nomeArquivo = m[1].replace(/"/g, "").trim();

                const bytes = new Uint8Array(await blob.arrayBuffer());
                let binario = "";
                for (let i = 0; i < bytes.length; i += 0x8000) {
                    binario += String.fromCharCode(...bytes.subarray(i, i + 0x8000));
                }
                const salvo = bridge.saveBase64File(nomeArquivo, btoa(binario));
                if (salvo) { mostrarAlerta(`${tipo.toUpperCase()} exportado com sucesso!`); return; }
            } catch (bridgeErr) {
                console.warn("desktopBridge falhou:", bridgeErr);
            }
        }

        // 2. Verifica se o endpoint responde
        try {
            const check = await fetch(downloadUrl, { method: "HEAD" });
            if (!check.ok) {
                mostrarAlerta(`Servidor retornou erro ao gerar o arquivo (HTTP ${check.status}).`);
                return;
            }
        } catch (e) {
            console.warn("HEAD check falhou:", e);
        }

        // 3. Busca conteúdo e tenta abordagens JavaScript
        let blob = null;
        try {
            const res = await fetch(downloadUrl);
            if (res.ok) {
                blob = await res.blob();
                const cd = res.headers.get("content-disposition") || "";
                const m = cd.match(/filename=([^;]+)/i);
                if (m && m[1]) nomeArquivo = m[1].replace(/"/g, "").trim();
            }
        } catch (e) {
            console.warn("Fetch do blob falhou:", e);
        }

        if (blob) {
            // 3a. Blob URL (funciona em browsers normais)
            try {
                const blobUrl = URL.createObjectURL(blob);
                const a = document.createElement("a");
                a.href = blobUrl;
                a.download = nomeArquivo;
                a.style.display = "none";
                document.body.appendChild(a);
                a.click();
                a.remove();
                setTimeout(() => URL.revokeObjectURL(blobUrl), 60000);
            } catch (e) { console.warn("Blob URL:", e); }

            // 3b. Data URI (às vezes funciona em JavaFX quando blob URL falha)
            try {
                const arrayBuffer = await blob.arrayBuffer();
                const bytes = new Uint8Array(arrayBuffer);
                let binary = "";
                for (let i = 0; i < bytes.length; i += 0x8000) {
                    binary += String.fromCharCode(...bytes.subarray(i, i + 0x8000));
                }
                const base64 = btoa(binary);
                const mimeType = blob.type || "application/octet-stream";
                const dataUri = `data:${mimeType};base64,${base64}`;

                const a2 = document.createElement("a");
                a2.href = dataUri;
                a2.download = nomeArquivo;
                a2.style.display = "none";
                document.body.appendChild(a2);
                a2.click();
                a2.remove();
            } catch (e) { console.warn("Data URI:", e); }
        }

        // 4. Em JavaFX: iframe (WebEngine pode acionar loadWorker → download handler)
        setTimeout(() => {
            try {
                const ifr = document.createElement("iframe");
                ifr.style.cssText = "display:none;width:0;height:0;border:0;";
                ifr.src = downloadUrl;
                document.body.appendChild(ifr);
                setTimeout(() => { try { document.body.removeChild(ifr); } catch (_) {} }, 60000);
            } catch (e) { console.warn("Iframe:", e); }
        }, 300);

        // 5. Mostra modal com link direto + botões (fallback confiável para JavaFX)
        setTimeout(() => {
            mostrarModalDownload(downloadUrl, nomeArquivo, tipo);
        }, 800);
    }

    window.exportarDados = function () {
        abrirModalExportacao();
    };


    // ── CALENDÁRIO – SELEÇÃO DE PERÍODO PARA EXCLUSÃO ────────────
    let cfgCalCampo = null;        // 'inicio' | 'fim'
    let cfgCalDataSelecionada = null;
    let cfgDeleteInicio = null;    // YYYY-MM-DD
    let cfgDeleteFim    = null;    // YYYY-MM-DD

    let cfgCalMesAtual  = new Date().getMonth();
    let cfgCalAnoAtual  = new Date().getFullYear();

    function cfgCalFormatar(iso) {
        const [a, m, d] = iso.split("-");
        return `${d}/${m}/${a}`;
    }

    function cfgCalGerar() {
        const dias    = document.getElementById("cfgCalDias");
        const mesAno  = document.getElementById("cfgCalMesAno");
        const confirmar = document.getElementById("cfgCalConfirmar");
        if (!dias) return;

        dias.innerHTML = "";
        cfgCalDataSelecionada = null;
        if (confirmar) confirmar.disabled = true;

        mesAno.innerText = new Date(cfgCalAnoAtual, cfgCalMesAtual)
            .toLocaleString("pt-BR", { month: "long", year: "numeric" });

        const primeiroDia = new Date(cfgCalAnoAtual, cfgCalMesAtual, 1).getDay();
        const totalDias   = new Date(cfgCalAnoAtual, cfgCalMesAtual + 1, 0).getDate();

        for (let i = 0; i < primeiroDia; i++) dias.innerHTML += `<span></span>`;

        for (let dia = 1; dia <= totalDias; dia++) {
            const iso = `${cfgCalAnoAtual}-${String(cfgCalMesAtual + 1).padStart(2, "0")}-${String(dia).padStart(2, "0")}`;
            const span = document.createElement("span");
            span.innerText = dia;
            span.onclick = () => {
                dias.querySelectorAll(".diaSelecionado").forEach(e => e.classList.remove("diaSelecionado"));
                span.classList.add("diaSelecionado");
                cfgCalDataSelecionada = iso;
                if (confirmar) confirmar.disabled = false;
            };
            dias.appendChild(span);
        }
    }

    window.abrirCalendarioDelete = function (campo) {
        cfgCalCampo = campo;
        cfgCalMesAtual = new Date().getMonth();
        cfgCalAnoAtual = new Date().getFullYear();
        const modal = document.getElementById("cfgCalModal");
        if (modal) { modal.style.display = "flex"; cfgCalGerar(); }
    };

    document.addEventListener("DOMContentLoaded", () => {
        const fechar    = document.getElementById("cfgCalFechar");
        const anterior  = document.getElementById("cfgCalAnterior");
        const proximo   = document.getElementById("cfgCalProximo");
        const confirmar = document.getElementById("cfgCalConfirmar");
        const modal     = document.getElementById("cfgCalModal");

        if (fechar)    fechar.onclick   = () => { if (modal) modal.style.display = "none"; };
        if (anterior)  anterior.onclick = () => {
            cfgCalMesAtual--;
            if (cfgCalMesAtual < 0) { cfgCalMesAtual = 11; cfgCalAnoAtual--; }
            cfgCalGerar();
        };
        if (proximo)   proximo.onclick  = () => {
            cfgCalMesAtual++;
            if (cfgCalMesAtual > 11) { cfgCalMesAtual = 0; cfgCalAnoAtual++; }
            cfgCalGerar();
        };
        if (confirmar) confirmar.onclick = () => {
            if (!cfgCalDataSelecionada) return;
            if (cfgCalCampo === "inicio") {
                cfgDeleteInicio = cfgCalDataSelecionada;
                const lbl = document.getElementById("cfgDeleteInicioLabel");
                if (lbl) lbl.textContent = cfgCalFormatar(cfgDeleteInicio);
            } else {
                cfgDeleteFim = cfgCalDataSelecionada;
                const lbl = document.getElementById("cfgDeleteFimLabel");
                if (lbl) lbl.textContent = cfgCalFormatar(cfgDeleteFim);
            }
            if (modal) modal.style.display = "none";
        };
    });

    // ── APAGAR REGISTROS ─────────────────────────────────────────
    window.apagarRegistrosPeriodo = function () {
        if (!cfgDeleteInicio || !cfgDeleteFim) {
            mostrarAlerta("Escolha a data inicial e a data final do período.");
            return;
        }
        if (cfgDeleteInicio > cfgDeleteFim) {
            mostrarAlerta("A data inicial não pode ser maior que a data final.");
            return;
        }
        if (!cfgId) {
            mostrarAlerta("Configuração do usuário não carregada.");
            return;
        }

        mostrarConfirmacao(
            `Apagar todos os registros de ${cfgCalFormatar(cfgDeleteInicio)} até ${cfgCalFormatar(cfgDeleteFim)}? Esta ação é irreversível.`,
            async () => {
                try {
                    const res = await fetch(`${API}/configuracoes/${cfgId}/dados/periodo-tempo`, {
                        method: "DELETE",
                        headers: { "Content-Type": "application/json" },
                        body: JSON.stringify({ dataInical: cfgDeleteInicio, dataFinal: cfgDeleteFim })
                    });
                    if (res.status === 204) {
                        mostrarAlerta("Registros do período apagados com sucesso!");
                        cfgDeleteInicio = cfgDeleteFim = null;
                        const lI = document.getElementById("cfgDeleteInicioLabel");
                        const lF = document.getElementById("cfgDeleteFimLabel");
                        if (lI) lI.textContent = "";
                        if (lF) lF.textContent = "";
                    } else {
                        const txt = await res.text();
                        mostrarAlerta(`Erro ao apagar registros (HTTP ${res.status}): ${txt}`);
                    }
                } catch (e) {
                    console.error("Erro ao apagar registros por período:", e);
                    mostrarAlerta("Erro ao apagar registros do período.");
                }
            }
        );
    };

    window.apagarTodosRegistros = function () {
        if (!userId) {
            mostrarAlerta("Usuário não identificado.");
            return;
        }

        mostrarConfirmacao(
            "Apagar TODOS os registros do usuário? Esta ação é irreversível.",
            async () => {
                try {
                    const res = await fetch(`${API}/configuracoes/usuarios/${userId}/dados/deletar-tudo`, {
                        method: "DELETE"
                    });
                    if (res.status === 204) {
                        mostrarAlerta("Todos os registros foram apagados com sucesso!");
                    } else {
                        const txt = await res.text();
                        mostrarAlerta(`Erro ao apagar registros (HTTP ${res.status}): ${txt}`);
                    }
                } catch (e) {
                    console.error("Erro ao apagar todos os registros:", e);
                    mostrarAlerta("Erro ao apagar todos os registros.");
                }
            }
        );
    };

    if (document.readyState === "loading") {
        document.addEventListener("DOMContentLoaded", init);
    } else {
        init();
    }
})();

package controle.api.back_end.controller;

import controle.api.back_end.dto.poupanca.in.CaixinhaCreateDTO;
import controle.api.back_end.dto.poupanca.out.CaixinhaResponseDTO;
import controle.api.back_end.dto.poupanca.out.GraficoProgressoConsolidadoCaixinhaDto;
import controle.api.back_end.dto.poupanca.out.KpiProgressoGeralCaixinhaDto;
import controle.api.back_end.dto.poupanca.out.KpiRendimentoEstimadoMesCaixinhaDto;
import controle.api.back_end.dto.poupanca.out.KpiStatusCaixinhasDto;
import controle.api.back_end.dto.poupanca.out.KpiTotalAcumuladoCaixinhaDto;
import controle.api.back_end.service.CaixinhaService;
import io.swagger.v3.oas.annotations.Operation;
import io.swagger.v3.oas.annotations.media.Content;
import io.swagger.v3.oas.annotations.media.Schema;
import io.swagger.v3.oas.annotations.responses.ApiResponse;
import io.swagger.v3.oas.annotations.responses.ApiResponses;
import io.swagger.v3.oas.annotations.tags.Tag;
import jakarta.validation.Valid;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.math.BigDecimal;
import java.util.List;
import java.util.UUID;

@CrossOrigin
@RestController
@RequestMapping("/caixinhas")
@Tag(name = "Caixinhas / Poupança",
     description = "Gerenciamento de caixinhas de poupança com metas, rendimentos (CDI/SELIC/Prefixado) " +
                   "e projeções financeiras. Suporta metas simples e compartilhadas entre múltiplas instituições.")
public class CaixinhaController {

    private final CaixinhaService caixinhaService;

    public CaixinhaController(CaixinhaService caixinhaService) {
        this.caixinhaService = caixinhaService;
    }

    // =========================================================================
    // CRIAR
    // =========================================================================

    @PostMapping
    @Operation(summary = "Criar uma nova caixinha",
               description = """
                       Cria uma caixinha de poupança com meta, prazo e rendimento configuráveis.

                       **Tipos de rendimento:**
                       - `CDI` – percentual do CDI (ex.: 100% ou 110%). Informe `taxaReferenciaAtual` (CDI atual em % a.a.) e `percentualRendimento`.
                       - `SELIC` – percentual da SELIC. Informe `taxaReferenciaAtual` e `percentualRendimento`.
                       - `POUPANCA` – rendimento tradicional (70% da SELIC). Informe `taxaReferenciaAtual`.
                       - `PREFIXADO` – taxa fixa anual. Informe `taxaAnualPersonalizada` (ex.: 12.5 para 12,5% a.a.).
                       - `PERSONALIZADO` – taxa definida livremente. Informe `taxaAnualPersonalizada`.

                       **Meta compartilhada:** informe `isCompartilhada=true` e 2 ou mais `instituicaoUsuarioIds`.
                       A API somará os aportes de todas as instituições para calcular o saldo total.
                       """)
    @ApiResponses({
            @ApiResponse(responseCode = "201", description = "Caixinha criada com sucesso.",
                    content = @Content(mediaType = "application/json",
                            schema = @Schema(implementation = CaixinhaResponseDTO.class))),
            @ApiResponse(responseCode = "400", description = "Dados inválidos.", content = @Content),
            @ApiResponse(responseCode = "404", description = "Usuário ou instituição não encontrados.", content = @Content)
    })
    public ResponseEntity<CaixinhaResponseDTO> criar(@Valid @RequestBody CaixinhaCreateDTO dto) {
        return ResponseEntity.status(201).body(caixinhaService.criar(dto));
    }

    // =========================================================================
    // CONSULTAS
    // =========================================================================

    @GetMapping("/usuarios/{user_id}")
    @Operation(summary = "Listar todas as caixinhas do usuário",
               description = "Retorna todas as caixinhas (ativas e encerradas) com saldo atual, " +
                             "projeções e aporte sugerido calculados em tempo real.")
    @ApiResponses({
            @ApiResponse(responseCode = "200", description = "Caixinhas encontradas.",
                    content = @Content(mediaType = "application/json",
                            schema = @Schema(implementation = CaixinhaResponseDTO.class))),
            @ApiResponse(responseCode = "204", description = "Nenhuma caixinha cadastrada.", content = @Content),
            @ApiResponse(responseCode = "404", description = "Usuário não encontrado.", content = @Content)
    })
    public ResponseEntity<List<CaixinhaResponseDTO>> listarPorUsuario(@PathVariable UUID user_id) {
        List<CaixinhaResponseDTO> lista = caixinhaService.listarPorUsuario(user_id);
        return lista.isEmpty() ? ResponseEntity.noContent().build() : ResponseEntity.ok(lista);
    }

    @GetMapping("/ativas/usuarios/{user_id}")
    @Operation(summary = "Listar caixinhas ativas do usuário",
               description = "Retorna apenas as caixinhas em andamento (não encerradas).")
    @ApiResponses({
            @ApiResponse(responseCode = "200", description = "Caixinhas encontradas.",
                    content = @Content(mediaType = "application/json",
                            schema = @Schema(implementation = CaixinhaResponseDTO.class))),
            @ApiResponse(responseCode = "204", description = "Nenhuma caixinha ativa.", content = @Content),
            @ApiResponse(responseCode = "404", description = "Usuário não encontrado.", content = @Content)
    })
    public ResponseEntity<List<CaixinhaResponseDTO>> listarAtivasPorUsuario(@PathVariable UUID user_id) {
        List<CaixinhaResponseDTO> lista = caixinhaService.listarAtivasPorUsuario(user_id);
        return lista.isEmpty() ? ResponseEntity.noContent().build() : ResponseEntity.ok(lista);
    }

    @GetMapping("/{caixinha_id}")
    @Operation(summary = "Buscar uma caixinha por ID",
               description = "Retorna os dados completos de uma caixinha com todos os cálculos atualizados.")
    @ApiResponses({
            @ApiResponse(responseCode = "200", description = "Caixinha encontrada.",
                    content = @Content(mediaType = "application/json",
                            schema = @Schema(implementation = CaixinhaResponseDTO.class))),
            @ApiResponse(responseCode = "404", description = "Caixinha não encontrada.", content = @Content)
    })
    public ResponseEntity<CaixinhaResponseDTO> buscarPorId(@PathVariable UUID caixinha_id) {
        return ResponseEntity.ok(caixinhaService.buscarPorId(caixinha_id));
    }

    @GetMapping("/resumo/usuarios/{user_id}")
    @Operation(summary = "Total acumulado em poupança",
               description = "Soma o saldo atual de todas as caixinhas ativas do usuário. " +
                             "Útil para exibir um número único de 'total guardado' na tela inicial.")
    @ApiResponses({
            @ApiResponse(responseCode = "200", description = "Total calculado.",
                    content = @Content(mediaType = "application/json",
                            schema = @Schema(example = "4750.00"))),
            @ApiResponse(responseCode = "404", description = "Usuário não encontrado.", content = @Content)
    })
    public ResponseEntity<BigDecimal> resumoTotal(@PathVariable UUID user_id) {
        return ResponseEntity.ok(caixinhaService.resumoTotalPoupanca(user_id));
    }

    @GetMapping("/kpi/total-acumulado/usuarios/{user_id}")
    @Operation(summary = "KPI de total acumulado das caixinhas",
            description = "Retorna o total acumulado em todas as caixinhas ativas e a quantidade de caixinhas ativas do usuário.")
    @ApiResponses({
            @ApiResponse(responseCode = "200", description = "KPI calculado com sucesso.",
                    content = @Content(mediaType = "application/json",
                            schema = @Schema(implementation = KpiTotalAcumuladoCaixinhaDto.class))),
            @ApiResponse(responseCode = "404", description = "Usuário não encontrado.", content = @Content)
    })
    public ResponseEntity<KpiTotalAcumuladoCaixinhaDto> obterKpiTotalAcumulado(@PathVariable UUID user_id) {
        return ResponseEntity.ok(caixinhaService.obterKpiTotalAcumulado(user_id));
    }

    @GetMapping("/kpi/progresso-geral/usuarios/{user_id}")
    @Operation(summary = "KPI de progresso geral das caixinhas",
            description = "Retorna total acumulado, total de metas ativas e percentual geral de progresso. Se total de metas for zero, o percentual será zero.")
    @ApiResponses({
            @ApiResponse(responseCode = "200", description = "KPI calculado com sucesso.",
                    content = @Content(mediaType = "application/json",
                            schema = @Schema(implementation = KpiProgressoGeralCaixinhaDto.class))),
            @ApiResponse(responseCode = "404", description = "Usuário não encontrado.", content = @Content)
    })
    public ResponseEntity<KpiProgressoGeralCaixinhaDto> obterKpiProgressoGeral(@PathVariable UUID user_id) {
        return ResponseEntity.ok(caixinhaService.obterKpiProgressoGeral(user_id));
    }

    @GetMapping("/kpi/rendimento-estimado-mes/usuarios/{user_id}")
    @Operation(summary = "KPI de rendimento estimado no mês",
            description = "Retorna a soma do rendimento estimado do mês atual em todas as caixinhas ativas, respeitando o tipo de taxa de cada caixinha.")
    @ApiResponses({
            @ApiResponse(responseCode = "200", description = "KPI calculado com sucesso.",
                    content = @Content(mediaType = "application/json",
                            schema = @Schema(implementation = KpiRendimentoEstimadoMesCaixinhaDto.class))),
            @ApiResponse(responseCode = "404", description = "Usuário não encontrado.", content = @Content)
    })
    public ResponseEntity<KpiRendimentoEstimadoMesCaixinhaDto> obterKpiRendimentoEstimadoMes(@PathVariable UUID user_id) {
        return ResponseEntity.ok(caixinhaService.obterKpiRendimentoEstimadoMes(user_id));
    }

    @GetMapping("/kpi/status/usuarios/{user_id}")
    @Operation(summary = "KPI de status das caixinhas",
            description = "Retorna quantidade de caixinhas ativas e encerradas do usuário.")
    @ApiResponses({
            @ApiResponse(responseCode = "200", description = "KPI calculado com sucesso.",
                    content = @Content(mediaType = "application/json",
                            schema = @Schema(implementation = KpiStatusCaixinhasDto.class))),
            @ApiResponse(responseCode = "404", description = "Usuário não encontrado.", content = @Content)
    })
    public ResponseEntity<KpiStatusCaixinhasDto> obterKpiStatus(@PathVariable UUID user_id) {
        return ResponseEntity.ok(caixinhaService.obterKpiStatusCaixinhas(user_id));
    }

    @GetMapping("/grafico/progresso-consolidado/usuarios/{user_id}")
    @Operation(summary = "Gráfico de progresso consolidado das caixinhas",
            description = "Retorna percentual geral de progresso, total acumulado e total de metas para consumo no gráfico consolidado.")
    @ApiResponses({
            @ApiResponse(responseCode = "200", description = "Dados do gráfico calculados com sucesso.",
                    content = @Content(mediaType = "application/json",
                            schema = @Schema(implementation = GraficoProgressoConsolidadoCaixinhaDto.class))),
            @ApiResponse(responseCode = "404", description = "Usuário não encontrado.", content = @Content)
    })
    public ResponseEntity<GraficoProgressoConsolidadoCaixinhaDto> obterGraficoProgressoConsolidado(@PathVariable UUID user_id) {
        return ResponseEntity.ok(caixinhaService.obterGraficoProgressoConsolidado(user_id));
    }

    // =========================================================================
    // EDITAR
    // =========================================================================

    @PutMapping("/{caixinha_id}")
    @Operation(summary = "Editar uma caixinha",
               description = "Atualiza nome, descrição, meta, prazo e/ou configuração de rendimento. " +
                             "Os aportes já realizados não são afetados.")
    @ApiResponses({
            @ApiResponse(responseCode = "200", description = "Caixinha atualizada.",
                    content = @Content(mediaType = "application/json",
                            schema = @Schema(implementation = CaixinhaResponseDTO.class))),
            @ApiResponse(responseCode = "404", description = "Caixinha não encontrada.", content = @Content)
    })
    public ResponseEntity<CaixinhaResponseDTO> editar(@PathVariable UUID caixinha_id,
                                                       @RequestBody CaixinhaCreateDTO dto) {
        return ResponseEntity.ok(caixinhaService.editar(caixinha_id, dto));
    }

    @PatchMapping("/{caixinha_id}/encerrar")
    @Operation(summary = "Encerrar uma caixinha",
               description = "Marca a caixinha como encerrada (meta atingida ou cancelada pelo usuário). " +
                             "Os dados e histórico de aportes são mantidos.")
    @ApiResponses({
            @ApiResponse(responseCode = "200", description = "Caixinha encerrada.",
                    content = @Content(mediaType = "application/json",
                            schema = @Schema(implementation = CaixinhaResponseDTO.class))),
            @ApiResponse(responseCode = "404", description = "Caixinha não encontrada.", content = @Content)
    })
    public ResponseEntity<CaixinhaResponseDTO> encerrar(@PathVariable UUID caixinha_id) {
        return ResponseEntity.ok(caixinhaService.encerrar(caixinha_id));
    }

    @PostMapping("/{caixinha_id}/instituicoes/{inst_id}")
    @Operation(summary = "Adicionar instituição a uma caixinha compartilhada",
               description = "Vincula uma nova instituição à caixinha, habilitando a meta compartilhada. " +
                             "O saldo total passa a somar os aportes de todas as instituições vinculadas.")
    @ApiResponses({
            @ApiResponse(responseCode = "200", description = "Instituição adicionada.",
                    content = @Content(mediaType = "application/json",
                            schema = @Schema(implementation = CaixinhaResponseDTO.class))),
            @ApiResponse(responseCode = "400", description = "Instituição já vinculada.", content = @Content),
            @ApiResponse(responseCode = "404", description = "Caixinha ou instituição não encontradas.", content = @Content)
    })
    public ResponseEntity<CaixinhaResponseDTO> adicionarInstituicao(@PathVariable UUID caixinha_id,
                                                                      @PathVariable Integer inst_id) {
        return ResponseEntity.ok(caixinhaService.adicionarInstituicao(caixinha_id, inst_id));
    }

    // =========================================================================
    // DELETAR
    // =========================================================================

    @DeleteMapping("/{caixinha_id}")
    @Operation(summary = "Deletar uma caixinha",
               description = "Remove permanentemente a caixinha e seus vínculos com instituições. " +
                             "Os aportes registrados como EventoFinanceiro NÃO são deletados.")
    @ApiResponses({
            @ApiResponse(responseCode = "204", description = "Caixinha deletada.", content = @Content),
            @ApiResponse(responseCode = "404", description = "Caixinha não encontrada.", content = @Content)
    })
    public ResponseEntity<Void> deletar(@PathVariable UUID caixinha_id) {
        caixinhaService.deletar(caixinha_id);
        return ResponseEntity.noContent().build();
    }
}

package controle.api.back_end.controller;

import controle.api.back_end.dto.poupanca.in.CaixinhaCreateDTO;
import controle.api.back_end.dto.poupanca.out.CaixinhaResponseDTO;
import controle.api.back_end.dto.poupanca.out.GraficoProgressoConsolidadoCaixinhaDto;
import controle.api.back_end.dto.poupanca.out.KpiProgressoGeralCaixinhaDto;
import controle.api.back_end.dto.poupanca.out.KpiRendimentoEstimadoMesCaixinhaDto;
import controle.api.back_end.dto.poupanca.out.KpiStatusCaixinhasDto;
import controle.api.back_end.dto.poupanca.out.KpiTotalAcumuladoCaixinhaDto;
import controle.api.back_end.service.CaixinhaService;
import io.swagger.v3.oas.annotations.Operation;
import io.swagger.v3.oas.annotations.media.Content;
import io.swagger.v3.oas.annotations.media.Schema;
import io.swagger.v3.oas.annotations.responses.ApiResponse;
import io.swagger.v3.oas.annotations.responses.ApiResponses;
import io.swagger.v3.oas.annotations.tags.Tag;
import jakarta.validation.Valid;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.math.BigDecimal;
import java.util.List;
import java.util.UUID;

@CrossOrigin
@RestController
@RequestMapping("/caixinhas")
@Tag(name = "Caixinhas / Poupança",
     description = "Gerenciamento de caixinhas de poupança com metas, rendimentos (CDI/SELIC/Prefixado) " +
                   "e projeções financeiras. Suporta metas simples e compartilhadas entre múltiplas instituições.")
public class CaixinhaController {

    private final CaixinhaService caixinhaService;

    public CaixinhaController(CaixinhaService caixinhaService) {
        this.caixinhaService = caixinhaService;
    }

    // =========================================================================
    // CRIAR
    // =========================================================================

    @PostMapping
    @Operation(summary = "Criar uma nova caixinha",
               description = """
                       Cria uma caixinha de poupança com meta, prazo e rendimento configuráveis.
                       
                       **Tipos de rendimento:**
                       - `CDI` – percentual do CDI (ex.: 100% ou 110%). Informe `taxaReferenciaAtual` (CDI atual em % a.a.) e `percentualRendimento`.
                       - `SELIC` – percentual da SELIC. Informe `taxaReferenciaAtual` e `percentualRendimento`.
                       - `POUPANCA` – rendimento tradicional (70% da SELIC). Informe `taxaReferenciaAtual`.
                       - `PREFIXADO` – taxa fixa anual. Informe `taxaAnualPersonalizada` (ex.: 12.5 para 12,5% a.a.).
                       - `PERSONALIZADO` – taxa definida livremente. Informe `taxaAnualPersonalizada`.
                       
                       **Meta compartilhada:** informe `isCompartilhada=true` e 2 ou mais `instituicaoUsuarioIds`.
                       A API somará os aportes de todas as instituições para calcular o saldo total.
                       """)
    @ApiResponses({
            @ApiResponse(responseCode = "201", description = "Caixinha criada com sucesso.",
                    content = @Content(mediaType = "application/json",
                            schema = @Schema(implementation = CaixinhaResponseDTO.class))),
            @ApiResponse(responseCode = "400", description = "Dados inválidos.", content = @Content),
            @ApiResponse(responseCode = "404", description = "Usuário ou instituição não encontrados.", content = @Content)
    })
    public ResponseEntity<CaixinhaResponseDTO> criar(@Valid @RequestBody CaixinhaCreateDTO dto) {
        return ResponseEntity.status(201).body(caixinhaService.criar(dto));
    }

    // =========================================================================
    // CONSULTAS
    // =========================================================================

    @GetMapping("/usuarios/{user_id}")
    @Operation(summary = "Listar todas as caixinhas do usuário",
               description = "Retorna todas as caixinhas (ativas e encerradas) com saldo atual, " +
                             "projeções e aporte sugerido calculados em tempo real.")
    @ApiResponses({
            @ApiResponse(responseCode = "200", description = "Caixinhas encontradas.",
                    content = @Content(mediaType = "application/json",
                            schema = @Schema(implementation = CaixinhaResponseDTO.class))),
            @ApiResponse(responseCode = "204", description = "Nenhuma caixinha cadastrada.", content = @Content),
            @ApiResponse(responseCode = "404", description = "Usuário não encontrado.", content = @Content)
    })
    public ResponseEntity<List<CaixinhaResponseDTO>> listarPorUsuario(@PathVariable UUID user_id) {
        List<CaixinhaResponseDTO> lista = caixinhaService.listarPorUsuario(user_id);
        return lista.isEmpty() ? ResponseEntity.noContent().build() : ResponseEntity.ok(lista);
    }

    @GetMapping("/ativas/usuarios/{user_id}")
    @Operation(summary = "Listar caixinhas ativas do usuário",
               description = "Retorna apenas as caixinhas em andamento (não encerradas).")
    @ApiResponses({
            @ApiResponse(responseCode = "200", description = "Caixinhas encontradas.",
                    content = @Content(mediaType = "application/json",
                            schema = @Schema(implementation = CaixinhaResponseDTO.class))),
            @ApiResponse(responseCode = "204", description = "Nenhuma caixinha ativa.", content = @Content),
            @ApiResponse(responseCode = "404", description = "Usuário não encontrado.", content = @Content)
    })
    public ResponseEntity<List<CaixinhaResponseDTO>> listarAtivasPorUsuario(@PathVariable UUID user_id) {
        List<CaixinhaResponseDTO> lista = caixinhaService.listarAtivasPorUsuario(user_id);
        return lista.isEmpty() ? ResponseEntity.noContent().build() : ResponseEntity.ok(lista);
    }

    @GetMapping("/{caixinha_id}")
    @Operation(summary = "Buscar uma caixinha por ID",
               description = "Retorna os dados completos de uma caixinha com todos os cálculos atualizados.")
    @ApiResponses({
            @ApiResponse(responseCode = "200", description = "Caixinha encontrada.",
                    content = @Content(mediaType = "application/json",
                            schema = @Schema(implementation = CaixinhaResponseDTO.class))),
            @ApiResponse(responseCode = "404", description = "Caixinha não encontrada.", content = @Content)
    })
    public ResponseEntity<CaixinhaResponseDTO> buscarPorId(@PathVariable UUID caixinha_id) {
        return ResponseEntity.ok(caixinhaService.buscarPorId(caixinha_id));
    }

    @GetMapping("/resumo/usuarios/{user_id}")
    @Operation(summary = "Total acumulado em poupança",
               description = "Soma o saldo atual de todas as caixinhas ativas do usuário. " +
                             "Útil para exibir um número único de 'total guardado' na tela inicial.")
    @ApiResponses({
            @ApiResponse(responseCode = "200", description = "Total calculado.",
                    content = @Content(mediaType = "application/json",
                            schema = @Schema(example = "4750.00"))),
            @ApiResponse(responseCode = "404", description = "Usuário não encontrado.", content = @Content)
    })
    public ResponseEntity<BigDecimal> resumoTotal(@PathVariable UUID user_id) {
        return ResponseEntity.ok(caixinhaService.resumoTotalPoupanca(user_id));
    }

    @GetMapping("/kpi/total-acumulado/usuarios/{user_id}")
    @Operation(summary = "KPI de total acumulado das caixinhas",
            description = "Retorna o total acumulado em todas as caixinhas ativas e a quantidade de caixinhas ativas do usuário.")
    @ApiResponses({
            @ApiResponse(responseCode = "200", description = "KPI calculado com sucesso.",
                    content = @Content(mediaType = "application/json",
                            schema = @Schema(implementation = KpiTotalAcumuladoCaixinhaDto.class))),
            @ApiResponse(responseCode = "404", description = "Usuário não encontrado.", content = @Content)
    })
    public ResponseEntity<KpiTotalAcumuladoCaixinhaDto> obterKpiTotalAcumulado(@PathVariable UUID user_id) {
        return ResponseEntity.ok(caixinhaService.obterKpiTotalAcumulado(user_id));
    }

    @GetMapping("/kpi/progresso-geral/usuarios/{user_id}")
    @Operation(summary = "KPI de progresso geral das caixinhas",
            description = "Retorna total acumulado, total de metas ativas e percentual geral de progresso. Se total de metas for zero, o percentual será zero.")
    @ApiResponses({
            @ApiResponse(responseCode = "200", description = "KPI calculado com sucesso.",
                    content = @Content(mediaType = "application/json",
                            schema = @Schema(implementation = KpiProgressoGeralCaixinhaDto.class))),
            @ApiResponse(responseCode = "404", description = "Usuário não encontrado.", content = @Content)
    })
    public ResponseEntity<KpiProgressoGeralCaixinhaDto> obterKpiProgressoGeral(@PathVariable UUID user_id) {
        return ResponseEntity.ok(caixinhaService.obterKpiProgressoGeral(user_id));
    }

    @GetMapping("/kpi/rendimento-estimado-mes/usuarios/{user_id}")
    @Operation(summary = "KPI de rendimento estimado no mês",
            description = "Retorna a soma do rendimento estimado do mês atual em todas as caixinhas ativas, respeitando o tipo de taxa de cada caixinha.")
    @ApiResponses({
            @ApiResponse(responseCode = "200", description = "KPI calculado com sucesso.",
                    content = @Content(mediaType = "application/json",
                            schema = @Schema(implementation = KpiRendimentoEstimadoMesCaixinhaDto.class))),
            @ApiResponse(responseCode = "404", description = "Usuário não encontrado.", content = @Content)
    })
    public ResponseEntity<KpiRendimentoEstimadoMesCaixinhaDto> obterKpiRendimentoEstimadoMes(@PathVariable UUID user_id) {
        return ResponseEntity.ok(caixinhaService.obterKpiRendimentoEstimadoMes(user_id));
    }

    @GetMapping("/kpi/status/usuarios/{user_id}")
    @Operation(summary = "KPI de status das caixinhas",
            description = "Retorna quantidade de caixinhas ativas e encerradas do usuário.")
    @ApiResponses({
            @ApiResponse(responseCode = "200", description = "KPI calculado com sucesso.",
                    content = @Content(mediaType = "application/json",
                            schema = @Schema(implementation = KpiStatusCaixinhasDto.class))),
            @ApiResponse(responseCode = "404", description = "Usuário não encontrado.", content = @Content)
    })
    public ResponseEntity<KpiStatusCaixinhasDto> obterKpiStatus(@PathVariable UUID user_id) {
        return ResponseEntity.ok(caixinhaService.obterKpiStatusCaixinhas(user_id));
    }

    @GetMapping("/grafico/progresso-consolidado/usuarios/{user_id}")
    @Operation(summary = "Gráfico de progresso consolidado das caixinhas",
            description = "Retorna percentual geral de progresso, total acumulado e total de metas para consumo no gráfico consolidado.")
    @ApiResponses({
            @ApiResponse(responseCode = "200", description = "Dados do gráfico calculados com sucesso.",
                    content = @Content(mediaType = "application/json",
                            schema = @Schema(implementation = GraficoProgressoConsolidadoCaixinhaDto.class))),
            @ApiResponse(responseCode = "404", description = "Usuário não encontrado.", content = @Content)
    })
    public ResponseEntity<GraficoProgressoConsolidadoCaixinhaDto> obterGraficoProgressoConsolidado(@PathVariable UUID user_id) {
        return ResponseEntity.ok(caixinhaService.obterGraficoProgressoConsolidado(user_id));
    }

    // =========================================================================
    // EDITAR
    // =========================================================================

    @PutMapping("/{caixinha_id}")
    @Operation(summary = "Editar uma caixinha",
               description = "Atualiza nome, descrição, meta, prazo e/ou configuração de rendimento. " +
                             "Os aportes já realizados não são afetados.")
    @ApiResponses({
            @ApiResponse(responseCode = "200", description = "Caixinha atualizada.",
                    content = @Content(mediaType = "application/json",
                            schema = @Schema(implementation = CaixinhaResponseDTO.class))),
            @ApiResponse(responseCode = "404", description = "Caixinha não encontrada.", content = @Content)
    })
    public ResponseEntity<CaixinhaResponseDTO> editar(@PathVariable UUID caixinha_id,
                                                       @RequestBody CaixinhaCreateDTO dto) {
        return ResponseEntity.ok(caixinhaService.editar(caixinha_id, dto));
    }

    @PatchMapping("/{caixinha_id}/encerrar")
    @Operation(summary = "Encerrar uma caixinha",
               description = "Marca a caixinha como encerrada (meta atingida ou cancelada pelo usuário). " +
                             "Os dados e histórico de aportes são mantidos.")
    @ApiResponses({
            @ApiResponse(responseCode = "200", description = "Caixinha encerrada.",
                    content = @Content(mediaType = "application/json",
                            schema = @Schema(implementation = CaixinhaResponseDTO.class))),
            @ApiResponse(responseCode = "404", description = "Caixinha não encontrada.", content = @Content)
    })
    public ResponseEntity<CaixinhaResponseDTO> encerrar(@PathVariable UUID caixinha_id) {
        return ResponseEntity.ok(caixinhaService.encerrar(caixinha_id));
    }

    @PatchMapping("/{caixinha_id}/reabrir")
    @Operation(summary = "Reabrir uma caixinha encerrada",
               description = "Desfaz o encerramento, marcando a caixinha como ativa novamente.")
    @ApiResponses({
            @ApiResponse(responseCode = "200", description = "Caixinha reaberta.",
                    content = @Content(mediaType = "application/json",
                            schema = @Schema(implementation = CaixinhaResponseDTO.class))),
            @ApiResponse(responseCode = "404", description = "Caixinha não encontrada.", content = @Content)
    })
    public ResponseEntity<CaixinhaResponseDTO> reabrir(@PathVariable UUID caixinha_id) {
        return ResponseEntity.ok(caixinhaService.reabrir(caixinha_id));
    }

    @PostMapping("/{caixinha_id}/instituicoes/{inst_id}")
    @Operation(summary = "Adicionar instituição a uma caixinha compartilhada",
               description = "Vincula uma nova instituição à caixinha, habilitando a meta compartilhada. " +
                             "O saldo total passa a somar os aportes de todas as instituições vinculadas.")
    @ApiResponses({
            @ApiResponse(responseCode = "200", description = "Instituição adicionada.",
                    content = @Content(mediaType = "application/json",
                            schema = @Schema(implementation = CaixinhaResponseDTO.class))),
            @ApiResponse(responseCode = "400", description = "Instituição já vinculada.", content = @Content),
            @ApiResponse(responseCode = "404", description = "Caixinha ou instituição não encontradas.", content = @Content)
    })
    public ResponseEntity<CaixinhaResponseDTO> adicionarInstituicao(@PathVariable UUID caixinha_id,
                                                                      @PathVariable Integer inst_id) {
        return ResponseEntity.ok(caixinhaService.adicionarInstituicao(caixinha_id, inst_id));
    }

    // =========================================================================
    // DELETAR
    // =========================================================================

    @DeleteMapping("/{caixinha_id}")
    @Operation(summary = "Deletar uma caixinha",
               description = "Remove permanentemente a caixinha e seus vínculos com instituições. " +
                             "Os aportes registrados como EventoFinanceiro NÃO são deletados.")
    @ApiResponses({
            @ApiResponse(responseCode = "204", description = "Caixinha deletada.", content = @Content),
            @ApiResponse(responseCode = "404", description = "Caixinha não encontrada.", content = @Content)
    })
    public ResponseEntity<Void> deletar(@PathVariable UUID caixinha_id) {
        caixinhaService.deletar(caixinha_id);
        return ResponseEntity.noContent().build();
    }
}

package controle.api.back_end.dto.dashboard.out;

import java.math.BigDecimal;
import java.util.List;

/** Gráfico 1 — Evolução dos gastos ao longo do período (line chart). */
public record EvolucaoGastosDto(
        String labelPeriodo,
        /** DIARIO | SEMANAL | MENSAL dependendo do tipo de período */
        String granularidade,
        List<Ponto> dados
) {
    public record Ponto(String label, BigDecimal valor) {}
}

package controle.api.back_end.dto.dashboard.out;

import java.math.BigDecimal;
import java.util.List;

/** Gráfico 1 — Evolução dos gastos e recebimentos ao longo do período. */
public record EvolucaoGastosDto(
        String labelPeriodo,
        /** DIARIO | SEMANAL | MENSAL dependendo do tipo de período */
        String granularidade,
        List<Ponto> dados,
        /** Série de recebimentos (Recebimento + Empréstimo) — mesmos labels que dados */
        List<Ponto> dadosRecebimentos
) {
    public record Ponto(String label, BigDecimal valor) {}
}

package controle.api.back_end.dto.registros.in;

import controle.api.back_end.model.eventoFinanceiro.Tipo;
import io.swagger.v3.oas.annotations.media.Schema;
import jakarta.validation.constraints.NotNull;
import jakarta.validation.constraints.PastOrPresent;
import jakarta.validation.constraints.Positive;

import java.time.DayOfWeek;
import java.time.LocalDate;
import java.util.List;
import java.util.UUID;

public class EventoFinanceiroCreateDto {
    @Schema(example = "21eb5d2f-3fd8-439e-b647-5cc1f753ae58", description = "Representa o id do usuário responsável por criar o evento")
    @NotNull
    private UUID usuario_id;

    @Schema(example = "1", description = "Representa o tipo do evento financeiro")
    @NotNull
    private Tipo tipo;

    @Schema(example = "100.0", description = "Representa o valor do evento financeiro.")
    @NotNull
    @Positive
    private Double valor;

    @Schema(example = "Champagne de Ano novo")
    private String descricao;

    @Schema(example = "2026-01-01")
    @NotNull
    private LocalDate dataEvento;

    @Schema(example = "true",
            description = "Indica se o evento é recorrente (apenas Gasto e Recebimento)")
    private Boolean recorrente;

    @Schema(example = "Semanal",
            description = "Periodicidade da recorrência: DIARIO, SEMANAL, MENSAL ou ANUAL")
    private String periodicidade;

    @Schema(example = "2",
            description = "Intervalo da recorrência (ex.: a cada 2 dias, 2 semanas, 2 meses)")
    private Integer intervalo;

    @Schema(example = "[\"MONDAY\", \"WEDNESDAY\"]",
            description = "Dias da semana em que o evento ocorre (apenas para recorrência semanal)")
    private List<DayOfWeek> diasDaSemana;

    @Schema(example = "15",
            description = "Dia específico do mês ou ano em que o evento ocorre (apenas para mensal/anual)")
    private Integer dia;

    @Schema(example = "2026-12-31",
            description = "Data final da recorrência")
    private LocalDate dataFim;

    @Schema(example = "2.7",
            description = "Taxa de rendimento na poupança")
    private Double taxaRendimento;

    @Schema(example = "12",
            description = "Tempo em meses que o valor ficará aplicado")
    private Integer tempoAplicacao;

    @Schema(example = "24",
            description = "Tempo em meses que o da projeção em que o valor ficaria aplicado")
    private Integer tempoProjecao;

    public UUID getUsuario_id() {
