                .map(RegistrosMapper::toEntityGasto)
                .toList();
    }

    public static RegistroUsuarioResponseDto toResponseUser(EventoFinanceiro eventoFinanceiro,
                                                            List<EventoInstituicao> eventoInstituicoes,
                                                            EventoDetalhe eventoDetalhe) {
        if (eventoInstituicoes == null || eventoFinanceiro == null || eventoDetalhe == null) {
            return null;
        }

        RegistroUsuarioResponseDto response = new RegistroUsuarioResponseDto();

        // Mapeando lista de EventoInstituicao
        List<RegistroUsuarioResponseDto.EventoInstituicaoDto> eventoInstituicaoDtos = eventoInstituicoes.stream()
                .map(ei -> {
                    RegistroUsuarioResponseDto.EventoInstituicaoDto.InstituicaoDto instituicaoDto =
                            new RegistroUsuarioResponseDto.EventoInstituicaoDto.InstituicaoDto();
                    instituicaoDto.setId(ei.getInstituicaoUsuario().getInstituicao().getId());
                    instituicaoDto.setNome(ei.getInstituicaoUsuario().getInstituicao().getNome());

                    RegistroUsuarioResponseDto.EventoInstituicaoDto eventoInstituicaoDto =
                            new RegistroUsuarioResponseDto.EventoInstituicaoDto();
                    eventoInstituicaoDto.setId(ei.getId());
                    eventoInstituicaoDto.setParcelas(ei.getParcelas());
                    eventoInstituicaoDto.setInstituicao(instituicaoDto);
                    eventoInstituicaoDto.setTipoMovimento(ei.getTipoMovimento());
                    eventoInstituicaoDto.setValor(ei.getValor());

                    return eventoInstituicaoDto;
                })
                .toList();

        // Mapeando EventoFinanceiro
        RegistroUsuarioResponseDto.EventoFinanceiroDto financeiroDto = new RegistroUsuarioResponseDto.EventoFinanceiroDto();
        financeiroDto.setId(eventoFinanceiro.getId());
        financeiroDto.setDescricao(eventoFinanceiro.getDescricao());
        financeiroDto.setTipo(eventoFinanceiro.getTipo());
        financeiroDto.setDataEvento(eventoFinanceiro.getDataEvento());
        financeiroDto.setValor(eventoFinanceiro.getValor());

        // Mapeando categorias do EventoDetalhe
        List<RegistroUsuarioResponseDto.GastoDetalheDto.CategoriaDto> categoriasDto = eventoDetalhe.getCategoriaUsuario().stream()
                .map(cu -> {
                    RegistroUsuarioResponseDto.GastoDetalheDto.CategoriaDto categoriaDto =
                            new RegistroUsuarioResponseDto.GastoDetalheDto.CategoriaDto();
                    categoriaDto.setId(cu.getCategoria().getId());
                    categoriaDto.setTitulo(cu.getCategoria().getTitulo());
                    return categoriaDto;
                })
                .toList();

        RegistroUsuarioResponseDto.GastoDetalheDto detalheDto = new RegistroUsuarioResponseDto.GastoDetalheDto();
        detalheDto.setId(eventoDetalhe.getId());
        detalheDto.setCategoria(categoriasDto);
        detalheDto.setTituloGasto(eventoDetalhe.getTituloGasto());

        // Mapeando usuário
        RegistroUsuarioResponseDto.UsuarioDto usuarioDto = new RegistroUsuarioResponseDto.UsuarioDto();
        usuarioDto.setId(eventoFinanceiro.getUsuario().getId());
        usuarioDto.setNome(eventoFinanceiro.getUsuario().getNome());
        usuarioDto.setEmail(eventoFinanceiro.getUsuario().getEmail());

        // Montando resposta final
        response.setUsuario(usuarioDto);
        response.setGastoDetalhe(detalheDto);
        response.setEventoFinanceiro(financeiroDto);
        response.setEventoInstituicao(eventoInstituicaoDtos);
        response.setDataRegistro(eventoFinanceiro.getDataRegistro());

        return response;
    }

    public static RegistroResponseDto toResponse(EventoFinanceiro eventoFinanceiro,
                                                 List<EventoInstituicao> eventoInstituicoes,
                                                 EventoDetalhe eventoDetalhe) {
        if (eventoInstituicoes == null || eventoFinanceiro == null || eventoDetalhe == null) {
            return null;
        }

        RegistroResponseDto response = new RegistroResponseDto();

        // Mapeando lista de EventoInstituicao
        List<RegistroResponseDto.EventoInstituicaoDto> eventoInstituicaoDtos = eventoInstituicoes.stream()
                .map(ei -> {
                    RegistroResponseDto.EventoInstituicaoDto.InstituicaoDto instituicaoDto =
                            new RegistroResponseDto.EventoInstituicaoDto.InstituicaoDto();
                    instituicaoDto.setId(ei.getInstituicaoUsuario().getInstituicao().getId());
                    instituicaoDto.setNome(ei.getInstituicaoUsuario().getInstituicao().getNome());

                    RegistroResponseDto.EventoInstituicaoDto eventoInstituicaoDto =
                            new RegistroResponseDto.EventoInstituicaoDto();
                    eventoInstituicaoDto.setId(ei.getId());
                    eventoInstituicaoDto.setParcelas(ei.getParcelas());
                    eventoInstituicaoDto.setInstituicao(instituicaoDto);
                    eventoInstituicaoDto.setTipoMovimento(ei.getTipoMovimento());
                    eventoInstituicaoDto.setValor(ei.getValor());

                    return eventoInstituicaoDto;
                })
                .toList();

        // Mapeando EventoFinanceiro
        RegistroResponseDto.EventoFinanceiroDto financeiroDto = new RegistroResponseDto.EventoFinanceiroDto();
        financeiroDto.setId(eventoFinanceiro.getId());
        financeiroDto.setDescricao(eventoFinanceiro.getDescricao());
        financeiroDto.setTipo(eventoFinanceiro.getTipo());
        financeiroDto.setDataEvento(eventoFinanceiro.getDataEvento());
        financeiroDto.setValor(eventoFinanceiro.getValor());

        // Mapeando categorias do EventoDetalhe
        List<RegistroResponseDto.GastoDetalheDto.CategoriaDto> categoriasDto = eventoDetalhe.getCategoriaUsuario().stream()
                .map(cu -> {
                    RegistroResponseDto.GastoDetalheDto.CategoriaDto categoriaDto =
                            new RegistroResponseDto.GastoDetalheDto.CategoriaDto();
                    categoriaDto.setId(cu.getCategoria().getId());
                    categoriaDto.setTitulo(cu.getCategoria().getTitulo());
                    return categoriaDto;
                })
                .toList();

        RegistroResponseDto.GastoDetalheDto detalheDto = new RegistroResponseDto.GastoDetalheDto();
        detalheDto.setId(eventoDetalhe.getId());
        detalheDto.setCategoria(categoriasDto); // agora é lista
        detalheDto.setTituloGasto(eventoDetalhe.getTituloGasto());

        // Montando resposta final
        response.setDataRegistro(eventoFinanceiro.getDataRegistro());
        response.setEventoFinanceiro(financeiroDto);
        response.setEventoInstituicao(eventoInstituicaoDtos);
        response.setGastoDetalhe(detalheDto);

        return response;
    }


    public static List<RegistroResponseDto> toResponse(
            List<EventoFinanceiro> eventosFinanceiros,
            List<List<EventoInstituicao>> eventosInstituicoes,
            List<EventoDetalhe> eventoDetalhes) {

        if (eventosFinanceiros.size() != eventosInstituicoes.size()
                || eventosFinanceiros.size() != eventoDetalhes.size()) {
            throw new IllegalArgumentException("As listas devem ter o mesmo tamanho");
        }

        List<RegistroResponseDto> responses = new ArrayList<>();

        for (int i = 0; i < eventosFinanceiros.size(); i++) {
            EventoFinanceiro eventoFinanceiro = eventosFinanceiros.get(i);
            List<EventoInstituicao> instituicoes = eventosInstituicoes.get(i);
            EventoDetalhe eventoDetalhe = eventoDetalhes.get(i);

            RegistroResponseDto response = toResponse(eventoFinanceiro, instituicoes, eventoDetalhe);
            if (response != null) {
                responses.add(response);
            }
        }

        return responses;
    }

    public static RegistroUsuarioResponseDto toResponseUser(Registro registro) {
        if (registro == null || registro.getEventosFinanceiros() == null) {
            return null;
        }

        // Pega o primeiro evento como referência
        EventoFinanceiro eventoFinanceiro = registro.getEventosFinanceiros().getFirst();

        // Recupera TODAS as instituições vinculadas ao registro
        List<EventoInstituicao> eventoInstituicoes = registro.getInstituicoesPorEvento()
                .values()
                .stream()
                .flatMap(List::stream)
                .collect(Collectors.toList());

        // Recupera detalhe único vinculado ao primeiro evento
        EventoDetalhe eventoDetalhe = registro.getDetalhePorEvento()
                .getOrDefault(eventoFinanceiro, null);

        if (eventoFinanceiro == null || eventoDetalhe == null) {
            return null;
        }

        return toResponseUser(eventoFinanceiro, eventoInstituicoes, eventoDetalhe);
    }

}

package controle.api.back_end.service;

import controle.api.back_end.dto.poupanca.in.CaixinhaCreateDTO;
import controle.api.back_end.dto.poupanca.out.CaixinhaResponseDTO;
import controle.api.back_end.dto.poupanca.out.GraficoProgressoConsolidadoCaixinhaDto;
import controle.api.back_end.dto.poupanca.out.KpiProgressoGeralCaixinhaDto;
import controle.api.back_end.dto.poupanca.out.KpiRendimentoEstimadoMesCaixinhaDto;
import controle.api.back_end.dto.poupanca.out.KpiStatusCaixinhasDto;
import controle.api.back_end.dto.poupanca.out.KpiTotalAcumuladoCaixinhaDto;
import controle.api.back_end.exception.EntidadeNaoEncontradaException;
import controle.api.back_end.model.eventoFinanceiro.EventoFinanceiro;
import controle.api.back_end.model.instituicao.InstituicaoUsuario;
import controle.api.back_end.model.poupanca.Caixinha;
import controle.api.back_end.model.poupanca.CaixinhaInstituicao;
import controle.api.back_end.repository.eventoFinanceiro.EventoFinanceiroRepository;
import controle.api.back_end.repository.instituicao.InstituicaoUsuarioRepository;
import controle.api.back_end.repository.poupanca.CaixinhaInstituicaoRepository;
import controle.api.back_end.repository.poupanca.CaixinhaRepository;
import controle.api.back_end.repository.usuario.UsuarioRepository;
import controle.api.back_end.model.configuracoes.TipoAlertaEmail;
import controle.api.back_end.repository.configuracoes.ConfiguracoesRepository;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.math.BigDecimal;
import java.math.RoundingMode;
import java.time.YearMonth;
import java.time.format.DateTimeFormatter;
import java.time.LocalDate;
import java.time.Period;
import java.util.ArrayList;
import java.util.List;
import java.util.UUID;

/**
 * Serviço responsável pelo ciclo de vida das caixinhas de poupança e
 * todos os cálculos financeiros associados.
 *
 * <h3>Cálculos implementados</h3>
 * <ul>
 *   <li><b>Taxa mensal efetiva</b>: convertida da taxa anual para composto mensal.</li>
 *   <li><b>Montante projetado sem aportes</b>: VF = VP × (1 + r)^n</li>
 *   <li><b>Aporte mensal sugerido (PMT)</b>:
 *       PMT = [VF − VP×(1+r)^n] × r / [(1+r)^n − 1]
 *       <br>Se r = 0: PMT = (VF − VP) / n</li>
 *   <li><b>Montante projetado com aportes</b>:
 *       VF = VP×(1+r)^n + PMT × [(1+r)^n − 1] / r</li>
 * </ul>
 */
@Service
@Transactional
public class CaixinhaService {

    private static final Logger log = LoggerFactory.getLogger(CaixinhaService.class);

    private final CaixinhaRepository caixinhaRepository;
    private final CaixinhaInstituicaoRepository caixinhaInstituicaoRepository;
    private final UsuarioRepository usuarioRepository;
    private final InstituicaoUsuarioRepository instituicaoUsuarioRepository;
    private final EventoFinanceiroRepository eventoFinanceiroRepository;
    private final ConfiguracoesRepository configuracoesRepository;
    private final EmailService emailService;

    public CaixinhaService(CaixinhaRepository caixinhaRepository,
                           CaixinhaInstituicaoRepository caixinhaInstituicaoRepository,
                           UsuarioRepository usuarioRepository,
                           InstituicaoUsuarioRepository instituicaoUsuarioRepository,
                           EventoFinanceiroRepository eventoFinanceiroRepository,
                           ConfiguracoesRepository configuracoesRepository,
                           EmailService emailService) {
        this.caixinhaRepository              = caixinhaRepository;
        this.caixinhaInstituicaoRepository   = caixinhaInstituicaoRepository;
        this.usuarioRepository               = usuarioRepository;
        this.instituicaoUsuarioRepository    = instituicaoUsuarioRepository;
        this.eventoFinanceiroRepository      = eventoFinanceiroRepository;
        this.configuracoesRepository         = configuracoesRepository;
        this.emailService                    = emailService;
    }

    // =========================================================================
    // CRIAR
    // =========================================================================

    /** Cria uma nova caixinha e vincula as instituições informadas. */
    public CaixinhaResponseDTO criar(CaixinhaCreateDTO dto) {
        usuarioRepository.findById(dto.getUsuarioId())
                .orElseThrow(() -> new EntidadeNaoEncontradaException(
                        "Usuário de id: %s não encontrado.".formatted(dto.getUsuarioId())));

        Caixinha caixinha = new Caixinha();
        caixinha.setUsuario(usuarioRepository.getReferenceById(dto.getUsuarioId()));
        caixinha.setNome(dto.getNome());
        caixinha.setDescricao(dto.getDescricao());
        caixinha.setValorMeta(dto.getValorMeta());
        caixinha.setDataPrazo(dto.getDataPrazo());
        caixinha.setTipoRendimento(dto.getTipoRendimento());
        caixinha.setPercentualRendimento(dto.getPercentualRendimento());
        caixinha.setTaxaAnualPersonalizada(dto.getTaxaAnualPersonalizada());
        caixinha.setTaxaReferenciaAtual(dto.getTaxaReferenciaAtual());
        caixinha.setIsCompartilhada(dto.getIsCompartilhada() != null && dto.getIsCompartilhada());
        caixinha.setIsAtiva(true);
        caixinha.setDataCriacao(LocalDate.now());

        Caixinha salva = caixinhaRepository.save(caixinha);

        // Vincula as instituicoes
        for (Integer instId : dto.getInstituicaoUsuarioIds()) {
            InstituicaoUsuario inst = instituicaoUsuarioRepository.findById(instId)
                    .orElseThrow(() -> new EntidadeNaoEncontradaException(
                            "InstituicaoUsuario de id: %d nao encontrada.".formatted(instId)));
            CaixinhaInstituicao vinculo = new CaixinhaInstituicao();
            vinculo.setCaixinha(salva);
            vinculo.setInstituicaoUsuario(inst);
            caixinhaInstituicaoRepository.save(vinculo);
        }

        CaixinhaResponseDTO resultado = calcularEMontar(salva);
        verificarEEnviarAlertaMeta(salva, resultado);
        return resultado;
    }

    // =========================================================================
    // CONSULTAS
    // =========================================================================

    /** Retorna todas as caixinhas (ativas e inativas) do usuário com cálculos. */
    @Transactional(readOnly = true)
    public List<CaixinhaResponseDTO> listarPorUsuario(UUID usuarioId) {
        validarUsuario(usuarioId);
        return caixinhaRepository.findAllByUsuario_Id(usuarioId).stream()
                .map(this::calcularEMontar)
                .toList();
    }

    /** Retorna apenas as caixinhas ativas do usuário. */
    @Transactional(readOnly = true)
    public List<CaixinhaResponseDTO> listarAtivasPorUsuario(UUID usuarioId) {
        validarUsuario(usuarioId);
        return caixinhaRepository.findAllByUsuario_IdAndIsAtivaTrue(usuarioId).stream()
                .map(this::calcularEMontar)
                .toList();
    }

    /** Retorna uma caixinha específica com todos os cálculos. */
    @Transactional(readOnly = true)
    public CaixinhaResponseDTO buscarPorId(UUID caixinhaId) {
        Caixinha caixinha = caixinhaRepository.findById(caixinhaId)
                .orElseThrow(() -> new EntidadeNaoEncontradaException(
                        "Caixinha de id: %s não encontrada.".formatted(caixinhaId)));
        return calcularEMontar(caixinha);
    }

    /** Resumo total de poupança do usuário (soma de todas as caixinhas ativas). */
    @Transactional(readOnly = true)
    public BigDecimal resumoTotalPoupanca(UUID usuarioId) {
        validarUsuario(usuarioId);
        return caixinhaRepository.findAllByUsuario_IdAndIsAtivaTrue(usuarioId).stream()
                .map(c -> eventoFinanceiroRepository.sumValorByCaixinha(c.getId()))
                .reduce(BigDecimal.ZERO, BigDecimal::add);
    }

    @Transactional(readOnly = true)
    public KpiTotalAcumuladoCaixinhaDto obterKpiTotalAcumulado(UUID usuarioId) {
        List<Caixinha> caixinhasAtivas = buscarCaixinhasAtivasPorUsuario(usuarioId);
        BigDecimal totalAcumulado = resumoTotalPoupanca(usuarioId);
        return new KpiTotalAcumuladoCaixinhaDto(totalAcumulado, caixinhasAtivas.size());
    }

    @Transactional(readOnly = true)
    public KpiProgressoGeralCaixinhaDto obterKpiProgressoGeral(UUID usuarioId) {
        List<Caixinha> caixinhasAtivas = buscarCaixinhasAtivasPorUsuario(usuarioId);
        BigDecimal totalAcumulado = resumoTotalPoupanca(usuarioId);
        BigDecimal totalMetas = somarMetasDasCaixinhas(caixinhasAtivas);

        int percentualProgressoGeral = 0;
        if (totalMetas.compareTo(BigDecimal.ZERO) > 0) {
            percentualProgressoGeral = totalAcumulado
                    .divide(totalMetas, 6, RoundingMode.HALF_UP)
                    .multiply(BigDecimal.valueOf(100))
                    .setScale(0, RoundingMode.HALF_UP)
                    .intValue();
            percentualProgressoGeral = Math.min(percentualProgressoGeral, 100);
        }

        return new KpiProgressoGeralCaixinhaDto(totalAcumulado, totalMetas, percentualProgressoGeral);
    }

    @Transactional(readOnly = true)
    public KpiRendimentoEstimadoMesCaixinhaDto obterKpiRendimentoEstimadoMes(UUID usuarioId) {
        List<Caixinha> caixinhasAtivas = buscarCaixinhasAtivasPorUsuario(usuarioId);

        BigDecimal rendimentoEstimadoMes = caixinhasAtivas.stream()
                .map(caixinha -> {
                    BigDecimal valorAtual = eventoFinanceiroRepository.sumValorByCaixinha(caixinha.getId());
                    BigDecimal taxaMensalEfetiva = BigDecimal.valueOf(calcularTaxaMensal(caixinha));
                    return valorAtual.multiply(taxaMensalEfetiva);
                })
                .reduce(BigDecimal.ZERO, BigDecimal::add)
                .setScale(2, RoundingMode.HALF_UP);

        String mesReferencia = YearMonth.now().format(DateTimeFormatter.ofPattern("MM/yyyy"));
        return new KpiRendimentoEstimadoMesCaixinhaDto(rendimentoEstimadoMes, mesReferencia);
    }

    @Transactional(readOnly = true)
    public KpiStatusCaixinhasDto obterKpiStatusCaixinhas(UUID usuarioId) {
        validarUsuario(usuarioId);
        List<Caixinha> todasCaixinhas = caixinhaRepository.findAllByUsuario_Id(usuarioId);

        int quantidadeAtivas = (int) todasCaixinhas.stream()
                .filter(caixinha -> Boolean.TRUE.equals(caixinha.getIsAtiva()))
                .count();
        int quantidadeEncerradas = (int) todasCaixinhas.stream()
                .filter(caixinha -> !Boolean.TRUE.equals(caixinha.getIsAtiva()))
                .count();

        return new KpiStatusCaixinhasDto(quantidadeAtivas, quantidadeEncerradas);
    }

    @Transactional(readOnly = true)
    public GraficoProgressoConsolidadoCaixinhaDto obterGraficoProgressoConsolidado(UUID usuarioId) {
        KpiProgressoGeralCaixinhaDto kpiProgresso = obterKpiProgressoGeral(usuarioId);
        return new GraficoProgressoConsolidadoCaixinhaDto(
                kpiProgresso.percentualProgressoGeral(),
                kpiProgresso.totalAcumulado(),
                kpiProgresso.totalMetas());
    }

    // =========================================================================
    // EDITAR
    // =========================================================================

    /** Edita os dados configuráveis de uma caixinha (não afeta aportes existentes). */
    public CaixinhaResponseDTO editar(UUID caixinhaId, CaixinhaCreateDTO dto) {
        Caixinha caixinha = caixinhaRepository.findById(caixinhaId)
                .orElseThrow(() -> new EntidadeNaoEncontradaException(
                        "Caixinha de id: %s não encontrada.".formatted(caixinhaId)));

        if (dto.getNome() != null) caixinha.setNome(dto.getNome());
        // Permite limpar a descrição passando string vazia
        if (dto.getDescricao() != null) caixinha.setDescricao(dto.getDescricao().isBlank() ? null : dto.getDescricao());
        if (dto.getValorMeta() != null) caixinha.setValorMeta(dto.getValorMeta());
        if (dto.getDataPrazo() != null) caixinha.setDataPrazo(dto.getDataPrazo());
        if (dto.getTipoRendimento() != null) caixinha.setTipoRendimento(dto.getTipoRendimento());
        if (dto.getPercentualRendimento() != null) caixinha.setPercentualRendimento(dto.getPercentualRendimento());
        if (dto.getTaxaAnualPersonalizada() != null) caixinha.setTaxaAnualPersonalizada(dto.getTaxaAnualPersonalizada());
        if (dto.getTaxaReferenciaAtual() != null) caixinha.setTaxaReferenciaAtual(dto.getTaxaReferenciaAtual());

        // Atualiza vínculos de instituição se informados
        if (dto.getInstituicaoUsuarioIds() != null && !dto.getInstituicaoUsuarioIds().isEmpty()) {
            // Remove vínculos antigos
            List<CaixinhaInstituicao> vinculosAtuais = caixinhaInstituicaoRepository.findAllByCaixinha_Id(caixinhaId);
            caixinhaInstituicaoRepository.deleteAll(vinculosAtuais);
            caixinhaInstituicaoRepository.flush();

            // Adiciona novos vínculos
            for (Integer instId : dto.getInstituicaoUsuarioIds()) {
                InstituicaoUsuario inst = instituicaoUsuarioRepository.findById(instId)
                        .orElseThrow(() -> new EntidadeNaoEncontradaException(
                                "InstituicaoUsuario de id: %d nao encontrada.".formatted(instId)));
                CaixinhaInstituicao vinculo = new CaixinhaInstituicao();
                vinculo.setCaixinha(caixinha);
                vinculo.setInstituicaoUsuario(inst);
                caixinhaInstituicaoRepository.save(vinculo);
            }

            caixinha.setIsCompartilhada(dto.getInstituicaoUsuarioIds().size() > 1);
        }

        return calcularEMontar(caixinhaRepository.save(caixinha));
    }

    /** Encerra uma caixinha (marca como inativa). */
    public CaixinhaResponseDTO encerrar(UUID caixinhaId) {
        Caixinha caixinha = caixinhaRepository.findById(caixinhaId)
                .orElseThrow(() -> new EntidadeNaoEncontradaException(
                        "Caixinha de id: %s não encontrada.".formatted(caixinhaId)));
        caixinha.setIsAtiva(false);
        caixinha.setDataEncerramento(LocalDate.now());
        return calcularEMontar(caixinhaRepository.save(caixinha));
    }

    /** Vincula uma nova instituição a uma caixinha compartilhada. */
    public CaixinhaResponseDTO adicionarInstituicao(UUID caixinhaId, Integer instId) {
        Caixinha caixinha = caixinhaRepository.findById(caixinhaId)
                .orElseThrow(() -> new EntidadeNaoEncontradaException(
                        "Caixinha de id: %s não encontrada.".formatted(caixinhaId)));
        if (caixinhaInstituicaoRepository.existsByCaixinha_IdAndInstituicaoUsuario_Id(caixinhaId, instId)) {
            throw new IllegalArgumentException("Instituição já vinculada a esta caixinha.");
        }
        InstituicaoUsuario inst = instituicaoUsuarioRepository.findById(instId)
                .orElseThrow(() -> new EntidadeNaoEncontradaException(
                        "InstituicaoUsuario de id: %d não encontrada.".formatted(instId)));
        CaixinhaInstituicao vinculo = new CaixinhaInstituicao();
        vinculo.setCaixinha(caixinha);
        vinculo.setInstituicaoUsuario(inst);
        caixinhaInstituicaoRepository.save(vinculo);
        caixinha.setIsCompartilhada(true);
        return calcularEMontar(caixinhaRepository.save(caixinha));
    }

    // =========================================================================
    // DELETAR
    // =========================================================================

    public void deletar(UUID caixinhaId) {
        if (!caixinhaRepository.existsById(caixinhaId)) {
            throw new EntidadeNaoEncontradaException(
                    "Caixinha de id: %s não encontrada.".formatted(caixinhaId));
        }
        // Desvincula EventoFinanceiro antes de deletar para evitar violação de FK
        List<EventoFinanceiro> aportes = eventoFinanceiroRepository.findAllByCaixinha_Id(caixinhaId);
        aportes.forEach(e -> e.setCaixinha(null));
        eventoFinanceiroRepository.saveAll(aportes);
        eventoFinanceiroRepository.flush();

        caixinhaRepository.deleteById(caixinhaId);
    }

    // =========================================================================
    // CÁLCULOS FINANCEIROS (acesso package para uso no EmailService)
    // =========================================================================

    /**
     * Monta o DTO de resposta completo com todos os cálculos aplicados.
     */
    CaixinhaResponseDTO calcularEMontar(Caixinha c) {
        CaixinhaResponseDTO dto = new CaixinhaResponseDTO();

        // Dados básicos
        dto.setId(c.getId());
        dto.setNome(c.getNome());
        dto.setDescricao(c.getDescricao());
        dto.setIsAtiva(c.getIsAtiva());
        dto.setIsCompartilhada(c.getIsCompartilhada());
        dto.setDataCriacao(c.getDataCriacao());
        dto.setDataEncerramento(c.getDataEncerramento());
        dto.setValorMeta(c.getValorMeta());
        dto.setDataPrazo(c.getDataPrazo());
        dto.setTipoRendimento(c.getTipoRendimento());
        dto.setPercentualRendimento(c.getPercentualRendimento());
        dto.setTaxaAnualPersonalizada(c.getTaxaAnualPersonalizada());
        dto.setTaxaReferenciaAtual(c.getTaxaReferenciaAtual());

        // Valor atual = soma dos aportes registrados
        BigDecimal valorAtual = eventoFinanceiroRepository.sumValorByCaixinha(c.getId());
        dto.setValorAtual(valorAtual);

        // Progresso em relação à meta
        if (c.getValorMeta() != null && c.getValorMeta().compareTo(BigDecimal.ZERO) > 0) {
            BigDecimal falta = c.getValorMeta().subtract(valorAtual).max(BigDecimal.ZERO);
            dto.setFaltaParaMeta(falta);
            double pct = valorAtual.divide(c.getValorMeta(), 6, RoundingMode.HALF_UP)
                                   .multiply(BigDecimal.valueOf(100))
                                   .doubleValue();
            dto.setPercentualAtingido(Math.min(pct, 100.0));
        }

        // Taxa mensal efetiva
        double taxaMensal = calcularTaxaMensal(c);
        dto.setTaxaMensalEfetiva(taxaMensal);

        // Projeções com prazo
        if (c.getDataPrazo() != null && c.getDataPrazo().isAfter(LocalDate.now())) {
            int meses = (int) Period.between(LocalDate.now(), c.getDataPrazo()).toTotalMonths();
            dto.setMesesRestantes(meses);

            if (meses > 0) {
                double vp = valorAtual.doubleValue();
                double fatorN = Math.pow(1 + taxaMensal, meses);

                // Montante sem novos aportes: VP × (1+r)^n
                double montanteSemAportes = vp * fatorN;
                dto.setMontanteProjetadoSemAportes(
                        BigDecimal.valueOf(montanteSemAportes).setScale(2, RoundingMode.HALF_UP));

                // Aporte mensal sugerido (PMT)
                if (c.getValorMeta() != null) {
                    double vf = c.getValorMeta().doubleValue();
                    double pmt;
                    if (taxaMensal < 1e-10) {
                        // Taxa zero: divisão simples
                        pmt = Math.max(0, (vf - vp)) / meses;
                    } else {
                        pmt = Math.max(0, (vf - vp * fatorN) * taxaMensal / (fatorN - 1));
                    }
                    dto.setAporteMensalSugerido(
                            BigDecimal.valueOf(pmt).setScale(2, RoundingMode.HALF_UP));

                    // Montante com aportes: VP×(1+r)^n + PMT×[(1+r)^n − 1]/r
                    double montanteComAportes;
                    if (taxaMensal < 1e-10) {
                        montanteComAportes = vp + pmt * meses;
                    } else {
                        montanteComAportes = vp * fatorN + pmt * (fatorN - 1) / taxaMensal;
                    }
                    dto.setMontanteProjetadoComAportes(
                            BigDecimal.valueOf(montanteComAportes).setScale(2, RoundingMode.HALF_UP));

                    dto.setMetaAlcancavel(montanteComAportes >= vf - 0.01);
                }
            }
        }

        // Instituições com valor aportado por cada uma
        List<CaixinhaResponseDTO.InstituicaoDTO> instDtos = new ArrayList<>();
        List<CaixinhaInstituicao> vinculos = caixinhaInstituicaoRepository.findAllByCaixinha_Id(c.getId());
        for (CaixinhaInstituicao vi : vinculos) {
            List<EventoFinanceiro> eventosDaInst = eventoFinanceiroRepository
                    .findAllByCaixinha_Id(c.getId()).stream()
                    .filter(e -> e.getEventoInstituicoes() != null &&
                                 e.getEventoInstituicoes().stream()
                                   .anyMatch(ei -> ei.getInstituicaoUsuario().getId()
                                                     .equals(vi.getInstituicaoUsuario().getId())))
                    .toList();
            BigDecimal aportadoNaInst = eventosDaInst.stream()
                    .map(e -> BigDecimal.valueOf(e.getValor()))
                    .reduce(BigDecimal.ZERO, BigDecimal::add);

            CaixinhaResponseDTO.InstituicaoDTO iDto = new CaixinhaResponseDTO.InstituicaoDTO();
            iDto.setId(vi.getInstituicaoUsuario().getId());
            iDto.setNome(vi.getInstituicaoUsuario().getInstituicao().getNome());
            iDto.setValorAportado(aportadoNaInst);
            instDtos.add(iDto);
        }
        dto.setInstituicoes(instDtos);

        return dto;
    }

    /**
     * Calcula a taxa mensal efetiva a partir da configuração da caixinha.
     *
     * <ul>
     *   <li>CDI: taxaReferenciaAtual × (percentualRendimento / 100) / 12 (simplificado)</li>
     *   <li>SELIC: igual ao CDI</li>
     *   <li>POUPANÇA: 70% da SELIC + 0% TR simplificado</li>
     *   <li>PREFIXADO / PERSONALIZADO: taxa anual → mensal composto</li>
     * </ul>
     */
    private double calcularTaxaMensal(Caixinha c) {
        if (c.getTipoRendimento() == null) {
            return 0.0;
        }

        double taxaAnualPercent;

        switch (c.getTipoRendimento()) {
            case CDI, SELIC -> {
                if (c.getTaxaReferenciaAtual() == null) {
                    taxaAnualPercent = 0.0;
                    break;
                }
                double referencia = c.getTaxaReferenciaAtual(); // % a.a.
                double percentual = c.getPercentualRendimento() != null
                        ? c.getPercentualRendimento() / 100.0 : 1.0;
                taxaAnualPercent = referencia * percentual;
            }
            case POUPANCA -> {
                if (c.getTaxaReferenciaAtual() == null) {
                    taxaAnualPercent = 0.0;
                    break;
                }
                // Regra atual da poupança: 70% da SELIC quando SELIC > 8,5% a.a.
                taxaAnualPercent = c.getTaxaReferenciaAtual() * 0.70;
            }
            case PREFIXADO, PERSONALIZADO -> {
                taxaAnualPercent = c.getTaxaAnualPersonalizada() != null
                        ? c.getTaxaAnualPersonalizada() : 0.0;
            }
            default -> taxaAnualPercent = 0.0;
        }

        // Converte % a.a. para decimal mensal via juros compostos: (1 + i_a)^(1/12) - 1
        return Math.pow(1 + taxaAnualPercent / 100.0, 1.0 / 12.0) - 1;
    }

    // =========================================================================
    // PRIVADO
    // =========================================================================

    // =========================================================================
    // PRIVADO
    // =========================================================================

    /**
     * Verifica se a caixinha atingiu o percentual de meta configurado pelo usuario
     * e envia o alerta de e-mail (uma vez por mes).
     */
    private void verificarEEnviarAlertaMeta(Caixinha caixinha, CaixinhaResponseDTO dto) {
        try {
            if (dto.getPercentualAtingido() == null || caixinha.getValorMeta() == null) return;

            configuracoesRepository.findConfiguracoesByUsuario_Id(caixinha.getUsuario().getId())
                    .ifPresent(config -> {
                        if (!config.getAlertasEmailAtivos().contains(TipoAlertaEmail.ALERTA_META_POUPANCA)) return;

                        int threshold = config.getPercentualAlertaMeta() != null
                                ? config.getPercentualAlertaMeta() : 90;

                        if (dto.getPercentualAtingido() < threshold) return;

                        // Ja enviou este mes?
                        LocalDate hoje = java.time.LocalDate.now();
                        if (config.getUltimoAlertaMetaEnviado() != null
                                && config.getUltimoAlertaMetaEnviado().getMonth() == hoje.getMonth()
                                && config.getUltimoAlertaMetaEnviado().getYear() == hoje.getYear()) {
                            return;
                        }

                        emailService.enviarAlertaMetaPoupanca(
                                caixinha.getUsuario(),
                                caixinha.getNome(),
                                dto.getValorAtual(),
                                caixinha.getValorMeta(),
                                dto.getPercentualAtingido());

                        config.setUltimoAlertaMetaEnviado(hoje);
                        configuracoesRepository.save(config);
                    });
        } catch (Exception e) {
            log.warn("[CaixinhaService] Erro ao verificar alerta de meta: {}", e.getMessage());
        }
    }

    private void validarUsuario(UUID usuarioId) {
        if (!usuarioRepository.existsById(usuarioId)) {
            throw new EntidadeNaoEncontradaException(
                    "Usuário de id: %s não encontrado.".formatted(usuarioId));
        }
    }

    private List<Caixinha> buscarCaixinhasAtivasPorUsuario(UUID usuarioId) {
        validarUsuario(usuarioId);
        return caixinhaRepository.findAllByUsuario_IdAndIsAtivaTrue(usuarioId);
    }

    private BigDecimal somarMetasDasCaixinhas(List<Caixinha> caixinhas) {
        return caixinhas.stream()
                .map(Caixinha::getValorMeta)
                .filter(valorMeta -> valorMeta != null)
                .reduce(BigDecimal.ZERO, BigDecimal::add);
    }
}

package controle.api.back_end.service;

import controle.api.back_end.dto.poupanca.in.CaixinhaCreateDTO;
import controle.api.back_end.dto.poupanca.out.CaixinhaResponseDTO;
import controle.api.back_end.dto.poupanca.out.GraficoProgressoConsolidadoCaixinhaDto;
import controle.api.back_end.dto.poupanca.out.KpiProgressoGeralCaixinhaDto;
import controle.api.back_end.dto.poupanca.out.KpiRendimentoEstimadoMesCaixinhaDto;
import controle.api.back_end.dto.poupanca.out.KpiStatusCaixinhasDto;
import controle.api.back_end.dto.poupanca.out.KpiTotalAcumuladoCaixinhaDto;
import controle.api.back_end.exception.EntidadeNaoEncontradaException;
import controle.api.back_end.model.eventoFinanceiro.EventoFinanceiro;
import controle.api.back_end.model.instituicao.InstituicaoUsuario;
import controle.api.back_end.model.poupanca.Caixinha;
import controle.api.back_end.model.poupanca.CaixinhaInstituicao;
import controle.api.back_end.repository.eventoFinanceiro.EventoFinanceiroRepository;
import controle.api.back_end.repository.instituicao.InstituicaoUsuarioRepository;
import controle.api.back_end.repository.poupanca.CaixinhaInstituicaoRepository;
import controle.api.back_end.repository.poupanca.CaixinhaRepository;
import controle.api.back_end.repository.usuario.UsuarioRepository;
import controle.api.back_end.model.configuracoes.TipoAlertaEmail;
import controle.api.back_end.repository.configuracoes.ConfiguracoesRepository;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.math.BigDecimal;
import java.math.RoundingMode;
import java.time.YearMonth;
import java.time.format.DateTimeFormatter;
import java.time.LocalDate;
import java.time.Period;
import java.util.ArrayList;
import java.util.List;
import java.util.UUID;

/**
 * Serviço responsável pelo ciclo de vida das caixinhas de poupança e
 * todos os cálculos financeiros associados.
 *
 * <h3>Cálculos implementados</h3>
 * <ul>
 *   <li><b>Taxa mensal efetiva</b>: convertida da taxa anual para composto mensal.</li>
 *   <li><b>Montante projetado sem aportes</b>: VF = VP × (1 + r)^n</li>
 *   <li><b>Aporte mensal sugerido (PMT)</b>:
 *       PMT = [VF − VP×(1+r)^n] × r / [(1+r)^n − 1]
 *       <br>Se r = 0: PMT = (VF − VP) / n</li>
 *   <li><b>Montante projetado com aportes</b>:
 *       VF = VP×(1+r)^n + PMT × [(1+r)^n − 1] / r</li>
 * </ul>
 */
@Service
@Transactional
public class CaixinhaService {

    private static final Logger log = LoggerFactory.getLogger(CaixinhaService.class);

    private final CaixinhaRepository caixinhaRepository;
    private final CaixinhaInstituicaoRepository caixinhaInstituicaoRepository;
    private final UsuarioRepository usuarioRepository;
    private final InstituicaoUsuarioRepository instituicaoUsuarioRepository;
    private final EventoFinanceiroRepository eventoFinanceiroRepository;
    private final ConfiguracoesRepository configuracoesRepository;
    private final EmailService emailService;

    public CaixinhaService(CaixinhaRepository caixinhaRepository,
                           CaixinhaInstituicaoRepository caixinhaInstituicaoRepository,
                           UsuarioRepository usuarioRepository,
                           InstituicaoUsuarioRepository instituicaoUsuarioRepository,
                           EventoFinanceiroRepository eventoFinanceiroRepository,
                           ConfiguracoesRepository configuracoesRepository,
                           EmailService emailService) {
        this.caixinhaRepository              = caixinhaRepository;
        this.caixinhaInstituicaoRepository   = caixinhaInstituicaoRepository;
        this.usuarioRepository               = usuarioRepository;
        this.instituicaoUsuarioRepository    = instituicaoUsuarioRepository;
        this.eventoFinanceiroRepository      = eventoFinanceiroRepository;
        this.configuracoesRepository         = configuracoesRepository;
        this.emailService                    = emailService;
    }

    // =========================================================================
    // CRIAR
    // =========================================================================

    /** Cria uma nova caixinha e vincula as instituições informadas. */
    public CaixinhaResponseDTO criar(CaixinhaCreateDTO dto) {
        usuarioRepository.findById(dto.getUsuarioId())
                .orElseThrow(() -> new EntidadeNaoEncontradaException(
                        "Usuário de id: %s não encontrado.".formatted(dto.getUsuarioId())));

        Caixinha caixinha = new Caixinha();
        caixinha.setUsuario(usuarioRepository.getReferenceById(dto.getUsuarioId()));
        caixinha.setNome(dto.getNome());
        caixinha.setDescricao(dto.getDescricao());
        caixinha.setValorMeta(dto.getValorMeta());
        caixinha.setDataPrazo(dto.getDataPrazo());
        caixinha.setTipoRendimento(dto.getTipoRendimento());
        caixinha.setPercentualRendimento(dto.getPercentualRendimento());
        caixinha.setTaxaAnualPersonalizada(dto.getTaxaAnualPersonalizada());
        caixinha.setTaxaReferenciaAtual(dto.getTaxaReferenciaAtual());
        caixinha.setIsCompartilhada(dto.getIsCompartilhada() != null && dto.getIsCompartilhada());
        caixinha.setIsAtiva(true);
        caixinha.setDataCriacao(LocalDate.now());

        Caixinha salva = caixinhaRepository.save(caixinha);

        // Vincula as instituicoes
        for (Integer instId : dto.getInstituicaoUsuarioIds()) {
            InstituicaoUsuario inst = instituicaoUsuarioRepository.findById(instId)
                    .orElseThrow(() -> new EntidadeNaoEncontradaException(
                            "InstituicaoUsuario de id: %d nao encontrada.".formatted(instId)));
            CaixinhaInstituicao vinculo = new CaixinhaInstituicao();
            vinculo.setCaixinha(salva);
            vinculo.setInstituicaoUsuario(inst);
            caixinhaInstituicaoRepository.save(vinculo);
        }

        CaixinhaResponseDTO resultado = calcularEMontar(salva);
        verificarEEnviarAlertaMeta(salva, resultado);
        return resultado;
    }

    // =========================================================================
    // CONSULTAS
    // =========================================================================

    /** Retorna todas as caixinhas (ativas e inativas) do usuário com cálculos. */
    @Transactional(readOnly = true)
    public List<CaixinhaResponseDTO> listarPorUsuario(UUID usuarioId) {
        validarUsuario(usuarioId);
        return caixinhaRepository.findAllByUsuario_Id(usuarioId).stream()
                .map(this::calcularEMontar)
                .toList();
    }

    /** Retorna apenas as caixinhas ativas do usuário. */
    @Transactional(readOnly = true)
    public List<CaixinhaResponseDTO> listarAtivasPorUsuario(UUID usuarioId) {
        validarUsuario(usuarioId);
        return caixinhaRepository.findAllByUsuario_IdAndIsAtivaTrue(usuarioId).stream()
                .map(this::calcularEMontar)
                .toList();
    }

    /** Retorna uma caixinha específica com todos os cálculos. */
    @Transactional(readOnly = true)
    public CaixinhaResponseDTO buscarPorId(UUID caixinhaId) {
        Caixinha caixinha = caixinhaRepository.findById(caixinhaId)
                .orElseThrow(() -> new EntidadeNaoEncontradaException(
                        "Caixinha de id: %s não encontrada.".formatted(caixinhaId)));
        return calcularEMontar(caixinha);
    }

    /** Resumo total de poupança do usuário (soma de todas as caixinhas ativas). */
    @Transactional(readOnly = true)
    public BigDecimal resumoTotalPoupanca(UUID usuarioId) {
        validarUsuario(usuarioId);
        return caixinhaRepository.findAllByUsuario_IdAndIsAtivaTrue(usuarioId).stream()
                .map(c -> eventoFinanceiroRepository.sumValorByCaixinha(c.getId()))
                .reduce(BigDecimal.ZERO, BigDecimal::add);
    }

    @Transactional(readOnly = true)
    public KpiTotalAcumuladoCaixinhaDto obterKpiTotalAcumulado(UUID usuarioId) {
        List<Caixinha> caixinhasAtivas = buscarCaixinhasAtivasPorUsuario(usuarioId);
        BigDecimal totalAcumulado = resumoTotalPoupanca(usuarioId);
        return new KpiTotalAcumuladoCaixinhaDto(totalAcumulado, caixinhasAtivas.size());
    }

    @Transactional(readOnly = true)
    public KpiProgressoGeralCaixinhaDto obterKpiProgressoGeral(UUID usuarioId) {
        List<Caixinha> caixinhasAtivas = buscarCaixinhasAtivasPorUsuario(usuarioId);
        BigDecimal totalAcumulado = resumoTotalPoupanca(usuarioId);
        BigDecimal totalMetas = somarMetasDasCaixinhas(caixinhasAtivas);

        int percentualProgressoGeral = 0;
        if (totalMetas.compareTo(BigDecimal.ZERO) > 0) {
            percentualProgressoGeral = totalAcumulado
                    .divide(totalMetas, 6, RoundingMode.HALF_UP)
                    .multiply(BigDecimal.valueOf(100))
                    .setScale(0, RoundingMode.HALF_UP)
                    .intValue();
            percentualProgressoGeral = Math.min(percentualProgressoGeral, 100);
        }

        return new KpiProgressoGeralCaixinhaDto(totalAcumulado, totalMetas, percentualProgressoGeral);
    }

    @Transactional(readOnly = true)
    public KpiRendimentoEstimadoMesCaixinhaDto obterKpiRendimentoEstimadoMes(UUID usuarioId) {
        List<Caixinha> caixinhasAtivas = buscarCaixinhasAtivasPorUsuario(usuarioId);

        BigDecimal rendimentoEstimadoMes = caixinhasAtivas.stream()
                .map(caixinha -> {
                    BigDecimal valorAtual = eventoFinanceiroRepository.sumValorByCaixinha(caixinha.getId());
                    BigDecimal taxaMensalEfetiva = BigDecimal.valueOf(calcularTaxaMensal(caixinha));
                    return valorAtual.multiply(taxaMensalEfetiva);
                })
                .reduce(BigDecimal.ZERO, BigDecimal::add)
                .setScale(2, RoundingMode.HALF_UP);

        String mesReferencia = YearMonth.now().format(DateTimeFormatter.ofPattern("MM/yyyy"));
        return new KpiRendimentoEstimadoMesCaixinhaDto(rendimentoEstimadoMes, mesReferencia);
    }

    @Transactional(readOnly = true)
    public KpiStatusCaixinhasDto obterKpiStatusCaixinhas(UUID usuarioId) {
        validarUsuario(usuarioId);
        List<Caixinha> todasCaixinhas = caixinhaRepository.findAllByUsuario_Id(usuarioId);

        int quantidadeAtivas = (int) todasCaixinhas.stream()
                .filter(caixinha -> Boolean.TRUE.equals(caixinha.getIsAtiva()))
                .count();
        int quantidadeEncerradas = (int) todasCaixinhas.stream()
                .filter(caixinha -> !Boolean.TRUE.equals(caixinha.getIsAtiva()))
                .count();

        return new KpiStatusCaixinhasDto(quantidadeAtivas, quantidadeEncerradas);
    }

    @Transactional(readOnly = true)
    public GraficoProgressoConsolidadoCaixinhaDto obterGraficoProgressoConsolidado(UUID usuarioId) {
        KpiProgressoGeralCaixinhaDto kpiProgresso = obterKpiProgressoGeral(usuarioId);
        return new GraficoProgressoConsolidadoCaixinhaDto(
                kpiProgresso.percentualProgressoGeral(),
                kpiProgresso.totalAcumulado(),
                kpiProgresso.totalMetas());
    }

    // =========================================================================
    // EDITAR
    // =========================================================================

    /** Edita os dados configuráveis de uma caixinha (não afeta aportes existentes). */
    public CaixinhaResponseDTO editar(UUID caixinhaId, CaixinhaCreateDTO dto) {
        Caixinha caixinha = caixinhaRepository.findById(caixinhaId)
                .orElseThrow(() -> new EntidadeNaoEncontradaException(
                        "Caixinha de id: %s não encontrada.".formatted(caixinhaId)));

        if (dto.getNome() != null) caixinha.setNome(dto.getNome());
        // Permite limpar a descrição passando string vazia
        if (dto.getDescricao() != null) caixinha.setDescricao(dto.getDescricao().isBlank() ? null : dto.getDescricao());
        if (dto.getValorMeta() != null) caixinha.setValorMeta(dto.getValorMeta());
        if (dto.getDataPrazo() != null) caixinha.setDataPrazo(dto.getDataPrazo());
        if (dto.getTipoRendimento() != null) caixinha.setTipoRendimento(dto.getTipoRendimento());
        if (dto.getPercentualRendimento() != null) caixinha.setPercentualRendimento(dto.getPercentualRendimento());
        if (dto.getTaxaAnualPersonalizada() != null) caixinha.setTaxaAnualPersonalizada(dto.getTaxaAnualPersonalizada());
        if (dto.getTaxaReferenciaAtual() != null) caixinha.setTaxaReferenciaAtual(dto.getTaxaReferenciaAtual());

        // Atualiza vínculos de instituição se informados
        if (dto.getInstituicaoUsuarioIds() != null && !dto.getInstituicaoUsuarioIds().isEmpty()) {
            // Remove vínculos antigos
            List<CaixinhaInstituicao> vinculosAtuais = caixinhaInstituicaoRepository.findAllByCaixinha_Id(caixinhaId);
            caixinhaInstituicaoRepository.deleteAll(vinculosAtuais);
            caixinhaInstituicaoRepository.flush();

            // Adiciona novos vínculos
            for (Integer instId : dto.getInstituicaoUsuarioIds()) {
                InstituicaoUsuario inst = instituicaoUsuarioRepository.findById(instId)
                        .orElseThrow(() -> new EntidadeNaoEncontradaException(
                                "InstituicaoUsuario de id: %d nao encontrada.".formatted(instId)));
                CaixinhaInstituicao vinculo = new CaixinhaInstituicao();
                vinculo.setCaixinha(caixinha);
                vinculo.setInstituicaoUsuario(inst);
                caixinhaInstituicaoRepository.save(vinculo);
            }

            caixinha.setIsCompartilhada(dto.getInstituicaoUsuarioIds().size() > 1);
        }

        return calcularEMontar(caixinhaRepository.save(caixinha));
    }

    /** Encerra uma caixinha (marca como inativa). */
    public CaixinhaResponseDTO encerrar(UUID caixinhaId) {
        Caixinha caixinha = caixinhaRepository.findById(caixinhaId)
                .orElseThrow(() -> new EntidadeNaoEncontradaException(
                        "Caixinha de id: %s não encontrada.".formatted(caixinhaId)));
        caixinha.setIsAtiva(false);
        caixinha.setDataEncerramento(LocalDate.now());
        return calcularEMontar(caixinhaRepository.save(caixinha));
    }

    /** Reabre uma caixinha encerrada (desfaz o encerramento). */
    public CaixinhaResponseDTO reabrir(UUID caixinhaId) {
        Caixinha caixinha = caixinhaRepository.findById(caixinhaId)
                .orElseThrow(() -> new EntidadeNaoEncontradaException(
                        "Caixinha de id: %s não encontrada.".formatted(caixinhaId)));
        caixinha.setIsAtiva(true);
        caixinha.setDataEncerramento(null);
        return calcularEMontar(caixinhaRepository.save(caixinha));
    }

    /** Vincula uma nova instituição a uma caixinha compartilhada. */
    public CaixinhaResponseDTO adicionarInstituicao(UUID caixinhaId, Integer instId) {
        Caixinha caixinha = caixinhaRepository.findById(caixinhaId)
                .orElseThrow(() -> new EntidadeNaoEncontradaException(
                        "Caixinha de id: %s não encontrada.".formatted(caixinhaId)));
        if (caixinhaInstituicaoRepository.existsByCaixinha_IdAndInstituicaoUsuario_Id(caixinhaId, instId)) {
            throw new IllegalArgumentException("Instituição já vinculada a esta caixinha.");
        }
        InstituicaoUsuario inst = instituicaoUsuarioRepository.findById(instId)
                .orElseThrow(() -> new EntidadeNaoEncontradaException(
                        "InstituicaoUsuario de id: %d não encontrada.".formatted(instId)));
        CaixinhaInstituicao vinculo = new CaixinhaInstituicao();
        vinculo.setCaixinha(caixinha);
        vinculo.setInstituicaoUsuario(inst);
        caixinhaInstituicaoRepository.save(vinculo);
        caixinha.setIsCompartilhada(true);
        return calcularEMontar(caixinhaRepository.save(caixinha));
    }

    // =========================================================================
    // DELETAR
    // =========================================================================

    public void deletar(UUID caixinhaId) {
        if (!caixinhaRepository.existsById(caixinhaId)) {
            throw new EntidadeNaoEncontradaException(
                    "Caixinha de id: %s não encontrada.".formatted(caixinhaId));
        }
        // Desvincula EventoFinanceiro antes de deletar para evitar violação de FK
        List<EventoFinanceiro> aportes = eventoFinanceiroRepository.findAllByCaixinha_Id(caixinhaId);
        aportes.forEach(e -> e.setCaixinha(null));
        eventoFinanceiroRepository.saveAll(aportes);
        eventoFinanceiroRepository.flush();

        caixinhaRepository.deleteById(caixinhaId);
    }

    // =========================================================================
    // CÁLCULOS FINANCEIROS (acesso package para uso no EmailService)
    // =========================================================================

    /**
     * Monta o DTO de resposta completo com todos os cálculos aplicados.
     */
    CaixinhaResponseDTO calcularEMontar(Caixinha c) {
        CaixinhaResponseDTO dto = new CaixinhaResponseDTO();

        // Dados básicos
        dto.setId(c.getId());
        dto.setNome(c.getNome());
        dto.setDescricao(c.getDescricao());
        dto.setIsAtiva(c.getIsAtiva());
        dto.setIsCompartilhada(c.getIsCompartilhada());
        dto.setDataCriacao(c.getDataCriacao());
        dto.setDataEncerramento(c.getDataEncerramento());
        dto.setValorMeta(c.getValorMeta());
        dto.setDataPrazo(c.getDataPrazo());
        dto.setTipoRendimento(c.getTipoRendimento());
        dto.setPercentualRendimento(c.getPercentualRendimento());
        dto.setTaxaAnualPersonalizada(c.getTaxaAnualPersonalizada());
        dto.setTaxaReferenciaAtual(c.getTaxaReferenciaAtual());

        // Valor atual = soma dos aportes registrados
        BigDecimal valorAtual = eventoFinanceiroRepository.sumValorByCaixinha(c.getId());
        dto.setValorAtual(valorAtual);

        // Progresso em relação à meta
        if (c.getValorMeta() != null && c.getValorMeta().compareTo(BigDecimal.ZERO) > 0) {
            BigDecimal falta = c.getValorMeta().subtract(valorAtual).max(BigDecimal.ZERO);
            dto.setFaltaParaMeta(falta);
            double pct = valorAtual.divide(c.getValorMeta(), 6, RoundingMode.HALF_UP)
                                   .multiply(BigDecimal.valueOf(100))
                                   .doubleValue();
            dto.setPercentualAtingido(Math.min(pct, 100.0));
        }

        // Taxa mensal efetiva
        double taxaMensal = calcularTaxaMensal(c);
        dto.setTaxaMensalEfetiva(taxaMensal);

        // Projeções com prazo
        if (c.getDataPrazo() != null && c.getDataPrazo().isAfter(LocalDate.now())) {
            int meses = (int) Period.between(LocalDate.now(), c.getDataPrazo()).toTotalMonths();
            dto.setMesesRestantes(meses);

            if (meses > 0) {
                double vp = valorAtual.doubleValue();
                double fatorN = Math.pow(1 + taxaMensal, meses);

                // Montante sem novos aportes: VP × (1+r)^n
                double montanteSemAportes = vp * fatorN;
                dto.setMontanteProjetadoSemAportes(
                        BigDecimal.valueOf(montanteSemAportes).setScale(2, RoundingMode.HALF_UP));

                // Aporte mensal sugerido (PMT)
                if (c.getValorMeta() != null) {
                    double vf = c.getValorMeta().doubleValue();
                    double pmt;
                    if (taxaMensal < 1e-10) {
                        // Taxa zero: divisão simples
                        pmt = Math.max(0, (vf - vp)) / meses;
                    } else {
                        pmt = Math.max(0, (vf - vp * fatorN) * taxaMensal / (fatorN - 1));
                    }
                    dto.setAporteMensalSugerido(
                            BigDecimal.valueOf(pmt).setScale(2, RoundingMode.HALF_UP));

                    // Montante com aportes: VP×(1+r)^n + PMT×[(1+r)^n − 1]/r
                    double montanteComAportes;
                    if (taxaMensal < 1e-10) {
                        montanteComAportes = vp + pmt * meses;
                    } else {
                        montanteComAportes = vp * fatorN + pmt * (fatorN - 1) / taxaMensal;
                    }
                    dto.setMontanteProjetadoComAportes(
                            BigDecimal.valueOf(montanteComAportes).setScale(2, RoundingMode.HALF_UP));

                    dto.setMetaAlcancavel(montanteComAportes >= vf - 0.01);
                }
            }
        }

        // Instituições com valor aportado por cada uma
        List<CaixinhaResponseDTO.InstituicaoDTO> instDtos = new ArrayList<>();
        List<CaixinhaInstituicao> vinculos = caixinhaInstituicaoRepository.findAllByCaixinha_Id(c.getId());
        for (CaixinhaInstituicao vi : vinculos) {
            List<EventoFinanceiro> eventosDaInst = eventoFinanceiroRepository
                    .findAllByCaixinha_Id(c.getId()).stream()
                    .filter(e -> e.getEventoInstituicoes() != null &&
                                 e.getEventoInstituicoes().stream()
                                   .anyMatch(ei -> ei.getInstituicaoUsuario().getId()
                                                     .equals(vi.getInstituicaoUsuario().getId())))
                    .toList();
            BigDecimal aportadoNaInst = eventosDaInst.stream()
                    .map(e -> BigDecimal.valueOf(e.getValor()))
                    .reduce(BigDecimal.ZERO, BigDecimal::add);

            CaixinhaResponseDTO.InstituicaoDTO iDto = new CaixinhaResponseDTO.InstituicaoDTO();
            iDto.setId(vi.getInstituicaoUsuario().getId());
            iDto.setNome(vi.getInstituicaoUsuario().getInstituicao().getNome());
            iDto.setValorAportado(aportadoNaInst);
            instDtos.add(iDto);
        }
        dto.setInstituicoes(instDtos);

        return dto;
    }

    /**
     * Calcula a taxa mensal efetiva a partir da configuração da caixinha.
     *
     * <ul>
     *   <li>CDI: taxaReferenciaAtual × (percentualRendimento / 100) / 12 (simplificado)</li>
     *   <li>SELIC: igual ao CDI</li>
     *   <li>POUPANÇA: 70% da SELIC + 0% TR simplificado</li>
     *   <li>PREFIXADO / PERSONALIZADO: taxa anual → mensal composto</li>
     * </ul>
     */
    private double calcularTaxaMensal(Caixinha c) {
        if (c.getTipoRendimento() == null) {
            return 0.0;
        }

        double taxaAnualPercent;

        switch (c.getTipoRendimento()) {
            case CDI, SELIC -> {
                if (c.getTaxaReferenciaAtual() == null) {
                    taxaAnualPercent = 0.0;
                    break;
                }
                double referencia = c.getTaxaReferenciaAtual(); // % a.a.
                double percentual = c.getPercentualRendimento() != null
                        ? c.getPercentualRendimento() / 100.0 : 1.0;
                taxaAnualPercent = referencia * percentual;
            }
            case POUPANCA -> {
                if (c.getTaxaReferenciaAtual() == null) {
                    taxaAnualPercent = 0.0;
                    break;
                }
                // Regra atual da poupança: 70% da SELIC quando SELIC > 8,5% a.a.
                taxaAnualPercent = c.getTaxaReferenciaAtual() * 0.70;
            }
            case PREFIXADO, PERSONALIZADO -> {
                taxaAnualPercent = c.getTaxaAnualPersonalizada() != null
                        ? c.getTaxaAnualPersonalizada() : 0.0;
            }
            default -> taxaAnualPercent = 0.0;
        }

        // Converte % a.a. para decimal mensal via juros compostos: (1 + i_a)^(1/12) - 1
        return Math.pow(1 + taxaAnualPercent / 100.0, 1.0 / 12.0) - 1;
    }

    // =========================================================================
    // PRIVADO
    // =========================================================================

    // =========================================================================
    // PRIVADO
    // =========================================================================

    /**
     * Verifica se a caixinha atingiu o percentual de meta configurado pelo usuario
     * e envia o alerta de e-mail (uma vez por mes).
     */
    private void verificarEEnviarAlertaMeta(Caixinha caixinha, CaixinhaResponseDTO dto) {
        try {
            if (dto.getPercentualAtingido() == null || caixinha.getValorMeta() == null) return;

            configuracoesRepository.findConfiguracoesByUsuario_Id(caixinha.getUsuario().getId())
                    .ifPresent(config -> {
                        if (!config.getAlertasEmailAtivos().contains(TipoAlertaEmail.ALERTA_META_POUPANCA)) return;

                        int threshold = config.getPercentualAlertaMeta() != null
                                ? config.getPercentualAlertaMeta() : 90;

                        if (dto.getPercentualAtingido() < threshold) return;

                        // Ja enviou este mes?
                        LocalDate hoje = java.time.LocalDate.now();
                        if (config.getUltimoAlertaMetaEnviado() != null
                                && config.getUltimoAlertaMetaEnviado().getMonth() == hoje.getMonth()
                                && config.getUltimoAlertaMetaEnviado().getYear() == hoje.getYear()) {
                            return;
                        }

                        emailService.enviarAlertaMetaPoupanca(
                                caixinha.getUsuario(),
                                caixinha.getNome(),
                                dto.getValorAtual(),
                                caixinha.getValorMeta(),
                                dto.getPercentualAtingido());

                        config.setUltimoAlertaMetaEnviado(hoje);
                        configuracoesRepository.save(config);
                    });
        } catch (Exception e) {
            log.warn("[CaixinhaService] Erro ao verificar alerta de meta: {}", e.getMessage());
        }
    }

    private void validarUsuario(UUID usuarioId) {
        if (!usuarioRepository.existsById(usuarioId)) {
            throw new EntidadeNaoEncontradaException(
                    "Usuário de id: %s não encontrado.".formatted(usuarioId));
        }
    }

    private List<Caixinha> buscarCaixinhasAtivasPorUsuario(UUID usuarioId) {
        validarUsuario(usuarioId);
        return caixinhaRepository.findAllByUsuario_IdAndIsAtivaTrue(usuarioId);
    }

    private BigDecimal somarMetasDasCaixinhas(List<Caixinha> caixinhas) {
        return caixinhas.stream()
                .map(Caixinha::getValorMeta)
                .filter(valorMeta -> valorMeta != null)
                .reduce(BigDecimal.ZERO, BigDecimal::add);
    }
}

package controle.api.back_end.strategy.eventoFinanceiro;

import controle.api.back_end.model.eventoFinanceiro.EventoDetalhe;
import controle.api.back_end.model.eventoFinanceiro.EventoFinanceiro;
import controle.api.back_end.model.eventoFinanceiro.EventoInstituicao;
import controle.api.back_end.model.eventoFinanceiro.Tipo;
import org.springframework.stereotype.Component;

import java.time.LocalDateTime;
import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

@Component
public class PoupancaEvento implements EventoFinanceiroStrategy {

    @Override
    public Registro processar(EventoFinanceiro evento,
                              List<EventoInstituicao> eventoInstituicoes,
                              EventoDetalhe eventoDetalhe) {

        List<EventoFinanceiro> eventos = new ArrayList<>();
        Map<EventoFinanceiro, List<EventoInstituicao>> instituicoesPorEvento = new HashMap<>();
        Map<EventoFinanceiro, EventoDetalhe> detalhePorEvento = new HashMap<>();

        // 1. Evento inicial (aplicação)
        EventoFinanceiro aplicacao = new EventoFinanceiro();
        aplicacao.setUsuario(evento.getUsuario());
        aplicacao.setTipo(Tipo.Poupanca);
        aplicacao.setValor(evento.getValor());
        aplicacao.setDescricao("Aplicação em poupança");
        aplicacao.setDataEvento(evento.getDataEvento());
        aplicacao.setDataRegistro(LocalDateTime.now());
        eventos.add(aplicacao);

        // Instituições vinculadas à aplicação
        List<EventoInstituicao> instsAplicacao = new ArrayList<>();
        if (!eventoInstituicoes.isEmpty()) {
            EventoInstituicao instAplicacao = eventoInstituicoes.getFirst();
            instAplicacao.setEventoFinanceiro(aplicacao);
            instAplicacao.setValor(evento.getValor());
            instAplicacao.setParcelas(1);
            instsAplicacao.add(instAplicacao);
        }
        instituicoesPorEvento.put(aplicacao, instsAplicacao);

        // Detalhe único vinculado à aplicação
        if (eventoDetalhe != null) {
            eventoDetalhe.setEventoFinanceiro(aplicacao);
            detalhePorEvento.put(aplicacao, eventoDetalhe);
        }

        // 2. Projeção de rendimento
        double principal = evento.getValor();
        double taxa = evento.getTaxaRendimento(); // informado pelo usuário
        int tempoProjecao = evento.getTempoProjecao();   // em meses

        for (int mes = 1; mes <= tempoProjecao; mes++) {
            double montante = principal * Math.pow(1 + taxa, mes);
            double rendimento = montante - principal;

            EventoFinanceiro rendimentoEvento = new EventoFinanceiro();
            rendimentoEvento.setUsuario(evento.getUsuario());
            rendimentoEvento.setTipo(Tipo.Recebimento);
            rendimentoEvento.setValor(rendimento);
            rendimentoEvento.setDescricao("Rendimento projetado mês " + mes);
            rendimentoEvento.setDataEvento(evento.getDataEvento().plusMonths(mes));
            rendimentoEvento.setDataRegistro(LocalDateTime.now());
            eventos.add(rendimentoEvento);

            // Instituições vinculadas ao rendimento
            List<EventoInstituicao> instsRendimento = new ArrayList<>();
            if (!eventoInstituicoes.isEmpty()) {
                EventoInstituicao instRendimento = new EventoInstituicao();
                instRendimento.setEventoFinanceiro(rendimentoEvento);
                instRendimento.setInstituicaoUsuario(eventoInstituicoes.getFirst().getInstituicaoUsuario());
                instRendimento.setValor(rendimento);
                instRendimento.setParcelas(1);
                instsRendimento.add(instRendimento);
            }
            instituicoesPorEvento.put(rendimentoEvento, instsRendimento);

            // Detalhe único vinculado ao rendimento (se necessário)
            if (eventoDetalhe != null) {
                detalhePorEvento.put(rendimentoEvento, eventoDetalhe);
            }
        }

        // 3. Retornar registro completo
        return new Registro(eventos, instituicoesPorEvento, detalhePorEvento);
    }
}

package controle.api.back_end.strategy.eventoFinanceiro;

import controle.api.back_end.model.eventoFinanceiro.EventoDetalhe;
import controle.api.back_end.model.eventoFinanceiro.EventoFinanceiro;
import controle.api.back_end.model.eventoFinanceiro.EventoInstituicao;
import controle.api.back_end.model.eventoFinanceiro.Tipo;
import org.springframework.stereotype.Component;

import java.time.LocalDateTime;
import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

@Component
public class PoupancaEvento implements EventoFinanceiroStrategy {

    @Override
    public Registro processar(EventoFinanceiro evento,
                              List<EventoInstituicao> eventoInstituicoes,
                              EventoDetalhe eventoDetalhe) {

        List<EventoFinanceiro> eventos = new ArrayList<>();
        Map<EventoFinanceiro, List<EventoInstituicao>> instituicoesPorEvento = new HashMap<>();
        Map<EventoFinanceiro, EventoDetalhe> detalhePorEvento = new HashMap<>();

        // 1. Evento inicial (aplicação)
        EventoFinanceiro aplicacao = new EventoFinanceiro();
        aplicacao.setUsuario(evento.getUsuario());
        aplicacao.setTipo(Tipo.Poupanca);
        aplicacao.setValor(evento.getValor());
        aplicacao.setDescricao("Aplicação em poupança");
        aplicacao.setDataEvento(evento.getDataEvento());
        aplicacao.setDataRegistro(LocalDateTime.now());
        // Vincular à caixinha, se informada
        if (evento.getCaixinha() != null) {
            aplicacao.setCaixinha(evento.getCaixinha());
        }
        eventos.add(aplicacao);

        // Instituições vinculadas à aplicação
        List<EventoInstituicao> instsAplicacao = new ArrayList<>();
        if (!eventoInstituicoes.isEmpty()) {
            EventoInstituicao instAplicacao = eventoInstituicoes.getFirst();
            instAplicacao.setEventoFinanceiro(aplicacao);
            instAplicacao.setValor(evento.getValor());
            instAplicacao.setParcelas(1);
            instsAplicacao.add(instAplicacao);
        }
        instituicoesPorEvento.put(aplicacao, instsAplicacao);

        // Detalhe único vinculado à aplicação
        if (eventoDetalhe != null) {
            eventoDetalhe.setEventoFinanceiro(aplicacao);
            detalhePorEvento.put(aplicacao, eventoDetalhe);
        }

        // 2. Projeção de rendimento (opcional — só executa se taxa e prazo foram informados)
        Double taxaRaw    = evento.getTaxaRendimento();
        Integer tempoRaw  = evento.getTempoProjecao();
        double taxa       = (taxaRaw != null) ? taxaRaw : 0.0;
        int tempoProjecao = (tempoRaw != null) ? tempoRaw : 0;

        if (taxa > 0 && tempoProjecao > 0) {
            double principal = evento.getValor();
            for (int mes = 1; mes <= tempoProjecao; mes++) {
                double montante  = principal * Math.pow(1 + taxa, mes);
                double rendimento = montante - principal;

                EventoFinanceiro rendimentoEvento = new EventoFinanceiro();
                rendimentoEvento.setUsuario(evento.getUsuario());
                rendimentoEvento.setTipo(Tipo.Recebimento);
                rendimentoEvento.setValor(rendimento);
                rendimentoEvento.setDescricao("Rendimento projetado mês " + mes);
                rendimentoEvento.setDataEvento(evento.getDataEvento().plusMonths(mes));
                rendimentoEvento.setDataRegistro(LocalDateTime.now());
                eventos.add(rendimentoEvento);

                // Instituições vinculadas ao rendimento
                List<EventoInstituicao> instsRendimento = new ArrayList<>();
                if (!eventoInstituicoes.isEmpty()) {
                    EventoInstituicao instRendimento = new EventoInstituicao();
                    instRendimento.setEventoFinanceiro(rendimentoEvento);
                    instRendimento.setInstituicaoUsuario(eventoInstituicoes.getFirst().getInstituicaoUsuario());
                    instRendimento.setValor(rendimento);
                    instRendimento.setParcelas(1);
                    instsRendimento.add(instRendimento);
                }
                instituicoesPorEvento.put(rendimentoEvento, instsRendimento);
            }
        }

        // 3. Retornar registro completo
        return new Registro(eventos, instituicoesPorEvento, detalhePorEvento);
    }
}

const _divAlerta = document.getElementById('div_alerta');
if (_divAlerta) _divAlerta.style.display = 'none';

// Máscara monetária (aplicada depois do DOM carregar via gerarInformacoes)
let dataGasto;
const usuarioLogado = JSON.parse(localStorage.getItem("usuarioLogado") || "null");
const userId = usuarioLogado ? usuarioLogado.id : null;
let _alertaTimer = null;

/* ══════════════════════════════════════════════════
   Alertas
══════════════════════════════════════════════════ */
function habilitarFecharAlertaAoClicarFora() {
    const divAl = document.getElementById("div_alerta");
    const contAl = document.getElementById("conteudoAlerta");
    if (!divAl || !contAl || divAl.dataset.closeOutsideBound === "1") return;
    divAl.dataset.closeOutsideBound = "1";
    divAl.addEventListener("click", (event) => {
        if (event.target === divAl) {
            divAl.style.display = "none";
            if (_alertaTimer) { clearTimeout(_alertaTimer); _alertaTimer = null; }
        }
    });
}

function alerta(texto, duracaoMs = 4000) {
    const divAl = document.getElementById("div_alerta");
    const contAl = document.getElementById("conteudoAlerta");
    habilitarFecharAlertaAoClicarFora();
    if (divAl) divAl.style.display = "flex";
    if (contAl) contAl.innerHTML = texto;
    if (_alertaTimer) clearTimeout(_alertaTimer);
    if (duracaoMs > 0) {
        _alertaTimer = setTimeout(() => {
            if (divAl) divAl.style.display = "none";
            _alertaTimer = null;
        }, duracaoMs);
    }
}

/* ══════════════════════════════════════════════════
   Clear-on-focus (campos mantidos após registro)
══════════════════════════════════════════════════ */
function setupClearOnFocus() {
    const ids = ['ipt_nome','ipt_valor','ipt_desc','ipt_multi_nome','ipt_multi_valor','ipt_multi_desc'];
    ids.forEach(id => {
        const el = document.getElementById(id);
        if (!el) return;
        el.addEventListener('focus', function () {
            if (this.dataset.pendingClear !== 'true') return;
            if (this.id === 'ipt_valor' || this.id === 'ipt_multi_valor') {
                if (window.MainAPI && window.MainAPI.resetarMascaraMoeda) {
                    window.MainAPI.resetarMascaraMoeda(this);
                } else {
                    this.value = '';
                }
            } else {
                this.value = '';
            }
            delete this.dataset.pendingClear;
            this.classList.remove('ar-field-submitted');
        });
    });
}

function markFieldsForClear(ids) {
    ids.forEach(id => {
        const el = document.getElementById(id);
        if (el && el.value) {
            el.dataset.pendingClear = 'true';
            el.classList.add('ar-field-submitted');
        }
    });
}

/* ══════════════════════════════════════════════════
   Tag Picker system
══════════════════════════════════════════════════ */
const _tp = {}; // id -> { options, selected, placeholder, onchange }

function initTagPicker(id, options, placeholder, onchange) {
    if (_tp[id]) {
        // Reload: preserve selected, update options
        _tp[id].options = options;
        _tp[id].selected = _tp[id].selected.filter(s =>
            options.some(o => String(o.id) === String(s.id))
        );
        if (onchange) _tp[id].onchange = onchange;
    } else {
        _tp[id] = { options, selected: [], placeholder: placeholder || 'Selecionar...', onchange: onchange || null };
    }
    _renderTagPicker(id);
}

function openTagPicker(event, id) {
    event.stopPropagation();
    const dd = document.getElementById('tp-dd-' + id);
    const display = dd ? dd.previousElementSibling : null;
    if (!dd) return;
    const isOpen = dd.style.display !== 'none';
    // Close all
    document.querySelectorAll('.ar-tp-dd').forEach(el => {
        el.style.display = 'none';
        if (el.previousElementSibling) el.previousElementSibling.classList.remove('open');
    });
    if (!isOpen) {
        dd.style.display = '';
        if (display) display.classList.add('open');
    }
}

function _toggleTagItem(id, itemId, itemLabel) {
    const state = _tp[id];
    if (!state) return;
    const idx = state.selected.findIndex(s => String(s.id) === String(itemId));
    if (idx >= 0) {
        state.selected.splice(idx, 1);
    } else {
        state.selected.push({ id: itemId, label: itemLabel });
    }
    _renderTagPicker(id);
    if (state.onchange) state.onchange(state.selected);
}

function _removeTagItem(id, itemId) {
    const state = _tp[id];
    if (!state) return;
    state.selected = state.selected.filter(s => String(s.id) !== String(itemId));
    _renderTagPicker(id);
    if (state.onchange) state.onchange(state.selected);
}

function _renderTagPicker(id) {
    const state = _tp[id];
    const tagsEl = document.getElementById('tp-tags-' + id);
    const ddEl   = document.getElementById('tp-dd-'   + id);
    if (!tagsEl || !ddEl) return;

    // Tags display
    if (state.selected.length === 0) {
        tagsEl.innerHTML = `<span class="ar-tp-ph">${state.placeholder}</span>`;
    } else {
        tagsEl.innerHTML = state.selected.map(s =>
            `<span class="ar-tp-tag">${s.label}<button type="button" class="ar-tp-tag-rm"
                onclick="event.stopPropagation();_removeTagItem('${id}','${s.id}')">×</button></span>`
        ).join('');
    }

    // Dropdown options
    ddEl.innerHTML = '';
    state.options.forEach(opt => {
        const sel = state.selected.some(s => String(s.id) === String(opt.id));
        const btn = document.createElement('button');
        btn.type = 'button';
        btn.className = 'ar-tp-option' + (sel ? ' ar-tp-option-sel' : '');
        const check = document.createElement('span');
        check.className = 'ar-tp-opt-check';
        check.textContent = sel ? '✓' : '';
        btn.appendChild(check);
        btn.appendChild(document.createTextNode(opt.label));
        btn.addEventListener('click', e => {
            e.stopPropagation();
            _toggleTagItem(id, opt.id, opt.label);
        });
        ddEl.appendChild(btn);
    });
}

// Close all dropdowns when clicking outside
document.addEventListener('click', () => {
    document.querySelectorAll('.ar-tp-dd').forEach(dd => {
        dd.style.display = 'none';
        if (dd.previousElementSibling) dd.previousElementSibling.classList.remove('open');
    });
});

/* ── Institution amounts handler ── */
function _onInstChange(pickerId, selected) {
    const amountsId   = pickerId === 'inst' ? 'inst-amounts'   : 'm-inst-amounts';
    const wrapValorId = pickerId === 'inst' ? 'wrap_valor'      : 'wrap_multi_valor';

    const amountsEl   = document.getElementById(amountsId);
    const wrapValorEl = document.getElementById(wrapValorId);

    if (selected.length > 1) {
        // Esconde o campo de valor único
        if (wrapValorEl) wrapValorEl.style.display = 'none';

        // Mostra painel de valor por instituição
        if (amountsEl) {
            amountsEl.style.display = '';
            // Mantém o título, remove linhas antigas
            while (amountsEl.children.length > 1) amountsEl.removeChild(amountsEl.lastChild);
            selected.forEach(s => {
                const row = document.createElement('div');
                row.className = 'ar-inst-amount-row';
                const nameEl = document.createElement('span');
                nameEl.className = 'ar-inst-name';
                nameEl.textContent = s.label;
                const inp = document.createElement('input');
                inp.type = 'text';
                inp.id = `inst-amt-${pickerId}-${s.id}`;
                inp.className = 'ar-inst-amt-input';
                inp.setAttribute('inputmode', 'numeric');
                inp.setAttribute('autocomplete', 'off');
                row.appendChild(nameEl);
                row.appendChild(inp);
                amountsEl.appendChild(row);
                // Aplica máscara APÓS o elemento estar no DOM
                if (window.MainAPI && window.MainAPI.aplicarMascaraMoeda) {
                    window.MainAPI.aplicarMascaraMoeda(inp);
                }
            });
        }
    } else {
        // Mostra o campo de valor único novamente
        if (wrapValorEl) wrapValorEl.style.display = '';

        // Esconde painel de valor por instituição
        if (amountsEl) {
            amountsEl.style.display = 'none';
            while (amountsEl.children.length > 1) amountsEl.removeChild(amountsEl.lastChild);
        }
    }

    // Saldo display (formulário único apenas)
    if (pickerId === 'inst') {
        if (selected.length === 1) {
            atualizarSaldoDisplay(selected[0].id);
        } else {
            const saldoEl = document.getElementById('saldo_display');
            if (saldoEl) saldoEl.style.display = 'none';
        }
    }
}

/* ══════════════════════════════════════════════════
   Recurring section
══════════════════════════════════════════════════ */
let _isRecorrente = false;
let _periodicidade = null;
let _diasSemana    = [];
let _diaMes        = null;
let _mesAnual      = null;
let _diaAnual      = null;
let _dataFimRecorrente = null;

// Mapeamento: índice do botão DOM (0=Dom, 1=Seg, …, 6=Sáb) → DayOfWeek do Java
const _DOW_MAP = ['SUNDAY','MONDAY','TUESDAY','WEDNESDAY','THURSDAY','FRIDAY','SATURDAY'];
const _DOW_LABEL = ['Dom','Seg','Ter','Qua','Qui','Sex','Sáb'];
const _MESES_LABEL = ['Jan','Fev','Mar','Abr','Mai','Jun','Jul','Ago','Set','Out','Nov','Dez'];

function _atualizarResumoRecorrencia() {
    const el = document.getElementById('ar-recorrente-resumo');
    if (!el) return;
    if (!_isRecorrente || !_periodicidade) { el.style.display = 'none'; el.textContent = ''; return; }
    const partes = [_periodicidade.charAt(0).toUpperCase() + _periodicidade.slice(1)];
    if (_periodicidade === 'semanal' && _diasSemana.length > 0)
        partes.push(_diasSemana.map(d => _DOW_LABEL[d]).join(', '));
    if (_periodicidade === 'mensal' && _diaMes)
        partes.push(`Dia ${_diaMes}`);
    if (_periodicidade === 'anual') {
        if (_mesAnual) partes.push(_MESES_LABEL[_mesAnual - 1]);
        if (_diaAnual) partes.push(`Dia ${_diaAnual}`);
    }
    if (_dataFimRecorrente) partes.push(`até ${_dataFimRecorrente.split('-').reverse().join('/')}`);
    el.textContent = partes.join(' · ');
    el.style.display = '';
}

function toggleRecorrente() {
    _isRecorrente = !_isRecorrente;
    if (!_isRecorrente) {
        _periodicidade = null; _diasSemana = []; _diaMes = null; _mesAnual = null; _diaAnual = null; _dataFimRecorrente = null;
        const fim = document.getElementById('rec-data-fim');
        if (fim) fim.value = '';
        _atualizarResumoRecorrencia();
    }    const btn  = document.getElementById('ar-recorrente-btn');
    const icon = document.getElementById('ar-recorrente-icon');
    const opts = document.getElementById('recurring-options');
    if (btn)  btn.classList.toggle('active', _isRecorrente);
    if (icon) icon.style.display = _isRecorrente ? '' : 'none';
    if (opts) opts.style.display = _isRecorrente ? '' : 'none';
    if (!_isRecorrente) {
        ['rec-semanal','rec-mensal','rec-anual'].forEach(id => {
            const el = document.getElementById(id);
            if (el) el.style.display = 'none';
        });
        document.querySelectorAll('.ar-pill[data-period]').forEach(p => p.classList.remove('active'));
    }
}

function setPeriodicity(p) {
    _periodicidade = p;
    _diasSemana = []; _diaMes = null; _mesAnual = null; _diaAnual = null;
    document.querySelectorAll('.ar-pill[data-period]').forEach(pill =>
        pill.classList.toggle('active', pill.dataset.period === p)
    );
    document.getElementById('rec-semanal').style.display = p === 'semanal' ? '' : 'none';
    document.getElementById('rec-mensal').style.display  = p === 'mensal'  ? '' : 'none';
    document.getElementById('rec-anual').style.display   = p === 'anual'   ? '' : 'none';
    document.querySelectorAll('.ar-pill[data-day]').forEach(p => p.classList.remove('active'));
    document.querySelectorAll('#rec-mensal-days .ar-pill').forEach(p => p.classList.remove('active'));
    document.querySelectorAll('#rec-anual-months .ar-pill').forEach(p => p.classList.remove('active'));
    _atualizarResumoRecorrencia();
}

function toggleWeekDay(day) {
    const idx = _diasSemana.indexOf(day);
    if (idx >= 0) _diasSemana.splice(idx, 1); else _diasSemana.push(day);
    const pill = document.querySelector(`.ar-pill[data-day="${day}"]`);
    if (pill) pill.classList.toggle('active', _diasSemana.includes(day));
    _atualizarResumoRecorrencia();
}

function setMonthDay(day) {
    _diaMes = (_diaMes === day) ? null : day;
    document.querySelectorAll('#rec-mensal-days .ar-pill').forEach(p =>
        p.classList.toggle('active', Number(p.dataset.monthday) === _diaMes)
    );
    _atualizarResumoRecorrencia();
}

function setAnnualMonth(month) {
    _mesAnual = (_mesAnual === month) ? null : month;
    document.querySelectorAll('#rec-anual-months .ar-pill').forEach(p =>
        p.classList.toggle('active', Number(p.dataset.annualmonth) === _mesAnual)
    );
    _atualizarResumoRecorrencia();
}

function _initRecurringSubOptions() {
    // Monthly days 1-31
    const mensal = document.getElementById('rec-mensal-days');
    if (mensal && mensal.children.length === 0) {
        for (let d = 1; d <= 31; d++) {
            const btn = document.createElement('button');
            btn.type = 'button';
            btn.className = 'ar-pill ar-pill-sm';
            btn.dataset.monthday = d;
            btn.textContent = d;
            btn.addEventListener('click', () => setMonthDay(d));
            mensal.appendChild(btn);
        }
    }
    // Annual months
    const MONTHS = ['Jan','Fev','Mar','Abr','Mai','Jun','Jul','Ago','Set','Out','Nov','Dez'];
    const anualMonths = document.getElementById('rec-anual-months');
    if (anualMonths && anualMonths.children.length === 0) {
        MONTHS.forEach((m, i) => {
            const btn = document.createElement('button');
            btn.type = 'button';
            btn.className = 'ar-pill';
            btn.dataset.annualmonth = i + 1;
            btn.textContent = m;
            btn.addEventListener('click', () => setAnnualMonth(i + 1));
            anualMonths.appendChild(btn);
        });
    }
    // Annual day select
    const anualDay = document.getElementById('rec-anual-day');
    if (anualDay && anualDay.options.length <= 1) {
        for (let d = 1; d <= 31; d++) {
            const opt = document.createElement('option');
            opt.value = d; opt.textContent = `Dia ${d}`;
            anualDay.appendChild(opt);
        }
        anualDay.addEventListener('change', () => { _diaAnual = anualDay.value ? parseInt(anualDay.value) : null; });
    }

    // Campo de data final da recorrência — mesmo estilo da tela de filtros (dd/mm/aaaa)
    const recurringOpts = document.getElementById('recurring-options');
    if (recurringOpts && !document.getElementById('rec-data-fim')) {
        const grp = document.createElement('div');
        grp.className = 'ar-recurring-group';
        grp.id = 'rec-data-fim-group';
        grp.innerHTML = `
            <span class="ar-group-label">Data final da recorrência</span>
            <div style="margin-top:6px;display:flex;align-items:center;gap:8px;">
                <input type="text" id="rec-data-fim" class="ar-select-small"
                       placeholder="dd/mm/aaaa" maxlength="10" inputmode="numeric"
                       style="min-width:180px;max-width:220px;cursor:text;">
            </div>
        `;
        recurringOpts.appendChild(grp);

        const inputDataFim = document.getElementById('rec-data-fim');
        // Aplica a mesma máscara usada no filtro de registros
        if (window.MainAPI && window.MainAPI.aplicarMascaraData) {
            window.MainAPI.aplicarMascaraData(inputDataFim);
        }
        // Converte dd/mm/aaaa → aaaa-mm-dd para o backend
        inputDataFim.addEventListener('input', function () {
            _dataFimRecorrente = (window.MainAPI && window.MainAPI.dataParaISO)
                ? window.MainAPI.dataParaISO(this.value)
                : null;
            _atualizarResumoRecorrencia();
        });
    }
} // fim _initRecurringSubOptions

/* ══════════════════════════════════════════════════
   Painel de Poupança (Caixinha)
══════════════════════════════════════════════════ */
let _caixinhas = [];
let _caixinhaSelecionadaId = null;

async function _carregarCaixinhas() {
    if (!userId) return;
    try {
        _caixinhas = await MainAPI.getCaixinhas(userId);
    } catch (e) {
        _caixinhas = [];
    }
}

function _renderPainelPoupanca(show) {
    let painel = document.getElementById('ar-poupanca-painel');
    if (!show) {
        if (painel) painel.style.display = 'none';
        _caixinhaSelecionadaId = null;
        return;
    }
    if (!painel) {
        // Cria o painel dinamicamente na primeira vez
        painel = document.createElement('div');
        painel.id = 'ar-poupanca-painel';
        painel.className = 'ar-recurring-wrap ar-span-3';
        // Insere após o bloco de tipo de movimento
        const movWrap = document.getElementById('select_movimento')?.closest('.ar-field-wrap');
        if (movWrap && movWrap.parentNode) {
            movWrap.parentNode.insertBefore(painel, movWrap.nextSibling);
        }
    }
    painel.style.display = '';

    if (_caixinhas.length === 0) {
        painel.innerHTML = `
            <div style="background:var(--cor-tinte-suave);border-radius:12px;padding:14px 16px;border:1px solid var(--cor-tinte-borda);">
                <p style="margin:0;color:var(--cor-texto-secundario);font-size:0.92rem;">
                    <i class='bx bx-info-circle' style="color:var(--cor-principal);"></i>
                    Nenhuma caixinha ativa encontrada. 
                    <strong>Registre o aporte mesmo assim</strong> — ele aparecerá como Poupança sem caixinha vinculada.
                </p>
            </div>`;
        _caixinhaSelecionadaId = null;
        return;
    }

    const opts = _caixinhas.map(c => {
        const pct   = c.percentualAtingido != null ? `${c.percentualAtingido.toFixed(1)}%` : '—';
        const prazo = c.dataPrazo ? ` · prazo ${c.dataPrazo}` : '';
        return `<option value="${c.id}">${c.nome} (${pct} atingido${prazo})</option>`;
    }).join('');

    painel.innerHTML = `
        <div style="background:var(--cor-tinte-suave);border-radius:12px;padding:14px 16px;border:1px solid var(--cor-tinte-borda);display:flex;flex-direction:column;gap:10px;">
            <span style="font-size:0.82rem;font-weight:700;color:var(--cor-texto-secundario);text-transform:uppercase;letter-spacing:0.5px;">Vincular a uma Caixinha</span>
            <select id="ar-select-caixinha" style="background:var(--cor-fundo-card);border:1px solid var(--cor-tinte-borda);border-radius:8px;padding:8px 12px;color:var(--cor-texto-principal);font-size:0.95rem;">
                <option value="">Sem caixinha (aporte avulso)</option>
                ${opts}
            </select>
            <div id="ar-caixinha-info" style="display:none;font-size:0.87rem;color:var(--cor-texto-secundario);line-height:1.6;padding:8px 10px;background:var(--cor-fundo-campo);border-radius:8px;"></div>
        </div>`;

    document.getElementById('ar-select-caixinha').addEventListener('change', function () {
        _caixinhaSelecionadaId = this.value || null;
        const info = document.getElementById('ar-caixinha-info');
        if (!_caixinhaSelecionadaId) { info.style.display = 'none'; return; }
        const cx = _caixinhas.find(c => c.id === _caixinhaSelecionadaId);
        if (!cx) { info.style.display = 'none'; return; }
        const fmt = v => v != null ? `R$ ${Number(v).toFixed(2)}` : '—';
        const pct = cx.percentualAtingido != null ? `${cx.percentualAtingido.toFixed(1)}%` : '—';
        info.style.display = '';
        info.innerHTML = `
            <b>${cx.nome}</b><br>
            Meta: <b>${fmt(cx.valorMeta)}</b> · Acumulado: <b>${fmt(cx.valorAtual)}</b> (${pct})<br>
            ${cx.aporteMensalSugerido != null ? `Aporte mensal sugerido: <b style="color:var(--cor-principal)">${fmt(cx.aporteMensalSugerido)}</b>` : ''}
            ${cx.mesesRestantes != null ? ` · ${cx.mesesRestantes} meses restantes` : ''}`;
    });
}

function _onTipoChange() {
    const tipo = document.getElementById('select_tipo')?.value;
    _renderPainelPoupanca(tipo === 'Poupanca');
}

/* ══════════════════════════════════════════════════
   Inicialização
══════════════════════════════════════════════════ */
function gerarInformacoes() {
    // Init tag pickers (empty – options loaded async)
    initTagPicker('inst',   [], 'Escolha instituições...', sel => _onInstChange('inst',   sel));
    initTagPicker('cat',    [], 'Escolha categorias...',   null);
    initTagPicker('m-inst', [], 'Escolha...',              sel => _onInstChange('m-inst', sel));
    initTagPicker('m-cat',  [], 'Escolha...',              null);

    // Apply money mask
    const iV  = document.getElementById('ipt_valor');
    const imV = document.getElementById('ipt_multi_valor');
    if (iV  && window.MainAPI?.aplicarMascaraMoeda) window.MainAPI.aplicarMascaraMoeda(iV);
    if (imV && window.MainAPI?.aplicarMascaraMoeda) window.MainAPI.aplicarMascaraMoeda(imV);

    // Recurring sub-option builders
    _initRecurringSubOptions();

    // Clear-on-focus for text fields
    setupClearOnFocus();

    // Poupança: carrega caixinhas e escuta mudança de tipo
    _carregarCaixinhas();
    const selectTipo = document.getElementById('select_tipo');
    if (selectTipo) selectTipo.addEventListener('change', _onTipoChange);

    // Load data from API
    gerarCategorias();
    gerarInstituicao();
}

async function atualizarSaldoDisplay(instituicaoUsuarioId) {
    const el = document.getElementById('saldo_display');
    if (!el) return;
    if (!instituicaoUsuarioId || instituicaoUsuarioId === '#') { el.style.display = 'none'; return; }
    try {
        const res = await fetch(`http://localhost:8080/instituicoes/saldo/${Number(instituicaoUsuarioId)}`);
        if (!res.ok) { el.style.display = 'none'; return; }
        const saldo = await res.json();
        const valor = Number(saldo);
        el.textContent = `Saldo disponível: R$ ${valor.toFixed(2)}`;
        // Usa variáveis CSS para cores de saldo
        el.style.color = valor <= 0 ? 'var(--red-700)' : 'var(--cor-principal)';
        el.style.display = '';
    } catch (e) { el.style.display = 'none'; }
}

function toggleParcelas(inputId, movimento) {
    const requer = movimento === 'Credito' || movimento === 'Boleto';
    const wrapId = inputId === 'ipt_parcelas' ? 'wrap_parcelas' : 'wrap_multi_parcelas';
    const wrap  = document.getElementById(wrapId);
    const input = document.getElementById(inputId);
    if (wrap)  wrap.style.display  = requer ? '' : 'none';
    if (input && !requer) input.value = '1';
}

function gerarCategorias() {
    if (!userId) return;
    MainAPI.getTipos(userId)
        .then(json => {
            const options = json.map(c => ({ id: c.id, label: c.categoria.titulo }));
            initTagPicker('cat',   options, 'Escolha categorias...');
            initTagPicker('m-cat', options, 'Escolha...');
        })
        .catch(() => alerta("Não foi possível carregar as categorias. Tente novamente."));
}

const gerarTipos = gerarCategorias;

async function gerarInstituicao() {
    if (!userId) return;
    try {
        const json = await MainAPI.getInstituicoes(userId);
        const options = json.map(i => ({ id: i.id, label: i.intituicao.nome }));
        initTagPicker('inst',   options, 'Escolha instituições...', sel => _onInstChange('inst',   sel));
        initTagPicker('m-inst', options, 'Escolha...',              sel => _onInstChange('m-inst', sel));
    } catch (e) {
        alerta("Não foi possível carregar as instituições. Tente novamente.");
    }
}

/* ══════════════════════════════════════════════════
   Registrar (formulário único)
══════════════════════════════════════════════════ */
async function registrar() {
    const valorInput = document.getElementById('ipt_valor');
    const valor      = window.MainAPI ? window.MainAPI.obterValorMoeda(valorInput) : Number(valorInput.value);
    const titulo     = document.getElementById('ipt_nome').value;
    const tipo       = document.getElementById('select_tipo').value;
    const descRaw    = document.getElementById('ipt_desc').value;
    const Desc       = descRaw || 'Nenhuma descrição fornecida';
    const movimento  = document.getElementById('select_movimento').value;
    const parcelas   = Number(document.getElementById('ipt_parcelas').value) || 1;
    const data       = dataGasto;

    const selectedInst = _tp['inst'] ? _tp['inst'].selected : [];
    const selectedCat  = _tp['cat']  ? _tp['cat'].selected  : [];

    if (!data || data === 0)         return alerta("Data inválida");
    if (!titulo)                     return alerta("Título inválido");
    if (tipo === '#')                return alerta("Escolha o tipo do evento");
    if (selectedCat.length === 0)    return alerta("Escolha uma categoria");
    if (selectedInst.length === 0)   return alerta("Escolha uma instituição");
    if (movimento === '#')           return alerta("Escolha o tipo de movimento");
    if ((movimento === 'Credito' || movimento === 'Boleto') && (parcelas < 1 || isNaN(parcelas)))
        return alerta("Informe a quantidade de parcelas (mínimo 1)");

    // Validação de valor: quando múltiplas instituições o campo único fica oculto
    if (selectedInst.length <= 1) {
        if (valor <= 0 || !valor) return alerta("Valor inválido");
    } else {
        const algumValor = selectedInst.some(s => {
            const ai = document.getElementById(`inst-amt-inst-${s.id}`);
            return ai && (window.MainAPI ? window.MainAPI.obterValorMoeda(ai) : 0) > 0;
        });
        if (!algumValor) return alerta("Informe o valor para cada instituição");
    }

    // Verificar saldo quando o tipo exige débito
    if ((tipo === 'Gasto' || tipo === 'Transferencia') && selectedInst.length === 1) {
        try {
            const resSaldo = await fetch(`http://localhost:8080/instituicoes/saldo/${Number(selectedInst[0].id)}`);
            if (resSaldo.ok) {
                const saldo = await resSaldo.json();
                if (Number(saldo) < valor)
                    return alerta(`Saldo insuficiente. Disponível: R$ ${Number(saldo).toFixed(2)}`);
            }
        } catch (e) { console.warn("Não foi possível verificar saldo:", e); }
    }

    // Montar lista de instituições (com valor individual quando múltiplas)
    const instituicaoList = selectedInst.map(s => {
        let instValor = valor;
        if (selectedInst.length > 1) {
            const amtInput = document.getElementById(`inst-amt-inst-${s.id}`);
            if (amtInput) {
                const v = window.MainAPI ? window.MainAPI.obterValorMoeda(amtInput) : Number(amtInput.value);
                if (v > 0) instValor = v;
            }
        }
        return { instituicaoUsuario_id: Number(s.id), tipoMovimento: movimento, valor: instValor, parcelas };
    });

    // Quando múltiplas instituições, valor total = soma dos valores individuais
    const valorTotal = selectedInst.length > 1
        ? instituicaoList.reduce((acc, i) => acc + i.valor, 0)
        : valor;

    // Dados de recorrência — se ativada, usa endpoint /registros/recorrente
    if (_isRecorrente) {
        // Validações extras de recorrência
        if (tipo !== 'Gasto' && tipo !== 'Recebimento')
            return alerta("Recorrência disponível apenas para Gasto e Recebimento");
        if (!_periodicidade)
            return alerta("Escolha a periodicidade da recorrência");
        if (_periodicidade === 'semanal' && _diasSemana.length === 0)
            return alerta("Escolha pelo menos um dia da semana");
        if (_periodicidade === 'mensal' && !_diaMes)
            return alerta("Escolha o dia do mês");
        if (_periodicidade === 'anual' && (!_mesAnual || !_diaAnual))
            return alerta("Escolha o mês e o dia do ano");
        if (!_dataFimRecorrente)
            return alerta("Informe a data final da recorrência");

        // Capitalizar primeira letra do periodicidade (ex: 'semanal' → 'Semanal')
        const periodicidade = _periodicidade.charAt(0).toUpperCase() + _periodicidade.slice(1);

        // Mapear índices numéricos para DayOfWeek Java
        const diasDaSemana = _diasSemana.map(n => _DOW_MAP[n]);

        // Dia do mês ou do ano
        const dia = _diaMes || _diaAnual || null;

        alerta(`Registrando recorrência...
            <div class="glaceonCorrendoDiv">
                <img class="glaceon correndo" src="/assets/gif/glaceon-correndo-unscreen.gif" alt="">
            </div>`, 0);

        MainAPI.registrarRecorrente({
            financeiro: {
                usuario_id: userId,
                tipo,
                valor: valorTotal,
                descricao: Desc,
                dataEvento: data,          // data de início
                periodicidade,             // Diario | Semanal | Mensal | Anual
                diasDaSemana,              // ["MONDAY", "FRIDAY", ...]
                dia,                       // dia do mês ou do ano
                dataFim: _dataFimRecorrente, // data final
                intervalo: 1
            },
            instituicao: instituicaoList,
            detalhe: { categoriaUsuario_id: selectedCat.map(s => Number(s.id)), tituloGasto: titulo }
        }).then(async (response) => {
            if (response.ok) {
                window.dispatchEvent(new Event('xp:refresh'));
                markFieldsForClear(['ipt_nome', 'ipt_valor', 'ipt_desc']);
                alerta('✔ Recorrência registrada com sucesso!', 3000);
            } else {
                let detalhe = "";
                try { const corpo = await response.json(); detalhe = corpo.message || corpo.error || JSON.stringify(corpo); }
                catch (_) { detalhe = `HTTP ${response.status}`; }
                alerta(`Erro ao registrar recorrência (${response.status}): ${detalhe}`);
            }
        }).catch(err => {
            console.error("Erro de rede:", err);
            alerta("Erro de conexão ao registrar recorrência.");
        });
        return; // não continua para o registro normal
    }

    alerta(`Registrando...
        <div class="glaceonCorrendoDiv">
            <img class="glaceon correndo" src="/assets/gif/glaceon-correndo-unscreen.gif" alt="">
        </div>`, 0);

    MainAPI.registrarGasto({
        financeiro: {
            usuario_id: userId,
            tipo,
            valor: valorTotal,
            descricao: Desc,
            dataEvento: data,
            ...(tipo === 'Poupanca' && _caixinhaSelecionadaId ? { caixinha_id: _caixinhaSelecionadaId } : {})
        },
        instituicao: instituicaoList,
        detalhe: { categoriaUsuario_id: selectedCat.map(s => Number(s.id)), tituloGasto: titulo }
    }).then(async (response) => {
        if (response.ok) {
            window.dispatchEvent(new Event('xp:refresh'));
            if (selectedInst.length === 1) atualizarSaldoDisplay(selectedInst[0].id);
            // Manter campos – marcar para limpar ao clicar
            markFieldsForClear(['ipt_nome', 'ipt_valor', 'ipt_desc']);
            alerta('✔ Registro realizado com sucesso!<br><small>Clique nos campos de texto para editá-los.</small>', 3000);
        } else {
            let detalhe = "";
            try { const corpo = await response.json(); detalhe = corpo.message || corpo.error || JSON.stringify(corpo); }
            catch (_) { detalhe = `HTTP ${response.status}`; }
            alerta(`Erro ao registrar (${response.status}): ${detalhe}`);
        }
    }).catch(err => {
        console.error("Erro de rede:", err);
        alerta("Erro de conexão ao registrar.");
    });
}

function atualizarSaldo(valor, instituicao) {
    MainAPI.atualizarSaldo({ valorServer: valor, instituicaoServer: instituicao })
        .then(resposta => {
            if (!resposta.ok) console.error("Erro ao atualizar saldo", resposta);
        });
}

function adicionarTipos() {
    if (!userId) return alerta(`Nenhum usuário logado. <button onclick='div_alerta.style.display="none"'>OK</button>`);
    const titulo = document.getElementById("ipt_tituloTipo").value.trim();
    if (!titulo) return alerta(`Digite um nome para o tipo <button onclick='div_alerta.style.display="none"'>OK</button>`);
    MainAPI.adicionarTipo({ titulo }, userId).then(resposta => {
        if (resposta.ok) {
            gerarTipos();
            adicionarTipo.close();
            alerta(`Tipo adicionado com sucesso!<br><button onclick="div_alerta.style.display='none'">OK</button>`);
        } else {
            alerta(`Houve um erro ao adicionar tipo <button onclick='div_alerta.style.display="none"'>OK</button>`);
        }
    }).catch(() => alerta(`Erro ao conectar ao servidor. <button onclick='div_alerta.style.display="none"'>OK</button>`));
}

/* ══════════════════════════════════════════════════
   Calendário
══════════════════════════════════════════════════ */
const btnAbrir    = document.getElementById("calendario");
const modal       = document.getElementById("modal");
const fechar      = document.getElementById("fechar");
const dias        = document.getElementById("dias");
const mesAno      = document.getElementById("mesAno");
const gastosDoDia = document.getElementById("gastosDoDia");
const confirmar   = document.getElementById("confirmar");
const btnAnterior = document.getElementById("btnAnterior");
const btnProximo  = document.getElementById("btnProximo");

let dataSelecionada = null;
let hoje     = new Date();
let mesAtual = hoje.getMonth();
let anoAtual = hoje.getFullYear();
let modalAbertoPor = 'single';
let lote = [];

// O botão #calendario abre o modal para selecionar a data do evento único
btnAbrir.onclick = () => { modalAbertoPor = 'single'; modal.style.display = "flex"; };

function abrirCalendarioMulti() { modalAbertoPor = 'multi'; modal.style.display = 'flex'; }
fechar.onclick    = () => modal.style.display = "none";
btnAnterior.onclick = () => {
    mesAtual--; if (mesAtual < 0) { mesAtual = 11; anoAtual--; } gerarCalendario();
};
btnProximo.onclick = () => {
    mesAtual++; if (mesAtual > 11) { mesAtual = 0; anoAtual++; } gerarCalendario();
};

async function buscarGastosDia(dataSelecionada) {
    const json = await MainAPI.buscarRegistrosPorData(userId, dataSelecionada);
    let listaGastos = [];
    for (let c = 0; c < json.length; c++) {
        const data = new Date(json[c].dataGasto);
        if (data.toISOString().split("T")[0] === dataSelecionada) listaGastos.push(json[c]);
    }
    return listaGastos;
}

function gerarCalendario() {
    dias.innerHTML = "";
    let primeiroDia = new Date(anoAtual, mesAtual, 1).getDay();
    let totalDias   = new Date(anoAtual, mesAtual + 1, 0).getDate();
    mesAno.innerText = new Date(anoAtual, mesAtual).toLocaleString("pt-BR", { month: "long", year: "numeric" });
    for (let i = 0; i < primeiroDia; i++) dias.innerHTML += `<span></span>`;
    for (let dia = 1; dia <= totalDias; dia++) {
        let dataFormatada = `${anoAtual}-${String(mesAtual + 1).padStart(2,'0')}-${String(dia).padStart(2,'0')}`;
        let span = document.createElement("span");
        span.innerText = dia;
        span.onclick = () => selecionarDia(dataFormatada, span);
        dias.appendChild(span);
    }
}

async function selecionarDia(data, elemento) {
    dataSelecionada = data;
    document.querySelectorAll(".diaSelecionado").forEach(e => e.classList.remove("diaSelecionado"));
    elemento.classList.add("diaSelecionado");
    confirmar.disabled = false;
    try {
        const listaGastos = await buscarGastosDia(data);
        const gastosDia = document.getElementById('gastosDia');
        if (listaGastos.length > 0) {
            const dataRegistro = listaGastos[0].eventoFinanceiro?.dataEvento ?? listaGastos[0].dataGasto;
            const novaData     = new Date(dataRegistro);
            const dataFmt = isNaN(novaData.getTime()) ? formatarDataBR(data) : novaData.toLocaleDateString("pt-BR");
            gastosDia.innerHTML = `<b>Gastos de ${dataFmt}:</b><br>`;
            listaGastos.forEach(g => {
                const titulo = g.gastoDetalhe?.tituloGasto ?? g.tituloGasto;
                const valor  = g.eventoFinanceiro?.valor ?? g.valor;
                gastosDia.innerHTML += `<b>${titulo} - R$${valor}</b><br>`;
            });
        } else {
            gastosDia.innerHTML = "<i>Nenhum gasto neste dia.</i>";
        }
    } catch (e) {
        const gastosDia = document.getElementById('gastosDia');
        if (gastosDia) gastosDia.innerHTML = "";
    }
}

confirmar.onclick = () => {
    modal.style.display = "none";
    const dataFormatada = formatarDataBR(dataSelecionada);
    if (modalAbertoPor === 'multi') {
        const label  = document.getElementById('multi_data_label');
        const hidden = document.getElementById('multi_data');
        if (label)  { label.textContent = "Dia: " + dataFormatada; label.classList.remove('hidden'); label.style.display = ''; }
        if (hidden) hidden.value = dataSelecionada;
    } else {
        const dataEl = document.getElementById('data');
        if (dataEl) { dataEl.style.display = ''; dataEl.textContent = dataFormatada; dataEl.classList.remove('hidden'); }
        dataGasto = dataSelecionada;
    }
};

gerarCalendario();

function formatarDataBR(dataISO) {
    const [ano, mes, dia] = dataISO.split("-");
    return `${dia}/${mes}/${ano}`;
}

/* ══════════════════════════════════════════════════
   Múltiplos Registros
══════════════════════════════════════════════════ */
function adicionarAoLote() {
    const titulo    = document.getElementById('ipt_multi_nome').value.trim();
    const tipo      = document.getElementById('multi_select_tipo').value;
    const movimento = document.getElementById('multi_select_movimento').value;
    const parcelas  = Number(document.getElementById('ipt_multi_parcelas').value) || 1;
    const valorInput = document.getElementById('ipt_multi_valor');
    const valor     = window.MainAPI ? window.MainAPI.obterValorMoeda(valorInput) : Number(valorInput.value);
    const descRaw   = document.getElementById('ipt_multi_desc').value.trim();
    const desc      = descRaw || 'Nenhuma descrição fornecida';
    const data      = document.getElementById('multi_data').value;

    const selectedInst = _tp['m-inst'] ? _tp['m-inst'].selected : [];
    const selectedCat  = _tp['m-cat']  ? _tp['m-cat'].selected  : [];

    if (!titulo)                   return alerta('Título inválido');
    if (tipo === '#')              return alerta('Escolha o tipo do evento');
    if (selectedCat.length === 0)  return alerta('Escolha uma categoria');
    if (selectedInst.length === 0) return alerta('Escolha uma instituição');
    if (movimento === '#')         return alerta('Escolha o tipo de movimento');
    if ((movimento === 'Credito' || movimento === 'Boleto') && (parcelas < 1 || isNaN(parcelas)))
        return alerta('Informe a quantidade de parcelas (mínimo 1)');
    if (!data)                      return alerta('Escolha uma data');

    // Validação de valor: múltiplas instituições têm campos próprios
    if (selectedInst.length <= 1) {
        if (valor <= 0 || isNaN(valor)) return alerta('Valor inválido');
    } else {
        const algumValor = selectedInst.some(s => {
            const ai = document.getElementById(`inst-amt-m-inst-${s.id}`);
            return ai && (window.MainAPI ? window.MainAPI.obterValorMoeda(ai) : 0) > 0;
        });
        if (!algumValor) return alerta('Informe o valor para cada instituição');
    }

    const instituicaoList = selectedInst.map(s => {
        let instValor = valor;
        if (selectedInst.length > 1) {
            const amtInput = document.getElementById(`inst-amt-m-inst-${s.id}`);
            if (amtInput) {
                const v = window.MainAPI ? window.MainAPI.obterValorMoeda(amtInput) : Number(amtInput.value);
                if (v > 0) instValor = v;
            }
        }
        return { instituicaoUsuario_id: Number(s.id), tipoMovimento: movimento, valor: instValor, parcelas };
    });

    const valorTotal = selectedInst.length > 1
        ? instituicaoList.reduce((acc, i) => acc + i.valor, 0)
        : valor;

    lote.push({
        financeiro: { usuario_id: userId, tipo, valor: valorTotal, descricao: desc, dataEvento: data },
        instituicao: instituicaoList,
        detalhe: { categoriaUsuario_id: selectedCat.map(s => Number(s.id)), tituloGasto: titulo },
        _display: {
            titulo, tipo, movimento,
            instNome: selectedInst.map(s => s.label).join(', '),
            categorias: selectedCat.map(s => s.label).join(', '),
            valor: valorTotal
        }
    });

    renderizarLote();

    // Manter campos – marcar para limpar ao clicar
    markFieldsForClear(['ipt_multi_nome', 'ipt_multi_valor', 'ipt_multi_desc']);
}

function renderizarLote() {
    const tbody = document.getElementById('corpoLote');
    if (lote.length === 0) {
        tbody.innerHTML = `<tr id="loteVazio"><td colspan="6" class="ar-lote-vazio">Nenhum registro adicionado ainda.</td></tr>`;
        return;
    }
    tbody.innerHTML = '';
    lote.forEach((item, i) => {
        const d = item._display;
        const tr = document.createElement('tr');
        tr.innerHTML = `
            <td>${d.titulo}</td>
            <td>${d.tipo}</td>
            <td>${d.movimento}</td>
            <td>${d.instNome}</td>
            <td>R$ ${d.valor.toFixed(2)}</td>
            <td>
                <div class="ar-lote-actions">
                    <button class="ar-lote-btn edit" onclick="editarDoLote(${i})" title="Editar">✏</button>
                    <button class="ar-lote-btn delete" onclick="removerDoLote(${i})" title="Remover">✕</button>
                </div>
            </td>`;
        tbody.appendChild(tr);
    });
}

function removerDoLote(i) {
    lote.splice(i, 1);
    renderizarLote();
}

function editarDoLote(i) {
    const item = lote[i];
    const d    = item._display;

    // Preencher campos do formulário
    document.getElementById('ipt_multi_nome').value = d.titulo;
    document.getElementById('multi_select_tipo').value = item.financeiro.tipo || '#';
    document.getElementById('multi_select_movimento').value = item.instituicao[0]?.tipoMovimento || '#';
    toggleParcelas('ipt_multi_parcelas', item.instituicao[0]?.tipoMovimento || '#');

    const valInput = document.getElementById('ipt_multi_valor');
    valInput.value = d.valor.toFixed(2).replace('.', ',');
    // Reaplica máscara se disponível
    if (window.MainAPI?.aplicarMascaraMoeda) window.MainAPI.aplicarMascaraMoeda(valInput);

    document.getElementById('ipt_multi_desc').value =
        item.financeiro.descricao !== 'Nenhuma descrição fornecida' ? item.financeiro.descricao : '';

    // Restaurar tag pickers de instituição
    if (_tp['m-inst']) {
        _tp['m-inst'].selected = item.instituicao.map(inst => {
            const opt = _tp['m-inst'].options.find(o => String(o.id) === String(inst.instituicaoUsuario_id));
            return opt || { id: inst.instituicaoUsuario_id, label: String(inst.instituicaoUsuario_id) };
        });
        _renderTagPicker('m-inst');
        _onInstChange('m-inst', _tp['m-inst'].selected);
    }

    // Restaurar tag pickers de categoria
    if (_tp['m-cat']) {
        _tp['m-cat'].selected = item.detalhe.categoriaUsuario_id.map(catId => {
            const opt = _tp['m-cat'].options.find(o => String(o.id) === String(catId));
            return opt || { id: catId, label: String(catId) };
        });
        _renderTagPicker('m-cat');
    }

    // Remover do lote e atualizar tabela
    lote.splice(i, 1);
    renderizarLote();

    // Scroll até o formulário
    const form = document.querySelector('#multiplosRegistros .multi-form');
    if (form) form.scrollIntoView({ behavior: 'smooth', block: 'start' });

    alerta('Registro movido para edição. Altere e clique em Adicionar.', 3000);
}

function salvarLote() {
    if (lote.length === 0) return alerta('Nenhum registro no lote');
    alerta(`Salvando ${lote.length} registro(s)...`, 0);
    const promessas = lote.map(item => MainAPI.registrarGasto({
        financeiro: item.financeiro,
        instituicao: item.instituicao,
        detalhe: item.detalhe
    }));
    Promise.all(promessas).then(respostas => {
        const erros = respostas.filter(r => !r.ok).length;
        if (erros === 0) {
            window.dispatchEvent(new Event('xp:refresh'));
            lote = [];
            renderizarLote();
            alerta(`${respostas.length} registro(s) salvos com sucesso!<br><button onclick="document.getElementById('div_alerta').style.display='none'">OK</button>`, 0);
        } else {
            alerta(`${erros} erro(s) ao salvar. Verifique e tente novamente.`);
        }
    }).catch(() => alerta('Erro ao conectar ao servidor'));
}

/* ══════════════════════════════════════════════════
   Troca de aba
══════════════════════════════════════════════════ */
function trocarFormulario(tela) {
    const cardUnico    = document.getElementById("cardUnico");
    const cardMultiplo = document.getElementById("multiplosRegistros");
    const tabUnico     = document.getElementById("tabUnico");
    const tabMultiplo  = document.getElementById("tabMultiplo");
    if (tela === "multiplosRegistros") {
        if (cardUnico)    cardUnico.style.display    = "none";
        if (cardMultiplo) cardMultiplo.style.display = "flex";
        if (tabUnico)     tabUnico.classList.remove("ativo");
        if (tabMultiplo)  tabMultiplo.classList.add("ativo");
    } else {
        if (cardUnico)    cardUnico.style.display    = "";
        if (cardMultiplo) cardMultiplo.style.display = "none";
        if (tabUnico)     tabUnico.classList.add("ativo");
        if (tabMultiplo)  tabMultiplo.classList.remove("ativo");
    }
}

/* Header titulos (mantido para compatibilidade) */
const titulos = document.querySelectorAll(".headerFormulario .titulo");
titulos.forEach(item => {
    item.addEventListener("click", () => {
        titulos.forEach(e => e.classList.remove("ativo"));
        item.classList.add("ativo");
    });
});

const _divAlerta = document.getElementById('div_alerta');
if (_divAlerta) _divAlerta.style.display = 'none';

// Máscara monetária (aplicada depois do DOM carregar via gerarInformacoes)
let dataGasto;
const usuarioLogado = JSON.parse(localStorage.getItem("usuarioLogado") || "null");
const userId = usuarioLogado ? usuarioLogado.id : null;
let _alertaTimer = null;

/* ══════════════════════════════════════════════════
   Alertas
══════════════════════════════════════════════════ */
function habilitarFecharAlertaAoClicarFora() {
    const divAl = document.getElementById("div_alerta");
    const contAl = document.getElementById("conteudoAlerta");
    if (!divAl || !contAl || divAl.dataset.closeOutsideBound === "1") return;
    divAl.dataset.closeOutsideBound = "1";
    divAl.addEventListener("click", (event) => {
        if (event.target === divAl) {
            divAl.style.display = "none";
            if (_alertaTimer) { clearTimeout(_alertaTimer); _alertaTimer = null; }
        }
    });
}

function alerta(texto, duracaoMs = 4000) {
    const divAl = document.getElementById("div_alerta");
    const contAl = document.getElementById("conteudoAlerta");
    habilitarFecharAlertaAoClicarFora();
    if (divAl) divAl.style.display = "flex";
    if (contAl) contAl.innerHTML = texto;
    if (_alertaTimer) clearTimeout(_alertaTimer);
    if (duracaoMs > 0) {
        _alertaTimer = setTimeout(() => {
            if (divAl) divAl.style.display = "none";
            _alertaTimer = null;
        }, duracaoMs);
    }
}

/* ══════════════════════════════════════════════════
   Clear-on-focus (campos mantidos após registro)
══════════════════════════════════════════════════ */
function setupClearOnFocus() {
    const ids = ['ipt_nome','ipt_valor','ipt_desc','ipt_multi_nome','ipt_multi_valor','ipt_multi_desc'];
    ids.forEach(id => {
        const el = document.getElementById(id);
        if (!el) return;
        el.addEventListener('focus', function () {
            if (this.dataset.pendingClear !== 'true') return;
            if (this.id === 'ipt_valor' || this.id === 'ipt_multi_valor') {
                if (window.MainAPI && window.MainAPI.resetarMascaraMoeda) {
                    window.MainAPI.resetarMascaraMoeda(this);
                } else {
                    this.value = '';
                }
            } else {
                this.value = '';
            }
            delete this.dataset.pendingClear;
            this.classList.remove('ar-field-submitted');
        });
    });
}

function markFieldsForClear(ids) {
    ids.forEach(id => {
        const el = document.getElementById(id);
        if (el && el.value) {
            el.dataset.pendingClear = 'true';
            el.classList.add('ar-field-submitted');
        }
    });
}

/* ══════════════════════════════════════════════════
   Tag Picker system
══════════════════════════════════════════════════ */
const _tp = {}; // id -> { options, selected, placeholder, onchange }

function initTagPicker(id, options, placeholder, onchange) {
    if (_tp[id]) {
        // Reload: preserve selected, update options
        _tp[id].options = options;
        _tp[id].selected = _tp[id].selected.filter(s =>
            options.some(o => String(o.id) === String(s.id))
        );
        if (onchange) _tp[id].onchange = onchange;
    } else {
        _tp[id] = { options, selected: [], placeholder: placeholder || 'Selecionar...', onchange: onchange || null };
    }
    _renderTagPicker(id);
}

function openTagPicker(event, id) {
    event.stopPropagation();
    const dd = document.getElementById('tp-dd-' + id);
    const display = dd ? dd.previousElementSibling : null;
    if (!dd) return;
    const isOpen = dd.style.display !== 'none';
    // Close all
    document.querySelectorAll('.ar-tp-dd').forEach(el => {
        el.style.display = 'none';
        if (el.previousElementSibling) el.previousElementSibling.classList.remove('open');
    });
    if (!isOpen) {
        dd.style.display = '';
        if (display) display.classList.add('open');
    }
}

function _toggleTagItem(id, itemId, itemLabel) {
    const state = _tp[id];
    if (!state) return;
    const idx = state.selected.findIndex(s => String(s.id) === String(itemId));
    if (idx >= 0) {
        state.selected.splice(idx, 1);
    } else {
        state.selected.push({ id: itemId, label: itemLabel });
    }
    _renderTagPicker(id);
    if (state.onchange) state.onchange(state.selected);
}

function _removeTagItem(id, itemId) {
    const state = _tp[id];
    if (!state) return;
    state.selected = state.selected.filter(s => String(s.id) !== String(itemId));
    _renderTagPicker(id);
    if (state.onchange) state.onchange(state.selected);
}

function _renderTagPicker(id) {
    const state = _tp[id];
    const tagsEl = document.getElementById('tp-tags-' + id);
    const ddEl   = document.getElementById('tp-dd-'   + id);
    if (!tagsEl || !ddEl) return;

    // Tags display
    if (state.selected.length === 0) {
        tagsEl.innerHTML = `<span class="ar-tp-ph">${state.placeholder}</span>`;
    } else {
        tagsEl.innerHTML = state.selected.map(s =>
            `<span class="ar-tp-tag">${s.label}<button type="button" class="ar-tp-tag-rm"
                onclick="event.stopPropagation();_removeTagItem('${id}','${s.id}')">×</button></span>`
        ).join('');
    }

    // Dropdown options
    ddEl.innerHTML = '';
    state.options.forEach(opt => {
        const sel = state.selected.some(s => String(s.id) === String(opt.id));
        const btn = document.createElement('button');
        btn.type = 'button';
        btn.className = 'ar-tp-option' + (sel ? ' ar-tp-option-sel' : '');
        const check = document.createElement('span');
        check.className = 'ar-tp-opt-check';
        check.textContent = sel ? '✓' : '';
        btn.appendChild(check);
        btn.appendChild(document.createTextNode(opt.label));
        btn.addEventListener('click', e => {
            e.stopPropagation();
            _toggleTagItem(id, opt.id, opt.label);
        });
        ddEl.appendChild(btn);
    });
}

// Close all dropdowns when clicking outside
document.addEventListener('click', () => {
    document.querySelectorAll('.ar-tp-dd').forEach(dd => {
        dd.style.display = 'none';
        if (dd.previousElementSibling) dd.previousElementSibling.classList.remove('open');
    });
});

/* ── Institution amounts handler ── */
function _onInstChange(pickerId, selected) {
    const amountsId   = pickerId === 'inst' ? 'inst-amounts'   : 'm-inst-amounts';
    const wrapValorId = pickerId === 'inst' ? 'wrap_valor'      : 'wrap_multi_valor';

    const amountsEl   = document.getElementById(amountsId);
    const wrapValorEl = document.getElementById(wrapValorId);

    if (selected.length > 1) {
        // Esconde o campo de valor único
        if (wrapValorEl) wrapValorEl.style.display = 'none';

        // Mostra painel de valor por instituição
        if (amountsEl) {
            amountsEl.style.display = '';
            // Mantém o título, remove linhas antigas
            while (amountsEl.children.length > 1) amountsEl.removeChild(amountsEl.lastChild);
            selected.forEach(s => {
                const row = document.createElement('div');
                row.className = 'ar-inst-amount-row';
                const nameEl = document.createElement('span');
                nameEl.className = 'ar-inst-name';
                nameEl.textContent = s.label;
                const inp = document.createElement('input');
                inp.type = 'text';
                inp.id = `inst-amt-${pickerId}-${s.id}`;
                inp.className = 'ar-inst-amt-input';
                inp.setAttribute('inputmode', 'numeric');
                inp.setAttribute('autocomplete', 'off');
                row.appendChild(nameEl);
                row.appendChild(inp);
                amountsEl.appendChild(row);
                // Aplica máscara APÓS o elemento estar no DOM
                if (window.MainAPI && window.MainAPI.aplicarMascaraMoeda) {
                    window.MainAPI.aplicarMascaraMoeda(inp);
                }
            });
        }
    } else {
        // Mostra o campo de valor único novamente
        if (wrapValorEl) wrapValorEl.style.display = '';

        // Esconde painel de valor por instituição
        if (amountsEl) {
            amountsEl.style.display = 'none';
            while (amountsEl.children.length > 1) amountsEl.removeChild(amountsEl.lastChild);
        }
    }

    // Saldo display (formulário único apenas)
    if (pickerId === 'inst') {
        if (selected.length === 1) {
            atualizarSaldoDisplay(selected[0].id);
        } else {
            const saldoEl = document.getElementById('saldo_display');
            if (saldoEl) saldoEl.style.display = 'none';
        }
    }
}

/* ══════════════════════════════════════════════════
   Recurring section
══════════════════════════════════════════════════ */
let _isRecorrente = false;
let _periodicidade = null;
let _diasSemana    = [];
let _diaMes        = null;
let _mesAnual      = null;
let _diaAnual      = null;
let _dataFimRecorrente = null;

// Mapeamento: índice do botão DOM (0=Dom, 1=Seg, …, 6=Sáb) → DayOfWeek do Java
const _DOW_MAP = ['SUNDAY','MONDAY','TUESDAY','WEDNESDAY','THURSDAY','FRIDAY','SATURDAY'];
const _DOW_LABEL = ['Dom','Seg','Ter','Qua','Qui','Sex','Sáb'];
const _MESES_LABEL = ['Jan','Fev','Mar','Abr','Mai','Jun','Jul','Ago','Set','Out','Nov','Dez'];

function _atualizarResumoRecorrencia() {
    const el = document.getElementById('ar-recorrente-resumo');
    if (!el) return;
    if (!_isRecorrente || !_periodicidade) { el.style.display = 'none'; el.textContent = ''; return; }
    const partes = [_periodicidade.charAt(0).toUpperCase() + _periodicidade.slice(1)];
    if (_periodicidade === 'semanal' && _diasSemana.length > 0)
        partes.push(_diasSemana.map(d => _DOW_LABEL[d]).join(', '));
    if (_periodicidade === 'mensal' && _diaMes)
        partes.push(`Dia ${_diaMes}`);
    if (_periodicidade === 'anual') {
        if (_mesAnual) partes.push(_MESES_LABEL[_mesAnual - 1]);
        if (_diaAnual) partes.push(`Dia ${_diaAnual}`);
    }
    if (_dataFimRecorrente) partes.push(`até ${_dataFimRecorrente.split('-').reverse().join('/')}`);
    el.textContent = partes.join(' · ');
    el.style.display = '';
}

function toggleRecorrente() {
    _isRecorrente = !_isRecorrente;
    if (!_isRecorrente) {
        _periodicidade = null; _diasSemana = []; _diaMes = null; _mesAnual = null; _diaAnual = null; _dataFimRecorrente = null;
        const fim = document.getElementById('rec-data-fim');
        if (fim) fim.value = '';
        _atualizarResumoRecorrencia();
    }    const btn  = document.getElementById('ar-recorrente-btn');
    const icon = document.getElementById('ar-recorrente-icon');
    const opts = document.getElementById('recurring-options');
    if (btn)  btn.classList.toggle('active', _isRecorrente);
    if (icon) icon.style.display = _isRecorrente ? '' : 'none';
    if (opts) opts.style.display = _isRecorrente ? '' : 'none';
    if (!_isRecorrente) {
        ['rec-semanal','rec-mensal','rec-anual'].forEach(id => {
            const el = document.getElementById(id);
            if (el) el.style.display = 'none';
        });
        document.querySelectorAll('.ar-pill[data-period]').forEach(p => p.classList.remove('active'));
    }
}

function setPeriodicity(p) {
    _periodicidade = p;
    _diasSemana = []; _diaMes = null; _mesAnual = null; _diaAnual = null;
    document.querySelectorAll('.ar-pill[data-period]').forEach(pill =>
        pill.classList.toggle('active', pill.dataset.period === p)
    );
    document.getElementById('rec-semanal').style.display = p === 'semanal' ? '' : 'none';
    document.getElementById('rec-mensal').style.display  = p === 'mensal'  ? '' : 'none';
    document.getElementById('rec-anual').style.display   = p === 'anual'   ? '' : 'none';
    document.querySelectorAll('.ar-pill[data-day]').forEach(p => p.classList.remove('active'));
    document.querySelectorAll('#rec-mensal-days .ar-pill').forEach(p => p.classList.remove('active'));
    document.querySelectorAll('#rec-anual-months .ar-pill').forEach(p => p.classList.remove('active'));
    _atualizarResumoRecorrencia();
}

function toggleWeekDay(day) {
    const idx = _diasSemana.indexOf(day);
    if (idx >= 0) _diasSemana.splice(idx, 1); else _diasSemana.push(day);
    const pill = document.querySelector(`.ar-pill[data-day="${day}"]`);
    if (pill) pill.classList.toggle('active', _diasSemana.includes(day));
    _atualizarResumoRecorrencia();
}

function setMonthDay(day) {
    _diaMes = (_diaMes === day) ? null : day;
    document.querySelectorAll('#rec-mensal-days .ar-pill').forEach(p =>
        p.classList.toggle('active', Number(p.dataset.monthday) === _diaMes)
    );
    _atualizarResumoRecorrencia();
}

function setAnnualMonth(month) {
    _mesAnual = (_mesAnual === month) ? null : month;
    document.querySelectorAll('#rec-anual-months .ar-pill').forEach(p =>
        p.classList.toggle('active', Number(p.dataset.annualmonth) === _mesAnual)
    );
    _atualizarResumoRecorrencia();
}

function _initRecurringSubOptions() {
    // Monthly days 1-31
    const mensal = document.getElementById('rec-mensal-days');
    if (mensal && mensal.children.length === 0) {
        for (let d = 1; d <= 31; d++) {
            const btn = document.createElement('button');
            btn.type = 'button';
            btn.className = 'ar-pill ar-pill-sm';
            btn.dataset.monthday = d;
            btn.textContent = d;
            btn.addEventListener('click', () => setMonthDay(d));
            mensal.appendChild(btn);
        }
    }
    // Annual months
    const MONTHS = ['Jan','Fev','Mar','Abr','Mai','Jun','Jul','Ago','Set','Out','Nov','Dez'];
    const anualMonths = document.getElementById('rec-anual-months');
    if (anualMonths && anualMonths.children.length === 0) {
        MONTHS.forEach((m, i) => {
            const btn = document.createElement('button');
            btn.type = 'button';
            btn.className = 'ar-pill';
            btn.dataset.annualmonth = i + 1;
            btn.textContent = m;
            btn.addEventListener('click', () => setAnnualMonth(i + 1));
            anualMonths.appendChild(btn);
        });
    }
    // Annual day select
    const anualDay = document.getElementById('rec-anual-day');
    if (anualDay && anualDay.options.length <= 1) {
        for (let d = 1; d <= 31; d++) {
            const opt = document.createElement('option');
            opt.value = d; opt.textContent = `Dia ${d}`;
            anualDay.appendChild(opt);
        }
        anualDay.addEventListener('change', () => { _diaAnual = anualDay.value ? parseInt(anualDay.value) : null; });
    }

    // Campo de data final da recorrência — mesmo estilo da tela de filtros (dd/mm/aaaa)
    const recurringOpts = document.getElementById('recurring-options');
    if (recurringOpts && !document.getElementById('rec-data-fim')) {
        const grp = document.createElement('div');
        grp.className = 'ar-recurring-group';
        grp.id = 'rec-data-fim-group';
        grp.innerHTML = `
            <span class="ar-group-label">Data final da recorrência</span>
            <div style="margin-top:6px;display:flex;align-items:center;gap:8px;">
                <input type="text" id="rec-data-fim" class="ar-select-small"
                       placeholder="dd/mm/aaaa" maxlength="10" inputmode="numeric"
                       style="min-width:180px;max-width:220px;cursor:text;">
            </div>
        `;
        recurringOpts.appendChild(grp);

        const inputDataFim = document.getElementById('rec-data-fim');
        // Aplica a mesma máscara usada no filtro de registros
        if (window.MainAPI && window.MainAPI.aplicarMascaraData) {
            window.MainAPI.aplicarMascaraData(inputDataFim);
        }
        // Converte dd/mm/aaaa → aaaa-mm-dd para o backend
        inputDataFim.addEventListener('input', function () {
            _dataFimRecorrente = (window.MainAPI && window.MainAPI.dataParaISO)
                ? window.MainAPI.dataParaISO(this.value)
                : null;
            _atualizarResumoRecorrencia();
        });
    }
} // fim _initRecurringSubOptions

/* ══════════════════════════════════════════════════
   Painel de Poupança (Caixinha)
══════════════════════════════════════════════════ */
let _caixinhas = [];
let _caixinhaSelecionadaId = null;

async function _carregarCaixinhas() {
    if (!userId) return;
    try {
        _caixinhas = await MainAPI.getCaixinhas(userId);
    } catch (e) {
        _caixinhas = [];
    }
}

function _renderPainelPoupanca(show) {
    let painel = document.getElementById('ar-poupanca-painel');
    if (!show) {
        if (painel) painel.style.display = 'none';
        _caixinhaSelecionadaId = null;
        return;
    }
    if (!painel) {
        // Cria o painel dinamicamente na primeira vez
        painel = document.createElement('div');
        painel.id = 'ar-poupanca-painel';
        painel.className = 'ar-recurring-wrap ar-span-3';
        // Insere após o bloco de tipo de movimento
        const movWrap = document.getElementById('select_movimento')?.closest('.ar-field-wrap');
        if (movWrap && movWrap.parentNode) {
            movWrap.parentNode.insertBefore(painel, movWrap.nextSibling);
        }
    }
    painel.style.display = '';

    if (_caixinhas.length === 0) {
        painel.innerHTML = `
            <div style="background:var(--cor-tinte-suave);border-radius:12px;padding:14px 16px;border:1px solid var(--cor-tinte-borda);">
                <p style="margin:0;color:var(--cor-texto-secundario);font-size:0.92rem;">
                    <i class='bx bx-info-circle' style="color:var(--cor-principal);"></i>
                    Nenhuma caixinha ativa encontrada. 
                    <strong>Registre o aporte mesmo assim</strong> — ele aparecerá como Poupança sem caixinha vinculada.
                </p>
            </div>`;
        _caixinhaSelecionadaId = null;
        return;
    }

    const opts = _caixinhas.map(c => {
        const pct   = c.percentualAtingido != null ? `${c.percentualAtingido.toFixed(1)}%` : '—';
        const prazo = c.dataPrazo ? ` · prazo ${c.dataPrazo}` : '';
        return `<option value="${c.id}">${c.nome} (${pct} atingido${prazo})</option>`;
    }).join('');

    painel.innerHTML = `
        <div style="background:var(--cor-tinte-suave);border-radius:12px;padding:14px 16px;border:1px solid var(--cor-tinte-borda);display:flex;flex-direction:column;gap:10px;">
            <span style="font-size:0.82rem;font-weight:700;color:var(--cor-texto-secundario);text-transform:uppercase;letter-spacing:0.5px;">Vincular a uma Caixinha</span>
            <select id="ar-select-caixinha" style="background:var(--cor-fundo-card);border:1px solid var(--cor-tinte-borda);border-radius:8px;padding:8px 12px;color:var(--cor-texto-principal);font-size:0.95rem;">
                <option value="">Sem caixinha (aporte avulso)</option>
                ${opts}
            </select>
            <div id="ar-caixinha-info" style="display:none;font-size:0.87rem;color:var(--cor-texto-secundario);line-height:1.6;padding:8px 10px;background:var(--cor-fundo-campo);border-radius:8px;"></div>
        </div>`;

    document.getElementById('ar-select-caixinha').addEventListener('change', function () {
        _caixinhaSelecionadaId = this.value || null;
        const info = document.getElementById('ar-caixinha-info');
        if (!_caixinhaSelecionadaId) { info.style.display = 'none'; return; }
        const cx = _caixinhas.find(c => c.id === _caixinhaSelecionadaId);
        if (!cx) { info.style.display = 'none'; return; }
        const fmt = v => v != null ? `R$ ${Number(v).toFixed(2)}` : '—';
        const pct = cx.percentualAtingido != null ? `${cx.percentualAtingido.toFixed(1)}%` : '—';
        info.style.display = '';
        info.innerHTML = `
            <b>${cx.nome}</b><br>
            Meta: <b>${fmt(cx.valorMeta)}</b> · Acumulado: <b>${fmt(cx.valorAtual)}</b> (${pct})<br>
            ${cx.aporteMensalSugerido != null ? `Aporte mensal sugerido: <b style="color:var(--cor-principal)">${fmt(cx.aporteMensalSugerido)}</b>` : ''}
            ${cx.mesesRestantes != null ? ` · ${cx.mesesRestantes} meses restantes` : ''}`;
    });
}

function _onTipoChange() {
    const tipo = document.getElementById('select_tipo')?.value;
    _renderPainelPoupanca(tipo === 'Poupanca');
}

/* ══════════════════════════════════════════════════
   Inicialização
══════════════════════════════════════════════════ */
function gerarInformacoes() {
    // Init tag pickers (empty – options loaded async)
    initTagPicker('inst',   [], 'Escolha instituições...', sel => _onInstChange('inst',   sel));
    initTagPicker('cat',    [], 'Escolha categorias...',   null);
    initTagPicker('m-inst', [], 'Escolha...',              sel => _onInstChange('m-inst', sel));
    initTagPicker('m-cat',  [], 'Escolha...',              null);

    // Apply money mask
    const iV  = document.getElementById('ipt_valor');
    const imV = document.getElementById('ipt_multi_valor');
    if (iV  && window.MainAPI?.aplicarMascaraMoeda) window.MainAPI.aplicarMascaraMoeda(iV);
    if (imV && window.MainAPI?.aplicarMascaraMoeda) window.MainAPI.aplicarMascaraMoeda(imV);

    // Recurring sub-option builders
    _initRecurringSubOptions();

    // Clear-on-focus for text fields
    setupClearOnFocus();

    // Poupança: carrega caixinhas e escuta mudança de tipo
    _carregarCaixinhas();
    const selectTipo = document.getElementById('select_tipo');
    if (selectTipo) selectTipo.addEventListener('change', _onTipoChange);

    // Load data from API
    gerarCategorias();
    gerarInstituicao();
}

async function atualizarSaldoDisplay(instituicaoUsuarioId) {
    const el = document.getElementById('saldo_display');
    if (!el) return;
    if (!instituicaoUsuarioId || instituicaoUsuarioId === '#') { el.style.display = 'none'; return; }
    try {
        const res = await fetch(`http://localhost:8080/instituicoes/saldo/${Number(instituicaoUsuarioId)}`);
        if (!res.ok) { el.style.display = 'none'; return; }
        const saldo = await res.json();
        const valor = Number(saldo);
        el.textContent = `Saldo disponível: R$ ${valor.toFixed(2)}`;
        // Usa variáveis CSS para cores de saldo
        el.style.color = valor <= 0 ? 'var(--red-700)' : 'var(--cor-principal)';
        el.style.display = '';
    } catch (e) { el.style.display = 'none'; }
}

function toggleParcelas(inputId, movimento) {
    const requer = movimento === 'Credito' || movimento === 'Boleto';
    const wrapId = inputId === 'ipt_parcelas' ? 'wrap_parcelas' : 'wrap_multi_parcelas';
    const wrap  = document.getElementById(wrapId);
    const input = document.getElementById(inputId);
    if (wrap)  wrap.style.display  = requer ? '' : 'none';
    if (input && !requer) input.value = '1';
}

function gerarCategorias() {
    if (!userId) return;
    MainAPI.getTipos(userId)
        .then(json => {
            const options = json.map(c => ({ id: c.id, label: c.categoria.titulo }));
            initTagPicker('cat',   options, 'Escolha categorias...');
            initTagPicker('m-cat', options, 'Escolha...');
        })
        .catch(() => alerta("Não foi possível carregar as categorias. Tente novamente."));
}

const gerarTipos = gerarCategorias;

async function gerarInstituicao() {
    if (!userId) return;
    try {
        const json = await MainAPI.getInstituicoes(userId);
        const options = json.map(i => ({ id: i.id, label: i.intituicao.nome }));
        initTagPicker('inst',   options, 'Escolha instituições...', sel => _onInstChange('inst',   sel));
        initTagPicker('m-inst', options, 'Escolha...',              sel => _onInstChange('m-inst', sel));
    } catch (e) {
        alerta("Não foi possível carregar as instituições. Tente novamente.");
    }
}

/* ══════════════════════════════════════════════════
   Registrar (formulário único)
══════════════════════════════════════════════════ */
async function registrar() {
    const valorInput = document.getElementById('ipt_valor');
    const valor      = window.MainAPI ? window.MainAPI.obterValorMoeda(valorInput) : Number(valorInput.value);
    const titulo     = document.getElementById('ipt_nome').value;
    const tipo       = document.getElementById('select_tipo').value;
    const descRaw    = document.getElementById('ipt_desc').value;
    const Desc       = descRaw || 'Nenhuma descrição fornecida';
    const movimento  = document.getElementById('select_movimento').value;
    const parcelas   = Number(document.getElementById('ipt_parcelas').value) || 1;
    const data       = dataGasto;

    const selectedInst = _tp['inst'] ? _tp['inst'].selected : [];
    const selectedCat  = _tp['cat']  ? _tp['cat'].selected  : [];

    if (!data || data === 0)         return alerta("Data inválida");
    if (!titulo)                     return alerta("Título inválido");
    if (tipo === '#')                return alerta("Escolha o tipo do evento");
    if (selectedCat.length === 0)    return alerta("Escolha uma categoria");
    if (selectedInst.length === 0)   return alerta("Escolha uma instituição");
    if (movimento === '#')           return alerta("Escolha o tipo de movimento");
    if ((movimento === 'Credito' || movimento === 'Boleto') && (parcelas < 1 || isNaN(parcelas)))
        return alerta("Informe a quantidade de parcelas (mínimo 1)");

    // Validação de valor: quando múltiplas instituições o campo único fica oculto
    if (selectedInst.length <= 1) {
        if (valor <= 0 || !valor) return alerta("Valor inválido");
    } else {
        const algumValor = selectedInst.some(s => {
            const ai = document.getElementById(`inst-amt-inst-${s.id}`);
            return ai && (window.MainAPI ? window.MainAPI.obterValorMoeda(ai) : 0) > 0;
        });
        if (!algumValor) return alerta("Informe o valor para cada instituição");
    }

    // Verificar saldo quando o tipo exige débito
    if ((tipo === 'Gasto' || tipo === 'Transferencia') && selectedInst.length === 1) {
        try {
            const resSaldo = await fetch(`http://localhost:8080/instituicoes/saldo/${Number(selectedInst[0].id)}`);
            if (resSaldo.ok) {
                const saldo = await resSaldo.json();
                if (Number(saldo) < valor)
                    return alerta(`Saldo insuficiente. Disponível: R$ ${Number(saldo).toFixed(2)}`);
            }
        } catch (e) { console.warn("Não foi possível verificar saldo:", e); }
    }

    // Montar lista de instituições (com valor individual quando múltiplas)
    const instituicaoList = selectedInst.map(s => {
        let instValor = valor;
        if (selectedInst.length > 1) {
            const amtInput = document.getElementById(`inst-amt-inst-${s.id}`);
            if (amtInput) {
                const v = window.MainAPI ? window.MainAPI.obterValorMoeda(amtInput) : Number(amtInput.value);
                if (v > 0) instValor = v;
            }
        }
        return { instituicaoUsuario_id: Number(s.id), tipoMovimento: movimento, valor: instValor, parcelas };
    });

    // Quando múltiplas instituições, valor total = soma dos valores individuais
    const valorTotal = selectedInst.length > 1
        ? instituicaoList.reduce((acc, i) => acc + i.valor, 0)
        : valor;

    // Dados de recorrência — se ativada, usa endpoint /registros/recorrente
    if (_isRecorrente) {
        // Validações extras de recorrência
        if (tipo !== 'Gasto' && tipo !== 'Recebimento')
            return alerta("Recorrência disponível apenas para Gasto e Recebimento");
        if (!_periodicidade)
            return alerta("Escolha a periodicidade da recorrência");
        if (_periodicidade === 'semanal' && _diasSemana.length === 0)
            return alerta("Escolha pelo menos um dia da semana");
        if (_periodicidade === 'mensal' && !_diaMes)
            return alerta("Escolha o dia do mês");
        if (_periodicidade === 'anual' && (!_mesAnual || !_diaAnual))
            return alerta("Escolha o mês e o dia do ano");
        if (!_dataFimRecorrente)
            return alerta("Informe a data final da recorrência");

        // Capitalizar primeira letra do periodicidade (ex: 'semanal' → 'Semanal')
        const periodicidade = _periodicidade.charAt(0).toUpperCase() + _periodicidade.slice(1);

        // Mapear índices numéricos para DayOfWeek Java
        const diasDaSemana = _diasSemana.map(n => _DOW_MAP[n]);

        // Dia do mês ou do ano
        const dia = _diaMes || _diaAnual || null;

        alerta(`Registrando recorrência...
            <div class="glaceonCorrendoDiv">
                <img class="glaceon correndo" src="/assets/gif/glaceon-correndo-unscreen.gif" alt="">
            </div>`, 0);

        MainAPI.registrarRecorrente({
            financeiro: {
                usuario_id: userId,
                tipo,
                valor: valorTotal,
                descricao: Desc,
                dataEvento: data,          // data de início
                periodicidade,             // Diario | Semanal | Mensal | Anual
                diasDaSemana,              // ["MONDAY", "FRIDAY", ...]
                dia,                       // dia do mês ou do ano
                dataFim: _dataFimRecorrente, // data final
                intervalo: 1
            },
            instituicao: instituicaoList,
            detalhe: { categoriaUsuario_id: selectedCat.map(s => Number(s.id)), tituloGasto: titulo }
        }).then(async (response) => {
            if (response.ok) {
                window.dispatchEvent(new Event('xp:refresh'));
                markFieldsForClear(['ipt_nome', 'ipt_valor', 'ipt_desc']);
                alerta('✔ Recorrência registrada com sucesso!', 3000);
            } else {
                let detalhe = "";
                try { const corpo = await response.json(); detalhe = corpo.message || corpo.error || JSON.stringify(corpo); }
                catch (_) { detalhe = `HTTP ${response.status}`; }
                alerta(`Erro ao registrar recorrência (${response.status}): ${detalhe}`);
            }
        }).catch(err => {
            console.error("Erro de rede:", err);
            alerta("Erro de conexão ao registrar recorrência.");
        });
        return; // não continua para o registro normal
    }

    alerta(`Registrando...
        <div class="glaceonCorrendoDiv">
            <img class="glaceon correndo" src="/assets/gif/glaceon-correndo-unscreen.gif" alt="">
        </div>`, 0);

    MainAPI.registrarGasto({
        financeiro: {
            usuario_id: userId,
            tipo,
            valor: valorTotal,
            descricao: Desc,
            dataEvento: data,
            ...(tipo === 'Poupanca' && _caixinhaSelecionadaId ? { caixinha_id: _caixinhaSelecionadaId } : {})
        },
        instituicao: instituicaoList,
        detalhe: { categoriaUsuario_id: selectedCat.map(s => Number(s.id)), tituloGasto: titulo }
    }).then(async (response) => {
        if (response.ok) {
            window.dispatchEvent(new Event('xp:refresh'));
            if (selectedInst.length === 1) atualizarSaldoDisplay(selectedInst[0].id);
            // Manter campos – marcar para limpar ao clicar
            markFieldsForClear(['ipt_nome', 'ipt_valor', 'ipt_desc']);
            alerta('✔ Registro realizado com sucesso!<br><small>Clique nos campos de texto para editá-los.</small>', 3000);
        } else {
            let detalhe = "";
            try { const corpo = await response.json(); detalhe = corpo.message || corpo.error || JSON.stringify(corpo); }
            catch (_) { detalhe = `HTTP ${response.status}`; }
            alerta(`Erro ao registrar (${response.status}): ${detalhe}`);
        }
    }).catch(err => {
        console.error("Erro de rede:", err);
        alerta("Erro de conexão ao registrar.");
    });
}

function atualizarSaldo(valor, instituicao) {
    MainAPI.atualizarSaldo({ valorServer: valor, instituicaoServer: instituicao })
        .then(resposta => {
            if (!resposta.ok) console.error("Erro ao atualizar saldo", resposta);
        });
}

function adicionarTipos() {
    if (!userId) return alerta(`Nenhum usuário logado. <button onclick='div_alerta.style.display="none"'>OK</button>`);
    const titulo = document.getElementById("ipt_tituloTipo").value.trim();
    if (!titulo) return alerta(`Digite um nome para o tipo <button onclick='div_alerta.style.display="none"'>OK</button>`);
    MainAPI.adicionarTipo({ titulo }, userId).then(resposta => {
        if (resposta.ok) {
            gerarTipos();
            adicionarTipo.close();
            alerta(`Tipo adicionado com sucesso!<br><button onclick="div_alerta.style.display='none'">OK</button>`);
        } else {
            alerta(`Houve um erro ao adicionar tipo <button onclick='div_alerta.style.display="none"'>OK</button>`);
        }
    }).catch(() => alerta(`Erro ao conectar ao servidor. <button onclick='div_alerta.style.display="none"'>OK</button>`));
}

/* ══════════════════════════════════════════════════
   Calendário
══════════════════════════════════════════════════ */
const btnAbrir    = document.getElementById("calendario");
const modal       = document.getElementById("modal");
const fechar      = document.getElementById("fechar");
const dias        = document.getElementById("dias");
const mesAno      = document.getElementById("mesAno");
const gastosDoDia = document.getElementById("gastosDoDia");
const confirmar   = document.getElementById("confirmar");
const btnAnterior = document.getElementById("btnAnterior");
const btnProximo  = document.getElementById("btnProximo");

let dataSelecionada = null;
let hoje     = new Date();
let mesAtual = hoje.getMonth();
let anoAtual = hoje.getFullYear();
let modalAbertoPor = 'single';
let lote = [];

// O botão #calendario abre o modal para selecionar a data do evento único
btnAbrir.onclick = () => { modalAbertoPor = 'single'; modal.style.display = "flex"; };

function abrirCalendarioMulti() { modalAbertoPor = 'multi'; modal.style.display = 'flex'; }
fechar.onclick    = () => modal.style.display = "none";
btnAnterior.onclick = () => {
    mesAtual--; if (mesAtual < 0) { mesAtual = 11; anoAtual--; } gerarCalendario();
};
btnProximo.onclick = () => {
    mesAtual++; if (mesAtual > 11) { mesAtual = 0; anoAtual++; } gerarCalendario();
};

async function buscarGastosDia(dataSelecionada) {
    const json = await MainAPI.buscarRegistrosPorData(userId, dataSelecionada);
    let listaGastos = [];
    for (let c = 0; c < json.length; c++) {
        const data = new Date(json[c].dataGasto);
        if (data.toISOString().split("T")[0] === dataSelecionada) listaGastos.push(json[c]);
    }
    return listaGastos;
}

function gerarCalendario() {
    dias.innerHTML = "";
    let primeiroDia = new Date(anoAtual, mesAtual, 1).getDay();
    let totalDias   = new Date(anoAtual, mesAtual + 1, 0).getDate();
    mesAno.innerText = new Date(anoAtual, mesAtual).toLocaleString("pt-BR", { month: "long", year: "numeric" });
    for (let i = 0; i < primeiroDia; i++) dias.innerHTML += `<span></span>`;
    for (let dia = 1; dia <= totalDias; dia++) {
        let dataFormatada = `${anoAtual}-${String(mesAtual + 1).padStart(2,'0')}-${String(dia).padStart(2,'0')}`;
        let span = document.createElement("span");
        span.innerText = dia;
        span.onclick = () => selecionarDia(dataFormatada, span);
        dias.appendChild(span);
    }
}

async function selecionarDia(data, elemento) {
    dataSelecionada = data;
    document.querySelectorAll(".diaSelecionado").forEach(e => e.classList.remove("diaSelecionado"));
    elemento.classList.add("diaSelecionado");
    confirmar.disabled = false;
    try {
        const listaGastos = await buscarGastosDia(data);
        const gastosDia = document.getElementById('gastosDia');
        if (listaGastos.length > 0) {
            const dataRegistro = listaGastos[0].eventoFinanceiro?.dataEvento ?? listaGastos[0].dataGasto;
            const novaData     = new Date(dataRegistro);
            const dataFmt = isNaN(novaData.getTime()) ? formatarDataBR(data) : novaData.toLocaleDateString("pt-BR");
            gastosDia.innerHTML = `<b>Gastos de ${dataFmt}:</b><br>`;
            listaGastos.forEach(g => {
                const titulo = g.gastoDetalhe?.tituloGasto ?? g.tituloGasto;
                const valor  = g.eventoFinanceiro?.valor ?? g.valor;
                gastosDia.innerHTML += `<b>${titulo} - R$${valor}</b><br>`;
            });
        } else {
            gastosDia.innerHTML = "<i>Nenhum gasto neste dia.</i>";
        }
    } catch (e) {
        const gastosDia = document.getElementById('gastosDia');
        if (gastosDia) gastosDia.innerHTML = "";
    }
}

confirmar.onclick = () => {
    modal.style.display = "none";
    const dataFormatada = formatarDataBR(dataSelecionada);
    if (modalAbertoPor === 'multi') {
        const label  = document.getElementById('multi_data_label');
        const hidden = document.getElementById('multi_data');
        if (label)  { label.textContent = "Dia: " + dataFormatada; label.classList.remove('hidden'); label.style.display = ''; }
        if (hidden) hidden.value = dataSelecionada;
    } else {
        const dataEl = document.getElementById('data');
        if (dataEl) { dataEl.style.display = ''; dataEl.textContent = dataFormatada; dataEl.classList.remove('hidden'); }
        dataGasto = dataSelecionada;
    }
};

gerarCalendario();

function formatarDataBR(dataISO) {
    const [ano, mes, dia] = dataISO.split("-");
    return `${dia}/${mes}/${ano}`;
}

/* ══════════════════════════════════════════════════
   Múltiplos Registros
══════════════════════════════════════════════════ */
function adicionarAoLote() {
    const titulo    = document.getElementById('ipt_multi_nome').value.trim();
    const tipo      = document.getElementById('multi_select_tipo').value;
    const movimento = document.getElementById('multi_select_movimento').value;
    const parcelas  = Number(document.getElementById('ipt_multi_parcelas').value) || 1;
    const valorInput = document.getElementById('ipt_multi_valor');
    const valor     = window.MainAPI ? window.MainAPI.obterValorMoeda(valorInput) : Number(valorInput.value);
    const descRaw   = document.getElementById('ipt_multi_desc').value.trim();
    const desc      = descRaw || 'Nenhuma descrição fornecida';
    const data      = document.getElementById('multi_data').value;

    const selectedInst = _tp['m-inst'] ? _tp['m-inst'].selected : [];
    const selectedCat  = _tp['m-cat']  ? _tp['m-cat'].selected  : [];

    if (!titulo)                   return alerta('Título inválido');
    if (tipo === '#')              return alerta('Escolha o tipo do evento');
    if (selectedCat.length === 0)  return alerta('Escolha uma categoria');
    if (selectedInst.length === 0) return alerta('Escolha uma instituição');
    if (movimento === '#')         return alerta('Escolha o tipo de movimento');
    if ((movimento === 'Credito' || movimento === 'Boleto') && (parcelas < 1 || isNaN(parcelas)))
        return alerta('Informe a quantidade de parcelas (mínimo 1)');
    if (!data)                      return alerta('Escolha uma data');

    // Validação de valor: múltiplas instituições têm campos próprios
    if (selectedInst.length <= 1) {
        if (valor <= 0 || isNaN(valor)) return alerta('Valor inválido');
    } else {
        const algumValor = selectedInst.some(s => {
            const ai = document.getElementById(`inst-amt-m-inst-${s.id}`);
            return ai && (window.MainAPI ? window.MainAPI.obterValorMoeda(ai) : 0) > 0;
        });
        if (!algumValor) return alerta('Informe o valor para cada instituição');
    }

    const instituicaoList = selectedInst.map(s => {
        let instValor = valor;
        if (selectedInst.length > 1) {
            const amtInput = document.getElementById(`inst-amt-m-inst-${s.id}`);
            if (amtInput) {
                const v = window.MainAPI ? window.MainAPI.obterValorMoeda(amtInput) : Number(amtInput.value);
                if (v > 0) instValor = v;
            }
        }
        return { instituicaoUsuario_id: Number(s.id), tipoMovimento: movimento, valor: instValor, parcelas };
    });

    const valorTotal = selectedInst.length > 1
        ? instituicaoList.reduce((acc, i) => acc + i.valor, 0)
        : valor;

    lote.push({
        financeiro: { usuario_id: userId, tipo, valor: valorTotal, descricao: desc, dataEvento: data },
        instituicao: instituicaoList,
        detalhe: { categoriaUsuario_id: selectedCat.map(s => Number(s.id)), tituloGasto: titulo },
        _display: {
            titulo, tipo, movimento,
            instNome: selectedInst.map(s => s.label).join(', '),
            categorias: selectedCat.map(s => s.label).join(', '),
            valor: valorTotal
        }
    });

    renderizarLote();

    // Manter campos – marcar para limpar ao clicar
    markFieldsForClear(['ipt_multi_nome', 'ipt_multi_valor', 'ipt_multi_desc']);
}

function renderizarLote() {
    const tbody = document.getElementById('corpoLote');
    if (lote.length === 0) {
        tbody.innerHTML = `<tr id="loteVazio"><td colspan="6" class="ar-lote-vazio">Nenhum registro adicionado ainda.</td></tr>`;
        return;
    }
    tbody.innerHTML = '';
    lote.forEach((item, i) => {
        const d = item._display;
        const tr = document.createElement('tr');
        tr.innerHTML = `
            <td>${d.titulo}</td>
            <td>${d.tipo}</td>
            <td>${d.movimento}</td>
            <td>${d.instNome}</td>
            <td>R$ ${d.valor.toFixed(2)}</td>
            <td>
                <div class="ar-lote-actions">
                    <button class="ar-lote-btn edit" onclick="editarDoLote(${i})" title="Editar">✏</button>
                    <button class="ar-lote-btn delete" onclick="removerDoLote(${i})" title="Remover">✕</button>
                </div>
            </td>`;
        tbody.appendChild(tr);
    });
}

function removerDoLote(i) {
    lote.splice(i, 1);
    renderizarLote();
}

function editarDoLote(i) {
    const item = lote[i];
    const d    = item._display;

    // Preencher campos do formulário
    document.getElementById('ipt_multi_nome').value = d.titulo;
    document.getElementById('multi_select_tipo').value = item.financeiro.tipo || '#';
    document.getElementById('multi_select_movimento').value = item.instituicao[0]?.tipoMovimento || '#';
    toggleParcelas('ipt_multi_parcelas', item.instituicao[0]?.tipoMovimento || '#');

    const valInput = document.getElementById('ipt_multi_valor');
    const centavosEditar = Math.round(d.valor * 100);
    if (valInput.dataset.centavos !== undefined) {
        // Máscara já está aplicada — apenas atualiza o valor via dataset e dispara input
        valInput.dataset.centavos = String(centavosEditar);
        valInput.dispatchEvent(new Event('input'));
    } else {
        // Máscara ainda não aplicada (fallback)
        valInput.value = d.valor.toFixed(2).replace('.', ',');
        if (window.MainAPI?.aplicarMascaraMoeda) window.MainAPI.aplicarMascaraMoeda(valInput);
        valInput.dataset.centavos = String(centavosEditar);
        valInput.dispatchEvent(new Event('input'));
    }

    document.getElementById('ipt_multi_desc').value =
        item.financeiro.descricao !== 'Nenhuma descrição fornecida' ? item.financeiro.descricao : '';

    // Restaurar tag pickers de instituição
    if (_tp['m-inst']) {
        _tp['m-inst'].selected = item.instituicao.map(inst => {
            const opt = _tp['m-inst'].options.find(o => String(o.id) === String(inst.instituicaoUsuario_id));
            return opt || { id: inst.instituicaoUsuario_id, label: String(inst.instituicaoUsuario_id) };
        });
        _renderTagPicker('m-inst');
        _onInstChange('m-inst', _tp['m-inst'].selected);
    }

    // Restaurar tag pickers de categoria
    if (_tp['m-cat']) {
        _tp['m-cat'].selected = item.detalhe.categoriaUsuario_id.map(catId => {
            const opt = _tp['m-cat'].options.find(o => String(o.id) === String(catId));
            return opt || { id: catId, label: String(catId) };
        });
        _renderTagPicker('m-cat');
    }

    // Remover do lote e atualizar tabela
    lote.splice(i, 1);
    renderizarLote();

    // Scroll até o formulário
    const form = document.querySelector('#multiplosRegistros .multi-form');
    if (form) form.scrollIntoView({ behavior: 'smooth', block: 'start' });

    alerta('Registro movido para edição. Altere e clique em Adicionar.', 3000);
}

function salvarLote() {
    if (lote.length === 0) return alerta('Nenhum registro no lote');
    alerta(`Salvando ${lote.length} registro(s)...`, 0);
    const promessas = lote.map(item => MainAPI.registrarGasto({
        financeiro: item.financeiro,
        instituicao: item.instituicao,
        detalhe: item.detalhe
    }));
    Promise.all(promessas).then(respostas => {
        const erros = respostas.filter(r => !r.ok).length;
        if (erros === 0) {
            window.dispatchEvent(new Event('xp:refresh'));
            lote = [];
            renderizarLote();
            alerta(`${respostas.length} registro(s) salvos com sucesso!<br><button onclick="document.getElementById('div_alerta').style.display='none'">OK</button>`, 0);
        } else {
            alerta(`${erros} erro(s) ao salvar. Verifique e tente novamente.`);
        }
    }).catch(() => alerta('Erro ao conectar ao servidor'));
}

/* ══════════════════════════════════════════════════
   Troca de aba
══════════════════════════════════════════════════ */
function trocarFormulario(tela) {
    const cardUnico    = document.getElementById("cardUnico");
    const cardMultiplo = document.getElementById("multiplosRegistros");
    const tabUnico     = document.getElementById("tabUnico");
    const tabMultiplo  = document.getElementById("tabMultiplo");
    if (tela === "multiplosRegistros") {
        if (cardUnico)    cardUnico.style.display    = "none";
        if (cardMultiplo) cardMultiplo.style.display = "flex";
        if (tabUnico)     tabUnico.classList.remove("ativo");
        if (tabMultiplo)  tabMultiplo.classList.add("ativo");
    } else {
        if (cardUnico)    cardUnico.style.display    = "";
        if (cardMultiplo) cardMultiplo.style.display = "none";
        if (tabUnico)     tabUnico.classList.add("ativo");
        if (tabMultiplo)  tabMultiplo.classList.remove("ativo");
    }
}

/* Header titulos (mantido para compatibilidade) */
const titulos = document.querySelectorAll(".headerFormulario .titulo");
titulos.forEach(item => {
    item.addEventListener("click", () => {
        titulos.forEach(e => e.classList.remove("ativo"));
        item.classList.add("ativo");
    });
});

(function () {
    const MESES = [
        "Janeiro", "Fevereiro", "Março", "Abril", "Maio", "Junho",
        "Julho", "Agosto", "Setembro", "Outubro", "Novembro", "Dezembro"
    ];

    const formatadorMoeda = new Intl.NumberFormat("pt-BR", {
        style: "currency",
        currency: "BRL"
    });

    const usuarioLogado = JSON.parse(localStorage.getItem("usuarioLogado") || "null");
    const userId = usuarioLogado ? usuarioLogado.id : null;

    let hoje = new Date();
    hoje.setHours(0, 0, 0, 0);
    let anoAtual = hoje.getFullYear();
    let mesAtual = hoje.getMonth();

    let eventosPorDia = {};

    function classificar(registro) {
        const tipo = registro.eventoFinanceiro && registro.eventoFinanceiro.tipo
            ? registro.eventoFinanceiro.tipo.toLowerCase()
            : "";
        const dataEvento = registro.eventoFinanceiro && registro.eventoFinanceiro.dataEvento
            ? new Date(registro.eventoFinanceiro.dataEvento + "T00:00:00")
            : null;

        if (tipo === "transferencia") return "transferencia";
        if (tipo === "recebimento") return "recebimento";
        if (tipo === "gasto") {
            if (dataEvento && dataEvento > hoje) return "agendamento";
            return "gasto";
        }
        return "gasto";
    }

    function toLocalDateKey(isoString) {
        return isoString.substring(0, 10);
    }

    function carregarEventos() {
        if (!userId) {
            renderizarCalendario();
            return Promise.resolve();
        }
        return MainAPI.carregarRegistros(userId)
            .then(registros => {
                eventosPorDia = {};
                registros.forEach(r => {
                    const dataISO = r.eventoFinanceiro && r.eventoFinanceiro.dataEvento;
                    if (!dataISO) return;
                    const key = toLocalDateKey(dataISO);
                    if (!eventosPorDia[key]) eventosPorDia[key] = [];
                    eventosPorDia[key].push(r);
                });
                renderizarCalendario();
            })
            .catch(() => {
                renderizarCalendario();
            });
    }

    function renderizarCalendario() {
        const grid = document.getElementById("calGrid");
        const nomeMes = document.getElementById("mesNome");

        nomeMes.textContent = MESES[mesAtual] + " " + anoAtual;
        grid.innerHTML = "";

        const primeiroDia = new Date(anoAtual, mesAtual, 1).getDay();
        const diasNoMes = new Date(anoAtual, mesAtual + 1, 0).getDate();
        const todayKey = hoje.getFullYear() + "-" + String(hoje.getMonth() + 1).padStart(2, "0") + "-" + String(hoje.getDate()).padStart(2, "0");

        for (let i = 0; i < primeiroDia; i++) {
            const vazio = document.createElement("div");
            vazio.className = "ag-day ag-empty";
            grid.appendChild(vazio);
        }

        for (let dia = 1; dia <= diasNoMes; dia++) {
            const key = anoAtual + "-" + String(mesAtual + 1).padStart(2, "0") + "-" + String(dia).padStart(2, "0");
            const cell = document.createElement("div");
            cell.className = "ag-day";
            if (key === todayKey) cell.classList.add("ag-today");
            cell.dataset.key = key;

            const numEl = document.createElement("div");
            numEl.className = "ag-day-num";
            numEl.textContent = dia;
            cell.appendChild(numEl);

            const eventos = eventosPorDia[key] || [];
            if (eventos.length > 0) {
                const dotsEl = document.createElement("div");
                dotsEl.className = "ag-dots";
                const tiposVistos = new Set();
                eventos.forEach(function(r) {
                    const tipo = classificar(r);
                    if (!tiposVistos.has(tipo)) {
                        tiposVistos.add(tipo);
                        const dot = document.createElement("div");
                        dot.className = "ag-dot ag-dot-" + tipo;
                        dotsEl.appendChild(dot);
                    }
                });
                cell.appendChild(dotsEl);
            }

            cell.addEventListener("click", (function(k, d) {
                return function() { selecionarDia(k, d); };
            })(key, dia));
            grid.appendChild(cell);
        }
    }

    function selecionarDia(key, dia) {
        document.querySelectorAll(".ag-day.ag-selected").forEach(function(el) { el.classList.remove("ag-selected"); });
        const cell = document.querySelector(".ag-day[data-key='" + key + "']");
        if (cell) cell.classList.add("ag-selected");

        const empty = document.getElementById("resumoEmpty");
        const conteudo = document.getElementById("resumoConteudo");
        const eventos = eventosPorDia[key] || [];

        conteudo.innerHTML = "";

        if (eventos.length === 0) {
            empty.style.display = "";
            empty.textContent = "Nenhum evento neste dia.";
            return;
        }

        empty.style.display = "none";

        const partes = key.split("-");
        const dataHeader = document.createElement("div");
        dataHeader.className = "ag-resumo-data";
        dataHeader.textContent = partes[2] + "/" + partes[1] + "/" + partes[0];
        conteudo.appendChild(dataHeader);

        eventos.forEach(function(r) {
            const tipo = classificar(r);
            const titulo = r.gastoDetalhe ? r.gastoDetalhe.tituloGasto : "-";
            const valor = r.eventoFinanceiro ? (r.eventoFinanceiro.valor || 0) : 0;
            const chip = document.createElement("div");
            chip.className = "ag-evento " + tipo;
            const prefix = tipo === "recebimento" ? "+" : tipo === "transferencia" ? "" : "-";
            chip.innerHTML = '<span class="ag-evento-titulo">' + titulo + '</span>'
                + '<span class="ag-evento-valor">' + prefix + formatadorMoeda.format(Math.abs(valor)) + '</span>';
            conteudo.appendChild(chip);
        });
    }

    function mostrarMesCompleto() {
        const empty = document.getElementById("resumoEmpty");
        const conteudo = document.getElementById("resumoConteudo");
        conteudo.innerHTML = "";

        const prefixo = anoAtual + "-" + String(mesAtual + 1).padStart(2, "0") + "-";
        const chavesDoMes = Object.keys(eventosPorDia)
            .filter(function(k) { return k.startsWith(prefixo); })
            .sort();

        if (chavesDoMes.length === 0) {
            empty.style.display = "";
            empty.textContent = "Nenhum evento neste mês.";
            return;
        }

        empty.style.display = "none";

        chavesDoMes.forEach(function(key) {
            const partes = key.split("-");
            const dataHeader = document.createElement("div");
            dataHeader.className = "ag-resumo-data";
            dataHeader.textContent = partes[2] + "/" + partes[1] + "/" + partes[0];
            conteudo.appendChild(dataHeader);

            eventosPorDia[key].forEach(function(r) {
                const tipo = classificar(r);
                const titulo = r.gastoDetalhe ? r.gastoDetalhe.tituloGasto : "-";
                const valor = r.eventoFinanceiro ? (r.eventoFinanceiro.valor || 0) : 0;
                const chip = document.createElement("div");
                chip.className = "ag-evento " + tipo;
                const prefix = tipo === "recebimento" ? "+" : tipo === "transferencia" ? "" : "-";
                chip.innerHTML = '<span class="ag-evento-titulo">' + titulo + '</span>'
                    + '<span class="ag-evento-valor">' + prefix + formatadorMoeda.format(Math.abs(valor)) + '</span>';
                conteudo.appendChild(chip);
            });
        });
    }

    document.getElementById("btnPrevMes").addEventListener("click", function() {
        mesAtual--;
        if (mesAtual < 0) { mesAtual = 11; anoAtual--; }
        renderizarCalendario();
        mostrarMesCompleto();
    });

    document.getElementById("btnNextMes").addEventListener("click", function() {
        mesAtual++;
        if (mesAtual > 11) { mesAtual = 0; anoAtual++; }
        renderizarCalendario();
        mostrarMesCompleto();
    });

    carregarEventos().then(function() { mostrarMesCompleto(); });
})();

(function () {
    const MESES = [
        "Janeiro", "Fevereiro", "Março", "Abril", "Maio", "Junho",
        "Julho", "Agosto", "Setembro", "Outubro", "Novembro", "Dezembro"
    ];

    const fmt = new Intl.NumberFormat("pt-BR", { style: "currency", currency: "BRL" });

    const usuarioLogado = JSON.parse(localStorage.getItem("usuarioLogado") || "null");
    const userId = usuarioLogado ? usuarioLogado.id : null;

    let hoje = new Date();
    hoje.setHours(0, 0, 0, 0);
    let anoAtual = hoje.getFullYear();
    let mesAtual = hoje.getMonth();

    let eventosPorDia = {};

    // ── Classificação ────────────────────────────────────────────
    function classificar(registro) {
        const tipo = (registro.eventoFinanceiro && registro.eventoFinanceiro.tipo
            ? registro.eventoFinanceiro.tipo : "").toLowerCase();
        const dataEvento = registro.eventoFinanceiro && registro.eventoFinanceiro.dataEvento
            ? new Date(registro.eventoFinanceiro.dataEvento + "T00:00:00") : null;

        if (tipo === "transferencia")  return "transferencia";
        if (tipo === "recebimento")    return "recebimento";
        if (tipo === "poupanca")       return "poupanca";
        if (tipo === "emprestimo")     return "emprestimo";
        if (tipo === "gasto") {
            if (dataEvento && dataEvento > hoje) return "agendamento";
            return "gasto";
        }
        return "gasto";
    }

    function toLocalDateKey(iso) { return iso.substring(0, 10); }

    // ── Carregar eventos ─────────────────────────────────────────
    function carregarEventos() {
        if (!userId) { renderizarCalendario(); return Promise.resolve(); }
        return MainAPI.carregarRegistros(userId)
            .then(registros => {
                eventosPorDia = {};
                registros.forEach(r => {
                    const dataISO = r.eventoFinanceiro && r.eventoFinanceiro.dataEvento;
                    if (!dataISO) return;
                    const key = toLocalDateKey(dataISO);
                    if (!eventosPorDia[key]) eventosPorDia[key] = [];
                    eventosPorDia[key].push(r);
                });
                renderizarCalendario();
            })
            .catch(() => renderizarCalendario());
    }

    // ── Renderizar calendário ────────────────────────────────────
    function renderizarCalendario() {
        const grid = document.getElementById("calGrid");
        document.getElementById("mesNome").textContent = MESES[mesAtual] + " " + anoAtual;
        grid.innerHTML = "";

        const primeiroDia  = new Date(anoAtual, mesAtual, 1).getDay();
        const diasNoMes    = new Date(anoAtual, mesAtual + 1, 0).getDate();
        const todayKey     = anoAtual + "-" + String(mesAtual + 1).padStart(2, "0") + "-" + String(hoje.getDate()).padStart(2, "0");

        for (let i = 0; i < primeiroDia; i++) {
            const v = document.createElement("div");
            v.className = "ag-day ag-empty";
            grid.appendChild(v);
        }

        for (let dia = 1; dia <= diasNoMes; dia++) {
            const key  = anoAtual + "-" + String(mesAtual + 1).padStart(2, "0") + "-" + String(dia).padStart(2, "0");
            const cell = document.createElement("div");
            cell.className = "ag-day";
            if (key === todayKey) cell.classList.add("ag-today");
            cell.dataset.key = key;

            const numEl = document.createElement("div");
            numEl.className = "ag-day-num";
            numEl.textContent = dia;
            cell.appendChild(numEl);

            const eventos = eventosPorDia[key] || [];
            if (eventos.length > 0) {
                const dotsEl = document.createElement("div");
                dotsEl.className = "ag-dots";
                const tiposVistos = new Set();
                eventos.forEach(r => {
                    const tipo = classificar(r);
                    if (!tiposVistos.has(tipo)) {
                        tiposVistos.add(tipo);
                        const dot = document.createElement("div");
                        dot.className = "ag-dot ag-dot-" + tipo;
                        dotsEl.appendChild(dot);
                    }
                });
                cell.appendChild(dotsEl);
            }

            cell.addEventListener("click", (function(k, d) {
                return function() { selecionarDia(k, d); };
            })(key, dia));
            grid.appendChild(cell);
        }
    }

    // ── Selecionar dia → abrir modal ─────────────────────────────
    function selecionarDia(key, dia) {
        // Marcar no calendário
        document.querySelectorAll(".ag-day.ag-selected").forEach(el => el.classList.remove("ag-selected"));
        const cell = document.querySelector(".ag-day[data-key='" + key + "']");
        if (cell) cell.classList.add("ag-selected");

        // Também atualizar painel lateral (mantido para visão mensal)
        const empty    = document.getElementById("resumoEmpty");
        const conteudo = document.getElementById("resumoConteudo");
        const eventos  = eventosPorDia[key] || [];

        conteudo.innerHTML = "";
        if (eventos.length === 0) {
            empty.style.display = "";
            empty.textContent   = "Nenhum evento neste dia.";
        } else {
            empty.style.display = "none";
            const partes = key.split("-");
            const dh = document.createElement("div");
            dh.className = "ag-resumo-data";
            dh.textContent = partes[2] + "/" + partes[1] + "/" + partes[0];
            conteudo.appendChild(dh);
            eventos.forEach(r => {
                const tipo = classificar(r);
                const titulo = r.gastoDetalhe ? r.gastoDetalhe.tituloGasto : "-";
                const valor  = r.eventoFinanceiro ? (r.eventoFinanceiro.valor || 0) : 0;
                const chip = document.createElement("div");
                chip.className = "ag-evento " + tipo;
                const prefix = tipo === "recebimento" ? "+" : tipo === "transferencia" ? "↔" : "-";
                chip.innerHTML = '<span class="ag-evento-titulo">' + titulo + '</span>'
                    + '<span class="ag-evento-valor">' + prefix + fmt.format(Math.abs(valor)) + '</span>';
                conteudo.appendChild(chip);
            });
        }

        // Abrir modal detalhado se houver eventos
        if (eventos.length > 0) abrirModalDia(key, eventos);
    }

    // ── Modal de detalhes do dia ──────────────────────────────────
    const GRUPOS = [
        { tipo: "recebimento",  label: "Recebimentos",   icon: "bx-trending-up",    sinal:  1 },
        { tipo: "gasto",        label: "Gastos",          icon: "bx-trending-down",  sinal: -1 },
        { tipo: "transferencia",label: "Transferências",  icon: "bx-transfer",       sinal:  0 },
        { tipo: "poupanca",     label: "Poupança",        icon: "bx-piggy-bank",     sinal: -1 },
        { tipo: "emprestimo",   label: "Empréstimos",     icon: "bx-money",          sinal:  0 },
        { tipo: "agendamento",  label: "Agendamentos",    icon: "bx-calendar-check", sinal: -1 }
    ];

    function abrirModalDia(key, eventos) {
        const partes  = key.split("-");
        const dataFmt = partes[2] + "/" + partes[1] + "/" + partes[0];
        document.getElementById("agDiaModalTitulo").textContent = "Eventos de " + dataFmt;

        const body = document.getElementById("agDiaModalBody");
        body.innerHTML = "";

        let saldo = 0;

        GRUPOS.forEach(grupo => {
            const lista = eventos.filter(r => classificar(r) === grupo.tipo);
            if (lista.length === 0) return;

            const total = lista.reduce((s, r) => s + (r.eventoFinanceiro ? (r.eventoFinanceiro.valor || 0) : 0), 0);
            if (grupo.sinal !== 0) saldo += grupo.sinal * total;

            // Seção
            const secao = document.createElement("div");
            secao.className = "ag-modal-secao";

            const header = document.createElement("div");
            header.className = "ag-modal-secao-header ag-secao-" + grupo.tipo;
            header.innerHTML = `<i class='bx ${grupo.icon}'></i><span>${grupo.label}</span>`;
            secao.appendChild(header);

            const tabela = document.createElement("div");
            tabela.className = "ag-modal-tabela";

            lista.forEach(r => {
                const titulo = r.gastoDetalhe ? r.gastoDetalhe.tituloGasto : "-";
                const valor  = r.eventoFinanceiro ? (r.eventoFinanceiro.valor || 0) : 0;
                const linha  = document.createElement("div");
                linha.className = "ag-modal-linha";
                linha.innerHTML = `<span class="ag-modal-linha-titulo">${escHtml(titulo)}</span>`
                    + `<span class="ag-modal-linha-valor ag-val-${grupo.tipo}">${fmt.format(Math.abs(valor))}</span>`;
                tabela.appendChild(linha);
            });

            // Subtotal
            const subtotal = document.createElement("div");
            subtotal.className = "ag-modal-subtotal";
            subtotal.innerHTML = `<span>Total ${grupo.label}</span><span class="ag-val-${grupo.tipo}">${fmt.format(total)}</span>`;
            tabela.appendChild(subtotal);

            secao.appendChild(tabela);
            body.appendChild(secao);
        });

        // Saldo final
        const saldoEl = document.getElementById("agDiaSaldo");
        saldoEl.textContent = fmt.format(saldo);
        saldoEl.className = "ag-dia-saldo-valor " + (saldo >= 0 ? "ag-saldo-positivo" : "ag-saldo-negativo");

        document.getElementById("agDiaModalOverlay").classList.add("aberto");
    }

    window.fecharModalDia = function(e) {
        if (e && e.target !== document.getElementById("agDiaModalOverlay")) return;
        document.getElementById("agDiaModalOverlay").classList.remove("aberto");
    };

    function escHtml(str) {
        return String(str || "").replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;");
    }

    // ── Visão mensal (painel lateral) ────────────────────────────
    function mostrarMesCompleto() {
        const empty    = document.getElementById("resumoEmpty");
        const conteudo = document.getElementById("resumoConteudo");
        conteudo.innerHTML = "";

        const prefixo = anoAtual + "-" + String(mesAtual + 1).padStart(2, "0") + "-";
        const chaves  = Object.keys(eventosPorDia).filter(k => k.startsWith(prefixo)).sort();

        if (chaves.length === 0) {
            empty.style.display = "";
            empty.textContent   = "Nenhum evento neste mês.";
            return;
        }
        empty.style.display = "none";

        chaves.forEach(key => {
            const partes = key.split("-");
            const dh = document.createElement("div");
            dh.className = "ag-resumo-data";
            dh.textContent = partes[2] + "/" + partes[1] + "/" + partes[0];
            conteudo.appendChild(dh);

            eventosPorDia[key].forEach(r => {
                const tipo  = classificar(r);
                const titulo = r.gastoDetalhe ? r.gastoDetalhe.tituloGasto : "-";
                const valor  = r.eventoFinanceiro ? (r.eventoFinanceiro.valor || 0) : 0;
                const chip   = document.createElement("div");
                chip.className = "ag-evento " + tipo;
                const prefix = tipo === "recebimento" ? "+" : tipo === "transferencia" ? "↔" : "-";
                chip.innerHTML = '<span class="ag-evento-titulo">' + titulo + '</span>'
                    + '<span class="ag-evento-valor">' + prefix + fmt.format(Math.abs(valor)) + '</span>';
                conteudo.appendChild(chip);
            });
        });
    }

    document.getElementById("btnPrevMes").addEventListener("click", function() {
        mesAtual--;
        if (mesAtual < 0) { mesAtual = 11; anoAtual--; }
        renderizarCalendario();
        mostrarMesCompleto();
    });

    document.getElementById("btnNextMes").addEventListener("click", function() {
        mesAtual++;
        if (mesAtual > 11) { mesAtual = 0; anoAtual++; }
        renderizarCalendario();
        mostrarMesCompleto();
    });

    carregarEventos().then(function() { mostrarMesCompleto(); });

})();

/* ═══════════════════════════════════════════════════════════════
   caixinhas.js — Lógica completa da tela de Poupança/Caixinhas
   ═══════════════════════════════════════════════════════════════ */

'use strict';

// ── Estado ────────────────────────────────────────────────────
let _usuario        = null;
let _caixinhas      = [];          // cache de todas as caixinhas carregadas
let _filtroAtivo    = 'ativas';    // 'ativas' | 'encerradas' | 'todas'
let _caixinhaAtual  = null;        // caixinha aberta no modal de detalhes
let _editandoId     = null;        // id sendo editado (null = criar)
let _tipoRendimento = 'CDI';       // tipo selecionado no form
let _instsSelecionadas = new Set(); // ids de instituicaoUsuario selecionados
let _todasInstituicoes = [];       // lista de instituições do usuário

// ── Defaults de taxa por tipo ──────────────────────────────────
const TAXA_DEFAULTS = {
    CDI:          10.40,
    SELIC:        10.75,
    POUPANCA:     10.75,
    PREFIXADO:    null,
    PERSONALIZADO: null
};

// ════════════════════════════════════════════════════════════════
// INIT
// ════════════════════════════════════════════════════════════════
async function iniciarPagina() {
    // Recuperar usuário logado
    _usuario = JSON.parse(localStorage.getItem('usuarioLogado') || 'null');
    if (!_usuario || !_usuario.id) {
        window.location.href = 'index.html';
        return;
    }

    // Aplicar tema do localStorage
    const temaSalvo = localStorage.getItem('tema');
    const modoSalvo = localStorage.getItem('modo');
    if (temaSalvo) document.body.setAttribute('data-tema', temaSalvo);
    if (modoSalvo) document.body.setAttribute('data-mode', modoSalvo);

    // Aplicar máscara de moeda
    MainAPI.aplicarMascaraMoeda(document.getElementById('inputValorMeta'));
    // Aplicar máscara de data
    MainAPI.aplicarMascaraData(document.getElementById('inputDataPrazo'));

    // Carregar dados em paralelo
    await Promise.all([
        carregarKPIs(),
        carregarCaixinhas(_filtroAtivo),
        carregarInstituicoes()
    ]);
}

// ════════════════════════════════════════════════════════════════
// KPIs
// ════════════════════════════════════════════════════════════════
async function carregarKPIs() {
    const uid = _usuario.id;
    try {
        const [resTA, resPG, resRM, resST] = await Promise.allSettled([
            MainAPI.request(`/caixinhas/kpi/total-acumulado/usuarios/${uid}`).then(r => r.ok ? r.json() : null),
            MainAPI.request(`/caixinhas/kpi/progresso-geral/usuarios/${uid}`).then(r => r.ok ? r.json() : null),
            MainAPI.request(`/caixinhas/kpi/rendimento-estimado-mes/usuarios/${uid}`).then(r => r.ok ? r.json() : null),
            MainAPI.request(`/caixinhas/kpi/status/usuarios/${uid}`).then(r => r.ok ? r.json() : null)
        ]);

        // KPI 1 — Total Acumulado
        if (resTA.status === 'fulfilled' && resTA.value) {
            document.getElementById('kpiTotalAcumulado').textContent = formatarMoeda(resTA.value.totalAcumulado ?? 0);
            document.getElementById('kpiQtdAtivas').textContent = `${resTA.value.quantidadeAtivas ?? 0} caixinha(s) ativa(s)`;
        }

        // KPI 2 — Progresso Geral
        if (resPG.status === 'fulfilled' && resPG.value) {
            const pg = resPG.value;
            const pct = pg.percentualGeral ?? 0;
            document.getElementById('kpiProgressoPct').textContent = `${pct.toFixed(1)}%`;
            document.getElementById('kpiProgressoSub').textContent = 'da meta total atingida';

            // Atualizar barra consolidada
            const fillPct = Math.min(100, pct);
            document.getElementById('cxhProgressoFill').style.width = `${fillPct}%`;
            document.getElementById('cxhProgressoPctBar').textContent = `${pct.toFixed(1)}%`;
            document.getElementById('cxhProgressoValAtual').textContent = `${formatarMoeda(pg.totalAcumulado ?? 0)} acumulados`;
            document.getElementById('cxhProgressoValMeta').textContent = `Meta: ${formatarMoeda(pg.totalMetas ?? 0)}`;
        }

        // KPI 3 — Rendimento Estimado
        if (resRM.status === 'fulfilled' && resRM.value) {
            document.getElementById('kpiRendimento').textContent = formatarMoeda(resRM.value.rendimentoEstimadoMes ?? 0);
        }

        // KPI 4 — Status
        if (resST.status === 'fulfilled' && resST.value) {
            const st = resST.value;
            document.getElementById('kpiStatusAtivas').textContent = `${st.quantidadeAtivas ?? 0} ativas`;
            document.getElementById('kpiStatusSub').textContent = `${st.quantidadeEncerradas ?? 0} encerradas`;
        }
    } catch (e) {
        console.error('Erro ao carregar KPIs:', e);
    }
}

// ════════════════════════════════════════════════════════════════
// CAIXINHAS
// ════════════════════════════════════════════════════════════════
async function carregarCaixinhas(filtro) {
    _filtroAtivo = filtro;
    mostrarLoading(true);

    try {
        const uid = _usuario.id;
        let endpoint;
        if (filtro === 'ativas') {
            endpoint = `/caixinhas/ativas/usuarios/${uid}`;
        } else {
            endpoint = `/caixinhas/usuarios/${uid}`;
        }

        const res = await MainAPI.request(endpoint);
        if (res.status === 204) {
            _caixinhas = [];
        } else if (res.ok) {
            _caixinhas = await res.json();
            if (!Array.isArray(_caixinhas)) _caixinhas = [];
        } else {
            _caixinhas = [];
        }

        // Filtrar encerradas no cliente quando necessário
        let lista = _caixinhas;
        if (filtro === 'encerradas') {
            lista = _caixinhas.filter(c => !c.isAtiva);
        }

        renderizarCards(lista);
        mostrarInsight(lista);
    } catch (e) {
        console.error('Erro ao carregar caixinhas:', e);
        _caixinhas = [];
        renderizarCards([]);
    } finally {
        mostrarLoading(false);
    }
}

function mostrarLoading(show) {
    document.getElementById('cxhLoading').style.display = show ? 'flex' : 'none';
    if (show) {
        document.getElementById('cxhGrid').style.display = 'none';
        document.getElementById('cxhVazio').style.display = 'none';
        document.getElementById('cxhInsight').style.display = 'none';
    }
}

function renderizarCards(lista) {
    const grid  = document.getElementById('cxhGrid');
    const vazio = document.getElementById('cxhVazio');

    if (!lista || lista.length === 0) {
        grid.style.display  = 'none';
        vazio.style.display = 'flex';
        return;
    }

    vazio.style.display = 'none';
    grid.style.display  = 'grid';

    grid.innerHTML = lista.map(c => gerarCardHTML(c)).join('');

    // Adicionar listeners de clique
    grid.querySelectorAll('.cxh-card').forEach(card => {
        const id = card.dataset.id;
        card.addEventListener('click', () => {
            const caixinha = _caixinhas.find(c => c.id === id)
                || lista.find(c => c.id === id);
            if (caixinha) abrirModalDetalhes(caixinha);
        });
    });
}

function gerarCardHTML(c) {
    const pct     = Math.min(100, c.percentualAtingido ?? 0);
    const atingida = pct >= 100;
    const tipo    = c.tipoRendimento || 'CDI';
    const encerrada = !c.isAtiva;

    const alcancavel = c.metaAlcancavel;
    const alcancavelHTML = typeof alcancavel === 'boolean'
        ? `<span class="cxh-card-meta-alcancavel ${alcancavel ? '' : 'nao'}">
               <i class='bx ${alcancavel ? 'bx-check-circle' : 'bx-x-circle'}'></i>
               ${alcancavel ? 'Meta alcançável' : 'Aporte insuficiente'}
           </span>`
        : '';

    const mesesTxt = c.mesesRestantes != null ? `${c.mesesRestantes} meses restantes` : '–';
    const prazoTxt = c.dataPrazo ? formatarData(c.dataPrazo) : '–';

    return `
    <div class="cxh-card ${encerrada ? 'encerrada' : ''}" data-id="${c.id}">
        <div class="cxh-card-header">
            <div>
                <div class="cxh-card-nome">${escHtml(c.nome)}</div>
                ${c.descricao ? `<div class="cxh-card-desc">${escHtml(c.descricao)}</div>` : ''}
            </div>
            <span class="cxh-badge cxh-badge-${tipo}">${labelTipo(tipo)}</span>
        </div>

        <div class="cxh-card-valores">
            <span class="cxh-card-valor-atual">${formatarMoeda(c.valorAtual ?? 0)}</span>
            <span class="cxh-card-meta">/ ${formatarMoeda(c.valorMeta ?? 0)}</span>
        </div>

        <div>
            <div class="cxh-card-progress-track">
                <div class="cxh-card-progress-fill ${atingida ? 'atingida' : ''}" style="width:${pct}%"></div>
            </div>
            <div class="cxh-card-progress-info">
                <span class="cxh-card-pct">${pct.toFixed(1)}%</span>
                <span>${mesesTxt}</span>
            </div>
        </div>

        <div class="cxh-card-footer">
            ${alcancavelHTML}
            <span>${prazoTxt}</span>
        </div>
    </div>`;
}

// ════════════════════════════════════════════════════════════════
// FILTROS / ABAS
// ════════════════════════════════════════════════════════════════
function trocarFiltro(filtro, btnEl) {
    document.querySelectorAll('.cxh-filtro-btn').forEach(b => b.classList.remove('ativo'));
    btnEl.classList.add('ativo');
    carregarCaixinhas(filtro);
}

// ════════════════════════════════════════════════════════════════
// MODAL DETALHES
// ════════════════════════════════════════════════════════════════
function abrirModalDetalhes(c) {
    _caixinhaAtual = c;
    const encerrada = !c.isAtiva;

    // Cabeçalho
    document.getElementById('detNome').textContent    = c.nome;
    document.getElementById('detDesc').textContent    = c.descricao || '';
    document.getElementById('detBadge').className     = `cxh-badge cxh-badge-${c.tipoRendimento || 'CDI'}`;
    document.getElementById('detBadge').textContent   = labelTipo(c.tipoRendimento);
    document.getElementById('detStatusBadge').innerHTML = encerrada
        ? `<span style="font-size:0.7rem;font-weight:700;padding:3px 9px;border-radius:12px;background:var(--cor-fundo-inativo);color:var(--cor-texto-secundario);">Encerrada</span>`
        : `<span style="font-size:0.7rem;font-weight:700;padding:3px 9px;border-radius:12px;background:var(--green-100);color:var(--green-700);">Ativa</span>`;

    // Stats
    document.getElementById('detValorAtual').textContent  = formatarMoeda(c.valorAtual ?? 0);
    document.getElementById('detMeta').textContent        = formatarMoeda(c.valorMeta ?? 0);
    document.getElementById('detFalta').textContent       = formatarMoeda(c.faltaParaMeta ?? 0);
    const pct = c.percentualAtingido ?? 0;
    document.getElementById('detPct').textContent         = `${pct.toFixed(1)}%`;
    document.getElementById('detMeses').textContent       = c.mesesRestantes != null ? `${c.mesesRestantes} meses` : '–';
    document.getElementById('detPrazo').textContent       = c.dataPrazo ? formatarData(c.dataPrazo) : '–';
    document.getElementById('detAporte').textContent      = c.aporteMensalSugerido != null ? formatarMoeda(c.aporteMensalSugerido) : '–';
    document.getElementById('detTaxaMensal').textContent  = c.taxaMensalEfetiva != null
        ? `${(c.taxaMensalEfetiva * 100).toFixed(4)}% a.m.`
        : '–';

    // Barra de progresso
    const fillPct = Math.min(100, pct);
    document.getElementById('detProgressoFill').style.width = `${fillPct}%`;
    document.getElementById('detPctBar').textContent = `${pct.toFixed(1)}%`;

    // Meta alcançável
    const alcDiv = document.getElementById('detAlcancavel');
    if (typeof c.metaAlcancavel === 'boolean') {
        alcDiv.innerHTML = `
            <span class="cxh-det-alcancavel ${c.metaAlcancavel ? '' : 'nao'}">
                <i class='bx ${c.metaAlcancavel ? 'bx-check-circle' : 'bx-x-circle'}'></i>
                ${c.metaAlcancavel ? 'Meta alcançável com aportes sugeridos' : 'Meta pode não ser atingida com os aportes atuais'}
            </span>`;
    } else {
        alcDiv.innerHTML = '';
    }

    // Projeção
    document.getElementById('detProjecao').innerHTML = gerarTextoProjecao(c);

    // Instituições
    const instLista = document.getElementById('detInstLista');
    const instSection = document.getElementById('detInstSection');
    if (c.instituicoes && c.instituicoes.length > 0) {
        instSection.style.display = '';
        instLista.innerHTML = c.instituicoes.map(inst =>
            `<div class="cxh-det-inst-item">
                <span class="cxh-det-inst-nome"><i class='bx bx-buildings'></i> ${escHtml(inst.nome || 'Instituição')}</span>
                <span class="cxh-det-inst-val">${formatarMoeda(inst.valorAportado ?? 0)}</span>
            </div>`
        ).join('');
    } else {
        instSection.style.display = 'none';
    }

    // Botões: desabilitar encerrar se já encerrada
    document.getElementById('btnDetEncerrar').disabled = encerrada;
    document.getElementById('btnDetEncerrar').style.opacity = encerrada ? '0.4' : '1';

    document.getElementById('modalDetOverlay').classList.add('aberto');
}

function fecharModalDet() {
    document.getElementById('modalDetOverlay').classList.remove('aberto');
    _caixinhaAtual = null;
}

function fecharModalDetOutside(e) {
    if (e.target === document.getElementById('modalDetOverlay')) fecharModalDet();
}

function gerarTextoProjecao(c) {
    const semAportes = c.montanteProjetadoSemAportes;
    const comAportes = c.montanteProjetadoComAportes;
    const aporte     = c.aporteMensalSugerido;
    const meses      = c.mesesRestantes;
    const taxa       = c.taxaMensalEfetiva;

    // Calcular projeção localmente se os dados do servidor estiverem ausentes
    const r = taxa != null ? taxa : 0;
    const n = meses != null ? meses : 0;
    const VA = c.valorAtual ?? 0;

    // Projeção sem aportes: VA * (1+r)^n
    const projSemAp = semAportes != null ? semAportes : (r > 0 ? VA * Math.pow(1 + r, n) : VA);
    // Projeção com aportes sugeridos
    const ap = aporte != null ? aporte : 0;
    const projComAp = comAportes != null ? comAportes
        : (r > 0 ? projSemAp + ap * ((Math.pow(1 + r, n) - 1) / r)
                 : projSemAp + ap * n);

    return `
        <strong>Sem novos aportes:</strong> você terá <strong>${formatarMoeda(projSemAp)}</strong> no prazo.<br>
        <strong>Com aporte de ${formatarMoeda(ap)}/mês:</strong> você terá <strong>${formatarMoeda(projComAp)}</strong>.<br>
        <strong>Meta:</strong> ${formatarMoeda(c.valorMeta ?? 0)}&nbsp;·&nbsp;
        <strong>Falta:</strong> ${formatarMoeda(c.faltaParaMeta ?? 0)}&nbsp;·&nbsp;
        <strong>Taxa mensal:</strong> ${r > 0 ? (r * 100).toFixed(4) + '% a.m.' : 'sem rendimento definido'}
    `;
}

// ── Ações do modal de detalhes ─────────────────────────────────
function editarCaixinhaAtual() {
    if (!_caixinhaAtual) return;
    const c = _caixinhaAtual; // salva referência ANTES de fechar (fecharModalDet zera _caixinhaAtual)
    fecharModalDet();
    abrirModalEditar(c);
}

async function encerrarCaixinhaAtual() {
    if (!_caixinhaAtual) return;
    const c = _caixinhaAtual;
    if (!confirm(`Encerrar a caixinha "${c.nome}"? Esta ação não pode ser desfeita.`)) return;
    fecharModalDet();
    await encerrarCaixinha(c.id);
}

async function deletarCaixinhaAtual() {
    if (!_caixinhaAtual) return;
    const c = _caixinhaAtual;
    if (!confirm(`Deletar permanentemente a caixinha "${c.nome}"? Esta ação não pode ser desfeita.`)) return;
    fecharModalDet();
    await deletarCaixinha(c.id);
}

// ════════════════════════════════════════════════════════════════
// MODAL CRIAR / EDITAR
// ════════════════════════════════════════════════════════════════
function abrirModalCriar() {
    _editandoId = null;
    document.getElementById('modalCriarTitulo').innerHTML = "<i class='bx bx-plus-circle'></i> Nova Caixinha";
    resetarFormulario();
    document.getElementById('modalCriarOverlay').classList.add('aberto');
    validarBotaoSalvar();
}

function abrirModalEditar(c) {
    _editandoId = c.id;
    document.getElementById('modalCriarTitulo').innerHTML = "<i class='bx bx-edit'></i> Editar Caixinha";
    preencherFormulario(c);
    document.getElementById('modalCriarOverlay').classList.add('aberto');
    validarBotaoSalvar();
}

function fecharModalCriar() {
    document.getElementById('modalCriarOverlay').classList.remove('aberto');
}

function fecharModalCriarOutside(e) {
    if (e.target === document.getElementById('modalCriarOverlay')) fecharModalCriar();
}

function resetarFormulario() {
    document.getElementById('inputNome').value        = '';
    document.getElementById('inputDescricao').value   = '';
    MainAPI.resetarMascaraMoeda(document.getElementById('inputValorMeta'));
    document.getElementById('inputDataPrazo').value   = '';
    document.getElementById('inputPctRendimento').value  = '';
    document.getElementById('inputTaxaRef').value        = '';
    document.getElementById('inputTaxaRefPoupanca').value = '';
    document.getElementById('inputTaxaAnual').value      = '';
    _instsSelecionadas.clear();
    selecionarTipoRendimento('CDI');
    renderizarInstituicoes();
    document.getElementById('taxaResumo').style.display = 'none';
}

function preencherFormulario(c) {
    document.getElementById('inputNome').value      = c.nome || '';
    document.getElementById('inputDescricao').value = c.descricao || '';

    // Valor meta
    const inputMeta = document.getElementById('inputValorMeta');
    const centavos  = Math.round((c.valorMeta ?? 0) * 100);
    inputMeta.dataset.centavos = String(centavos);
    const reais = Math.floor(centavos / 100);
    const cts   = String(centavos % 100).padStart(2, '0');
    const reaisStr = String(reais).replace(/\B(?=(\d{3})+(?!\d))/g, '.');
    inputMeta.value = `R$ ${reaisStr},${cts}`;

    // Data prazo — backend pode retornar string "aaaa-mm-dd" ou array [ano, mes, dia]
    if (c.dataPrazo) {
        let iso = c.dataPrazo;
        if (Array.isArray(iso) && iso.length >= 3) {
            iso = `${iso[0]}-${String(iso[1]).padStart(2,'0')}-${String(iso[2]).padStart(2,'0')}`;
        }
        document.getElementById('inputDataPrazo').value = MainAPI.dataDeISO(String(iso));
    }

    // Tipo de rendimento
    const tipo = c.tipoRendimento || 'CDI';
    selecionarTipoRendimento(tipo);

    if (tipo === 'CDI' || tipo === 'SELIC') {
        document.getElementById('inputPctRendimento').value  = c.percentualRendimento ?? 100;
        document.getElementById('inputTaxaRef').value        = c.taxaReferenciaAtual ?? TAXA_DEFAULTS[tipo];
    } else if (tipo === 'POUPANCA') {
        document.getElementById('inputTaxaRefPoupanca').value = c.taxaReferenciaAtual ?? TAXA_DEFAULTS.POUPANCA;
    } else {
        document.getElementById('inputTaxaAnual').value = c.taxaAnualPersonalizada ?? '';
    }

    calcularTaxaEfetiva();

    // Instituições
    _instsSelecionadas.clear();
    if (c.instituicoes && Array.isArray(c.instituicoes)) {
        c.instituicoes.forEach(inst => {
            // inst.id pode ser o id da vinculação (instituicaoUsuarioId)
            _instsSelecionadas.add(inst.id);
        });
    }
    renderizarInstituicoes();
}

// ── Tipo de rendimento ─────────────────────────────────────────
function selecionarTipoRendimento(tipo) {
    _tipoRendimento = tipo;

    // Atualizar botões
    document.querySelectorAll('.cxh-rend-btn').forEach(btn => {
        btn.className = 'cxh-rend-btn';
        if (btn.dataset.tipo === tipo) btn.classList.add(`ativo-${tipo}`);
    });

    // Mostrar campos corretos
    ['camposCdiSelic', 'camposPoupanca', 'camposPrefixado'].forEach(id => {
        document.getElementById(id).classList.remove('visivel');
    });

    if (tipo === 'CDI' || tipo === 'SELIC') {
        document.getElementById('camposCdiSelic').classList.add('visivel');
        const lbl = document.getElementById('labelPctCdi');
        const lbl2 = document.getElementById('labelTaxaRef');
        lbl.textContent  = tipo === 'CDI' ? '% do CDI' : '% da SELIC';
        lbl2.textContent = tipo === 'CDI' ? 'Taxa CDI atual (% a.a.)' : 'Taxa SELIC atual (% a.a.)';
        // Preencher default se vazio
        const inp = document.getElementById('inputTaxaRef');
        if (!inp.value) inp.value = TAXA_DEFAULTS[tipo];
        const inpPct = document.getElementById('inputPctRendimento');
        if (!inpPct.value) inpPct.value = 100;
    } else if (tipo === 'POUPANCA') {
        document.getElementById('camposPoupanca').classList.add('visivel');
        const inp = document.getElementById('inputTaxaRefPoupanca');
        if (!inp.value) inp.value = TAXA_DEFAULTS.POUPANCA;
    } else {
        document.getElementById('camposPrefixado').classList.add('visivel');
    }

    calcularTaxaEfetiva();
}

// ── Calcular taxa efetiva ──────────────────────────────────────
function calcularTaxaEfetiva() {
    const tipo = _tipoRendimento;
    let taxaAnual = 0;

    if (tipo === 'CDI' || tipo === 'SELIC') {
        const pct     = parseFloat(document.getElementById('inputPctRendimento').value) || 100;
        const taxaRef = parseFloat(document.getElementById('inputTaxaRef').value) || 0;
        taxaAnual = taxaRef * (pct / 100);
    } else if (tipo === 'POUPANCA') {
        const taxaRef = parseFloat(document.getElementById('inputTaxaRefPoupanca').value) || 0;
        taxaAnual = taxaRef * 0.70;
    } else {
        taxaAnual = parseFloat(document.getElementById('inputTaxaAnual').value) || 0;
    }

    const taxaMensal = taxaAnual > 0 ? (Math.pow(1 + taxaAnual / 100, 1 / 12) - 1) * 100 : 0;

    const resumo = document.getElementById('taxaResumo');
    const txt    = document.getElementById('taxaResumoTexto');

    if (taxaAnual > 0) {
        resumo.style.display = 'flex';
        txt.innerHTML = `Taxa efetiva: <strong>${taxaAnual.toFixed(2)}% a.a.</strong> · <strong>${taxaMensal.toFixed(4)}% a.m.</strong>`;

        // Verificar alcançabilidade em tempo real
        const meta    = MainAPI.obterValorMoeda(document.getElementById('inputValorMeta'));
        const prazoTxt = document.getElementById('inputDataPrazo').value;
        if (meta > 0 && prazoTxt && prazoTxt.length === 10) {
            const prazoISO = MainAPI.dataParaISO(prazoTxt);
            if (prazoISO) {
                const hoje    = new Date();
                const prazo   = new Date(prazoISO);
                const diffMs  = prazo - hoje;
                const meses   = Math.max(0, Math.floor(diffMs / (1000 * 60 * 60 * 24 * 30.4)));
                if (meses > 0) {
                    const r   = taxaMensal / 100;
                    const VA  = 0; // sem valor atual inicial no form
                    const projSem = r > 0 ? VA * Math.pow(1 + r, meses) : VA;
                    const aporteNecessario = r > 0
                        ? ((meta - projSem) * r) / (Math.pow(1 + r, meses) - 1)
                        : (meta - projSem) / meses;
                    if (aporteNecessario > 0) {
                        txt.innerHTML += ` · Aporte necessário: <strong>${formatarMoeda(aporteNecessario)}/mês</strong> por <strong>${meses} meses</strong>`;
                    }
                }
            }
        }
    } else {
        resumo.style.display = 'none';
    }
}

// ── Instituições ───────────────────────────────────────────────
async function carregarInstituicoes() {
    try {
        _todasInstituicoes = await MainAPI.getInstituicoes(_usuario.id);
        if (!Array.isArray(_todasInstituicoes)) _todasInstituicoes = [];
        renderizarInstituicoes();
    } catch (e) {
        console.error('Erro ao carregar instituições:', e);
        _todasInstituicoes = [];
    }
}

function renderizarInstituicoes() {
    const grid = document.getElementById('instGrid');
    if (_todasInstituicoes.length === 0) {
        grid.innerHTML = '<span style="font-size:0.82rem;color:var(--cor-texto-secundario);">Nenhuma instituição vinculada. <a href="configurações.html" style="color:var(--cor-principal);">Configurar</a></span>';
        return;
    }

    grid.innerHTML = _todasInstituicoes.map(inst => {
        const selecionada = _instsSelecionadas.has(inst.id);
        return `
        <div class="cxh-inst-item ${selecionada ? 'selecionada' : ''}" 
             data-instid="${inst.id}"
             onclick="toggleInstituicao(${inst.id}, this)">
            <span class="cxh-inst-check">${selecionada ? '✓' : ''}</span>
            <span>${escHtml(inst.intituicao?.nome || inst.instituicao?.nome || inst.nomeInstituicao || inst.nome || `Inst. ${inst.id}`)}</span>
        </div>`;
    }).join('');
}

function toggleInstituicao(instId, el) {
    if (_instsSelecionadas.has(instId)) {
        _instsSelecionadas.delete(instId);
        el.classList.remove('selecionada');
        el.querySelector('.cxh-inst-check').textContent = '';
    } else {
        _instsSelecionadas.add(instId);
        el.classList.add('selecionada');
        el.querySelector('.cxh-inst-check').textContent = '✓';
    }
    validarBotaoSalvar();
}

// ── Validar botão salvar ───────────────────────────────────────
function validarBotaoSalvar() {
    const nome    = (document.getElementById('inputNome').value || '').trim();
    const temInst = _instsSelecionadas.size > 0;
    const btn     = document.getElementById('btnSalvarCaixinha');
    const aviso   = document.getElementById('instAviso');

    btn.disabled = !(nome && temInst);
    if (aviso) aviso.style.display = (!temInst && nome) ? '' : 'none';
}

// ════════════════════════════════════════════════════════════════
// SALVAR (POST / PUT)
// ════════════════════════════════════════════════════════════════
async function salvarCaixinha() {
    const nome     = document.getElementById('inputNome').value.trim();
    const descricao = document.getElementById('inputDescricao').value.trim();
    const valorMeta = MainAPI.obterValorMoeda(document.getElementById('inputValorMeta'));
    const prazoTxt  = document.getElementById('inputDataPrazo').value;
    const tipo      = _tipoRendimento;

    if (!nome) { mostrarToast('Informe o nome da caixinha.', 'erro'); return; }
    if (_instsSelecionadas.size === 0) { mostrarToast('Selecione ao menos uma instituição.', 'erro'); return; }

    // Montar payload
    const payload = {
        usuarioId:    _usuario.id,
        nome,
        descricao:    descricao || null,
        valorMeta:    valorMeta > 0 ? valorMeta : null,
        dataPrazo:    prazoTxt ? MainAPI.dataParaISO(prazoTxt) : null,
        tipoRendimento: tipo,
        isCompartilhada: false,
        instituicaoUsuarioIds: Array.from(_instsSelecionadas)
    };

    // Campos condicionais de rendimento
    if (tipo === 'CDI' || tipo === 'SELIC') {
        payload.percentualRendimento  = parseFloat(document.getElementById('inputPctRendimento').value) || 100;
        payload.taxaReferenciaAtual   = parseFloat(document.getElementById('inputTaxaRef').value) || TAXA_DEFAULTS[tipo];
        payload.taxaAnualPersonalizada = null;
    } else if (tipo === 'POUPANCA') {
        payload.percentualRendimento  = 70;
        payload.taxaReferenciaAtual   = parseFloat(document.getElementById('inputTaxaRefPoupanca').value) || TAXA_DEFAULTS.POUPANCA;
        payload.taxaAnualPersonalizada = null;
    } else {
        payload.percentualRendimento  = 100;
        payload.taxaReferenciaAtual   = null;
        payload.taxaAnualPersonalizada = parseFloat(document.getElementById('inputTaxaAnual').value) || null;
    }

    const btn = document.getElementById('btnSalvarCaixinha');
    btn.disabled = true;
    btn.innerHTML = "<i class='bx bx-loader-alt bx-spin'></i> Salvando...";

    try {
        let res;
        if (_editandoId) {
            res = await MainAPI.request(`/caixinhas/${_editandoId}`, {
                method: 'PUT',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(payload)
            });
        } else {
            res = await MainAPI.request('/caixinhas', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(payload)
            });
        }

        if (res.ok || res.status === 201) {
            fecharModalCriar();
            mostrarToast(_editandoId ? 'Caixinha atualizada com sucesso!' : 'Caixinha criada com sucesso!', 'sucesso');
            await Promise.all([carregarKPIs(), carregarCaixinhas(_filtroAtivo)]);
        } else {
            const err = await res.text().catch(() => '');
            mostrarToast(`Erro ao salvar: ${res.status}. ${err}`, 'erro');
        }
    } catch (e) {
        console.error('Erro ao salvar caixinha:', e);
        mostrarToast('Erro de conexão ao salvar.', 'erro');
    } finally {
        btn.disabled = false;
        btn.innerHTML = "<i class='bx bx-save'></i> Salvar";
        validarBotaoSalvar();
    }
}

// ════════════════════════════════════════════════════════════════
// ENCERRAR / DELETAR
// ════════════════════════════════════════════════════════════════
async function encerrarCaixinha(id) {
    try {
        const res = await MainAPI.request(`/caixinhas/${id}/encerrar`, { method: 'PATCH' });
        if (res.ok) {
            mostrarToast('Caixinha encerrada.', 'sucesso');
            await Promise.all([carregarKPIs(), carregarCaixinhas(_filtroAtivo)]);
        } else {
            mostrarToast(`Erro ao encerrar: ${res.status}`, 'erro');
        }
    } catch (e) {
        mostrarToast('Erro de conexão ao encerrar.', 'erro');
    }
}

async function deletarCaixinha(id) {
    try {
        const res = await MainAPI.request(`/caixinhas/${id}`, { method: 'DELETE' });
        if (res.ok || res.status === 204) {
            mostrarToast('Caixinha deletada.', 'sucesso');
            await Promise.all([carregarKPIs(), carregarCaixinhas(_filtroAtivo)]);
        } else {
            mostrarToast(`Erro ao deletar: ${res.status}`, 'erro');
        }
    } catch (e) {
        mostrarToast('Erro de conexão ao deletar.', 'erro');
    }
}

// ════════════════════════════════════════════════════════════════
// INSIGHT
// ════════════════════════════════════════════════════════════════
function mostrarInsight(lista) {
    const insightEl = document.getElementById('cxhInsight');
    const textoEl   = document.getElementById('cxhInsightTexto');

    if (!lista || lista.length === 0) {
        insightEl.style.display = 'none';
        return;
    }

    const ativas  = lista.filter(c => c.isAtiva);
    const qtd     = ativas.length;
    const alcanc  = ativas.filter(c => c.metaAlcancavel === true).length;
    const proxima = [...ativas].sort((a, b) => (a.faltaParaMeta ?? 0) - (b.faltaParaMeta ?? 0))[0];

    let texto = `Você tem <strong>${qtd}</strong> caixinha(s) ativa(s). `;
    if (alcanc > 0) texto += `<strong>${alcanc}</strong> delas com meta alcançável no prazo. `;
    if (proxima) texto += `A mais próxima da meta é <strong>"${escHtml(proxima.nome)}"</strong> (${(proxima.percentualAtingido ?? 0).toFixed(1)}% atingido, faltam ${formatarMoeda(proxima.faltaParaMeta ?? 0)}).`;

    textoEl.innerHTML = texto;
    insightEl.style.display = 'flex';
}

// ════════════════════════════════════════════════════════════════
// UTILITÁRIOS
// ════════════════════════════════════════════════════════════════
function formatarMoeda(valor) {
    const n = Number(valor) || 0;
    return n.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
}

function formatarData(iso) {
    if (!iso) return '–';
    // Suporta array [ano,mes,dia] ou string "aaaa-mm-dd"
    if (Array.isArray(iso) && iso.length >= 3) {
        return `${String(iso[2]).padStart(2,'0')}/${String(iso[1]).padStart(2,'0')}/${iso[0]}`;
    }
    const m = String(iso).match(/^(\d{4})-(\d{2})-(\d{2})/);
    if (m) return `${m[3]}/${m[2]}/${m[1]}`;
    return iso;
}

function labelTipo(tipo) {
    const map = {
        CDI: 'CDI', SELIC: 'SELIC', POUPANCA: 'Poupança',
        PREFIXADO: 'Prefixado', PERSONALIZADO: 'Personalizado'
    };
    return map[tipo] || tipo;
}

function escHtml(str) {
    if (!str) return '';
    return String(str)
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;')
        .replace(/"/g, '&quot;');
}

// Toast
function mostrarToast(msg, tipo) {
    const existing = document.querySelector('.cxh-toast');
    if (existing) existing.remove();

    const toast = document.createElement('div');
    toast.className = `cxh-toast ${tipo || ''}`;
    toast.innerHTML = `<i class='bx ${tipo === 'sucesso' ? 'bx-check-circle' : 'bx-error-circle'}'></i> ${escHtml(msg)}`;
    document.body.appendChild(toast);

    setTimeout(() => {
        toast.style.transition = 'opacity 0.3s';
        toast.style.opacity = '0';
        setTimeout(() => toast.remove(), 320);
    }, 3500);
}

/* ═══════════════════════════════════════════════════════════════
   caixinhas.js — Lógica completa da tela de Poupança/Caixinhas
   ═══════════════════════════════════════════════════════════════ */

'use strict';

// ── Estado ────────────────────────────────────────────────────
let _usuario        = null;
let _caixinhas      = [];          // cache de todas as caixinhas carregadas
let _filtroAtivo    = 'ativas';    // 'ativas' | 'encerradas' | 'todas'
let _caixinhaAtual  = null;        // caixinha aberta no modal de detalhes
let _editandoId     = null;        // id sendo editado (null = criar)
let _tipoRendimento = 'CDI';       // tipo selecionado no form
let _instsSelecionadas = new Set(); // ids de instituicaoUsuario selecionados
let _todasInstituicoes = [];       // lista de instituições do usuário

// ── Defaults de taxa por tipo ──────────────────────────────────
const TAXA_DEFAULTS = {
    CDI:          10.40,
    SELIC:        10.75,
    POUPANCA:     10.75,
    PREFIXADO:    null,
    PERSONALIZADO: null
};

// ════════════════════════════════════════════════════════════════
// INIT
// ════════════════════════════════════════════════════════════════
async function iniciarPagina() {
    // Recuperar usuário logado
    _usuario = JSON.parse(localStorage.getItem('usuarioLogado') || 'null');
    if (!_usuario || !_usuario.id) {
        window.location.href = 'index.html';
        return;
    }

    // Aplicar tema do localStorage
    const temaSalvo = localStorage.getItem('tema');
    const modoSalvo = localStorage.getItem('modo');
    if (temaSalvo) document.body.setAttribute('data-tema', temaSalvo);
    if (modoSalvo) document.body.setAttribute('data-mode', modoSalvo);

    // Aplicar máscara de moeda
    MainAPI.aplicarMascaraMoeda(document.getElementById('inputValorMeta'));
    // Aplicar máscara de data
    MainAPI.aplicarMascaraData(document.getElementById('inputDataPrazo'));

    // Carregar dados em paralelo
    await Promise.all([
        carregarKPIs(),
        carregarCaixinhas(_filtroAtivo),
        carregarInstituicoes()
    ]);
}

// ════════════════════════════════════════════════════════════════
// KPIs
// ════════════════════════════════════════════════════════════════
async function carregarKPIs() {
    const uid = _usuario.id;
    try {
        const [resTA, resPG, resRM, resST] = await Promise.allSettled([
            MainAPI.request(`/caixinhas/kpi/total-acumulado/usuarios/${uid}`).then(r => r.ok ? r.json() : null),
            MainAPI.request(`/caixinhas/kpi/progresso-geral/usuarios/${uid}`).then(r => r.ok ? r.json() : null),
            MainAPI.request(`/caixinhas/kpi/rendimento-estimado-mes/usuarios/${uid}`).then(r => r.ok ? r.json() : null),
            MainAPI.request(`/caixinhas/kpi/status/usuarios/${uid}`).then(r => r.ok ? r.json() : null)
        ]);

        // KPI 1 — Total Acumulado
        if (resTA.status === 'fulfilled' && resTA.value) {
            document.getElementById('kpiTotalAcumulado').textContent = formatarMoeda(resTA.value.totalAcumulado ?? 0);
            document.getElementById('kpiQtdAtivas').textContent = `${resTA.value.quantidadeAtivas ?? 0} caixinha(s) ativa(s)`;
        }

        // KPI 2 — Progresso Geral
        if (resPG.status === 'fulfilled' && resPG.value) {
            const pg = resPG.value;
            const pct = pg.percentualGeral ?? 0;
            document.getElementById('kpiProgressoPct').textContent = `${pct.toFixed(1)}%`;
            document.getElementById('kpiProgressoSub').textContent = 'da meta total atingida';

            // Atualizar barra consolidada
            const fillPct = Math.min(100, pct);
            document.getElementById('cxhProgressoFill').style.width = `${fillPct}%`;
            document.getElementById('cxhProgressoPctBar').textContent = `${pct.toFixed(1)}%`;
            document.getElementById('cxhProgressoValAtual').textContent = `${formatarMoeda(pg.totalAcumulado ?? 0)} acumulados`;
            document.getElementById('cxhProgressoValMeta').textContent = `Meta: ${formatarMoeda(pg.totalMetas ?? 0)}`;
        }

        // KPI 3 — Rendimento Estimado
        if (resRM.status === 'fulfilled' && resRM.value) {
            document.getElementById('kpiRendimento').textContent = formatarMoeda(resRM.value.rendimentoEstimadoMes ?? 0);
        }

        // KPI 4 — Status
        if (resST.status === 'fulfilled' && resST.value) {
            const st = resST.value;
            document.getElementById('kpiStatusAtivas').textContent = `${st.quantidadeAtivas ?? 0} ativas`;
            document.getElementById('kpiStatusSub').textContent = `${st.quantidadeEncerradas ?? 0} encerradas`;
        }
    } catch (e) {
        console.error('Erro ao carregar KPIs:', e);
    }
}

// ════════════════════════════════════════════════════════════════
// CAIXINHAS
// ════════════════════════════════════════════════════════════════
async function carregarCaixinhas(filtro) {
    _filtroAtivo = filtro;
    mostrarLoading(true);

    try {
        const uid = _usuario.id;
        let endpoint;
        if (filtro === 'ativas') {
            endpoint = `/caixinhas/ativas/usuarios/${uid}`;
        } else {
            endpoint = `/caixinhas/usuarios/${uid}`;
        }

        const res = await MainAPI.request(endpoint);
        if (res.status === 204) {
            _caixinhas = [];
        } else if (res.ok) {
            _caixinhas = await res.json();
            if (!Array.isArray(_caixinhas)) _caixinhas = [];
        } else {
            _caixinhas = [];
        }

        // Filtrar encerradas no cliente quando necessário
        let lista = _caixinhas;
        if (filtro === 'encerradas') {
            lista = _caixinhas.filter(c => !c.isAtiva);
        }

        renderizarCards(lista);
        mostrarInsight(lista);
    } catch (e) {
        console.error('Erro ao carregar caixinhas:', e);
        _caixinhas = [];
        renderizarCards([]);
    } finally {
        mostrarLoading(false);
    }
}

function mostrarLoading(show) {
    document.getElementById('cxhLoading').style.display = show ? 'flex' : 'none';
    if (show) {
        document.getElementById('cxhGrid').style.display = 'none';
        document.getElementById('cxhVazio').style.display = 'none';
        document.getElementById('cxhInsight').style.display = 'none';
    }
}

function renderizarCards(lista) {
    const grid  = document.getElementById('cxhGrid');
    const vazio = document.getElementById('cxhVazio');

    if (!lista || lista.length === 0) {
        grid.style.display  = 'none';
        vazio.style.display = 'flex';
        return;
    }

    vazio.style.display = 'none';
    grid.style.display  = 'grid';

    grid.innerHTML = lista.map(c => gerarCardHTML(c)).join('');

    // Adicionar listeners de clique
    grid.querySelectorAll('.cxh-card').forEach(card => {
        const id = card.dataset.id;
        card.addEventListener('click', () => {
            const caixinha = _caixinhas.find(c => c.id === id)
                || lista.find(c => c.id === id);
            if (caixinha) abrirModalDetalhes(caixinha);
        });
    });
}

function gerarCardHTML(c) {
    const pct     = Math.min(100, c.percentualAtingido ?? 0);
    const atingida = pct >= 100;
    const tipo    = c.tipoRendimento || 'CDI';
    const encerrada = !c.isAtiva;

    const alcancavel = c.metaAlcancavel;
    const alcancavelHTML = typeof alcancavel === 'boolean'
        ? `<span class="cxh-card-meta-alcancavel ${alcancavel ? '' : 'nao'}">
               <i class='bx ${alcancavel ? 'bx-check-circle' : 'bx-x-circle'}'></i>
               ${alcancavel ? 'Meta alcançável' : 'Aporte insuficiente'}
           </span>`
        : '';

    const mesesTxt = c.mesesRestantes != null ? `${c.mesesRestantes} meses restantes` : '–';
    const prazoTxt = c.dataPrazo ? formatarData(c.dataPrazo) : '–';

    return `
    <div class="cxh-card ${encerrada ? 'encerrada' : ''}" data-id="${c.id}">
        <div class="cxh-card-header">
            <div>
                <div class="cxh-card-nome">${escHtml(c.nome)}</div>
                ${c.descricao ? `<div class="cxh-card-desc">${escHtml(c.descricao)}</div>` : ''}
            </div>
            <span class="cxh-badge cxh-badge-${tipo}">${labelTipo(tipo)}</span>
        </div>

        <div class="cxh-card-valores">
            <span class="cxh-card-valor-atual">${formatarMoeda(c.valorAtual ?? 0)}</span>
            <span class="cxh-card-meta">/ ${formatarMoeda(c.valorMeta ?? 0)}</span>
        </div>

        <div>
            <div class="cxh-card-progress-track">
                <div class="cxh-card-progress-fill ${atingida ? 'atingida' : ''}" style="width:${pct}%"></div>
            </div>
            <div class="cxh-card-progress-info">
                <span class="cxh-card-pct">${pct.toFixed(1)}%</span>
                <span>${mesesTxt}</span>
            </div>
        </div>

        <div class="cxh-card-footer">
            ${alcancavelHTML}
            <span>${prazoTxt}</span>
        </div>
    </div>`;
}

// ════════════════════════════════════════════════════════════════
// FILTROS / ABAS
// ════════════════════════════════════════════════════════════════
function trocarFiltro(filtro, btnEl) {
    document.querySelectorAll('.cxh-filtro-btn').forEach(b => b.classList.remove('ativo'));
    btnEl.classList.add('ativo');
    carregarCaixinhas(filtro);
}

// ════════════════════════════════════════════════════════════════
// MODAL DETALHES
// ════════════════════════════════════════════════════════════════
function abrirModalDetalhes(c) {
    _caixinhaAtual = c;
    const encerrada = !c.isAtiva;

    // Cabeçalho
    document.getElementById('detNome').textContent    = c.nome;
    document.getElementById('detDesc').textContent    = c.descricao || '';
    document.getElementById('detBadge').className     = `cxh-badge cxh-badge-${c.tipoRendimento || 'CDI'}`;
    document.getElementById('detBadge').textContent   = labelTipo(c.tipoRendimento);
    document.getElementById('detStatusBadge').innerHTML = encerrada
        ? `<span style="font-size:0.7rem;font-weight:700;padding:3px 9px;border-radius:12px;background:var(--cor-fundo-inativo);color:var(--cor-texto-secundario);">Encerrada</span>`
        : `<span style="font-size:0.7rem;font-weight:700;padding:3px 9px;border-radius:12px;background:var(--green-100);color:var(--green-700);">Ativa</span>`;

    // Stats
    document.getElementById('detValorAtual').textContent  = formatarMoeda(c.valorAtual ?? 0);
    document.getElementById('detMeta').textContent        = formatarMoeda(c.valorMeta ?? 0);
    document.getElementById('detFalta').textContent       = formatarMoeda(c.faltaParaMeta ?? 0);
    const pct = c.percentualAtingido ?? 0;
    document.getElementById('detPct').textContent         = `${pct.toFixed(1)}%`;
    document.getElementById('detMeses').textContent       = c.mesesRestantes != null ? `${c.mesesRestantes} meses` : '–';
    document.getElementById('detPrazo').textContent       = c.dataPrazo ? formatarData(c.dataPrazo) : '–';
    document.getElementById('detAporte').textContent      = c.aporteMensalSugerido != null ? formatarMoeda(c.aporteMensalSugerido) : '–';
    document.getElementById('detTaxaMensal').textContent  = c.taxaMensalEfetiva != null
        ? `${(c.taxaMensalEfetiva * 100).toFixed(4)}% a.m.`
        : '–';

    // Barra de progresso
    const fillPct = Math.min(100, pct);
    document.getElementById('detProgressoFill').style.width = `${fillPct}%`;
    document.getElementById('detPctBar').textContent = `${pct.toFixed(1)}%`;

    // Meta alcançável
    const alcDiv = document.getElementById('detAlcancavel');
    if (typeof c.metaAlcancavel === 'boolean') {
        alcDiv.innerHTML = `
            <span class="cxh-det-alcancavel ${c.metaAlcancavel ? '' : 'nao'}">
                <i class='bx ${c.metaAlcancavel ? 'bx-check-circle' : 'bx-x-circle'}'></i>
                ${c.metaAlcancavel ? 'Meta alcançável com aportes sugeridos' : 'Meta pode não ser atingida com os aportes atuais'}
            </span>`;
    } else {
        alcDiv.innerHTML = '';
    }

    // Projeção
    document.getElementById('detProjecao').innerHTML = gerarTextoProjecao(c);

    // Instituições
    const instLista = document.getElementById('detInstLista');
    const instSection = document.getElementById('detInstSection');
    if (c.instituicoes && c.instituicoes.length > 0) {
        instSection.style.display = '';
        instLista.innerHTML = c.instituicoes.map(inst =>
            `<div class="cxh-det-inst-item">
                <span class="cxh-det-inst-nome"><i class='bx bx-buildings'></i> ${escHtml(inst.nome || 'Instituição')}</span>
                <span class="cxh-det-inst-val">${formatarMoeda(inst.valorAportado ?? 0)}</span>
            </div>`
        ).join('');
    } else {
        instSection.style.display = 'none';
    }

    // Botões: mostrar Encerrar OU Reabrir conforme status
    const btnEnc = document.getElementById('btnDetEncerrar');
    const btnReab = document.getElementById('btnDetReabrir');
    if (encerrada) {
        btnEnc.style.display  = 'none';
        btnReab.style.display = '';
    } else {
        btnEnc.style.display  = '';
        btnReab.style.display = 'none';
    }

    document.getElementById('modalDetOverlay').classList.add('aberto');
}

function fecharModalDet() {
    document.getElementById('modalDetOverlay').classList.remove('aberto');
    // Resetar footer de confirmação
    const fnormal = document.getElementById('detFooterNormal');
    const fconf   = document.getElementById('detFooterConfirmacao');
    if (fnormal) fnormal.style.display = 'flex';
    if (fconf)   fconf.style.display   = 'none';
    _caixinhaAtual = null;
}

function fecharModalDetOutside(e) {
    if (e.target === document.getElementById('modalDetOverlay')) fecharModalDet();
}

function gerarTextoProjecao(c) {
    const semAportes = c.montanteProjetadoSemAportes;
    const comAportes = c.montanteProjetadoComAportes;
    const aporte     = c.aporteMensalSugerido;
    const meses      = c.mesesRestantes;
    const taxa       = c.taxaMensalEfetiva;

    // Calcular projeção localmente se os dados do servidor estiverem ausentes
    const r = taxa != null ? taxa : 0;
    const n = meses != null ? meses : 0;
    const VA = c.valorAtual ?? 0;

    // Projeção sem aportes: VA * (1+r)^n
    const projSemAp = semAportes != null ? semAportes : (r > 0 ? VA * Math.pow(1 + r, n) : VA);
    // Projeção com aportes sugeridos
    const ap = aporte != null ? aporte : 0;
    const projComAp = comAportes != null ? comAportes
        : (r > 0 ? projSemAp + ap * ((Math.pow(1 + r, n) - 1) / r)
                 : projSemAp + ap * n);

    return `
        <strong>Sem novos aportes:</strong> você terá <strong>${formatarMoeda(projSemAp)}</strong> no prazo.<br>
        <strong>Com aporte de ${formatarMoeda(ap)}/mês:</strong> você terá <strong>${formatarMoeda(projComAp)}</strong>.<br>
        <strong>Meta:</strong> ${formatarMoeda(c.valorMeta ?? 0)}&nbsp;·&nbsp;
        <strong>Falta:</strong> ${formatarMoeda(c.faltaParaMeta ?? 0)}&nbsp;·&nbsp;
        <strong>Taxa mensal:</strong> ${r > 0 ? (r * 100).toFixed(4) + '% a.m.' : 'sem rendimento definido'}
    `;
}

// ── Ações do modal de detalhes ─────────────────────────────────
function editarCaixinhaAtual() {
    if (!_caixinhaAtual) return;
    const c = _caixinhaAtual; // salva referência ANTES de fechar (fecharModalDet zera _caixinhaAtual)
    fecharModalDet();
    abrirModalEditar(c);
}

// Exibe confirmação inline (sem confirm() nativo)
function pedirConfirmacaoReabrir() {
    if (!_caixinhaAtual) return;
    document.getElementById('detConfirmacaoTexto').textContent =
        `Reabrir "${_caixinhaAtual.nome}"? A caixinha voltará a aparecer como ativa.`;
    document.getElementById('btnConfirmarAcao').className = 'btn-cxh-reabrir-confirmar';
    document.getElementById('btnConfirmarAcao').onclick = confirmarReabrir;
    document.getElementById('detFooterNormal').style.display = 'none';
    document.getElementById('detFooterConfirmacao').style.display = 'flex';
}

async function confirmarReabrir() {
    const c = _caixinhaAtual;
    if (!c) return;
    cancelarConfirmacao();
    fecharModalDet();
    await reabrirCaixinha(c.id);
}

async function reabrirCaixinha(id) {
    try {
        const res = await MainAPI.request(`/caixinhas/${id}/reabrir`, { method: 'PATCH' });
        if (res.ok) {
            mostrarToast('Caixinha reaberta com sucesso!', 'sucesso');
            await Promise.all([carregarKPIs(), carregarCaixinhas(_filtroAtivo)]);
        } else {
            mostrarToast(`Erro ao reabrir: ${res.status}`, 'erro');
        }
    } catch (e) {
        mostrarToast('Erro de conexão ao reabrir.', 'erro');
    }
}

function pedirConfirmacaoEncerrar() {
    if (!_caixinhaAtual) return;
    document.getElementById('detConfirmacaoTexto').textContent =
        `Encerrar "${_caixinhaAtual.nome}"? Os dados serão mantidos.`;
    document.getElementById('btnConfirmarAcao').className = 'btn-cxh-encerrar-confirmar';
    document.getElementById('btnConfirmarAcao').onclick = confirmarEncerrar;
    document.getElementById('detFooterNormal').style.display = 'none';
    document.getElementById('detFooterConfirmacao').style.display = 'flex';
}

function pedirConfirmacaoDeletar() {
    if (!_caixinhaAtual) return;
    document.getElementById('detConfirmacaoTexto').textContent =
        `Deletar permanentemente "${_caixinhaAtual.nome}"? Ação irreversível.`;
    document.getElementById('btnConfirmarAcao').className = 'btn-cxh-deletar-confirmar';
    document.getElementById('btnConfirmarAcao').onclick = confirmarDeletar;
    document.getElementById('detFooterNormal').style.display = 'none';
    document.getElementById('detFooterConfirmacao').style.display = 'flex';
}

function cancelarConfirmacao() {
    document.getElementById('detFooterNormal').style.display = 'flex';
    document.getElementById('detFooterConfirmacao').style.display = 'none';
}

async function confirmarEncerrar() {
    const c = _caixinhaAtual;
    if (!c) return;
    cancelarConfirmacao();
    fecharModalDet();
    await encerrarCaixinha(c.id);
}

async function confirmarDeletar() {
    const c = _caixinhaAtual;
    if (!c) return;
    cancelarConfirmacao();
    fecharModalDet();
    await deletarCaixinha(c.id);
}

// Mantidas por compatibilidade (não usam mais confirm() nativo)
async function encerrarCaixinhaAtual() { pedirConfirmacaoEncerrar(); }
async function deletarCaixinhaAtual()  { pedirConfirmacaoDeletar(); }

// ════════════════════════════════════════════════════════════════
// MODAL CRIAR / EDITAR
// ════════════════════════════════════════════════════════════════
function abrirModalCriar() {
    _editandoId = null;
    document.getElementById('modalCriarTitulo').innerHTML = "<i class='bx bx-plus-circle'></i> Nova Caixinha";
    resetarFormulario();
    document.getElementById('modalCriarOverlay').classList.add('aberto');
    validarBotaoSalvar();
}

function abrirModalEditar(c) {
    _editandoId = c.id;
    document.getElementById('modalCriarTitulo').innerHTML = "<i class='bx bx-edit'></i> Editar Caixinha";
    preencherFormulario(c);
    document.getElementById('modalCriarOverlay').classList.add('aberto');
    validarBotaoSalvar();
}

function fecharModalCriar() {
    document.getElementById('modalCriarOverlay').classList.remove('aberto');
}

function fecharModalCriarOutside(e) {
    if (e.target === document.getElementById('modalCriarOverlay')) fecharModalCriar();
}

function resetarFormulario() {
    document.getElementById('inputNome').value        = '';
    document.getElementById('inputDescricao').value   = '';
    MainAPI.resetarMascaraMoeda(document.getElementById('inputValorMeta'));
    document.getElementById('inputDataPrazo').value   = '';
    document.getElementById('inputPctRendimento').value  = '';
    document.getElementById('inputTaxaRef').value        = '';
    document.getElementById('inputTaxaRefPoupanca').value = '';
    document.getElementById('inputTaxaAnual').value      = '';
    _instsSelecionadas.clear();
    selecionarTipoRendimento('CDI');
    renderizarInstituicoes();
    document.getElementById('taxaResumo').style.display = 'none';
}

function preencherFormulario(c) {
    document.getElementById('inputNome').value      = c.nome || '';
    document.getElementById('inputDescricao').value = c.descricao || '';

    // Valor meta
    const inputMeta = document.getElementById('inputValorMeta');
    const centavos  = Math.round((c.valorMeta ?? 0) * 100);
    inputMeta.dataset.centavos = String(centavos);
    const reais = Math.floor(centavos / 100);
    const cts   = String(centavos % 100).padStart(2, '0');
    const reaisStr = String(reais).replace(/\B(?=(\d{3})+(?!\d))/g, '.');
    inputMeta.value = `R$ ${reaisStr},${cts}`;

    // Data prazo — backend pode retornar string "aaaa-mm-dd" ou array [ano, mes, dia]
    if (c.dataPrazo) {
        let iso = c.dataPrazo;
        if (Array.isArray(iso) && iso.length >= 3) {
            iso = `${iso[0]}-${String(iso[1]).padStart(2,'0')}-${String(iso[2]).padStart(2,'0')}`;
        }
        document.getElementById('inputDataPrazo').value = MainAPI.dataDeISO(String(iso));
    }

    // Tipo de rendimento
    const tipo = c.tipoRendimento || 'CDI';
    selecionarTipoRendimento(tipo);

    if (tipo === 'CDI' || tipo === 'SELIC') {
        document.getElementById('inputPctRendimento').value  = c.percentualRendimento ?? 100;
        document.getElementById('inputTaxaRef').value        = c.taxaReferenciaAtual ?? TAXA_DEFAULTS[tipo];
    } else if (tipo === 'POUPANCA') {
        document.getElementById('inputTaxaRefPoupanca').value = c.taxaReferenciaAtual ?? TAXA_DEFAULTS.POUPANCA;
    } else {
        document.getElementById('inputTaxaAnual').value = c.taxaAnualPersonalizada ?? '';
    }

    calcularTaxaEfetiva();

    // Instituições
    _instsSelecionadas.clear();
    if (c.instituicoes && Array.isArray(c.instituicoes)) {
        c.instituicoes.forEach(inst => {
            // inst.id pode ser o id da vinculação (instituicaoUsuarioId)
            _instsSelecionadas.add(inst.id);
        });
    }
    renderizarInstituicoes();
}

// ── Tipo de rendimento ─────────────────────────────────────────
function selecionarTipoRendimento(tipo) {
    _tipoRendimento = tipo;

    // Atualizar botões
    document.querySelectorAll('.cxh-rend-btn').forEach(btn => {
        btn.className = 'cxh-rend-btn';
        if (btn.dataset.tipo === tipo) btn.classList.add(`ativo-${tipo}`);
    });

    // Mostrar campos corretos
    ['camposCdiSelic', 'camposPoupanca', 'camposPrefixado'].forEach(id => {
        document.getElementById(id).classList.remove('visivel');
    });

    if (tipo === 'CDI' || tipo === 'SELIC') {
        document.getElementById('camposCdiSelic').classList.add('visivel');
        const lbl = document.getElementById('labelPctCdi');
        const lbl2 = document.getElementById('labelTaxaRef');
        lbl.textContent  = tipo === 'CDI' ? '% do CDI' : '% da SELIC';
        lbl2.textContent = tipo === 'CDI' ? 'Taxa CDI atual (% a.a.)' : 'Taxa SELIC atual (% a.a.)';
        // Preencher default se vazio
        const inp = document.getElementById('inputTaxaRef');
        if (!inp.value) inp.value = TAXA_DEFAULTS[tipo];
        const inpPct = document.getElementById('inputPctRendimento');
        if (!inpPct.value) inpPct.value = 100;
    } else if (tipo === 'POUPANCA') {
        document.getElementById('camposPoupanca').classList.add('visivel');
        const inp = document.getElementById('inputTaxaRefPoupanca');
        if (!inp.value) inp.value = TAXA_DEFAULTS.POUPANCA;
    } else {
        document.getElementById('camposPrefixado').classList.add('visivel');
    }

    calcularTaxaEfetiva();
}

// ── Calcular taxa efetiva ──────────────────────────────────────
function calcularTaxaEfetiva() {
    const tipo = _tipoRendimento;
    let taxaAnual = 0;

    if (tipo === 'CDI' || tipo === 'SELIC') {
        const pct     = parseFloat(document.getElementById('inputPctRendimento').value) || 100;
        const taxaRef = parseFloat(document.getElementById('inputTaxaRef').value) || 0;
        taxaAnual = taxaRef * (pct / 100);
    } else if (tipo === 'POUPANCA') {
        const taxaRef = parseFloat(document.getElementById('inputTaxaRefPoupanca').value) || 0;
        taxaAnual = taxaRef * 0.70;
    } else {
        taxaAnual = parseFloat(document.getElementById('inputTaxaAnual').value) || 0;
    }

    const taxaMensal = taxaAnual > 0 ? (Math.pow(1 + taxaAnual / 100, 1 / 12) - 1) * 100 : 0;

    const resumo = document.getElementById('taxaResumo');
    const txt    = document.getElementById('taxaResumoTexto');

    if (taxaAnual > 0) {
        resumo.style.display = 'flex';
        txt.innerHTML = `Taxa efetiva: <strong>${taxaAnual.toFixed(2)}% a.a.</strong> · <strong>${taxaMensal.toFixed(4)}% a.m.</strong>`;

        // Verificar alcançabilidade em tempo real
        const meta    = MainAPI.obterValorMoeda(document.getElementById('inputValorMeta'));
        const prazoTxt = document.getElementById('inputDataPrazo').value;
        if (meta > 0 && prazoTxt && prazoTxt.length === 10) {
            const prazoISO = MainAPI.dataParaISO(prazoTxt);
            if (prazoISO) {
                const hoje    = new Date();
                const prazo   = new Date(prazoISO);
                const diffMs  = prazo - hoje;
                const meses   = Math.max(0, Math.floor(diffMs / (1000 * 60 * 60 * 24 * 30.4)));
                if (meses > 0) {
                    const r   = taxaMensal / 100;
                    const VA  = 0; // sem valor atual inicial no form
                    const projSem = r > 0 ? VA * Math.pow(1 + r, meses) : VA;
                    const aporteNecessario = r > 0
                        ? ((meta - projSem) * r) / (Math.pow(1 + r, meses) - 1)
                        : (meta - projSem) / meses;
                    if (aporteNecessario > 0) {
                        txt.innerHTML += ` · Aporte necessário: <strong>${formatarMoeda(aporteNecessario)}/mês</strong> por <strong>${meses} meses</strong>`;
                    }
                }
            }
        }
    } else {
        resumo.style.display = 'none';
    }
}

// ── Instituições ───────────────────────────────────────────────
async function carregarInstituicoes() {
    try {
        _todasInstituicoes = await MainAPI.getInstituicoes(_usuario.id);
        if (!Array.isArray(_todasInstituicoes)) _todasInstituicoes = [];
        renderizarInstituicoes();
    } catch (e) {
        console.error('Erro ao carregar instituições:', e);
        _todasInstituicoes = [];
    }
}

function renderizarInstituicoes() {
    const grid = document.getElementById('instGrid');
    if (_todasInstituicoes.length === 0) {
        grid.innerHTML = '<span style="font-size:0.82rem;color:var(--cor-texto-secundario);">Nenhuma instituição vinculada. <a href="configurações.html" style="color:var(--cor-principal);">Configurar</a></span>';
        return;
    }

    grid.innerHTML = _todasInstituicoes.map(inst => {
        const selecionada = _instsSelecionadas.has(inst.id);
        return `
        <div class="cxh-inst-item ${selecionada ? 'selecionada' : ''}" 
             data-instid="${inst.id}"
             onclick="toggleInstituicao(${inst.id}, this)">
            <span class="cxh-inst-check">${selecionada ? '✓' : ''}</span>
            <span>${escHtml(inst.intituicao?.nome || inst.instituicao?.nome || inst.nomeInstituicao || inst.nome || `Inst. ${inst.id}`)}</span>
        </div>`;
    }).join('');
}

function toggleInstituicao(instId, el) {
    if (_instsSelecionadas.has(instId)) {
        _instsSelecionadas.delete(instId);
        el.classList.remove('selecionada');
        el.querySelector('.cxh-inst-check').textContent = '';
    } else {
        _instsSelecionadas.add(instId);
        el.classList.add('selecionada');
        el.querySelector('.cxh-inst-check').textContent = '✓';
    }
    validarBotaoSalvar();
}

// ── Validar botão salvar ───────────────────────────────────────
function validarBotaoSalvar() {
    const nome    = (document.getElementById('inputNome').value || '').trim();
    const temInst = _instsSelecionadas.size > 0;
    const btn     = document.getElementById('btnSalvarCaixinha');
    const aviso   = document.getElementById('instAviso');

    btn.disabled = !(nome && temInst);
    if (aviso) aviso.style.display = (!temInst && nome) ? '' : 'none';
}

// ════════════════════════════════════════════════════════════════
// SALVAR (POST / PUT)
// ════════════════════════════════════════════════════════════════
async function salvarCaixinha() {
    const nome     = document.getElementById('inputNome').value.trim();
    const descricao = document.getElementById('inputDescricao').value.trim();
    const valorMeta = MainAPI.obterValorMoeda(document.getElementById('inputValorMeta'));
    const prazoTxt  = document.getElementById('inputDataPrazo').value;
    const tipo      = _tipoRendimento;

    if (!nome) { mostrarToast('Informe o nome da caixinha.', 'erro'); return; }
    if (_instsSelecionadas.size === 0) { mostrarToast('Selecione ao menos uma instituição.', 'erro'); return; }

    // Montar payload
    const payload = {
        usuarioId:    _usuario.id,
        nome,
        descricao:    descricao || null,
        valorMeta:    valorMeta > 0 ? valorMeta : null,
        dataPrazo:    prazoTxt ? MainAPI.dataParaISO(prazoTxt) : null,
        tipoRendimento: tipo,
        isCompartilhada: false,
        instituicaoUsuarioIds: Array.from(_instsSelecionadas)
    };

    // Campos condicionais de rendimento
    if (tipo === 'CDI' || tipo === 'SELIC') {
        payload.percentualRendimento  = parseFloat(document.getElementById('inputPctRendimento').value) || 100;
        payload.taxaReferenciaAtual   = parseFloat(document.getElementById('inputTaxaRef').value) || TAXA_DEFAULTS[tipo];
        payload.taxaAnualPersonalizada = null;
    } else if (tipo === 'POUPANCA') {
        payload.percentualRendimento  = 70;
        payload.taxaReferenciaAtual   = parseFloat(document.getElementById('inputTaxaRefPoupanca').value) || TAXA_DEFAULTS.POUPANCA;
        payload.taxaAnualPersonalizada = null;
    } else {
        payload.percentualRendimento  = 100;
        payload.taxaReferenciaAtual   = null;
        payload.taxaAnualPersonalizada = parseFloat(document.getElementById('inputTaxaAnual').value) || null;
    }

    const btn = document.getElementById('btnSalvarCaixinha');
    btn.disabled = true;
    btn.innerHTML = "<i class='bx bx-loader-alt bx-spin'></i> Salvando...";

    try {
        let res;
        if (_editandoId) {
            res = await MainAPI.request(`/caixinhas/${_editandoId}`, {
                method: 'PUT',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(payload)
            });
        } else {
            res = await MainAPI.request('/caixinhas', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(payload)
            });
        }

        if (res.ok || res.status === 201) {
            fecharModalCriar();
            mostrarToast(_editandoId ? 'Caixinha atualizada com sucesso!' : 'Caixinha criada com sucesso!', 'sucesso');
            await Promise.all([carregarKPIs(), carregarCaixinhas(_filtroAtivo)]);
        } else {
            const err = await res.text().catch(() => '');
            mostrarToast(`Erro ao salvar: ${res.status}. ${err}`, 'erro');
        }
    } catch (e) {
        console.error('Erro ao salvar caixinha:', e);
        mostrarToast('Erro de conexão ao salvar.', 'erro');
    } finally {
        btn.disabled = false;
        btn.innerHTML = "<i class='bx bx-save'></i> Salvar";
        validarBotaoSalvar();
    }
}

// ════════════════════════════════════════════════════════════════
// ENCERRAR / DELETAR
// ════════════════════════════════════════════════════════════════
async function encerrarCaixinha(id) {
    try {
        const res = await MainAPI.request(`/caixinhas/${id}/encerrar`, { method: 'PATCH' });
        if (res.ok) {
            mostrarToast('Caixinha encerrada.', 'sucesso');
            await Promise.all([carregarKPIs(), carregarCaixinhas(_filtroAtivo)]);
        } else {
            mostrarToast(`Erro ao encerrar: ${res.status}`, 'erro');
        }
    } catch (e) {
        mostrarToast('Erro de conexão ao encerrar.', 'erro');
    }
}

async function deletarCaixinha(id) {
    try {
        const res = await MainAPI.request(`/caixinhas/${id}`, { method: 'DELETE' });
        if (res.ok || res.status === 204) {
            mostrarToast('Caixinha deletada.', 'sucesso');
            await Promise.all([carregarKPIs(), carregarCaixinhas(_filtroAtivo)]);
        } else {
            mostrarToast(`Erro ao deletar: ${res.status}`, 'erro');
        }
    } catch (e) {
        mostrarToast('Erro de conexão ao deletar.', 'erro');
    }
}

// ════════════════════════════════════════════════════════════════
// INSIGHT
// ════════════════════════════════════════════════════════════════
function mostrarInsight(lista) {
    const insightEl = document.getElementById('cxhInsight');
    const textoEl   = document.getElementById('cxhInsightTexto');

    if (!lista || lista.length === 0) {
        insightEl.style.display = 'none';
        return;
    }

    const ativas  = lista.filter(c => c.isAtiva);
    const qtd     = ativas.length;
    const alcanc  = ativas.filter(c => c.metaAlcancavel === true).length;
    const proxima = [...ativas].sort((a, b) => (a.faltaParaMeta ?? 0) - (b.faltaParaMeta ?? 0))[0];

    let texto = `Você tem <strong>${qtd}</strong> caixinha(s) ativa(s). `;
    if (alcanc > 0) texto += `<strong>${alcanc}</strong> delas com meta alcançável no prazo. `;
    if (proxima) texto += `A mais próxima da meta é <strong>"${escHtml(proxima.nome)}"</strong> (${(proxima.percentualAtingido ?? 0).toFixed(1)}% atingido, faltam ${formatarMoeda(proxima.faltaParaMeta ?? 0)}).`;

    textoEl.innerHTML = texto;
    insightEl.style.display = 'flex';
}

// ════════════════════════════════════════════════════════════════
// UTILITÁRIOS
// ════════════════════════════════════════════════════════════════
function formatarMoeda(valor) {
    const n = Number(valor) || 0;
    return n.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
}

function formatarData(iso) {
    if (!iso) return '–';
    // Suporta array [ano,mes,dia] ou string "aaaa-mm-dd"
    if (Array.isArray(iso) && iso.length >= 3) {
        return `${String(iso[2]).padStart(2,'0')}/${String(iso[1]).padStart(2,'0')}/${iso[0]}`;
    }
    const m = String(iso).match(/^(\d{4})-(\d{2})-(\d{2})/);
    if (m) return `${m[3]}/${m[2]}/${m[1]}`;
    return iso;
}

function labelTipo(tipo) {
    const map = {
        CDI: 'CDI', SELIC: 'SELIC', POUPANCA: 'Poupança',
        PREFIXADO: 'Prefixado', PERSONALIZADO: 'Personalizado'
    };
    return map[tipo] || tipo;
}

function escHtml(str) {
    if (!str) return '';
    return String(str)
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;')
        .replace(/"/g, '&quot;');
}

// Toast
function mostrarToast(msg, tipo) {
    const existing = document.querySelector('.cxh-toast');
    if (existing) existing.remove();

    const toast = document.createElement('div');
    toast.className = `cxh-toast ${tipo || ''}`;
    toast.innerHTML = `<i class='bx ${tipo === 'sucesso' ? 'bx-check-circle' : 'bx-error-circle'}'></i> ${escHtml(msg)}`;
    document.body.appendChild(toast);

    setTimeout(() => {
        toast.style.transition = 'opacity 0.3s';
        toast.style.opacity = '0';
        setTimeout(() => toast.remove(), 320);
    }, 3500);
}

/* ═══════════════════════════════════════════════════════════════
   caixinhas.css — Tela de Poupança / Caixinhas
   ═══════════════════════════════════════════════════════════════ */

/* ── Page header ─────────────────────────────────────────── */
.cxh-page-header {
    display: flex;
    flex-direction: row;
    align-items: center;
    justify-content: space-between;
    margin-bottom: 8px;
    flex-wrap: wrap;
    gap: 12px;
}
.cxh-page-header h1 { margin-bottom: 0; }

.cxh-header-left {
    display: flex;
    flex-direction: column;
    gap: 2px;
}

.cxh-header-subtitle {
    font-size: 0.85rem;
    color: var(--cor-texto-secundario);
    font-weight: 400;
}

.btn-nova-caixinha {
    display: inline-flex;
    align-items: center;
    gap: 8px;
    background: var(--cor-principal);
    color: var(--cor-texto-claro);
    border: none;
    border-radius: 10px;
    padding: 10px 20px;
    font-size: 0.95rem;
    font-weight: 600;
    cursor: pointer;
    transition: opacity 0.18s, transform 0.15s;
    text-decoration: none;
}
.btn-nova-caixinha:hover { opacity: 0.88; transform: translateY(-1px); }

/* ── KPI grid ────────────────────────────────────────────── */
.cxh-kpi-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
    gap: 16px;
    margin-bottom: 20px;
}

.cxh-kpi-card {
    background: var(--cor-fundo-card);
    border-radius: 14px;
    padding: 18px 20px;
    box-shadow: 0 2px 12px var(--sombra-card);
    display: flex;
    flex-direction: column;
    gap: 6px;
    border: 1px solid var(--cor-tinte-borda);
    transition: transform 0.18s, box-shadow 0.18s;
}
.cxh-kpi-card:hover { transform: translateY(-2px); box-shadow: 0 6px 20px var(--sombra-card); }

.cxh-kpi-head {
    display: flex;
    align-items: center;
    justify-content: space-between;
}
.cxh-kpi-label {
    font-size: 0.78rem;
    font-weight: 600;
    color: var(--cor-texto-secundario);
    text-transform: uppercase;
    letter-spacing: 0.05em;
}
.cxh-kpi-icon {
    width: 34px;
    height: 34px;
    border-radius: 8px;
    background: var(--cor-tinte-suave);
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 1.2rem;
    color: var(--cor-principal);
}
.cxh-kpi-valor {
    font-size: 1.55rem;
    font-weight: 700;
    color: var(--cor-titulo);
    line-height: 1.1;
}
.cxh-kpi-sub {
    font-size: 0.78rem;
    color: var(--cor-texto-secundario);
}

/* ── Barra de progresso consolidada ─────────────────────── */
.cxh-progresso-card {
    background: var(--cor-fundo-card);
    border-radius: 14px;
    padding: 16px 20px;
    box-shadow: 0 2px 12px var(--sombra-card);
    border: 1px solid var(--cor-tinte-borda);
    margin-bottom: 20px;
}
.cxh-progresso-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    margin-bottom: 10px;
}
.cxh-progresso-label {
    font-size: 0.85rem;
    font-weight: 600;
    color: var(--cor-texto-secundario);
}
.cxh-progresso-pct {
    font-size: 1rem;
    font-weight: 700;
    color: var(--cor-titulo);
}
.cxh-progress-track {
    height: 10px;
    background: var(--cor-tinte-suave);
    border-radius: 6px;
    overflow: hidden;
}
.cxh-progress-fill {
    height: 100%;
    background: linear-gradient(90deg, var(--cor-principal), var(--cor-titulo));
    border-radius: 6px;
    transition: width 0.5s ease;
}

/* ── Filtros / Abas ─────────────────────────────────────── */
.cxh-filtros {
    display: flex;
    gap: 8px;
    margin-bottom: 20px;
    flex-wrap: wrap;
}
.cxh-filtro-btn {
    padding: 8px 18px;
    border-radius: 20px;
    border: 1.5px solid var(--cor-tinte-borda);
    background: var(--cor-fundo-card);
    color: var(--cor-texto-secundario);
    font-size: 0.85rem;
    font-weight: 600;
    cursor: pointer;
    transition: all 0.18s;
}
.cxh-filtro-btn:hover {
    background: var(--cor-tinte-suave);
    color: var(--cor-titulo);
}
.cxh-filtro-btn.ativo {
    background: var(--cor-principal);
    color: var(--cor-texto-claro);
    border-color: var(--cor-principal);
}

/* ── Grid de cards ──────────────────────────────────────── */
.cxh-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(300px, 1fr));
    gap: 18px;
    margin-bottom: 24px;
}

/* ── Card individual de caixinha ────────────────────────── */
.cxh-card {
    background: var(--cor-fundo-card);
    border-radius: 16px;
    padding: 20px;
    box-shadow: 0 2px 12px var(--sombra-card);
    border: 1.5px solid var(--cor-tinte-borda);
    cursor: pointer;
    transition: transform 0.18s, box-shadow 0.18s, border-color 0.18s;
    display: flex;
    flex-direction: column;
    gap: 12px;
    position: relative;
    overflow: hidden;
}
.cxh-card:hover {
    transform: translateY(-3px);
    box-shadow: 0 8px 24px var(--sombra-card);
    border-color: var(--cor-principal);
}
.cxh-card.encerrada {
    opacity: 0.72;
}
.cxh-card.encerrada::after {
    content: "ENCERRADA";
    position: absolute;
    top: 12px;
    right: -22px;
    background: var(--cor-texto-secundario);
    color: #fff;
    font-size: 0.62rem;
    font-weight: 700;
    letter-spacing: 0.08em;
    padding: 3px 30px;
    transform: rotate(45deg);
}

.cxh-card-header {
    display: flex;
    align-items: flex-start;
    justify-content: space-between;
    gap: 10px;
}
.cxh-card-nome {
    font-size: 1rem;
    font-weight: 700;
    color: var(--cor-titulo);
    line-height: 1.3;
}
.cxh-card-desc {
    font-size: 0.78rem;
    color: var(--cor-texto-secundario);
    margin-top: 2px;
}

/* Badge de tipo de rendimento */
.cxh-badge {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 3px 9px;
    border-radius: 12px;
    white-space: nowrap;
    letter-spacing: 0.04em;
}
.cxh-badge-CDI       { background: rgba(54,115,115,0.12);  color: var(--cor-principal); }
.cxh-badge-SELIC     { background: rgba(59,130,246,0.12);  color: #3B82F6; }
.cxh-badge-POUPANCA  { background: rgba(16,185,129,0.12);  color: #10B981; }
.cxh-badge-PREFIXADO { background: rgba(139,92,246,0.12);  color: #8B5CF6; }
.cxh-badge-PERSONALIZADO { background: rgba(245,158,11,0.12); color: #F59E0B; }

/* Valores */
.cxh-card-valores {
    display: flex;
    align-items: baseline;
    gap: 6px;
}
.cxh-card-valor-atual {
    font-size: 1.35rem;
    font-weight: 700;
    color: var(--cor-titulo);
}
.cxh-card-meta {
    font-size: 0.8rem;
    color: var(--cor-texto-secundario);
}

/* Barra de progresso do card */
.cxh-card-progress-track {
    height: 7px;
    background: var(--cor-tinte-suave);
    border-radius: 4px;
    overflow: hidden;
}
.cxh-card-progress-fill {
    height: 100%;
    border-radius: 4px;
    background: linear-gradient(90deg, var(--cor-principal), var(--cor-titulo));
    transition: width 0.5s ease;
}
.cxh-card-progress-fill.atingida {
    background: linear-gradient(90deg, var(--green-700), #22c55e);
}

.cxh-card-progress-info {
    display: flex;
    justify-content: space-between;
    font-size: 0.75rem;
    color: var(--cor-texto-secundario);
}
.cxh-card-pct { font-weight: 700; color: var(--cor-titulo); }

/* Footer do card */
.cxh-card-footer {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding-top: 8px;
    border-top: 1px solid var(--cor-tinte-suave);
    font-size: 0.75rem;
    color: var(--cor-texto-secundario);
}
.cxh-card-meta-alcancavel {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    font-size: 0.72rem;
    font-weight: 600;
    color: var(--green-700);
}
.cxh-card-meta-alcancavel.nao { color: var(--red-700); }

/* ── Estado vazio ────────────────────────────────────────── */
.cxh-vazio {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    gap: 12px;
    padding: 60px 20px;
    color: var(--cor-texto-secundario);
    text-align: center;
}
.cxh-vazio i { font-size: 3rem; opacity: 0.4; }
.cxh-vazio h3 { font-size: 1.1rem; color: var(--cor-titulo); }
.cxh-vazio p { font-size: 0.88rem; }

/* Loading */
.cxh-loading {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 10px;
    padding: 40px;
    color: var(--cor-texto-secundario);
    font-size: 0.95rem;
}

/* ── Insight card ─────────────────────────────────────────── */
.cxh-insight {
    background: var(--cor-tinte-suave);
    border: 1px solid var(--cor-tinte-borda);
    border-radius: 12px;
    padding: 14px 18px;
    display: flex;
    align-items: flex-start;
    gap: 12px;
    margin-bottom: 24px;
    font-size: 0.85rem;
    color: var(--cor-texto-secundario);
    line-height: 1.55;
}
.cxh-insight i {
    font-size: 1.3rem;
    color: var(--cor-principal);
    flex-shrink: 0;
    margin-top: 1px;
}

/* ═══════════════════════════════════════════════════════════════
   MODAL BASE
   ═══════════════════════════════════════════════════════════════ */
.cxh-modal-overlay {
    display: none;
    position: fixed;
    inset: 0;
    z-index: 9000;
    background: var(--cor-overlay);
    backdrop-filter: blur(3px);
    align-items: center;
    justify-content: center;
    padding: 16px;
}
.cxh-modal-overlay.aberto { display: flex; }

.cxh-modal {
    background: var(--cor-fundo-card);
    border-radius: 20px;
    box-shadow: 0 20px 60px var(--sombra-caixa);
    width: 100%;
    max-width: 580px;
    max-height: 90vh;
    overflow-y: auto;
    animation: cxhModalIn 0.22s ease;
    display: flex;
    flex-direction: column;
}
.cxh-modal-lg { max-width: 720px; }

@keyframes cxhModalIn {
    from { opacity: 0; transform: scale(0.93) translateY(14px); }
    to   { opacity: 1; transform: scale(1)    translateY(0); }
}

.cxh-modal-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 22px 24px 16px;
    border-bottom: 1px solid var(--cor-tinte-borda);
    flex-shrink: 0;
}
.cxh-modal-header h2 {
    font-size: 1.15rem;
    font-weight: 700;
    color: var(--cor-titulo);
    margin: 0;
}
.cxh-modal-close {
    width: 32px;
    height: 32px;
    border-radius: 8px;
    border: none;
    background: var(--cor-tinte-suave);
    color: var(--cor-texto-secundario);
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 1.2rem;
    transition: background 0.15s;
    padding: 0;
    margin: 0;
}
.cxh-modal-close:hover { background: var(--cor-tinte-medio); }

.cxh-modal-body {
    padding: 20px 24px;
    display: flex;
    flex-direction: column;
    gap: 20px;
    flex: 1;
}

.cxh-modal-footer {
    padding: 16px 24px;
    border-top: 1px solid var(--cor-tinte-borda);
    display: flex;
    gap: 10px;
    justify-content: flex-end;
    flex-shrink: 0;
}

/* ── Seções do modal de criação ──────────────────────────── */
.cxh-secao-titulo {
    font-size: 0.75rem;
    font-weight: 700;
    text-transform: uppercase;
    letter-spacing: 0.07em;
    color: var(--cor-principal);
    margin-bottom: 12px;
    display: flex;
    align-items: center;
    gap: 6px;
}
.cxh-secao-titulo::after {
    content: "";
    flex: 1;
    height: 1px;
    background: var(--cor-tinte-borda);
}

/* ── Campos de formulário ─────────────────────────────────── */
.cxh-campo-wrap {
    display: flex;
    flex-direction: column;
    gap: 5px;
}
.cxh-campo-label {
    font-size: 0.8rem;
    font-weight: 600;
    color: var(--cor-texto-secundario);
}
.cxh-campo-input {
    padding: 10px 12px;
    border-radius: 9px;
    border: 1.5px solid var(--cor-tinte-borda);
    background: var(--cor-fundo-campo);
    color: var(--cor-texto-principal);
    font-size: 0.9rem;
    width: 100%;
    transition: border-color 0.15s;
    outline: none;
}
.cxh-campo-input:focus {
    border-color: var(--cor-principal);
    background: var(--cor-fundo-card);
}
.cxh-campo-input::placeholder { color: var(--cor-texto-secundario); opacity: 0.6; }

.cxh-campo-row {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 12px;
}

/* ── Tipo de rendimento – botões inline ──────────────────── */
.cxh-rendimento-btns {
    display: flex;
    gap: 7px;
    flex-wrap: wrap;
    margin-bottom: 14px;
}
.cxh-rend-btn {
    padding: 7px 14px;
    border-radius: 20px;
    border: 1.5px solid var(--cor-tinte-borda);
    background: var(--cor-fundo-card);
    font-size: 0.8rem;
    font-weight: 600;
    cursor: pointer;
    transition: all 0.15s;
    color: var(--cor-texto-secundario);
    margin: 0;
}
.cxh-rend-btn:hover { background: var(--cor-tinte-suave); }
.cxh-rend-btn.ativo-CDI       { background: rgba(54,115,115,0.14);  color: var(--cor-principal); border-color: var(--cor-principal); }
.cxh-rend-btn.ativo-SELIC     { background: rgba(59,130,246,0.14);  color: #3B82F6;  border-color: #3B82F6; }
.cxh-rend-btn.ativo-POUPANCA  { background: rgba(16,185,129,0.14);  color: #10B981;  border-color: #10B981; }
.cxh-rend-btn.ativo-PREFIXADO { background: rgba(139,92,246,0.14);  color: #8B5CF6;  border-color: #8B5CF6; }
.cxh-rend-btn.ativo-PERSONALIZADO { background: rgba(245,158,11,0.14); color: #F59E0B; border-color: #F59E0B; }

/* Campos condicionais de rendimento */
.cxh-rend-campos { display: none; }
.cxh-rend-campos.visivel { display: flex; flex-direction: column; gap: 10px; }

/* Linha resumo taxa efetiva */
.cxh-taxa-resumo {
    font-size: 0.8rem;
    color: var(--cor-texto-secundario);
    background: var(--cor-tinte-suave);
    border-radius: 7px;
    padding: 7px 11px;
    display: flex;
    align-items: center;
    gap: 6px;
}
.cxh-taxa-resumo strong { color: var(--cor-titulo); }

/* ── Seleção de Instituições ─────────────────────────────── */
.cxh-inst-grid {
    display: flex;
    flex-wrap: wrap;
    gap: 8px;
    max-height: 160px;
    overflow-y: auto;
    padding: 4px 2px;
}
.cxh-inst-item {
    display: flex;
    align-items: center;
    gap: 7px;
    padding: 7px 12px;
    border-radius: 20px;
    border: 1.5px solid var(--cor-tinte-borda);
    background: var(--cor-fundo-card);
    cursor: pointer;
    font-size: 0.82rem;
    font-weight: 600;
    color: var(--cor-texto-secundario);
    transition: all 0.15s;
    user-select: none;
}
.cxh-inst-item:hover { background: var(--cor-tinte-suave); }
.cxh-inst-item.selecionada {
    background: var(--cor-tinte-medio);
    border-color: var(--cor-principal);
    color: var(--cor-titulo);
}
.cxh-inst-item input[type="checkbox"] { display: none; }
.cxh-inst-check {
    width: 16px;
    height: 16px;
    border-radius: 4px;
    border: 1.5px solid var(--cor-tinte-borda);
    background: transparent;
    display: flex;
    align-items: center;
    justify-content: center;
    flex-shrink: 0;
    font-size: 0.65rem;
    color: transparent;
}
.cxh-inst-item.selecionada .cxh-inst-check {
    background: var(--cor-principal);
    border-color: var(--cor-principal);
    color: #fff;
}

/* ── Botões do modal ─────────────────────────────────────── */
.btn-cxh-salvar {
    padding: 10px 22px;
    border-radius: 10px;
    background: var(--cor-principal);
    color: var(--cor-texto-claro);
    border: none;
    font-size: 0.9rem;
    font-weight: 700;
    cursor: pointer;
    transition: opacity 0.18s;
    display: inline-flex;
    align-items: center;
    gap: 7px;
    margin: 0;
}
.btn-cxh-salvar:hover:not(:disabled) { opacity: 0.85; }
.btn-cxh-salvar:disabled { opacity: 0.45; cursor: not-allowed; }

.btn-cxh-cancelar {
    padding: 10px 18px;
    border-radius: 10px;
    background: transparent;
    color: var(--cor-texto-secundario);
    border: 1.5px solid var(--cor-tinte-borda);
    font-size: 0.9rem;
    font-weight: 600;
    cursor: pointer;
    transition: background 0.15s;
    display: inline-flex;
    align-items: center;
    gap: 7px;
    margin: 0;
}
.btn-cxh-cancelar:hover { background: var(--cor-tinte-suave); }

.btn-cxh-encerrar {
    padding: 10px 18px;
    border-radius: 10px;
    background: transparent;
    color: #F59E0B;
    border: 1.5px solid #F59E0B;
    font-size: 0.88rem;
    font-weight: 600;
    cursor: pointer;
    transition: background 0.15s;
    display: inline-flex;
    align-items: center;
    gap: 6px;
    margin: 0;
}
.btn-cxh-encerrar:hover { background: rgba(245,158,11,0.1); }

.btn-cxh-deletar {
    padding: 10px 18px;
    border-radius: 10px;
    background: transparent;
    color: var(--red-700);
    border: 1.5px solid var(--red-700);
    font-size: 0.88rem;
    font-weight: 600;
    cursor: pointer;
    transition: background 0.15s;
    display: inline-flex;
    align-items: center;
    gap: 6px;
    margin: 0;
}
.btn-cxh-deletar:hover { background: var(--red-100); }

.btn-cxh-editar {
    padding: 10px 18px;
    border-radius: 10px;
    background: transparent;
    color: var(--cor-acao-editar);
    border: 1.5px solid var(--cor-acao-editar);
    font-size: 0.88rem;
    font-weight: 600;
    cursor: pointer;
    transition: background 0.15s;
    display: inline-flex;
    align-items: center;
    gap: 6px;
    margin: 0;
}
.btn-cxh-editar:hover { background: var(--cor-acao-editar-suave); }

/* ═══════════════════════════════════════════════════════════════
   MODAL DE DETALHES
   ═══════════════════════════════════════════════════════════════ */
.cxh-det-grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 12px;
}

.cxh-det-stat {
    background: var(--cor-tinte-suave);
    border-radius: 10px;
    padding: 12px 14px;
    display: flex;
    flex-direction: column;
    gap: 3px;
}
.cxh-det-stat-label {
    font-size: 0.72rem;
    font-weight: 600;
    text-transform: uppercase;
    letter-spacing: 0.05em;
    color: var(--cor-texto-secundario);
}
.cxh-det-stat-val {
    font-size: 1.05rem;
    font-weight: 700;
    color: var(--cor-titulo);
}
.cxh-det-stat-val.positivo { color: var(--green-700); }
.cxh-det-stat-val.negativo { color: var(--red-700); }

.cxh-det-projecao {
    background: var(--cor-tinte-suave);
    border-radius: 10px;
    padding: 14px;
    font-size: 0.82rem;
    color: var(--cor-texto-secundario);
    line-height: 1.65;
    border: 1px solid var(--cor-tinte-borda);
}
.cxh-det-projecao strong { color: var(--cor-titulo); }

.cxh-det-alcancavel {
    display: inline-flex;
    align-items: center;
    gap: 6px;
    padding: 8px 14px;
    border-radius: 20px;
    font-size: 0.82rem;
    font-weight: 700;
    background: var(--green-100);
    color: var(--green-700);
}
.cxh-det-alcancavel.nao {
    background: var(--red-100);
    color: var(--red-700);
}

/* Instituições no detalhe */
.cxh-det-inst-lista {
    display: flex;
    flex-direction: column;
    gap: 6px;
}
.cxh-det-inst-item {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 8px 12px;
    border-radius: 8px;
    background: var(--cor-tinte-suave);
    font-size: 0.82rem;
}
.cxh-det-inst-nome { font-weight: 600; color: var(--cor-titulo); }
.cxh-det-inst-val { color: var(--cor-texto-secundario); }

/* ── Feedback / Toast ─────────────────────────────────────── */
.cxh-toast {
    position: fixed;
    bottom: 28px;
    right: 28px;
    z-index: 99999;
    display: flex;
    align-items: center;
    gap: 10px;
    padding: 12px 18px;
    border-radius: 12px;
    font-size: 0.88rem;
    font-weight: 600;
    background: var(--cor-fundo-card);
    box-shadow: 0 6px 24px var(--sombra-caixa);
    border: 1px solid var(--cor-tinte-borda);
    animation: cxhToastIn 0.22s ease;
    max-width: 340px;
}
.cxh-toast.sucesso { border-color: var(--green-700); color: var(--green-700); }
.cxh-toast.erro    { border-color: var(--red-700);   color: var(--red-700);   }

@keyframes cxhToastIn {
    from { opacity: 0; transform: translateY(16px); }
    to   { opacity: 1; transform: translateY(0); }
}

/* ── Responsivo ──────────────────────────────────────────── */
@media (max-width: 600px) {
    .cxh-campo-row { grid-template-columns: 1fr; }
    .cxh-det-grid  { grid-template-columns: 1fr; }
    .cxh-modal-footer { flex-direction: column; }
    .cxh-modal-footer button { width: 100%; justify-content: center; }
    .cxh-rendimento-btns { gap: 5px; }
    .cxh-rend-btn { font-size: 0.72rem; padding: 6px 10px; }
}

/* ═══════════════════════════════════════════════════════════════
   caixinhas.css — Tela de Poupança / Caixinhas
   ═══════════════════════════════════════════════════════════════ */

/* ── Page header ─────────────────────────────────────────── */
.cxh-page-header {
    display: flex;
    flex-direction: row;
    align-items: center;
    justify-content: space-between;
    margin-bottom: 8px;
    flex-wrap: wrap;
    gap: 12px;
}
.cxh-page-header h1 { margin-bottom: 0; }

.cxh-header-left {
    display: flex;
    flex-direction: column;
    gap: 2px;
}

.cxh-header-subtitle {
    font-size: 0.85rem;
    color: var(--cor-texto-secundario);
    font-weight: 400;
}

.btn-nova-caixinha {
    display: inline-flex;
    align-items: center;
    gap: 8px;
    background: var(--cor-principal);
    color: var(--cor-texto-claro);
    border: none;
    border-radius: 10px;
    padding: 10px 20px;
    font-size: 0.95rem;
    font-weight: 600;
    cursor: pointer;
    transition: opacity 0.18s, transform 0.15s;
    text-decoration: none;
}
.btn-nova-caixinha:hover { opacity: 0.88; transform: translateY(-1px); }

/* ── KPI grid ────────────────────────────────────────────── */
.cxh-kpi-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
    gap: 16px;
    margin-bottom: 20px;
}

.cxh-kpi-card {
    background: var(--cor-fundo-card);
    border-radius: 14px;
    padding: 18px 20px;
    box-shadow: 0 2px 12px var(--sombra-card);
    display: flex;
    flex-direction: column;
    gap: 6px;
    border: 1px solid var(--cor-tinte-borda);
    transition: transform 0.18s, box-shadow 0.18s;
}
.cxh-kpi-card:hover { transform: translateY(-2px); box-shadow: 0 6px 20px var(--sombra-card); }

.cxh-kpi-head {
    display: flex;
    align-items: center;
    justify-content: space-between;
}
.cxh-kpi-label {
    font-size: 0.78rem;
    font-weight: 600;
    color: var(--cor-texto-secundario);
    text-transform: uppercase;
    letter-spacing: 0.05em;
}
.cxh-kpi-icon {
    width: 34px;
    height: 34px;
    border-radius: 8px;
    background: var(--cor-tinte-suave);
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 1.2rem;
    color: var(--cor-principal);
}
.cxh-kpi-valor {
    font-size: 1.55rem;
    font-weight: 700;
    color: var(--cor-titulo);
    line-height: 1.1;
}
.cxh-kpi-sub {
    font-size: 0.78rem;
    color: var(--cor-texto-secundario);
}

/* ── Barra de progresso consolidada ─────────────────────── */
.cxh-progresso-card {
    background: var(--cor-fundo-card);
    border-radius: 14px;
    padding: 16px 20px;
    box-shadow: 0 2px 12px var(--sombra-card);
    border: 1px solid var(--cor-tinte-borda);
    margin-bottom: 20px;
}
.cxh-progresso-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    margin-bottom: 10px;
}
.cxh-progresso-label {
    font-size: 0.85rem;
    font-weight: 600;
    color: var(--cor-texto-secundario);
}
.cxh-progresso-pct {
    font-size: 1rem;
    font-weight: 700;
    color: var(--cor-titulo);
}
.cxh-progress-track {
    height: 10px;
    background: var(--cor-tinte-suave);
    border-radius: 6px;
    overflow: hidden;
}
.cxh-progress-fill {
    height: 100%;
    background: linear-gradient(90deg, var(--cor-principal), var(--cor-titulo));
    border-radius: 6px;
    transition: width 0.5s ease;
}

/* ── Filtros / Abas ─────────────────────────────────────── */
.cxh-filtros {
    display: flex;
    gap: 8px;
    margin-bottom: 20px;
    flex-wrap: wrap;
}
.cxh-filtro-btn {
    padding: 8px 18px;
    border-radius: 20px;
    border: 1.5px solid var(--cor-tinte-borda);
    background: var(--cor-fundo-card);
    color: var(--cor-texto-secundario);
    font-size: 0.85rem;
    font-weight: 600;
    cursor: pointer;
    transition: all 0.18s;
}
.cxh-filtro-btn:hover {
    background: var(--cor-tinte-suave);
    color: var(--cor-titulo);
}
.cxh-filtro-btn.ativo {
    background: var(--cor-principal);
    color: var(--cor-texto-claro);
    border-color: var(--cor-principal);
}

/* ── Grid de cards ──────────────────────────────────────── */
.cxh-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(300px, 1fr));
    gap: 18px;
    margin-bottom: 24px;
}

/* ── Card individual de caixinha ────────────────────────── */
.cxh-card {
    background: var(--cor-fundo-card);
    border-radius: 16px;
    padding: 20px;
    box-shadow: 0 2px 12px var(--sombra-card);
    border: 1.5px solid var(--cor-tinte-borda);
    cursor: pointer;
    transition: transform 0.18s, box-shadow 0.18s, border-color 0.18s;
    display: flex;
    flex-direction: column;
    gap: 12px;
    position: relative;
    overflow: hidden;
}
.cxh-card:hover {
    transform: translateY(-3px);
    box-shadow: 0 8px 24px var(--sombra-card);
    border-color: var(--cor-principal);
}
.cxh-card.encerrada {
    opacity: 0.72;
}
.cxh-card.encerrada::after {
    content: "ENCERRADA";
    position: absolute;
    top: 12px;
    right: -22px;
    background: var(--cor-texto-secundario);
    color: #fff;
    font-size: 0.62rem;
    font-weight: 700;
    letter-spacing: 0.08em;
    padding: 3px 30px;
    transform: rotate(45deg);
}

.cxh-card-header {
    display: flex;
    align-items: flex-start;
    justify-content: space-between;
    gap: 10px;
}
.cxh-card-nome {
    font-size: 1rem;
    font-weight: 700;
    color: var(--cor-titulo);
    line-height: 1.3;
}
.cxh-card-desc {
    font-size: 0.78rem;
    color: var(--cor-texto-secundario);
    margin-top: 2px;
}

/* Badge de tipo de rendimento */
.cxh-badge {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 3px 9px;
    border-radius: 12px;
    white-space: nowrap;
    letter-spacing: 0.04em;
}
.cxh-badge-CDI       { background: rgba(54,115,115,0.12);  color: var(--cor-principal); }
.cxh-badge-SELIC     { background: rgba(59,130,246,0.12);  color: #3B82F6; }
.cxh-badge-POUPANCA  { background: rgba(16,185,129,0.12);  color: #10B981; }
.cxh-badge-PREFIXADO { background: rgba(139,92,246,0.12);  color: #8B5CF6; }
.cxh-badge-PERSONALIZADO { background: rgba(245,158,11,0.12); color: #F59E0B; }

/* Valores */
.cxh-card-valores {
    display: flex;
    align-items: baseline;
    gap: 6px;
}
.cxh-card-valor-atual {
    font-size: 1.35rem;
    font-weight: 700;
    color: var(--cor-titulo);
}
.cxh-card-meta {
    font-size: 0.8rem;
    color: var(--cor-texto-secundario);
}

/* Barra de progresso do card */
.cxh-card-progress-track {
    height: 7px;
    background: var(--cor-tinte-suave);
    border-radius: 4px;
    overflow: hidden;
}
.cxh-card-progress-fill {
    height: 100%;
    border-radius: 4px;
    background: linear-gradient(90deg, var(--cor-principal), var(--cor-titulo));
    transition: width 0.5s ease;
}
.cxh-card-progress-fill.atingida {
    background: linear-gradient(90deg, var(--green-700), #22c55e);
}

.cxh-card-progress-info {
    display: flex;
    justify-content: space-between;
    font-size: 0.75rem;
    color: var(--cor-texto-secundario);
}
.cxh-card-pct { font-weight: 700; color: var(--cor-titulo); }

/* Footer do card */
.cxh-card-footer {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding-top: 8px;
    border-top: 1px solid var(--cor-tinte-suave);
    font-size: 0.75rem;
    color: var(--cor-texto-secundario);
}
.cxh-card-meta-alcancavel {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    font-size: 0.72rem;
    font-weight: 600;
    color: var(--green-700);
}
.cxh-card-meta-alcancavel.nao { color: var(--red-700); }

/* ── Estado vazio ────────────────────────────────────────── */
.cxh-vazio {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    gap: 12px;
    padding: 60px 20px;
    color: var(--cor-texto-secundario);
    text-align: center;
}
.cxh-vazio i { font-size: 3rem; opacity: 0.4; }
.cxh-vazio h3 { font-size: 1.1rem; color: var(--cor-titulo); }
.cxh-vazio p { font-size: 0.88rem; }

/* Loading */
.cxh-loading {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 10px;
    padding: 40px;
    color: var(--cor-texto-secundario);
    font-size: 0.95rem;
}

/* ── Insight card ─────────────────────────────────────────── */
.cxh-insight {
    background: var(--cor-tinte-suave);
    border: 1px solid var(--cor-tinte-borda);
    border-radius: 12px;
    padding: 14px 18px;
    display: flex;
    align-items: flex-start;
    gap: 12px;
    margin-bottom: 24px;
    font-size: 0.85rem;
    color: var(--cor-texto-secundario);
    line-height: 1.55;
}
.cxh-insight i {
    font-size: 1.3rem;
    color: var(--cor-principal);
    flex-shrink: 0;
    margin-top: 1px;
}

/* ═══════════════════════════════════════════════════════════════
   MODAL BASE
   ═══════════════════════════════════════════════════════════════ */
.cxh-modal-overlay {
    display: none;
    position: fixed;
    inset: 0;
    z-index: 9000;
    background: var(--cor-overlay);
    backdrop-filter: blur(3px);
    align-items: center;
    justify-content: center;
    padding: 16px;
}
.cxh-modal-overlay.aberto { display: flex; }

.cxh-modal {
    background: var(--cor-fundo-card);
    border-radius: 20px;
    box-shadow: 0 20px 60px var(--sombra-caixa);
    width: 100%;
    max-width: 580px;
    max-height: 90vh;
    overflow-y: auto;
    animation: cxhModalIn 0.22s ease;
    display: flex;
    flex-direction: column;
}
.cxh-modal-lg { max-width: 720px; }

@keyframes cxhModalIn {
    from { opacity: 0; transform: scale(0.93) translateY(14px); }
    to   { opacity: 1; transform: scale(1)    translateY(0); }
}

.cxh-modal-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 22px 24px 16px;
    border-bottom: 1px solid var(--cor-tinte-borda);
    flex-shrink: 0;
}
.cxh-modal-header h2 {
    font-size: 1.15rem;
    font-weight: 700;
    color: var(--cor-titulo);
    margin: 0;
}
.cxh-modal-close {
    width: 32px;
    height: 32px;
    border-radius: 8px;
    border: none;
    background: var(--cor-tinte-suave);
    color: var(--cor-texto-secundario);
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 1.2rem;
    transition: background 0.15s;
    padding: 0;
    margin: 0;
}
.cxh-modal-close:hover { background: var(--cor-tinte-medio); }

.cxh-modal-body {
    padding: 20px 24px;
    display: flex;
    flex-direction: column;
    gap: 20px;
    flex: 1;
}

.cxh-modal-footer {
    padding: 16px 24px;
    border-top: 1px solid var(--cor-tinte-borda);
    display: flex;
    gap: 10px;
    justify-content: flex-end;
    flex-shrink: 0;
}

/* ── Seções do modal de criação ──────────────────────────── */
.cxh-secao-titulo {
    font-size: 0.75rem;
    font-weight: 700;
    text-transform: uppercase;
    letter-spacing: 0.07em;
    color: var(--cor-principal);
    margin-bottom: 12px;
    display: flex;
    align-items: center;
    gap: 6px;
}
.cxh-secao-titulo::after {
    content: "";
    flex: 1;
    height: 1px;
    background: var(--cor-tinte-borda);
}

/* ── Campos de formulário ─────────────────────────────────── */
.cxh-campo-wrap {
    display: flex;
    flex-direction: column;
    gap: 5px;
}
.cxh-campo-label {
    font-size: 0.8rem;
    font-weight: 600;
    color: var(--cor-texto-secundario);
}
.cxh-campo-input {
    padding: 10px 12px;
    border-radius: 9px;
    border: 1.5px solid var(--cor-tinte-borda);
    background: var(--cor-fundo-campo);
    color: var(--cor-texto-principal);
    font-size: 0.9rem;
    width: 100%;
    transition: border-color 0.15s;
    outline: none;
}
.cxh-campo-input:focus {
    border-color: var(--cor-principal);
    background: var(--cor-fundo-card);
}
.cxh-campo-input::placeholder { color: var(--cor-texto-secundario); opacity: 0.6; }

.cxh-campo-row {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 12px;
}

/* ── Tipo de rendimento – botões inline ──────────────────── */
.cxh-rendimento-btns {
    display: flex;
    gap: 7px;
    flex-wrap: wrap;
    margin-bottom: 14px;
}
.cxh-rend-btn {
    padding: 7px 14px;
    border-radius: 20px;
    border: 1.5px solid var(--cor-tinte-borda);
    background: var(--cor-fundo-card);
    font-size: 0.8rem;
    font-weight: 600;
    cursor: pointer;
    transition: all 0.15s;
    color: var(--cor-texto-secundario);
    margin: 0;
}
.cxh-rend-btn:hover { background: var(--cor-tinte-suave); }
.cxh-rend-btn.ativo-CDI       { background: rgba(54,115,115,0.14);  color: var(--cor-principal); border-color: var(--cor-principal); }
.cxh-rend-btn.ativo-SELIC     { background: rgba(59,130,246,0.14);  color: #3B82F6;  border-color: #3B82F6; }
.cxh-rend-btn.ativo-POUPANCA  { background: rgba(16,185,129,0.14);  color: #10B981;  border-color: #10B981; }
.cxh-rend-btn.ativo-PREFIXADO { background: rgba(139,92,246,0.14);  color: #8B5CF6;  border-color: #8B5CF6; }
.cxh-rend-btn.ativo-PERSONALIZADO { background: rgba(245,158,11,0.14); color: #F59E0B; border-color: #F59E0B; }

/* Campos condicionais de rendimento */
.cxh-rend-campos { display: none; }
.cxh-rend-campos.visivel { display: flex; flex-direction: column; gap: 10px; }

/* Linha resumo taxa efetiva */
.cxh-taxa-resumo {
    font-size: 0.8rem;
    color: var(--cor-texto-secundario);
    background: var(--cor-tinte-suave);
    border-radius: 7px;
    padding: 7px 11px;
    display: flex;
    align-items: center;
    gap: 6px;
}
.cxh-taxa-resumo strong { color: var(--cor-titulo); }

/* ── Seleção de Instituições ─────────────────────────────── */
.cxh-inst-grid {
    display: flex;
    flex-wrap: wrap;
    gap: 8px;
    max-height: 160px;
    overflow-y: auto;
    padding: 4px 2px;
}
.cxh-inst-item {
    display: flex;
    align-items: center;
    gap: 7px;
    padding: 7px 12px;
    border-radius: 20px;
    border: 1.5px solid var(--cor-tinte-borda);
    background: var(--cor-fundo-card);
    cursor: pointer;
    font-size: 0.82rem;
    font-weight: 600;
    color: var(--cor-texto-secundario);
    transition: all 0.15s;
    user-select: none;
}
.cxh-inst-item:hover { background: var(--cor-tinte-suave); }
.cxh-inst-item.selecionada {
    background: var(--cor-tinte-medio);
    border-color: var(--cor-principal);
    color: var(--cor-titulo);
}
.cxh-inst-item input[type="checkbox"] { display: none; }
.cxh-inst-check {
    width: 16px;
    height: 16px;
    border-radius: 4px;
    border: 1.5px solid var(--cor-tinte-borda);
    background: transparent;
    display: flex;
    align-items: center;
    justify-content: center;
    flex-shrink: 0;
    font-size: 0.65rem;
    color: transparent;
}
.cxh-inst-item.selecionada .cxh-inst-check {
    background: var(--cor-principal);
    border-color: var(--cor-principal);
    color: #fff;
}

/* ── Botões do modal ─────────────────────────────────────── */
.btn-cxh-salvar {
    padding: 10px 22px;
    border-radius: 10px;
    background: var(--cor-principal);
    color: var(--cor-texto-claro);
    border: none;
    font-size: 0.9rem;
    font-weight: 700;
    cursor: pointer;
    transition: opacity 0.18s;
    display: inline-flex;
    align-items: center;
    gap: 7px;
    margin: 0;
}
.btn-cxh-salvar:hover:not(:disabled) { opacity: 0.85; }
.btn-cxh-salvar:disabled { opacity: 0.45; cursor: not-allowed; }

.btn-cxh-cancelar {
    padding: 10px 18px;
    border-radius: 10px;
    background: transparent;
    color: var(--cor-texto-secundario);
    border: 1.5px solid var(--cor-tinte-borda);
    font-size: 0.9rem;
    font-weight: 600;
    cursor: pointer;
    transition: background 0.15s;
    display: inline-flex;
    align-items: center;
    gap: 7px;
    margin: 0;
}
.btn-cxh-cancelar:hover { background: var(--cor-tinte-suave); }

.btn-cxh-encerrar {
    padding: 10px 18px;
    border-radius: 10px;
    background: transparent;
    color: #F59E0B;
    border: 1.5px solid #F59E0B;
    font-size: 0.88rem;
    font-weight: 600;
    cursor: pointer;
    transition: background 0.15s;
    display: inline-flex;
    align-items: center;
    gap: 6px;
    margin: 0;
}
.btn-cxh-encerrar:hover { background: rgba(245,158,11,0.1); }

.btn-cxh-deletar {
    padding: 10px 18px;
    border-radius: 10px;
    background: transparent;
    color: var(--red-700);
    border: 1.5px solid var(--red-700);
    font-size: 0.88rem;
    font-weight: 600;
    cursor: pointer;
    transition: background 0.15s;
    display: inline-flex;
    align-items: center;
    gap: 6px;
    margin: 0;
}
.btn-cxh-deletar:hover { background: var(--red-100); }

.btn-cxh-editar {
    padding: 10px 18px;
    border-radius: 10px;
    background: transparent;
    color: var(--cor-acao-editar);
    border: 1.5px solid var(--cor-acao-editar);
    font-size: 0.88rem;
    font-weight: 600;
    cursor: pointer;
    transition: background 0.15s;
    display: inline-flex;
    align-items: center;
    gap: 6px;
    margin: 0;
}
.btn-cxh-editar:hover { background: var(--cor-acao-editar-suave); }

.btn-cxh-reabrir {
    display: inline-flex; align-items: center; gap: 6px;
    padding: 9px 18px; border: 1.5px solid #059669; border-radius: 8px;
    background: transparent; color: #059669;
    font-size: 0.88rem; font-weight: 600; cursor: pointer; transition: background 0.15s;
}
.btn-cxh-reabrir:hover { background: rgba(5,150,105,0.08); }

.btn-cxh-reabrir-confirmar {
    display: inline-flex; align-items: center; gap: 6px;
    padding: 9px 18px; border: none; border-radius: 8px;
    background: #059669; color: #fff;
    font-size: 0.88rem; font-weight: 600; cursor: pointer; transition: opacity 0.15s;
}
.btn-cxh-reabrir-confirmar:hover { opacity: 0.85; }

/* Footer de confirmação inline */
.cxh-footer-confirmacao {
    background: var(--cor-tinte-suave);
    border-top: 1px solid var(--cor-tinte-borda);
    border-radius: 0 0 16px 16px;
    animation: fadeIn 0.15s ease;
    gap: 10px;
    align-items: center;
}

.btn-cxh-encerrar-confirmar,
.btn-cxh-deletar-confirmar {
    display: inline-flex;
    align-items: center;
    gap: 6px;
    padding: 9px 18px;
    border: none;
    border-radius: 8px;
    font-size: 0.88rem;
    font-weight: 600;
    cursor: pointer;
    transition: opacity 0.15s;
}

.btn-cxh-encerrar-confirmar {
    background: #f59e0b;
    color: #fff;
}
.btn-cxh-encerrar-confirmar:hover { opacity: 0.85; }

.btn-cxh-deletar-confirmar {
    background: var(--red-600, #dc2626);
    color: #fff;
}
.btn-cxh-deletar-confirmar:hover { opacity: 0.85; }


   MODAL DE DETALHES
   ═══════════════════════════════════════════════════════════════ */
.cxh-det-grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 12px;
}

.cxh-det-stat {
    background: var(--cor-tinte-suave);
    border-radius: 10px;
    padding: 12px 14px;
    display: flex;
    flex-direction: column;
    gap: 3px;
}
.cxh-det-stat-label {
    font-size: 0.72rem;
    font-weight: 600;
    text-transform: uppercase;
    letter-spacing: 0.05em;
    color: var(--cor-texto-secundario);
}
.cxh-det-stat-val {
    font-size: 1.05rem;
    font-weight: 700;
    color: var(--cor-titulo);
}
.cxh-det-stat-val.positivo { color: var(--green-700); }
.cxh-det-stat-val.negativo { color: var(--red-700); }

.cxh-det-projecao {
    background: var(--cor-tinte-suave);
    border-radius: 10px;
    padding: 14px;
    font-size: 0.82rem;
    color: var(--cor-texto-secundario);
    line-height: 1.65;
    border: 1px solid var(--cor-tinte-borda);
}
.cxh-det-projecao strong { color: var(--cor-titulo); }

.cxh-det-alcancavel {
    display: inline-flex;
    align-items: center;
    gap: 6px;
    padding: 8px 14px;
    border-radius: 20px;
    font-size: 0.82rem;
    font-weight: 700;
    background: var(--green-100);
    color: var(--green-700);
}
.cxh-det-alcancavel.nao {
    background: var(--red-100);
    color: var(--red-700);
}

/* Instituições no detalhe */
.cxh-det-inst-lista {
    display: flex;
    flex-direction: column;
    gap: 6px;
}
.cxh-det-inst-item {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 8px 12px;
    border-radius: 8px;
    background: var(--cor-tinte-suave);
    font-size: 0.82rem;
}
.cxh-det-inst-nome { font-weight: 600; color: var(--cor-titulo); }
.cxh-det-inst-val { color: var(--cor-texto-secundario); }

/* ── Feedback / Toast ─────────────────────────────────────── */
.cxh-toast {
    position: fixed;
    bottom: 28px;
    right: 28px;
    z-index: 99999;
    display: flex;
    align-items: center;
    gap: 10px;
    padding: 12px 18px;
    border-radius: 12px;
    font-size: 0.88rem;
    font-weight: 600;
    background: var(--cor-fundo-card);
    box-shadow: 0 6px 24px var(--sombra-caixa);
    border: 1px solid var(--cor-tinte-borda);
    animation: cxhToastIn 0.22s ease;
    max-width: 340px;
}
.cxh-toast.sucesso { border-color: var(--green-700); color: var(--green-700); }
.cxh-toast.erro    { border-color: var(--red-700);   color: var(--red-700);   }

@keyframes cxhToastIn {
    from { opacity: 0; transform: translateY(16px); }
    to   { opacity: 1; transform: translateY(0); }
}

/* ── Responsivo ──────────────────────────────────────────── */
@media (max-width: 600px) {
    .cxh-campo-row { grid-template-columns: 1fr; }
    .cxh-det-grid  { grid-template-columns: 1fr; }
    .cxh-modal-footer { flex-direction: column; }
    .cxh-modal-footer button { width: 100%; justify-content: center; }
    .cxh-rendimento-btns { gap: 5px; }
    .cxh-rend-btn { font-size: 0.72rem; padding: 6px 10px; }
}

@import "root.css"; 

/* ── Agenda page ── */

/* Two-column layout */
.ag-layout {
    display: flex;
    gap: 24px;
    align-items: flex-start;
}

/* ── Calendar panel ── */
.ag-cal-panel {
    flex: 1 1 0;
    min-width: 0;
}

/* Month navigation */
.ag-month-nav {
    display: flex;
    align-items: center;
    gap: 20px;
    margin-bottom: 16px;
}

.ag-month-name {
    color: var(--cor-titulo);
    font-size: 2.5rem;
    font-weight: 500;
    min-width: 220px;
}

.ag-nav-btn {
    background: var(--cor-principal);
    color: var(--cor-texto-claro);
    border: none;
    border-radius: 8px;
    width: 38px;
    height: 38px;
    font-size: 1.3rem;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: background 0.2s;
    margin: 0;
    padding: 0;
}

.ag-nav-btn:hover {
    background: var(--cor-hover);
}

/* Day-of-week header */
.ag-weekdays {
    display: grid;
    grid-template-columns: repeat(7, 1fr);
    gap: 6px;
    margin-bottom: 6px;
}

.ag-weekday {
    text-align: center;
    font-size: 1.1rem;
    font-weight: 600;
    color: var(--cor-principal);
    padding: 4px 0;
}

/* Calendar grid */
.ag-grid {
    display: grid;
    grid-template-columns: repeat(7, 1fr);
    gap: 6px;
}

/* Single day cell */
.ag-day {
    background: var(--cor-principal);
    border-radius: 10px;
    box-shadow: 0px 4px 4px var(--sombra-caixa);
    padding: 10px 8px 6px;
    min-height: 80px;
    cursor: pointer;
    display: flex;
    flex-direction: column;
    justify-content: space-between;
    transition: background 0.15s, transform 0.1s;
    user-select: none;
}

.ag-day:hover {
    background: var(--cor-hover);
    transform: translateY(-2px);
}

.ag-day.ag-today {
    outline: 2px solid var(--cor-hover);
    outline-offset: -2px;
}

.ag-day.ag-selected {
    background: var(--cor-hover);
}

.ag-day.ag-empty {
    background: transparent;
    box-shadow: none;
    cursor: default;
    pointer-events: none;
}

.ag-day-num {
    color: var(--cor-texto-claro);
    font-size: 1.4rem;
    font-weight: 400;
    line-height: 1;
}

/* Colored dots */
.ag-dots {
    display: flex;
    flex-wrap: wrap;
    gap: 3px;
    margin-top: 4px;
}

.ag-dot {
    width: 10px;
    height: 10px;
    border-radius: 9999px;
    flex-shrink: 0;
}

.ag-dot-gasto {
    background: var(--cor-gasto-bg);
}

.ag-dot-recebimento {
    background: var(--cor-recebimento-bg);
}

.ag-dot-transferencia {
    background: var(--cor-transferencia-bg);
}

.ag-dot-agendamento {
    background: var(--cor-agendamento-bg);
}

/* ── Summary panel ── */
.ag-resumo {
    width: 340px;
    flex-shrink: 0;
    background: var(--cor-fundo-card);
    border-radius: 30px;
    box-shadow: 0px 4px 4px var(--sombra-caixa);
    padding: 24px 20px;
    display: flex;
    flex-direction: column;
    gap: 16px;
    max-height: calc(100vh - 120px);
    overflow-y: auto;
    position: sticky;
    top: 20px;
}

.ag-resumo-titulo {
    color: var(--cor-titulo);
    font-size: 2rem;
    font-weight: 400;
    border-bottom: 2px solid var(--cor-principal);
    padding-bottom: 10px;
}

.ag-resumo-empty {
    color: var(--cor-texto-secundario);
    font-size: 1rem;
    text-align: center;
    padding: 20px 0;
}

/* Event group date header */
.ag-resumo-data {
    color: var(--cor-texto-principal);
    font-size: 1.2rem;
    font-weight: 400;
    margin-top: 8px;
}

/* Event chip */
.ag-evento {
    border-radius: 10px;
    padding: 10px 14px;
    display: flex;
    justify-content: space-between;
    align-items: center;
    gap: 10px;
}

.ag-evento-titulo {
    font-size: 1rem;
    font-weight: 400;
}

.ag-evento-valor {
    font-size: 0.95rem;
    font-weight: 400;
    white-space: nowrap;
}

.ag-evento.gasto {
    background: var(--cor-gasto-bg);
    color: var(--cor-gasto-texto);
}

.ag-evento.recebimento {
    background: var(--cor-recebimento-bg);
    color: var(--cor-recebimento-texto);
}

.ag-evento.transferencia {
    background: var(--cor-transferencia-bg);
    color: var(--cor-transferencia-texto);
}

.ag-evento.agendamento {
    background: var(--cor-agendamento-bg);
    color: var(--cor-agendamento-texto);
}

