    color: var(--cor-principal);
    min-width: 90px;
    max-width: 110px;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
}

.ar-inst-amt-input {
    flex: 1;
    height: 34px;
    border-radius: 8px;
    border: 1px solid var(--cor-principal);
    padding: 0 10px;
    font-size: 0.88rem;
    font-weight: 600;
    color: var(--cor-principal);
    background: var(--cor-fundo-card);
    outline: none;
    box-sizing: border-box;
}
.ar-inst-amt-input:focus { border-color: var(--cor-titulo); border-width: 2px; }

/* ══════════════════════════════════════════════════
   Recurring section
══════════════════════════════════════════════════ */
.ar-recurring-wrap { padding: 0 4px; }

.ar-recurring-toggle {
    display: inline-flex;
    align-items: center;
    gap: 10px;
    cursor: pointer;
    user-select: none;
    font-size: 0.95rem;
    font-weight: 600;
    color: var(--cor-principal);
}
.ar-recurring-toggle:hover .ar-checkbox-btn { border-color: var(--cor-titulo); }

.ar-checkbox-btn {
    width: 22px;
    height: 22px;
    border-radius: 6px;
    border: 2px solid var(--cor-principal);
    background: transparent;
    display: flex;
    align-items: center;
    justify-content: center;
    flex-shrink: 0;
    transition: background 0.15s, border-color 0.15s;
}
.ar-checkbox-btn.active { background: var(--cor-principal); border-color: var(--cor-principal); }

.ar-recurring-body {
    margin-top: 12px;
    margin-left: 32px;
    padding-left: 16px;
    border-left: 2px solid var(--cor-tinte-borda);
}

.ar-recurring-group { margin-bottom: 14px; }
.ar-recurring-group:last-child { margin-bottom: 0; }

.ar-group-label {
    display: block;
    font-size: 10px;
    font-weight: 700;
    color: var(--cor-principal);
    opacity: 0.6;
    text-transform: uppercase;
    letter-spacing: 0.07em;
    margin-bottom: 8px;
}

/* ── Pills (periodicidade, semana, mês, meses) ── */
.ar-pills {
    display: flex;
    flex-wrap: wrap;
    gap: 6px;
}

.ar-pill {
    padding: 6px 16px;
    border-radius: 20px;
    border: 2px solid var(--cor-principal);
    background: transparent;
    color: var(--cor-principal);
    font-size: 0.83rem;
    font-weight: 600;
    cursor: pointer;
    transition: all 0.15s;
    line-height: 1;
}
.ar-pill:hover { background: var(--cor-tinte-medio); }
.ar-pill.active {
    background: var(--cor-principal);
    color: var(--cor-texto-claro);
    box-shadow: 0 2px 8px rgba(0,0,0,0.18);
}
.ar-pill.active::before {
    content: '✓ ';
    font-weight: 700;
    font-size: 0.8em;
}

/* Resumo da recorrência selecionada no toggle */
.ar-recorrente-resumo {
    font-size: 0.78rem;
    font-weight: 600;
    color: var(--cor-principal);
    background: var(--cor-tinte-suave);
    border: 1px solid var(--cor-tinte-borda);
    border-radius: 20px;
    padding: 2px 10px;
    margin-left: 6px;
    white-space: nowrap;
    max-width: 260px;
    overflow: hidden;
    text-overflow: ellipsis;
}

.ar-pill-sm { padding: 5px 9px; font-size: 0.78rem; }

.ar-daygrid { gap: 4px; }

.ar-select-small {
    height: 40px;
    border-radius: 8px;
    border: 2px solid var(--cor-principal);
    padding: 0 12px;
    font-size: 0.88rem;
    font-weight: 600;
    color: var(--cor-principal);
    background: transparent;
    cursor: pointer;
    appearance: none;
    margin-top: 4px;
    outline: none;
}
.ar-select-small:focus { border-color: var(--cor-titulo); }

/* ══════════════════════════════════════════════════
   Clear-on-focus state indicator
══════════════════════════════════════════════════ */
.ar-field-submitted {
    background: var(--cor-fundo-campo) !important;
}
.ar-field-submitted + label {
    color: var(--cor-principal) !important;
    opacity: 0.7;
}

/* Empty lote row */
.ar-lote-vazio {
    text-align: center;
    color: var(--cor-texto-secundario);
    font-style: italic;
    padding: 20px;
}

/* Edit/delete action buttons in table */
.ar-lote-actions {
    display: flex;
    gap: 4px;
    align-items: center;
}
.ar-lote-btn {
    width: 30px;
    height: 30px;
    border: none;
    border-radius: 7px;
    background: transparent;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 1rem;
    transition: background 0.14s, color 0.14s;
}
.ar-lote-btn:hover { background: var(--cor-tinte-medio); }
.ar-lote-btn.delete:hover { background: var(--red-100); color: var(--red-700); }
.ar-lote-btn.edit:hover { background: var(--cor-tinte-medio); color: var(--cor-principal); }

:root {
    --cor-principal: #367373;
    --cor-fundo-pagina: #EBF4F4;
    --cor-fundo-card: #FAFFFF;
    --cor-titulo: #004C58;
    --cor-hover: #B4D9D5;
    --cor-texto-principal: #1A1A1A;
    --cor-texto-secundario: #4A4A4A;
    --cor-texto-alternativo: #367373;
    --cor-texto-claro: #FFFFFF;
    --cor-para-destacar: #004C58;
    --sombra-card: rgba(54, 115, 115, 0.099);
    --red-700: #b91c1c;
    --red-100: #fee2e2;
    --red-800: #9b1c1c;
    --green-700: #15803d;
    --green-100: #d1fae5;
    /* Tints */
    --cor-tinte-suave: rgba(54,115,115,0.06);
    --cor-tinte-medio: rgba(54,115,115,0.10);
    --cor-tinte-borda: rgba(54,115,115,0.18);
    --cor-fundo-campo: rgba(54,115,115,0.05);
    --cor-fundo-inativo: #d4e8e8;
    --cor-borda-mascote: #00AEFF;
    --sombra-flutuante: rgba(0,0,0,0.12);
    --sombra-caixa: rgba(0,0,0,0.22);
    /* UI general */
    --cor-overlay: rgba(0,0,0,0.5);
    --cor-borda-divisor: #cccccc;
    --cor-fundo-cadastro: #5FA8A3;
    --cor-padrao-geometrico: rgba(255,255,255,0.08);
    /* Toggle / switch */
    --cor-toggle-inativo: #d1d5db;
    --cor-toggle-handle: #535353;
    /* Action colors (edit / delete) */
    --cor-acao-editar: #00BBDD;
    --cor-acao-editar-suave: rgba(0,187,221,0.12);
    --cor-acao-deletar-suave: rgba(229,62,62,0.12);
    /* Event / agenda colors */
    --cor-gasto-bg: #FF9E9E;
    --cor-gasto-texto: #A00000;
    --cor-recebimento-bg: #B7FFB6;
    --cor-recebimento-texto: #0A6000;
    --cor-transferencia-bg: #7FFFFF;
    --cor-transferencia-texto: #006C9E;
    --cor-agendamento-bg: #FFFF9E;
    --cor-agendamento-texto: #AFA900;
}

